export type Message = {
  id: string
  roomId: string
  sender: string
  text: string
  timestamp: number
}

export type Room = {
  id: string
  name: string
  createdAt: number
  members: string[]
}

export type ReadCursor = {
  roomId: string
  userId: string
  lastReadMessageId: string | null
  lastReadAt: number
}

export type RoomData = {
  room: Room
  messages: Message[]
  cursors: ReadCursor[]
}

export type StoreData = {
  rooms: Record<string, RoomData>
}

import type { StoreData, RoomData } from './types'

const DATA_PATH = './data/chat-store.json'

const emptyStore = (): StoreData => ({ rooms: {} })

export const loadStore = async (): Promise<StoreData> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return emptyStore()
  try {
    return (await file.json()) as StoreData
  } catch {
    return emptyStore()
  }
}

export const saveStore = async (data: StoreData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const getRoomData = async (roomId: string): Promise<RoomData | null> => {
  const store = await loadStore()
  return store.rooms[roomId] ?? null
}

export const saveRoomData = async (roomId: string, roomData: RoomData): Promise<void> => {
  const store = await loadStore()
  store.rooms[roomId] = roomData
  await saveStore(store)
}

import { h } from '@plaited/template'
import type { TemplateObject } from '@plaited/template'

/**
 * Parses markdown-style bold (**text**) and italic (*text*) into
 * plaited template nodes. Returns an array of string and TemplateObject segments.
 */
export const formatText = (raw: string): (string | TemplateObject)[] => {
  const segments: (string | TemplateObject)[] = []
  // Match **bold** first, then *italic*
  const pattern = /\*\*(.+?)\*\*|\*(.+?)\*/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = pattern.exec(raw)) !== null) {
    // Push any plain text before this match
    if (match.index > lastIndex) {
      segments.push(raw.slice(lastIndex, match.index))
    }

    if (match[1] !== undefined) {
      // Bold match
      segments.push(h('strong', {}, match[1]))
    } else if (match[2] !== undefined) {
      // Italic match
      segments.push(h('em', {}, match[2]))
    }

    lastIndex = pattern.lastIndex
  }

  // Push any remaining plain text
  if (lastIndex < raw.length) {
    segments.push(raw.slice(lastIndex))
  }

  if (segments.length === 0) {
    segments.push(raw)
  }

  return segments
}

import type { Room, RoomData, ReadCursor } from './types'
import { loadStore, saveStore, getRoomData, saveRoomData } from './store'

export const createRoom = async (name: string): Promise<Room> => {
  const id = name.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '')
  const store = await loadStore()

  if (store.rooms[id]) {
    return store.rooms[id].room
  }

  const room: Room = {
    id,
    name,
    createdAt: Date.now(),
    members: [],
  }

  const roomData: RoomData = {
    room,
    messages: [],
    cursors: [],
  }

  store.rooms[id] = roomData
  await saveStore(store)
  return room
}

export const joinRoom = async (roomId: string, userId: string): Promise<boolean> => {
  const roomData = await getRoomData(roomId)
  if (!roomData) return false

  if (!roomData.room.members.includes(userId)) {
    roomData.room.members.push(userId)
  }

  // Initialize read cursor if missing
  const hasCursor = roomData.cursors.some(
    (c) => c.roomId === roomId && c.userId === userId,
  )
  if (!hasCursor) {
    roomData.cursors.push({
      roomId,
      userId,
      lastReadMessageId: null,
      lastReadAt: Date.now(),
    })
  }

  await saveRoomData(roomId, roomData)
  return true
}

export const getRooms = async (): Promise<Room[]> => {
  const store = await loadStore()
  return Object.values(store.rooms).map((rd) => rd.room)
}

export const getUnreadCount = async (roomId: string, userId: string): Promise<number> => {
  const roomData = await getRoomData(roomId)
  if (!roomData) return 0

  const cursor = roomData.cursors.find(
    (c) => c.roomId === roomId && c.userId === userId,
  )

  if (!cursor || !cursor.lastReadMessageId) {
    return roomData.messages.length
  }

  const lastReadIndex = roomData.messages.findIndex(
    (m) => m.id === cursor.lastReadMessageId,
  )

  if (lastReadIndex === -1) return roomData.messages.length
  return roomData.messages.length - lastReadIndex - 1
}

export const markAsRead = async (roomId: string, userId: string): Promise<void> => {
  const roomData = await getRoomData(roomId)
  if (!roomData) return

  const lastMessage = roomData.messages[roomData.messages.length - 1]
  if (!lastMessage) return

  const cursor = roomData.cursors.find(
    (c) => c.roomId === roomId && c.userId === userId,
  )

  if (cursor) {
    cursor.lastReadMessageId = lastMessage.id
    cursor.lastReadAt = Date.now()
  } else {
    roomData.cursors.push({
      roomId,
      userId,
      lastReadMessageId: lastMessage.id,
      lastReadAt: Date.now(),
    })
  }

  await saveRoomData(roomId, roomData)
}

import type { Message } from './types'
import { getRoomData, saveRoomData } from './store'

const generateId = (): string =>
  `msg_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const postMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message | null> => {
  const roomData = await getRoomData(roomId)
  if (!roomData) return null

  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  }

  roomData.messages.push(message)
  await saveRoomData(roomId, roomData)
  return message
}

export const getRoomMessages = async (
  roomId: string,
  limit = 50,
  before?: string,
): Promise<Message[]> => {
  const roomData = await getRoomData(roomId)
  if (!roomData) return []

  let messages = roomData.messages

  if (before) {
    const idx = messages.findIndex((m) => m.id === before)
    if (idx !== -1) {
      messages = messages.slice(0, idx)
    }
  }

  return messages.slice(-limit)
}

