    h('div', { style: styles.messageMeta },
      h('span', { style: styles.senderName }, msg.sender),
      h('span', { style: styles.timestamp }, formatTimestamp(msg.timestamp)),
    ),
    h('div', { style: styles.messageText }, ...formatText(msg.text)),
  )

const renderRoomListItem = (
  room: Room,
  unread: number,
): TemplateObject =>
  h('li', {
    style: styles.roomItem,
    'p-trigger': `{ "click": "room-select" }`,
    'data-room-id': room.id,
  },
    h('span', {}, `# ${room.name}`),
    unread > 0
      ? h('span', { style: styles.unreadBadge }, String(unread))
      : h(Fragment, {}),
  )

export const renderRoomList = async (userId: string): Promise<string> => {
  const rooms = await getRooms()
  const items: TemplateObject[] = []

  for (const room of rooms) {
    const unread = await getUnreadCount(room.id, userId)
    items.push(renderRoomListItem(room, unread))
  }

  const template = h('div', { style: styles.sidebar },
    h('div', { style: styles.sidebarHeader }, 'Chat Rooms'),
    h('ul', { style: styles.roomList, 'p-target': 'room-list' }, ...items),
    h('button', {
      style: styles.createButton,
      'p-trigger': '{ "click": "create-room" }',
    }, '+ New Room'),
  )

  const { render } = createSSR()
  return render(template)
}

export const renderRoom = async (
  roomId: string,
  userId: string,
): Promise<string> => {
  const messages = await getRoomMessages(roomId)
  const rooms = await getRooms()
  const room = rooms.find((r) => r.id === roomId)
  const roomName = room?.name ?? roomId

  const template = h('div', { style: styles.chatArea },
    h('div', { style: styles.chatHeader }, `# ${roomName}`),
    h('div', {
      style: styles.messageList,
      'p-target': 'message-list',
    },
      ...messages.map(renderMessage),
    ),
    h('div', {
      style: styles.typingIndicator,
      'p-target': 'typing-indicator',
    }),
    h('div', { style: styles.inputArea },
      h('input', {
        style: styles.input,
        type: 'text',
        placeholder: 'Type a message... (**bold**, *italic*)',
        'p-target': 'message-input',
        'p-trigger': '{ "keydown": "input-keydown" }',
      }),
      h('button', {
        style: styles.sendButton,
        'p-trigger': '{ "click": "send-message" }',
      }, 'Send'),
    ),
  )

  const { render } = createSSR()
  return render(template)
}

export const renderApp = async (
  userId: string,
  activeRoomId?: string,
): Promise<string> => {
  const sidebarHtml = await renderRoomList(userId)
  const chatHtml = activeRoomId
    ? await renderRoom(activeRoomId, userId)
    : '<div style="flex:1;display:flex;align-items:center;justify-content:center;color:#999">Select or create a room to start chatting</div>'

  const { render } = createSSR()
  const template = h('div', { style: styles.container },
    h('div', { innerHTML: sidebarHtml }),
    h('div', { innerHTML: chatHtml }),
  )

  return render(template)
}

