export type Message = {
  id: string
  sender: string
  text: string
  timestamp: string
}

export type Room = {
  name: string
  messages: Message[]
  createdAt: string
}

export type RoomMeta = {
  name: string
  messageCount: number
  lastReadCount: number
  typingUsers: string[]
}

export type ChatState = {
  rooms: Record<string, Room>
  roomMeta: Record<string, RoomMeta>
}

import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

const BOLD_RE = /\*([^*]+)\*/g
const ITALIC_RE = /_([^_]+)_/g

export const formatText = (text: string): TemplateObject[] => {
  const parts: TemplateObject[] = []
  let remaining = text
  let match: RegExpExecArray | null

  // Process bold and italic patterns by splitting into segments
  const segments = splitFormatted(remaining)
  for (const seg of segments) {
    parts.push(seg)
  }

  return parts
}

const splitFormatted = (text: string): TemplateObject[] => {
  const results: TemplateObject[] = []
  const combined = /(\*([^*]+)\*)|(_([^_]+)_)/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = combined.exec(text)) !== null) {
    // Add plain text before this match
    if (match.index > lastIndex) {
      results.push(h('span', {}, text.slice(lastIndex, match.index)))
    }

    if (match[1]) {
      // Bold: *text*
      results.push(h('strong', {}, match[2]))
    } else if (match[3]) {
      // Italic: _text_
      results.push(h('em', {}, match[4]))
    }

    lastIndex = match.index + match[0].length
  }

  // Add remaining plain text
  if (lastIndex < text.length) {
    results.push(h('span', {}, text.slice(lastIndex)))
  }

  if (results.length === 0) {
    results.push(h('span', {}, text))
  }

  return results
}

import type { ChatState, Message, Room, RoomMeta } from './types'

const DATA_DIR = `${import.meta.dir}/data`

const stateFilePath = `${DATA_DIR}/state.json`

const defaultState: ChatState = {
  rooms: {},
  roomMeta: {},
}

const loadState = async (): Promise<ChatState> => {
  const file = Bun.file(stateFilePath)
  const exists = await file.exists()
  if (!exists) return { ...defaultState, rooms: {}, roomMeta: {} }
  const text = await file.text()
  return JSON.parse(text) as ChatState
}

const saveState = async (state: ChatState): Promise<void> => {
  await Bun.write(stateFilePath, JSON.stringify(state, null, 2))
}

export const createRoom = async (name: string): Promise<Room> => {
  const state = await loadState()
  if (state.rooms[name]) return state.rooms[name]

  const room: Room = {
    name,
    messages: [],
    createdAt: new Date().toISOString(),
  }

  const meta: RoomMeta = {
    name,
    messageCount: 0,
    lastReadCount: 0,
    typingUsers: [],
  }

  state.rooms[name] = room
  state.roomMeta[name] = meta
  await saveState(state)
  return room
}

export const getRooms = async (): Promise<RoomMeta[]> => {
  const state = await loadState()
  return Object.values(state.roomMeta)
}

export const getRoom = async (name: string): Promise<Room | null> => {
  const state = await loadState()
  return state.rooms[name] ?? null
}

export const getMessages = async (roomName: string): Promise<Message[]> => {
  const state = await loadState()
  return state.rooms[roomName]?.messages ?? []
}

export const sendMessage = async (
  roomName: string,
  sender: string,
  text: string,
): Promise<Message | null> => {
  const state = await loadState()
  const room = state.rooms[roomName]
  if (!room) return null

  const message: Message = {
    id: crypto.randomUUID(),
    sender,
    text,
    timestamp: new Date().toISOString(),
  }

  room.messages.push(message)
  state.roomMeta[roomName].messageCount = room.messages.length
  await saveState(state)
  return message
}

export const markRoomRead = async (roomName: string): Promise<void> => {
  const state = await loadState()
  const meta = state.roomMeta[roomName]
  if (!meta) return
  meta.lastReadCount = state.rooms[roomName]?.messages.length ?? 0
  await saveState(state)
}

export const getUnreadCount = async (roomName: string): Promise<number> => {
  const state = await loadState()
  const meta = state.roomMeta[roomName]
  if (!meta) return 0
  const totalMessages = state.rooms[roomName]?.messages.length ?? 0
  return totalMessages - meta.lastReadCount
}

export const setTyping = async (
  roomName: string,
  user: string,
  isTyping: boolean,
): Promise<void> => {
  const state = await loadState()
  const meta = state.roomMeta[roomName]
  if (!meta) return

  if (isTyping && !meta.typingUsers.includes(user)) {
    meta.typingUsers.push(user)
  } else if (!isTyping) {
    meta.typingUsers = meta.typingUsers.filter((u) => u !== user)
  }

  await saveState(state)
}

export const deleteRoom = async (name: string): Promise<boolean> => {
  const state = await loadState()
  if (!state.rooms[name]) return false
  delete state.rooms[name]
  delete state.roomMeta[name]
  await saveState(state)
  return true
}

