const toStyleString = (obj: Record<string, string>): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (c) => `-${c.toLowerCase()}`)}:${v}`)
    .join(';')

const renderMessage = (msg: Message) => {
  const time = new Date(msg.timestamp)
  const timeStr = time.toLocaleTimeString('en-US', {
    hour: '2-digit',
    minute: '2-digit',
  })

  return h(
    'div',
    { style: toStyleString(styles.messageBubble) },
    h('div', { style: toStyleString(styles.messageSender) }, msg.sender),
    h('div', { style: toStyleString(styles.messageText) }, ...formatText(msg.text)),
    h('div', { style: toStyleString(styles.messageTime) }, timeStr),
  )
}

const renderRoomItem = (meta: RoomMeta, isActive: boolean) => {
  const itemStyle = {
    ...styles.roomItem,
    ...(isActive ? styles.roomItemActive : {}),
  }
  const unread = meta.messageCount - meta.lastReadCount

