import { createRoom, getRooms, getMessages, sendMessage, markRoomRead, getUnreadCount, setTyping } from './store'
import { renderApp } from './render'

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname

  // GET /rooms — list all rooms
  if (req.method === 'GET' && path === '/rooms') {
    const rooms = await getRooms()
    return Response.json(rooms)
  }

  // POST /rooms — create a room { name }
  if (req.method === 'POST' && path === '/rooms') {
    const body = (await req.json()) as { name: string }
    const room = await createRoom(body.name)
    return Response.json(room, { status: 201 })
  }

  // GET /rooms/:name/messages — get messages for a room
  const messagesMatch = path.match(/^\/rooms\/([^/]+)\/messages$/)
  if (req.method === 'GET' && messagesMatch) {
    const roomName = decodeURIComponent(messagesMatch[1])
    const messages = await getMessages(roomName)
    return Response.json(messages)
  }

  // POST /rooms/:name/messages — send a message { sender, text }
  if (req.method === 'POST' && messagesMatch) {
    const roomName = decodeURIComponent(messagesMatch[1])
    const body = (await req.json()) as { sender: string; text: string }
    const message = await sendMessage(roomName, body.sender, body.text)
    if (!message) return Response.json({ error: 'Room not found' }, { status: 404 })
    return Response.json(message, { status: 201 })
  }

  // POST /rooms/:name/read — mark room as read
  const readMatch = path.match(/^\/rooms\/([^/]+)\/read$/)
  if (req.method === 'POST' && readMatch) {
    const roomName = decodeURIComponent(readMatch[1])
    await markRoomRead(roomName)
    return Response.json({ ok: true })
  }

  // GET /rooms/:name/unread — get unread count
  const unreadMatch = path.match(/^\/rooms\/([^/]+)\/unread$/)
  if (req.method === 'GET' && unreadMatch) {
    const roomName = decodeURIComponent(unreadMatch[1])
    const count = await getUnreadCount(roomName)
    return Response.json({ unread: count })
  }

  // POST /rooms/:name/typing — set typing status { user, isTyping }
  const typingMatch = path.match(/^\/rooms\/([^/]+)\/typing$/)
  if (req.method === 'POST' && typingMatch) {
    const roomName = decodeURIComponent(typingMatch[1])
    const body = (await req.json()) as { user: string; isTyping: boolean }
    await setTyping(roomName, body.user, body.isTyping)
    return Response.json({ ok: true })
  }

  // GET /view?room=name&user=name — render HTML view
  if (req.method === 'GET' && path === '/view') {
    const activeRoom = url.searchParams.get('room')
    const rooms = await getRooms()
    const messages = activeRoom ? await getMessages(activeRoom) : []
    const meta = rooms.find((r) => r.name === activeRoom)
    const typingUsers = meta?.typingUsers ?? []

    if (activeRoom) {
      await markRoomRead(activeRoom)
    }

    const html = renderApp(rooms, activeRoom, messages, typingUsers)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  return Response.json({ error: 'Not found' }, { status: 404 })
}

