import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

const BOLD_RE = /\*\*(.+?)\*\*/g
const ITALIC_RE = /\*(.+?)\*/g

export const formatMessageText = (text: string): TemplateObject[] => {
  const parts: TemplateObject[] = []
  let remaining = text
  let key = 0

  // Process bold first, then italic on remaining segments
  const segments = remaining.split(BOLD_RE)

  for (let i = 0; i < segments.length; i++) {
    const segment = segments[i]
    if (i % 2 === 1) {
      // Bold match
      parts.push(h('strong', { key: `b-${key++}` }, segment))
    } else {
      // Check for italic in non-bold segments
      const italicSegments = segment.split(ITALIC_RE)
      for (let j = 0; j < italicSegments.length; j++) {
        const sub = italicSegments[j]
        if (j % 2 === 1) {
          parts.push(h('em', { key: `i-${key++}` }, sub))
        } else if (sub) {
          parts.push(h('span', { key: `t-${key++}` }, sub))
        }
      }
    }
  }

  return parts
}

import type { Room, Message, RoomData, ReadStatus, TypingStatus } from './types'

const ROOMS_PATH = './data/rooms.json'
const MESSAGES_DIR = './data/messages'
const READ_STATUS_PATH = './data/read-status.json'

const generateId = (): string => crypto.randomUUID()

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  const file = Bun.file(path)
  if (await file.exists()) {
    return file.json() as Promise<T>
  }
  return fallback
}

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

// Room operations

export const getRooms = async (): Promise<Room[]> => {
  return readJson<Room[]>(ROOMS_PATH, [])
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await getRooms()
  return rooms.find((r) => r.id === roomId)
}

export const createRoom = async (id: string, name: string, creator: string): Promise<Room> => {
  const rooms = await getRooms()

  if (rooms.some((r) => r.id === id)) {
    throw new Error(`Room "${id}" already exists`)
  }

  const now = Date.now()
  const room: Room = {
    id,
    name,
    members: [creator],
    createdAt: now,
    lastActivity: now,
  }

  rooms.push(room)
  await writeJson(ROOMS_PATH, rooms)

  // Initialize empty message file
  await writeJson(`${MESSAGES_DIR}/${id}.json`, [])

  return room
}

export const joinRoom = async (roomId: string, userId: string): Promise<Room> => {
  const rooms = await getRooms()
  const room = rooms.find((r) => r.id === roomId)

  if (!room) {
    throw new Error(`Room "${roomId}" not found`)
  }

  if (!room.members.includes(userId)) {
    room.members.push(userId)
    await writeJson(ROOMS_PATH, rooms)
  }

  return room
}

// Message operations

export const getMessages = async (roomId: string): Promise<Message[]> => {
  return readJson<Message[]>(`${MESSAGES_DIR}/${roomId}.json`, [])
}

export const sendMessage = async (
  roomId: string,
  params: { sender: string; text: string }
): Promise<Message> => {
  const rooms = await getRooms()
  const room = rooms.find((r) => r.id === roomId)

  if (!room) {
    throw new Error(`Room "${roomId}" not found`)
  }

  const message: Message = {
    id: generateId(),
    roomId,
    sender: params.sender,
    text: params.text,
    timestamp: Date.now(),
  }

  const messages = await getMessages(roomId)
  messages.push(message)
  await writeJson(`${MESSAGES_DIR}/${roomId}.json`, messages)

  // Update room lastActivity
  room.lastActivity = message.timestamp
  await writeJson(ROOMS_PATH, rooms)

  return message
}

// Read status operations

export const getReadStatus = async (): Promise<ReadStatus> => {
  return readJson<ReadStatus>(READ_STATUS_PATH, {})
}

export const markAsRead = async (roomId: string, userId: string): Promise<void> => {
  const status = await getReadStatus()
  if (!status[roomId]) {
    status[roomId] = {}
  }
  status[roomId][userId] = Date.now()
  await writeJson(READ_STATUS_PATH, status)
}

export const getUnreadCount = async (roomId: string, userId: string): Promise<number> => {
  const [status, messages] = await Promise.all([getReadStatus(), getMessages(roomId)])
  const lastRead = status[roomId]?.[userId] ?? 0
  return messages.filter((m) => m.timestamp > lastRead && m.sender !== userId).length
}

// Typing status (in-memory only, not persisted)

const typingStatus: TypingStatus = {}
const TYPING_TIMEOUT = 3000

export const setTyping = (roomId: string, userId: string): void => {
  if (!typingStatus[roomId]) {
    typingStatus[roomId] = {}
  }
  typingStatus[roomId][userId] = Date.now()
}

export const clearTyping = (roomId: string, userId: string): void => {
  if (typingStatus[roomId]) {
    delete typingStatus[roomId][userId]
  }
}

export const getTypingUsers = (roomId: string, excludeUserId?: string): string[] => {
  const roomTyping = typingStatus[roomId]
  if (!roomTyping) return []

  const now = Date.now()
  return Object.entries(roomTyping)
    .filter(([uid, ts]) => uid !== excludeUserId && now - ts < TYPING_TIMEOUT)
    .map(([uid]) => uid)
}

