export const renderRoom = async (
  activeRoomId: string | null,
  currentUserId: string
): Promise<string> => {
  const rooms = await getRooms()
  const unreadCounts = await Promise.all(
    rooms.map(async (r) => ({
      roomId: r.id,
      count: await getUnreadCount(r.id, currentUserId),
    }))
  )
  const unreadMap = Object.fromEntries(unreadCounts.map((u) => [u.roomId, u.count]))

  const messages = activeRoomId ? await getMessages(activeRoomId) : []
  const activeRoom = rooms.find((r) => r.id === activeRoomId)
  const typingUsers = activeRoomId ? getTypingUsers(activeRoomId, currentUserId) : []

  const sidebar = h('div', { style: styles.sidebar },
    h('div', { style: styles.sidebarHeader }, 'Chat Rooms'),
    h('div', { style: styles.roomList },
      ...rooms.map((r) => renderRoomListItem(r, unreadMap[r.id] ?? 0, r.id === activeRoomId)),
    ),
    h('button', { style: styles.createButton, 'p-trigger': 'create-room' }, '+ New Room'),
  )

  const chatContent = activeRoom
    ? h(Fragment, null,
        h('div', { style: styles.chatHeader }, `# ${activeRoom.name}`),
        h('div', { style: styles.messageList, 'p-target': 'message-list' },
          ...messages.map(renderMessageItem),
        ),
        renderTypingIndicator(typingUsers),
        h('div', { style: styles.inputArea },
          h('input', {
            style: styles.input,
            placeholder: 'Type a message... (*italic*, **bold**)',
            'p-target': 'message-input',
            'p-trigger': 'input-change',
          }),
          h('button', { style: styles.sendButton, 'p-trigger': 'send-message' }, 'Send'),
        ),
      )
    : h('div', { style: styles.emptyState }, 'Select or create a room to start chatting')

  const template = h('div', { style: styles.container },
    sidebar,
    h('div', { style: styles.chatArea }, chatContent),
  )

  const ssr = createSSR()
  return ssr(template)
}

export const renderRoomList = async (currentUserId: string): Promise<string> => {
  const rooms = await getRooms()
  const unreadCounts = await Promise.all(
    rooms.map(async (r) => ({
      roomId: r.id,
      count: await getUnreadCount(r.id, currentUserId),
    }))
  )

  const items = rooms.map((r, i) => {
    const unread = unreadCounts[i].count
    const badge = unread > 0 ? ` (${unread} unread)` : ''
    return `# ${r.name}${badge}`
  })

  return items.join('\n')
}

