const statusColors: Record<ReadingStatus, { bg: string; text: string }> = {
  'want-to-read': { bg: '#fef3c7', text: '#92400e' },
  reading: { bg: '#dbeafe', text: '#1e40af' },
  completed: { bg: '#d1fae5', text: '#065f46' },
}

const statusLabels: Record<ReadingStatus, string> = {
  'want-to-read': 'Want to Read',
  reading: 'Reading',
  completed: 'Completed',
}

const progressColor = (pct: number): string => {
  if (pct >= 1) return '#059669'
  if (pct >= 0.5) return '#2563eb'
  if (pct > 0) return '#d97706'
  return '#94a3b8'
}

export const renderProgressBar = (current: number, total: number) => {
  const pct = total > 0 ? current / total : 0
  const pctDisplay = Math.round(pct * 100)
  return h('div', { style: styles.progressContainer },
    h('div', { style: styles.progressLabel },
      h('span', {}, `${current} / ${total} pages`),
      h('span', {}, `${pctDisplay}%`),
    ),
    h('div', { style: styles.progressBar },
      h('div', {
        style: {
          ...styles.progressFill,
          width: `${pctDisplay}%`,
          background: progressColor(pct),
        },
      }),
    ),
  )
}

export const renderStatusBadge = (status: ReadingStatus) => {
  const color = statusColors[status]
  return h('span', {
    style: {
      ...styles.badge,
      background: color.bg,
      color: color.text,
    },
  }, statusLabels[status])
}

export const renderBookCard = (book: Book) => {
  const cover = book.coverUrl
    ? h('img', { src: book.coverUrl, alt: book.title, style: styles.coverImg })
    : h('div', { style: styles.coverPlaceholder }, book.title.charAt(0).toUpperCase())

  return h('div', { style: styles.bookCard, 'data-book-id': book.id },
    cover,
    h('div', { style: styles.bookInfo },
      h('div', { style: styles.bookTitle }, book.title),
      h('div', { style: styles.bookAuthor }, `by ${book.author}`),
      h('div', { style: styles.bookMeta },
        renderStatusBadge(book.status),
        h('span', {}, book.genre),
        h('span', {}, `${book.pageCount} pages`),
      ),
      renderProgressBar(book.currentPage, book.pageCount),
      h('div', { style: styles.actions },
        h('button', {
          style: styles.actionBtn,
          'p-trigger': 'updateProgress',
          'data-id': book.id,
        }, 'Update Page'),
        h('button', {
          style: styles.actionBtn,
          'p-trigger': 'changeStatus',
          'data-id': book.id,
        }, 'Change Status'),
        h('button', {
          style: { ...styles.actionBtn, color: '#dc2626', borderColor: '#fecaca' },
          'p-trigger': 'removeBook',
          'data-id': book.id,
        }, 'Remove'),
      ),
    ),
  )
}

export const renderStats = (stats: ReadingStats) => {
  const avgPct = Math.round(stats.averageProgress * 100)
  return h('div', { style: styles.statsGrid },
    h('div', { style: styles.statCard },
      h('div', { style: styles.statValue }, `${stats.totalBooks}`),
      h('div', { style: styles.statLabel }, 'Total Books'),
    ),
    h('div', { style: styles.statCard },
      h('div', { style: styles.statValue }, `${stats.booksCompleted}`),
      h('div', { style: styles.statLabel }, 'Completed'),
    ),
    h('div', { style: styles.statCard },
      h('div', { style: styles.statValue }, `${stats.totalPagesRead.toLocaleString()}`),
      h('div', { style: styles.statLabel }, 'Pages Read'),
    ),
    h('div', { style: styles.statCard },
      h('div', { style: styles.statValue }, `${avgPct}%`),
      h('div', { style: styles.statLabel }, 'Avg Progress'),
