export const renderFilters = (
  activeStatus: ReadingStatus | null,
  activeGenre: string | null,
  genres: string[],
) => {
  const statuses: (ReadingStatus | null)[] = [null, 'want-to-read', 'reading', 'completed']
  return h('div', { style: styles.filters },
    ...statuses.map((s) =>
      h('button', {
        style: activeStatus === s ? styles.filterBtnActive : styles.filterBtn,
        'p-trigger': 'filterStatus',
        'data-status': s ?? 'all',
      }, s ? statusLabels[s] : 'All'),
    ),
    genres.length > 0
      ? h(Fragment, {},
          h('span', { style: { alignSelf: 'center', color: '#ccc', margin: '0 4px' } }, '|'),
          ...genres.map((g) =>
            h('button', {
              style: activeGenre === g ? styles.filterBtnActive : styles.filterBtn,
              'p-trigger': 'filterGenre',
              'data-genre': g,
            }, g),
          ),
          activeGenre
            ? h('button', {
                style: styles.filterBtn,
                'p-trigger': 'filterGenre',
                'data-genre': '',
              }, 'All Genres')
            : null,
        )
      : null,
  )
}

export const renderAddForm = () => {
  return h('div', { style: styles.form },
    h('div', { style: styles.formTitle }, 'Add a Book'),
    h('form', { 'p-trigger': 'addBook' },
      h('div', { style: styles.formGrid },
