export const renderPage = (
  books: Book[],
  stats: ReadingStats,
  genres: string[],
  activeStatus: ReadingStatus | null,
  activeGenre: string | null,
) => {
  return h('div', { style: styles.container },
    h('h1', { style: styles.header }, 'Reading List'),
    renderStats(stats),
    renderAddForm(),
    renderFilters(activeStatus, activeGenre, genres),
    books.length > 0
      ? h('div', { style: styles.bookList }, ...books.map(renderBookCard))
      : h('div', { style: styles.empty }, 'No books yet. Add one above!'),
  )
}

import { createSSR } from 'plaited'
import type { BookFilters, BookInput, ReadingStatus } from './types'
import * as store from './store'
import { renderPage } from './render'

export { addBook, removeBook, updateProgress, updateStatus, getBooks, getBook, getStats, getGenres } from './store'
export type { Book, BookInput, BookFilters, ReadingStats, ReadingStatus } from './types'

export const renderReadingList = async (filters?: BookFilters) => {
  const activeStatus = filters?.status ?? null
  const activeGenre = filters?.genre ?? null

  const [books, stats, genres] = await Promise.all([
    store.getBooks(filters),
    store.getStats(),
    store.getGenres(),
  ])

  const template = renderPage(books, stats, genres, activeStatus, activeGenre)
  const { html, stylesheets } = createSSR(template)

  return { html, stylesheets }
}

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const ct = req.headers.get('content-type') ?? ''
  if (ct.includes('application/json')) return req.json()
  if (ct.includes('form')) {
    const fd = await req.formData()
    const obj: Record<string, string> = {}
    fd.forEach((v, k) => { obj[k] = v.toString() })
    return obj
  }
  return {}
}

export const handler = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // GET / — render full page
  if (method === 'GET' && path === '/') {
    const status = (url.searchParams.get('status') as ReadingStatus) || undefined
    const genre = url.searchParams.get('genre') || undefined
    const { html } = await renderReadingList({ status, genre })
    return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
  }

  // GET /api/books — list books as JSON
  if (method === 'GET' && path === '/api/books') {
    const status = (url.searchParams.get('status') as ReadingStatus) || undefined
    const genre = url.searchParams.get('genre') || undefined
    const books = await store.getBooks({ status, genre })
    return Response.json(books)
  }

  // GET /api/stats
  if (method === 'GET' && path === '/api/stats') {
    const stats = await store.getStats()
    return Response.json(stats)
  }

  // POST /api/books — add book
  if (method === 'POST' && path === '/api/books') {
    const body = await parseBody(req)
    const input: BookInput = {
      title: body.title,
      author: body.author,
      genre: body.genre,
      pageCount: Number(body.pageCount),
      coverUrl: body.coverUrl || undefined,
    }
    if (!input.title || !input.author || !input.genre || !input.pageCount) {
      return Response.json({ error: 'Missing required fields: title, author, genre, pageCount' }, { status: 400 })
    }
    const book = await store.addBook(input)
    return Response.json(book, { status: 201 })
  }

  // PATCH /api/books/:id/progress — update progress
  if (method === 'PATCH' && path.match(/^\/api\/books\/[^/]+\/progress$/)) {
    const id = path.split('/')[3]
    const body = await parseBody(req)
    const currentPage = Number(body.currentPage)
    if (isNaN(currentPage)) {
      return Response.json({ error: 'currentPage must be a number' }, { status: 400 })
    }
    const book = await store.updateProgress(id, currentPage)
    if (!book) return Response.json({ error: 'Book not found' }, { status: 404 })
    return Response.json(book)
  }

  // PATCH /api/books/:id/status — update status
  if (method === 'PATCH' && path.match(/^\/api\/books\/[^/]+\/status$/)) {
    const id = path.split('/')[3]
    const body = await parseBody(req)
    const status = body.status as ReadingStatus
    if (!['want-to-read', 'reading', 'completed'].includes(status)) {
      return Response.json({ error: 'Invalid status' }, { status: 400 })
    }
    const book = await store.updateStatus(id, status)
    if (!book) return Response.json({ error: 'Book not found' }, { status: 404 })
    return Response.json(book)
  }

  // DELETE /api/books/:id — remove book
  if (method === 'DELETE' && path.match(/^\/api\/books\/[^/]+$/)) {
    const id = path.split('/')[3]
    const removed = await store.removeBook(id)
    if (!removed) return Response.json({ error: 'Book not found' }, { status: 404 })
    return Response.json({ ok: true })
  }

  return Response.json({ error: 'Not found' }, { status: 404 })
}

{
  "name": "@node/reading-list",
  "version": "1.0.0",
  "modnet": {
    "contentType": "books",
    "structure": "collection",
    "mechanics": ["filter", "sort", "track"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Book, BookInput, FilterOptions, ReadingStats, ReadingStatus } from './types'

const DATA_PATH = new URL('./data/books.json', import.meta.url).pathname

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

const generateId = (): string =>
  crypto.randomUUID()

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? '',
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null

  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount))

  if (book.currentPage >= book.pageCount) {
    book.status = 'completed'
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }

  await saveBooks(books)
  return book
}

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null

  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  }

  await saveBooks(books)
  return book
}

export const removeBook = async (id: string): Promise<boolean> => {
  const books = await loadBooks()
  const index = books.findIndex((b) => b.id === id)
  if (index === -1) return false
  books.splice(index, 1)
  await saveBooks(books)
  return true
}

export const getBook = async (id: string): Promise<Book | null> => {
  const books = await loadBooks()
  return books.find((b) => b.id === id) ?? null
}

export const getBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  let books = await loadBooks()

  if (filters?.status) {
    books = books.filter((b) => b.status === filters.status)
  }
  if (filters?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase())
  }

  return books
}

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks()
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks()
  const totalBooks = books.length
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress = totalBooks > 0
    ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / totalBooks * 100
    : 0

  return {
    totalBooks,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPagesRead,
    averageProgress: Math.round(averageProgress * 10) / 10,
  }
}

