export { addBook, updateProgress, updateStatus, removeBook, getBooks, getBook, getGenres, getStats }

export const render = async (filters?: FilterOptions): Promise<string> => {
  const [books, stats, genres] = await Promise.all([
    getBooks(filters),
    getStats(),
    getGenres(),
  ])
  const template = renderPage(books, stats, genres, filters)
  const { html } = createSSR(template)
  return html
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname

  if (req.method === 'GET' && path === '/') {
    const status = url.searchParams.get('status') as ReadingStatus | null
    const genre = url.searchParams.get('genre')
    const filters: FilterOptions = {}
    if (status) filters.status = status
    if (genre) filters.genre = genre

    const html = await render(filters)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (req.method === 'POST' && path === '/books') {
    const body = (await req.json()) as BookInput
    const book = await addBook(body)
    return Response.json(book, { status: 201 })
  }

  if (req.method === 'PATCH' && path.startsWith('/books/') && path.endsWith('/progress')) {
    const id = path.split('/')[2]
    const { currentPage } = (await req.json()) as { currentPage: number }
    const book = await updateProgress(id, currentPage)
    if (!book) return Response.json({ error: 'Book not found' }, { status: 404 })
    return Response.json(book)
  }

  if (req.method === 'PATCH' && path.startsWith('/books/') && path.endsWith('/status')) {
    const id = path.split('/')[2]
    const { status } = (await req.json()) as { status: ReadingStatus }
    const book = await updateStatus(id, status)
    if (!book) return Response.json({ error: 'Book not found' }, { status: 404 })
    return Response.json(book)
  }

  if (req.method === 'DELETE' && path.startsWith('/books/')) {
    const id = path.split('/')[2]
    const removed = await removeBook(id)
    if (!removed) return Response.json({ error: 'Book not found' }, { status: 404 })
    return Response.json({ success: true })
  }

  if (req.method === 'GET' && path === '/stats') {
    const stats = await getStats()
    return Response.json(stats)
  }

  if (req.method === 'GET' && path === '/genres') {
    const genres = await getGenres()
    return Response.json(genres)
  }

  return Response.json({ error: 'Not found' }, { status: 404 })
}

export default {
  fetch: handleRequest,
}

