import type { Book, BookInput, ReadingListData, ReadingStatus, FilterOptions, Stats } from './types'

const DATA_PATH = `${import.meta.dir}/data/reading-list.json`

const generateId = (): string => crypto.randomUUID()

const loadData = async (): Promise<ReadingListData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { books: [] }
}

const saveData = async (data: ReadingListData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const addBook = async (input: BookInput): Promise<Book> => {
  const data = await loadData()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? '',
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  }
  data.books.push(book)
  await saveData(data)
  return book
}

export const removeBook = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const index = data.books.findIndex((b) => b.id === id)
  if (index === -1) return false
  data.books.splice(index, 1)
  await saveData(data)
  return true
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const data = await loadData()
  const book = data.books.find((b) => b.id === id)
  if (!book) return null
  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount))
  if (book.currentPage >= book.pageCount) {
    book.status = 'completed'
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }
  await saveData(data)
  return book
}

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const data = await loadData()
  const book = data.books.find((b) => b.id === id)
  if (!book) return null
  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  }
  await saveData(data)
  return book
}

export const getBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  const data = await loadData()
  let books = data.books
  if (filters?.status) {
    books = books.filter((b) => b.status === filters.status)
  }
  if (filters?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase())
  }
  return books
}

export const getBook = async (id: string): Promise<Book | null> => {
  const data = await loadData()
  return data.books.find((b) => b.id === id) ?? null
}

export const getStats = async (): Promise<Stats> => {
  const data = await loadData()
  const { books } = data
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / books.length
      : 0
  const genres = [...new Set(books.map((b) => b.genre))].sort()
  return {
    totalBooks: books.length,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPagesRead,
    averageProgress,
    genres,
  }
}

import type { BookInput, FilterOptions, ReadingStatus } from './types'
import { addBook, removeBook, updateProgress, updateStatus, getBooks, getStats } from './store'
import { renderPage } from './render'
import { createSSR } from 'plaited'

export type ActionResult = {
  html: string
  status: number
  error?: string
}

const renderView = async (filters: FilterOptions = {}): Promise<string> => {
  const [books, stats] = await Promise.all([getBooks(filters), getStats()])
  const template = renderPage(books, stats, filters)
  const ssr = createSSR()
  return ssr(template)
}

export const handleListBooks = async (filters: FilterOptions = {}): Promise<ActionResult> => {
  const html = await renderView(filters)
  return { html, status: 200 }
}

export const handleAddBook = async (input: BookInput): Promise<ActionResult> => {
  if (!input.title?.trim()) {
    return { html: '', status: 400, error: 'Title is required' }
  }
  if (!input.author?.trim()) {
    return { html: '', status: 400, error: 'Author is required' }
  }
  if (!input.genre?.trim()) {
    return { html: '', status: 400, error: 'Genre is required' }
  }
  if (!input.pageCount || input.pageCount < 1) {
    return { html: '', status: 400, error: 'Page count must be at least 1' }
  }
  await addBook(input)
  const html = await renderView()
  return { html, status: 201 }
}

export const handleRemoveBook = async (id: string): Promise<ActionResult> => {
  const removed = await removeBook(id)
  if (!removed) {
    return { html: '', status: 404, error: 'Book not found' }
  }
  const html = await renderView()
  return { html, status: 200 }
}

export const handleUpdateProgress = async (id: string, currentPage: number): Promise<ActionResult> => {
  const book = await updateProgress(id, currentPage)
  if (!book) {
    return { html: '', status: 404, error: 'Book not found' }
  }
  const html = await renderView()
  return { html, status: 200 }
}

export const handleUpdateStatus = async (id: string, status: ReadingStatus): Promise<ActionResult> => {
  const validStatuses: ReadingStatus[] = ['want-to-read', 'reading', 'completed']
  if (!validStatuses.includes(status)) {
    return { html: '', status: 400, error: 'Invalid status' }
  }
  const book = await updateStatus(id, status)
  if (!book) {
    return { html: '', status: 404, error: 'Book not found' }
  }
  const html = await renderView()
  return { html, status: 200 }
}

import type { ReadingStatus, FilterOptions, BookInput } from './types'
import {
  handleListBooks,
  handleAddBook,
  handleRemoveBook,
  handleUpdateProgress,
  handleUpdateStatus,
} from './handlers'

const parseFilters = (url: URL): FilterOptions => {
  const status = url.searchParams.get('status') as ReadingStatus | null
  const genre = url.searchParams.get('genre')
  return {
    ...(status ? { status } : {}),
    ...(genre ? { genre } : {}),
  }
}

const jsonResponse = (body: unknown, status = 200) =>
  new Response(JSON.stringify(body), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export default {
  port: 3456,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const path = url.pathname

    // GET / — render the reading list page
    if (req.method === 'GET' && path === '/') {
      const filters = parseFilters(url)
      const result = await handleListBooks(filters)
      return htmlResponse(result.html, result.status)
    }

    // POST /books — add a new book
    if (req.method === 'POST' && path === '/books') {
      const body = (await req.json()) as BookInput
      const result = await handleAddBook(body)
      if (result.error) return jsonResponse({ error: result.error }, result.status)
      return htmlResponse(result.html, result.status)
    }

    // DELETE /books/:id — remove a book
    if (req.method === 'DELETE' && path.startsWith('/books/')) {
      const id = path.split('/')[2]
      const result = await handleRemoveBook(id)
      if (result.error) return jsonResponse({ error: result.error }, result.status)
      return htmlResponse(result.html, result.status)
    }

    // PATCH /books/:id/progress — update reading progress
    if (req.method === 'PATCH' && path.match(/^\/books\/[^/]+\/progress$/)) {
      const id = path.split('/')[2]
      const body = (await req.json()) as { currentPage: number }
      const result = await handleUpdateProgress(id, body.currentPage)
      if (result.error) return jsonResponse({ error: result.error }, result.status)
      return htmlResponse(result.html, result.status)
    }

    // PATCH /books/:id/status — update book status
    if (req.method === 'PATCH' && path.match(/^\/books\/[^/]+\/status$/)) {
      const id = path.split('/')[2]
      const body = (await req.json()) as { status: ReadingStatus }
      const result = await handleUpdateStatus(id, body.status)
      if (result.error) return jsonResponse({ error: result.error }, result.status)
      return htmlResponse(result.html, result.status)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

