import { join } from 'path'
import type { Meal, DailyGoal, FoodCategory, DailySummary, WeeklyData, LogMealInput, SetGoalInput } from './types'

const DATA_DIR = join(import.meta.dir, 'data')
const MEALS_PATH = join(DATA_DIR, 'meals.jsonl')
const GOALS_PATH = join(DATA_DIR, 'goals.json')

const generateId = (): string => crypto.randomUUID()

const toDateString = (date: Date): string =>
  `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`

export const loadMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Meal)
}

const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const prefix = existing && !existing.endsWith('\n') ? '\n' : ''
  await Bun.write(MEALS_PATH, existing + prefix + JSON.stringify(meal) + '\n')
}

export const loadGoal = async (): Promise<DailyGoal> => {
  const file = Bun.file(GOALS_PATH)
  const exists = await file.exists()
  if (!exists) return { dailyGoal: 2000, updatedAt: new Date().toISOString() }
  return JSON.parse(await file.text()) as DailyGoal
}

const saveGoal = async (goal: DailyGoal): Promise<void> => {
  await Bun.write(GOALS_PATH, JSON.stringify(goal, null, 2) + '\n')
}

export const logMeal = async (input: LogMealInput): Promise<Meal> => {
  const totalCalories = input.items.reduce((sum, item) => sum + item.calories, 0)
  const meal: Meal = {
    id: generateId(),
    name: input.name,
    items: input.items,
    totalCalories,
    timestamp: new Date().toISOString(),
  }
  await appendMeal(meal)
  return meal
}

export const setDailyGoal = async (input: SetGoalInput): Promise<DailyGoal> => {
  const goal: DailyGoal = {
    dailyGoal: input.dailyGoal,
    updatedAt: new Date().toISOString(),
  }
  await saveGoal(goal)
  return goal
}

export const getDailySummary = async (dateStr?: string): Promise<DailySummary> => {
  const targetDate = dateStr ?? toDateString(new Date())
  const meals = await loadMeals()
  const goal = await loadGoal()

  const dayMeals = meals.filter((m) => m.timestamp.startsWith(targetDate))
  const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0)

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  }

  for (const meal of dayMeals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories
      }
    }
  }

  return {
    date: targetDate,
    meals: dayMeals,
    totalCalories,
    categoryBreakdown,
    goal: goal.dailyGoal,
    remaining: goal.dailyGoal - totalCalories,
  }
}

export const getWeeklyData = async (): Promise<WeeklyData> => {
  const meals = await loadMeals()
  const goal = await loadGoal()
  const today = new Date()
  const result: WeeklyData = []

  for (let i = 6; i >= 0; i--) {
    const d = new Date(today)
    d.setDate(d.getDate() - i)
    const dateStr = toDateString(d)
    const dayMeals = meals.filter((m) => m.timestamp.startsWith(dateStr))
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0)
    result.push({ date: dateStr, totalCalories, goal: goal.dailyGoal })
  }

  return result
}

export const getMealsByCategory = async (category: FoodCategory): Promise<Meal[]> => {
  const meals = await loadMeals()
  return meals.filter((m) => m.items.some((item) => item.categories.includes(category)))
}

