import { createSSR } from 'plaited'
import { logMeal, setDailyGoal, getDailySummary, getWeeklyData, getMealsByCategory, loadGoal } from './data'
import { renderDailySummary, renderWeeklyChart, renderMealForm, renderGoalForm } from './views'
import type { LogMealInput, SetGoalInput, FoodCategory } from './types'

const ssr = createSSR()

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (template: ReturnType<typeof renderDailySummary>) =>
  new Response(ssr(template), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export default {
  port: 3000,

  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)
    const path = url.pathname

    // POST /api/meals — log a meal
    if (req.method === 'POST' && path === '/api/meals') {
      const body = (await req.json()) as LogMealInput
      if (!body.name || !Array.isArray(body.items) || body.items.length === 0) {
        return jsonResponse({ error: 'name and items[] are required' }, 400)
      }
      const meal = await logMeal(body)
      return jsonResponse(meal, 201)
    }

    // POST /api/goal — set daily calorie goal
    if (req.method === 'POST' && path === '/api/goal') {
      const body = (await req.json()) as SetGoalInput
      if (!body.dailyGoal || body.dailyGoal < 1) {
        return jsonResponse({ error: 'dailyGoal must be a positive number' }, 400)
      }
      const goal = await setDailyGoal(body)
      return jsonResponse(goal)
    }

    // GET /api/summary?date=YYYY-MM-DD — daily summary JSON
    if (req.method === 'GET' && path === '/api/summary') {
      const date = url.searchParams.get('date') ?? undefined
      const summary = await getDailySummary(date)
      return jsonResponse(summary)
    }

    // GET /api/weekly — weekly data JSON
    if (req.method === 'GET' && path === '/api/weekly') {
      const data = await getWeeklyData()
      return jsonResponse(data)
    }

    // GET /api/meals?category=protein — filter meals by category
    if (req.method === 'GET' && path === '/api/meals') {
      const category = url.searchParams.get('category') as FoodCategory | null
      if (category) {
        const meals = await getMealsByCategory(category)
        return jsonResponse(meals)
      }
      const { meals } = await getDailySummary()
      return jsonResponse(meals)
    }

    // GET /api/goal — current goal
    if (req.method === 'GET' && path === '/api/goal') {
      const goal = await loadGoal()
      return jsonResponse(goal)
    }

    // HTML views

    // GET / or /summary — rendered daily summary
    if (path === '/' || path === '/summary') {
      const date = url.searchParams.get('date') ?? undefined
      const summary = await getDailySummary(date)
      return htmlResponse(renderDailySummary(summary))
    }

    // GET /weekly — rendered weekly chart
    if (path === '/weekly') {
      const data = await getWeeklyData()
      return htmlResponse(renderWeeklyChart(data))
    }

    // GET /log — meal logging form
    if (path === '/log') {
      return htmlResponse(renderMealForm())
    }

    // GET /goal — goal setting form
    if (path === '/goal') {
      const goal = await loadGoal()
      return htmlResponse(renderGoalForm(goal.dailyGoal))
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

