  calories: number;
  category: FoodCategory;
};

export type Meal = {
  id: string;
  name: string;
  items: FoodItem[];
  timestamp: string; // ISO 8601
};

export type DailyGoal = {
  calories: number;
  updatedAt: string; // ISO 8601
};

export type DaySummary = {
  date: string; // YYYY-MM-DD
  meals: Meal[];
  totalCalories: number;
  categoryBreakdown: Record<FoodCategory, number>;
  goal: number;
};

export type WeekEntry = {
  date: string; // YYYY-MM-DD
  dayLabel: string; // e.g. "Mon 03/09"
  totalCalories: number;
};

import type { Meal, DailyGoal, FoodCategory, DaySummary, WeekEntry } from "./types";

const MEALS_PATH = new URL("./data/meals.json", import.meta.url).pathname;
const GOALS_PATH = new URL("./data/goals.json", import.meta.url).pathname;

// ── Helpers ──

const generateId = (): string =>
  `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

const toDateString = (iso: string): string => iso.slice(0, 10);

const today = (): string => new Date().toISOString().slice(0, 10);

// ── Meals ──

export const readMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

const writeMeals = async (meals: Meal[]): Promise<void> => {
  await Bun.write(MEALS_PATH, JSON.stringify(meals, null, 2));
};

export const logMeal = async (
  name: string,
  items: Meal["items"],
  timestamp?: string,
): Promise<Meal> => {
  const meals = await readMeals();
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    timestamp: timestamp ?? new Date().toISOString(),
  };
  meals.push(meal);
  await writeMeals(meals);
  return meal;
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await readMeals();
  const idx = meals.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  meals.splice(idx, 1);
  await writeMeals(meals);
  return true;
};

// ── Goals ──

export const readGoal = async (): Promise<DailyGoal> => {
  const file = Bun.file(GOALS_PATH);
  if (!(await file.exists()))
    return { calories: 2000, updatedAt: new Date().toISOString() };
  return file.json();
};

export const setGoal = async (calories: number): Promise<DailyGoal> => {
  const goal: DailyGoal = { calories, updatedAt: new Date().toISOString() };
  await Bun.write(GOALS_PATH, JSON.stringify(goal, null, 2));
  return goal;
};

// ── Summaries ──

export const getDailySummary = async (
  date?: string,
): Promise<DaySummary> => {
  const targetDate = date ?? today();
  const meals = await readMeals();
  const goal = await readGoal();

  const dayMeals = meals.filter(
    (m) => toDateString(m.timestamp) === targetDate,
  );

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  let totalCalories = 0;

  for (const meal of dayMeals) {
    for (const item of meal.items) {
      totalCalories += item.calories;
      categoryBreakdown[item.category] += item.calories;
    }
  }

  return {
    date: targetDate,
    meals: dayMeals,
    totalCalories,
    categoryBreakdown,
    goal: goal.calories,
  };
};

export const getWeekData = async (): Promise<WeekEntry[]> => {
  const meals = await readMeals();
  const entries: WeekEntry[] = [];
  const dayNames = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    const month = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    const dayLabel = `${dayNames[d.getDay()]} ${month}/${day}`;

    const total = meals
      .filter((m) => toDateString(m.timestamp) === dateStr)
      .reduce(
        (sum, m) => sum + m.items.reduce((s, it) => s + it.calories, 0),
        0,
      );

    entries.push({ date: dateStr, dayLabel, totalCalories: total });
  }

  return entries;
};

