import type { Meal, MealLogEntry, Settings } from './types';

const DATA_DIR = import.meta.dir + '/data';
const MEALS_PATH = `${DATA_DIR}/meals.jsonl`;
const SETTINGS_PATH = `${DATA_DIR}/settings.json`;

export const getSettings = async (): Promise<Settings> => {
  const file = Bun.file(SETTINGS_PATH);
  if (await file.exists()) {
    return file.json() as Promise<Settings>;
  }
  return { dailyGoal: 2000 };
};

export const saveSettings = async (settings: Settings): Promise<void> => {
  await Bun.write(SETTINGS_PATH, JSON.stringify(settings, null, 2));
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const entry: MealLogEntry = { ...meal, _type: 'meal' };
  const line = JSON.stringify(entry) + '\n';
  const file = Bun.file(MEALS_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  await Bun.write(MEALS_PATH, existing + line);
};

export const getAllMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => {
      const parsed = JSON.parse(line) as MealLogEntry;
      const { _type, ...meal } = parsed;
      return meal;
    });
};

export const getMealsForDate = async (date: string): Promise<Meal[]> => {
  const all = await getAllMeals();
  return all.filter((m) => m.timestamp.startsWith(date));
};

export const getMealsForDateRange = async (startDate: string, endDate: string): Promise<Meal[]> => {
  const all = await getAllMeals();
  return all.filter((m) => {
    const d = m.timestamp.slice(0, 10);
    return d >= startDate && d <= endDate;
  });
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const all = await getAllMeals();
  const filtered = all.filter((m) => m.id !== id);
  if (filtered.length === all.length) return false;
  const lines = filtered.map((m) => JSON.stringify({ ...m, _type: 'meal' })).join('\n') + (filtered.length > 0 ? '\n' : '');
  await Bun.write(MEALS_PATH, lines);
  return true;
};

import type { Meal, FoodItem, FoodCategory, DailySummary, WeeklyData } from './types';
import { getMealsForDate, getMealsForDateRange, appendMeal, getSettings, saveSettings } from './data';

const generateId = (): string => crypto.randomUUID();

const toDateString = (date: Date): string => date.toISOString().slice(0, 10);

export const logMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string,
): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name,
    timestamp: timestamp ?? new Date().toISOString(),
    items,
  };
  await appendMeal(meal);
  return meal;
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? toDateString(new Date());
  const meals = await getMealsForDate(targetDate);
  const settings = await getSettings();

  const totalCalories = meals.reduce(
    (sum, meal) => sum + meal.items.reduce((s, item) => s + item.calories, 0),
    0,
  );

  const categories: FoodCategory[] = ['protein', 'carbs', 'fat', 'fiber'];
  const categoryBreakdown = Object.fromEntries(
    categories.map((cat) => [
      cat,
      meals.reduce(
        (sum, meal) =>
          sum +
          meal.items
            .filter((item) => item.categories.includes(cat))
            .reduce((s, item) => s + item.calories, 0),
        0,
      ),
    ]),
  ) as Record<FoodCategory, number>;

  return {
    date: targetDate,
    meals,
    totalCalories,
    categoryBreakdown,
    goal: settings.dailyGoal,
    remaining: settings.dailyGoal - totalCalories,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date();
  const start = new Date(end);
  start.setDate(start.getDate() - 6);

  const startStr = toDateString(start);
  const endStr = toDateString(end);
  const meals = await getMealsForDateRange(startStr, endStr);
  const settings = await getSettings();

  const dayMap = new Map<string, number>();
  for (let i = 0; i < 7; i++) {
    const d = new Date(start);
    d.setDate(d.getDate() + i);
    dayMap.set(toDateString(d), 0);
  }

  for (const meal of meals) {
    const d = meal.timestamp.slice(0, 10);
    const current = dayMap.get(d) ?? 0;
    const mealCals = meal.items.reduce((s, item) => s + item.calories, 0);
    dayMap.set(d, current + mealCals);
  }

  const days = Array.from(dayMap.entries())
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([date, totalCalories]) => ({ date, totalCalories }));

  return { days, goal: settings.dailyGoal };
};

export const setDailyGoal = async (goal: number): Promise<Settings> => {
  const settings = await getSettings();
  settings.dailyGoal = goal;
  await saveSettings(settings);
  return settings;
};

export const filterMealsByCategory = async (
  category: FoodCategory,
  date?: string,
): Promise<Meal[]> => {
  const targetDate = date ?? toDateString(new Date());
  const meals = await getMealsForDate(targetDate);
  return meals
    .map((meal) => ({
      ...meal,
      items: meal.items.filter((item) => item.categories.includes(category)),
    }))
    .filter((meal) => meal.items.length > 0);
};

