import { h } from 'plaited';
import type { WeeklyData } from './types';

const CHART_MAX_WIDTH = 300;

const dayLabel = (dateStr: string): string => {
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
};

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCals = Math.max(data.goal, ...data.days.map((d) => d.totalCalories));
  const barScale = maxCals > 0 ? CHART_MAX_WIDTH / maxCals : 1;
  const goalLineLeft = Math.round(data.goal * barScale);

  const barRows = data.days.map((day) => {
    const barWidth = Math.max(2, Math.round(day.totalCalories * barScale));
    const overGoal = day.totalCalories > data.goal;
    const barColor = overGoal ? '#e74c3c' : '#27ae60';

    return h('div', {
      style: {
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        marginBottom: '6px',
      },
    },
      h('span', {
        style: {
          width: '100px',
          fontSize: '12px',
          textAlign: 'right',
          color: '#555',
          flexShrink: '0',
        },
      }, dayLabel(day.date)),
      h('div', {
        style: {
          position: 'relative',
          flex: '1',
          height: '22px',
        },
      },
        h('div', {
          style: {
            width: `${barWidth}px`,
            height: '100%',
            backgroundColor: barColor,
            borderRadius: '3px',
            transition: 'width 0.3s ease',
          },
        }),
      ),
      h('span', {
        style: {
          width: '55px',
          fontSize: '12px',
          color: overGoal ? '#e74c3c' : '#333',
          fontWeight: overGoal ? 'bold' : 'normal',
        },
      }, `${day.totalCalories} cal`),
    );
  });

  return h('div', {
    style: {
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
      padding: '16px',
      backgroundColor: '#fafafa',
      borderRadius: '8px',
      border: '1px solid #e0e0e0',
    },
  },
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '16px',
      },
    },
      h('h3', {
        style: { margin: '0', fontSize: '16px', color: '#333' },
      }, 'Weekly Calorie Intake'),
      h('span', {
        style: { fontSize: '12px', color: '#888' },
      }, `Goal: ${data.goal} cal/day`),
    ),
    h('div', {
      style: { position: 'relative' },
    },
      ...barRows,
      h('div', {
        style: {
          position: 'absolute',
          top: '0',
          bottom: '0',
          left: `${goalLineLeft + 108}px`,
          width: '2px',
          backgroundColor: '#3498db',
          opacity: '0.5',
        },
      }),
    ),
  );
};

