const renderProgressBar = (current: number, goal: number) => {
  const pct = Math.min(100, Math.round((current / goal) * 100));
  const overGoal = current > goal;

  return h('div', {
    style: {
      marginBottom: '16px',
      padding: '12px 16px',
      backgroundColor: '#fff',
      borderRadius: '8px',
      border: '1px solid #e0e0e0',
    },
  },
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'space-between',
        marginBottom: '6px',
        fontSize: '13px',
      },
    },
      h('span', { style: { color: '#555' } }, `${current} / ${goal} cal`),
      h('span', {
        style: { color: overGoal ? '#e74c3c' : '#27ae60', fontWeight: '600' },
      }, overGoal ? `${current - goal} cal over` : `${goal - current} cal remaining`),
    ),
    h('div', {
      style: {
        height: '10px',
        backgroundColor: '#eee',
        borderRadius: '5px',
        overflow: 'hidden',
      },
    },
      h('div', {
        style: {
          width: `${pct}%`,
          height: '100%',
          backgroundColor: overGoal ? '#e74c3c' : '#27ae60',
          borderRadius: '5px',
          transition: 'width 0.3s ease',
        },
      }),
    ),
  );
};

const renderCategoryBreakdown = (breakdown: Record<FoodCategory, number>) => {
  const categories = Object.entries(breakdown) as [FoodCategory, number][];
  const total = categories.reduce((s, [, v]) => s + v, 0) || 1;

  return h('div', {
    style: {
