        h('div', {
          style: { fontSize: '18px', fontWeight: '700', color: CATEGORY_COLORS[cat] },
        }, `${cals}`),
        h('div', { style: { fontSize: '11px', color: '#888', marginTop: '2px' } }, 'cal'),
        h('div', {
          style: {
