        }, `${Math.round((cals / total) * 100)}%`),
      ),
    ),
  );
};

export const renderDailyView = async (date?: string): Promise<string> => {
  const summary = await getDailySummary(date);

  const dateDisplay = new Date(summary.date + 'T00:00:00').toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const template = h('div', {
    style: {
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
      maxWidth: '600px',
      margin: '0 auto',
      padding: '20px',
    },
  },
    h('h2', {
      style: { fontSize: '20px', color: '#333', marginBottom: '4px' },
    }, 'Daily Summary'),
    h('p', {
      style: { fontSize: '13px', color: '#999', marginTop: '0', marginBottom: '16px' },
    }, dateDisplay),
    renderProgressBar(summary.totalCalories, summary.goal),
