export { renderDailyView, renderWeeklyView } from './views';
export { deleteMeal, getAllMeals } from './data';
export type { Meal, FoodItem, FoodCategory, DailySummary, WeeklyData, Settings } from './types';

import { logMeal, getDailySummary, getWeeklyData, setDailyGoal, filterMealsByCategory } from './meals';
import { renderDailyView, renderWeeklyView } from './views';
import { deleteMeal } from './data';
import type { FoodCategory, FoodItem } from './types';

type Action =
  | { action: 'log'; name: string; items: FoodItem[]; timestamp?: string }
  | { action: 'summary'; date?: string }
  | { action: 'weekly'; endDate?: string }
  | { action: 'setGoal'; goal: number }
  | { action: 'filter'; category: FoodCategory; date?: string }
  | { action: 'delete'; id: string }
  | { action: 'dailyView'; date?: string }
  | { action: 'weeklyView'; endDate?: string };

export const handleAction = async (input: Action) => {
  switch (input.action) {
    case 'log':
      return logMeal(input.name, input.items, input.timestamp);

    case 'summary':
      return getDailySummary(input.date);

    case 'weekly':
      return getWeeklyData(input.endDate);

    case 'setGoal':
      return setDailyGoal(input.goal);

    case 'filter':
      return filterMealsByCategory(input.category, input.date);

    case 'delete':
      return deleteMeal(input.id);

    case 'dailyView':
      return renderDailyView(input.date);

    case 'weeklyView':
      return renderWeeklyView(input.endDate);
  }
};

