import { BskyAgent } from '@atproto/api'
import type { LoginInput, SessionData } from './types.ts'

const SESSION_PATH = './data/session.json'
const DEFAULT_SERVICE = 'https://bsky.social'

export const saveSession = async (agent: BskyAgent): Promise<void> => {
  const session = agent.session
  if (!session) return
  const data: SessionData = {
    did: session.did,
    handle: session.handle,
    accessJwt: session.accessJwt,
    refreshJwt: session.refreshJwt,
    service: DEFAULT_SERVICE,
  }
  await Bun.write(SESSION_PATH, JSON.stringify(data, null, 2))
}

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  try {
    const text = await file.text()
    return JSON.parse(text) as SessionData
  } catch {
    return null
  }
}

export const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}')
  }
}

export const createAgent = (): BskyAgent => {
  return new BskyAgent({ service: DEFAULT_SERVICE })
}

export const login = async (
  agent: BskyAgent,
  input: LoginInput,
): Promise<void> => {
  await agent.login({
    identifier: input.identifier,
    password: input.password,
  })
  await saveSession(agent)
}

export const resumeSession = async (agent: BskyAgent): Promise<boolean> => {
  const session = await loadSession()
  if (!session) return false
  try {
    await agent.resumeSession({
      did: session.did,
      handle: session.handle,
      accessJwt: session.accessJwt,
      refreshJwt: session.refreshJwt,
      active: true,
    })
    await saveSession(agent)
    return true
  } catch {
    await clearSession()
    return false
  }
}

import type { BskyAgent } from '@atproto/api'
import type { TimelineInput, TimelineResult, PostView } from './types.ts'

const mapPost = (feedItem: Record<string, unknown>): PostView => {
  const post = feedItem.post as Record<string, unknown>
  const author = post.author as Record<string, unknown>
  const record = post.record as Record<string, unknown>
  const viewer = (post.viewer ?? {}) as Record<string, unknown>

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    authorHandle: author.handle as string,
    authorDisplayName: (author.displayName as string) ?? (author.handle as string),
    authorAvatar: author.avatar as string | undefined,
    text: (record.text as string) ?? '',
    createdAt: record.createdAt as string,
    likeCount: (post.likeCount as number) ?? 0,
    repostCount: (post.repostCount as number) ?? 0,
    replyCount: (post.replyCount as number) ?? 0,
    likeUri: viewer.like as string | undefined,
    isLiked: Boolean(viewer.like),
  }
}

export const getTimeline = async (
  agent: BskyAgent,
  input: TimelineInput = {},
): Promise<TimelineResult> => {
  const limit = input.limit ?? 25
  const response = await agent.getTimeline({
    cursor: input.cursor,
    limit,
  })
  const posts = response.data.feed.map((item) => mapPost(item as unknown as Record<string, unknown>))
  return {
    posts,
    cursor: response.data.cursor,
  }
}

