import type { BskyAgent } from '@atproto/api'
import type { ProfileInput, ProfileView, FollowInput, UnfollowInput } from './types.ts'

export const getProfile = async (
  agent: BskyAgent,
  input: ProfileInput,
): Promise<ProfileView> => {
  const response = await agent.getProfile({ actor: input.actor })
  const data = response.data
  const viewer = (data.viewer ?? {}) as Record<string, unknown>

  return {
    did: data.did,
    handle: data.handle,
    displayName: data.displayName,
    description: data.description,
    avatar: data.avatar,
    banner: data.banner,
    followersCount: data.followersCount ?? 0,
    followsCount: data.followsCount ?? 0,
    postsCount: data.postsCount ?? 0,
    isFollowing: Boolean(viewer.following),
    followUri: viewer.following as string | undefined,
  }
}

export const follow = async (
  agent: BskyAgent,
  input: FollowInput,
): Promise<{ uri: string }> => {
  const profile = await agent.getProfile({ actor: input.actor })
  const response = await agent.follow(profile.data.did)
  return { uri: response.uri }
}

export const unfollow = async (
  agent: BskyAgent,
  input: UnfollowInput,
): Promise<void> => {
  const profile = await agent.getProfile({ actor: input.actor })
  const viewer = (profile.data.viewer ?? {}) as Record<string, unknown>
  const followUri = viewer.following as string | undefined
  if (!followUri) {
    throw new Error(`Not following ${input.actor}`)
  }
  await agent.deleteFollow(followUri)
}

