    ),
  )
  return ssr(template)
}

import type { BskyAgent } from '@atproto/api'
import { createAgent, login, resumeSession, clearSession } from './auth.ts'
import { getTimeline } from './feed.ts'
import { createPost, likePost, unlikePost } from './posts.ts'
import { getProfile, follow, unfollow } from './profiles.ts'
import { renderTimeline, renderProfile, renderPostSuccess, renderError } from './render.ts'
import type {
  LoginInput,
  TimelineInput,
  CreatePostInput,
  ProfileInput,
  FollowInput,
  UnfollowInput,
  LikePostInput,
  UnlikePostInput,
  TimelineResult,
  ProfileView,
} from './types.ts'

export type BlueskyClient = {
  login: (input: LoginInput) => Promise<void>
  resumeSession: () => Promise<boolean>
  logout: () => Promise<void>
  getTimeline: (input?: TimelineInput) => Promise<TimelineResult>
  getTimelineHtml: (input?: TimelineInput) => Promise<string>
  createPost: (input: CreatePostInput) => Promise<{ uri: string; cid: string }>
  createPostHtml: (input: CreatePostInput) => Promise<string>
  getProfile: (input: ProfileInput) => Promise<ProfileView>
  getProfileHtml: (input: ProfileInput) => Promise<string>
  follow: (input: FollowInput) => Promise<{ uri: string }>
  unfollow: (input: UnfollowInput) => Promise<void>
  likePost: (input: LikePostInput) => Promise<{ uri: string }>
  unlikePost: (input: UnlikePostInput) => Promise<void>
  renderError: (message: string) => string
}

export const createClient = async (): Promise<BlueskyClient> => {
  const agent: BskyAgent = createAgent()

  const ensureAuth = (): void => {
    if (!agent.session) {
      throw new Error('Not authenticated. Call login() or resumeSession() first.')
    }
  }

  const client: BlueskyClient = {
    login: async (input: LoginInput) => {
      await login(agent, input)
    },

    resumeSession: async () => {
      return resumeSession(agent)
    },

    logout: async () => {
      await clearSession()
    },

    getTimeline: async (input?: TimelineInput) => {
      ensureAuth()
      return getTimeline(agent, input)
    },

    getTimelineHtml: async (input?: TimelineInput) => {
      ensureAuth()
      try {
        const result = await getTimeline(agent, input)
        return renderTimeline(result)
      } catch (err) {
        return renderError(`Failed to load timeline: ${(err as Error).message}`)
      }
    },

    createPost: async (input: CreatePostInput) => {
      ensureAuth()
      return createPost(agent, input)
    },

    createPostHtml: async (input: CreatePostInput) => {
      ensureAuth()
      try {
        const result = await createPost(agent, input)
        return renderPostSuccess(result.uri)
      } catch (err) {
        return renderError(`Failed to create post: ${(err as Error).message}`)
      }
    },

    getProfile: async (input: ProfileInput) => {
      ensureAuth()
      return getProfile(agent, input)
    },

    getProfileHtml: async (input: ProfileInput) => {
      ensureAuth()
      try {
        const result = await getProfile(agent, input)
        return renderProfile(result)
      } catch (err) {
        return renderError(`Failed to load profile: ${(err as Error).message}`)
      }
    },

    follow: async (input: FollowInput) => {
      ensureAuth()
      return follow(agent, input)
    },

    unfollow: async (input: UnfollowInput) => {
      ensureAuth()
      return unfollow(agent, input)
    },

    likePost: async (input: LikePostInput) => {
      ensureAuth()
      return likePost(agent, input)
    },

    unlikePost: async (input: UnlikePostInput) => {
      ensureAuth()
      return unlikePost(agent, input)
    },

    renderError,
  }

  return client
}

