import { BskyAgent } from '@atproto/api'
import type { SessionData } from './types'

const SESSION_PATH = `${import.meta.dir}/data/session.json`
const DEFAULT_SERVICE = 'https://bsky.social'

const saveSession = async (agent: BskyAgent, service: string): Promise<void> => {
  const session = agent.session
  if (!session) return

  const data: SessionData = {
    did: session.did,
    handle: session.handle,
    accessJwt: session.accessJwt,
    refreshJwt: session.refreshJwt,
    service,
  }

  await Bun.write(SESSION_PATH, JSON.stringify(data, null, 2))
}

const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null

  try {
    return (await file.json()) as SessionData
  } catch {
    return null
  }
}

const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}')
  }
}

export const createClient = async (
  identifier: string,
  password: string,
  service: string = DEFAULT_SERVICE
): Promise<BskyAgent> => {
  const agent = new BskyAgent({ service })

  await agent.login({ identifier, password })
  await saveSession(agent, service)

  return agent
}

export const resumeSession = async (): Promise<BskyAgent | null> => {
  const sessionData = await loadSession()
  if (!sessionData || !sessionData.refreshJwt) return null

  const agent = new BskyAgent({ service: sessionData.service })

  try {
    await agent.resumeSession({
      did: sessionData.did,
      handle: sessionData.handle,
      accessJwt: sessionData.accessJwt,
      refreshJwt: sessionData.refreshJwt,
      active: true,
    })
    await saveSession(agent, sessionData.service)
    return agent
  } catch {
    await clearSession()
    return null
  }
}

export const logout = async (): Promise<void> => {
  await clearSession()
}

export const getAgent = async (
  identifier?: string,
  password?: string,
  service?: string
): Promise<BskyAgent> => {
  const existing = await resumeSession()
  if (existing) return existing

  if (!identifier || !password) {
    throw new Error('No active session. Provide identifier and password to log in.')
  }

  return createClient(identifier, password, service)
}

import type { BskyAgent } from '@atproto/api'
import type { PostView, TimelineOptions, TimelineResult } from './types'

const parsePost = (feedItem: Record<string, unknown>): PostView => {
  const post = feedItem.post as Record<string, unknown>
  const author = post.author as Record<string, unknown>
  const record = post.record as Record<string, unknown>
  const viewer = (post.viewer ?? {}) as Record<string, unknown>

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: {
      did: author.did as string,
      handle: author.handle as string,
      displayName: (author.displayName as string) || (author.handle as string),
      avatar: author.avatar as string | undefined,
    },
    text: (record.text as string) || '',
    createdAt: record.createdAt as string,
    likeCount: (post.likeCount as number) ?? 0,
    repostCount: (post.repostCount as number) ?? 0,
    replyCount: (post.replyCount as number) ?? 0,
    isLiked: !!viewer.like,
    likeUri: viewer.like as string | undefined,
  }
}

export const getTimeline = async (
  agent: BskyAgent,
  options: TimelineOptions = {}
): Promise<TimelineResult> => {
  const { limit = 25, cursor } = options

  const response = await agent.getTimeline({ limit, cursor })
  const feed = response.data.feed as Record<string, unknown>[]

  return {
    posts: feed.map(parsePost),
    cursor: response.data.cursor,
  }
}

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  options: TimelineOptions = {}
): Promise<TimelineResult> => {
  const { limit = 25, cursor } = options

  const response = await agent.getAuthorFeed({ actor, limit, cursor })
  const feed = response.data.feed as Record<string, unknown>[]

  return {
    posts: feed.map(parsePost),
    cursor: response.data.cursor,
  }
}

export const likePost = async (
  agent: BskyAgent,
  uri: string,
  cid: string
): Promise<string> => {
  const response = await agent.like(uri, cid)
  return response.uri
}

export const unlikePost = async (
  agent: BskyAgent,
  likeUri: string
): Promise<void> => {
  await agent.deleteLike(likeUri)
}

import type { BskyAgent } from '@atproto/api'
import { RichText } from '@atproto/api'

export type CreatePostResult = {
  uri: string
  cid: string
}

export const createPost = async (
  agent: BskyAgent,
  text: string
): Promise<CreatePostResult> => {
  if (!text.trim()) {
    throw new Error('Post text cannot be empty')
  }

  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  })

  return {
    uri: response.uri,
    cid: response.cid,
  }
}

export const deletePost = async (
  agent: BskyAgent,
  postUri: string
): Promise<void> => {
  await agent.deletePost(postUri)
}

export const createReply = async (
  agent: BskyAgent,
  text: string,
  parentUri: string,
  parentCid: string,
  rootUri?: string,
  rootCid?: string
): Promise<CreatePostResult> => {
  if (!text.trim()) {
    throw new Error('Reply text cannot be empty')
  }

  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    reply: {
      parent: { uri: parentUri, cid: parentCid },
      root: {
        uri: rootUri ?? parentUri,
        cid: rootCid ?? parentCid,
      },
    },
    createdAt: new Date().toISOString(),
  })

  return {
    uri: response.uri,
    cid: response.cid,
  }
}

import type { BskyAgent } from '@atproto/api'
import type { ProfileView } from './types'

export const getProfile = async (
  agent: BskyAgent,
  actor: string
): Promise<ProfileView> => {
  const response = await agent.getProfile({ actor })
  const profile = response.data

  const viewer = (profile.viewer ?? {}) as Record<string, unknown>

  return {
    did: profile.did,
    handle: profile.handle,
    displayName: profile.displayName || profile.handle,
    description: profile.description || '',
    avatar: profile.avatar,
    banner: profile.banner,
    followersCount: profile.followersCount ?? 0,
    followsCount: profile.followsCount ?? 0,
    postsCount: profile.postsCount ?? 0,
    isFollowing: !!viewer.following,
    followUri: viewer.following as string | undefined,
  }
}

export const searchProfiles = async (
  agent: BskyAgent,
  query: string,
  limit: number = 10
): Promise<ProfileView[]> => {
  const response = await agent.searchActors({ term: query, limit })
  const actors = response.data.actors

  return actors.map((actor) => {
    const viewer = (actor.viewer ?? {}) as Record<string, unknown>

    return {
      did: actor.did,
      handle: actor.handle,
      displayName: actor.displayName || actor.handle,
      description: actor.description || '',
      avatar: actor.avatar,
      banner: undefined,
      followersCount: (actor as Record<string, unknown>).followersCount as number ?? 0,
      followsCount: (actor as Record<string, unknown>).followsCount as number ?? 0,
      postsCount: (actor as Record<string, unknown>).postsCount as number ?? 0,
      isFollowing: !!viewer.following,
      followUri: viewer.following as string | undefined,
    }
  })
}

import type { BskyAgent } from '@atproto/api'

export type FollowResult = {
  uri: string
  cid: string
}

export const followUser = async (
  agent: BskyAgent,
  handleOrDid: string
): Promise<FollowResult> => {
  let did = handleOrDid
  if (!handleOrDid.startsWith('did:')) {
    const profile = await agent.getProfile({ actor: handleOrDid })
    did = profile.data.did
  }

  const response = await agent.follow(did)

  return {
    uri: response.uri,
    cid: response.cid,
  }
}

export const unfollowUser = async (
  agent: BskyAgent,
  followUri: string
): Promise<void> => {
  await agent.deleteFollow(followUri)
}

export const unfollowByHandle = async (
  agent: BskyAgent,
  handleOrDid: string
): Promise<void> => {
  const profile = await agent.getProfile({ actor: handleOrDid })
  const viewer = (profile.data.viewer ?? {}) as Record<string, unknown>
  const followUri = viewer.following as string | undefined

  if (!followUri) {
    throw new Error(`Not following ${handleOrDid}`)
  }

  await agent.deleteFollow(followUri)
}

