import { BskyAgent } from '@atproto/api'
import type { SessionData, StoredSessions } from './types'

const SESSIONS_PATH = `${import.meta.dir}/data/sessions.json`

export const loadSessions = async (): Promise<StoredSessions> => {
  try {
    const file = Bun.file(SESSIONS_PATH)
    const text = await file.text()
    return JSON.parse(text) as StoredSessions
  } catch {
    return {}
  }
}

export const saveSession = async (session: SessionData): Promise<void> => {
  const sessions = await loadSessions()
  sessions[session.handle] = session
  await Bun.write(SESSIONS_PATH, JSON.stringify(sessions, null, 2))
}

export const removeSession = async (handle: string): Promise<void> => {
  const sessions = await loadSessions()
  delete sessions[handle]
  await Bun.write(SESSIONS_PATH, JSON.stringify(sessions, null, 2))
}

export const login = async (
  agent: BskyAgent,
  identifier: string,
  password: string,
): Promise<SessionData> => {
  const response = await agent.login({ identifier, password })
  const session: SessionData = {
    handle: response.data.handle,
    did: response.data.did,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
    email: response.data.email,
  }
  await saveSession(session)
  return session
}

export const resumeSession = async (
  agent: BskyAgent,
  handle: string,
): Promise<boolean> => {
  const sessions = await loadSessions()
  const stored = sessions[handle]
  if (!stored) return false

  try {
    await agent.resumeSession({
      did: stored.did,
      handle: stored.handle,
      accessJwt: stored.accessJwt,
      refreshJwt: stored.refreshJwt,
      active: true,
    })
    return true
  } catch {
    await removeSession(handle)
    return false
  }
}

import type { BskyAgent } from '@atproto/api'
import type { FeedPost, TimelineResponse } from './types'

const extractPost = (feedItem: Record<string, unknown>): FeedPost | null => {
  const post = feedItem.post as Record<string, unknown> | undefined
  if (!post) return null

  const author = post.author as Record<string, unknown>
  const record = post.record as Record<string, unknown>
  const viewer = post.viewer as Record<string, unknown> | undefined

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: {
      did: author.did as string,
      handle: author.handle as string,
      displayName: (author.displayName as string) || (author.handle as string),
      avatar: author.avatar as string | undefined,
    },
    text: (record.text as string) || '',
    createdAt: record.createdAt as string,
    likeCount: (post.likeCount as number) || 0,
    repostCount: (post.repostCount as number) || 0,
    replyCount: (post.replyCount as number) || 0,
    isLiked: !!viewer?.like,
    likeUri: viewer?.like as string | undefined,
    indexedAt: post.indexedAt as string,
  }
}

export const getTimeline = async (
  agent: BskyAgent,
  limit = 25,
  cursor?: string,
): Promise<TimelineResponse> => {
  const response = await agent.getTimeline({ limit, cursor })
  const posts = response.data.feed
    .map((item) => extractPost(item as unknown as Record<string, unknown>))
    .filter((p): p is FeedPost => p !== null)

  return {
    posts,
    cursor: response.data.cursor,
  }
}

import { RichText, type BskyAgent } from '@atproto/api'

export const createPost = async (
  agent: BskyAgent,
  text: string,
): Promise<{ uri: string; cid: string }> => {
  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  })

  return { uri: response.uri, cid: response.cid }
}

export const likePost = async (
  agent: BskyAgent,
  uri: string,
  cid: string,
): Promise<{ uri: string }> => {
  const response = await agent.like(uri, cid)
  return { uri: response.uri }
}

export const unlikePost = async (
  agent: BskyAgent,
  likeUri: string,
): Promise<void> => {
  await agent.deleteLike(likeUri)
}

