import { BskyAgent } from '@atproto/api'
import * as auth from './auth'
import * as feed from './feed'
import * as posts from './posts'
import * as profiles from './profiles'
import * as render from './render'
import type { BlueskyClient, SessionData } from './types'

const BLUESKY_SERVICE = 'https://bsky.social'

export const createClient = (): BlueskyClient => {
  const agent = new BskyAgent({ service: BLUESKY_SERVICE })
  let currentSession: SessionData | null = null

  const ensureAuthenticated = () => {
    if (!currentSession) {
      throw new Error('Not authenticated. Call login() or resumeSession() first.')
    }
  }

  return {
    login: async (identifier: string, password: string): Promise<SessionData> => {
      const session = await auth.login(agent, identifier, password)
      currentSession = session
      return session
    },

    resumeSession: async (handle: string): Promise<boolean> => {
      const success = await auth.resumeSession(agent, handle)
      if (success) {
        const sessions = await auth.loadSessions()
        currentSession = sessions[handle] || null
      }
      return success
    },

    getTimeline: async (limit = 25, cursor?: string) => {
      ensureAuthenticated()
      return feed.getTimeline(agent, limit, cursor)
    },

    createPost: async (text: string) => {
      ensureAuthenticated()
      return posts.createPost(agent, text)
    },

    likePost: async (uri: string, cid: string) => {
      ensureAuthenticated()
      return posts.likePost(agent, uri, cid)
    },

    unlikePost: async (likeUri: string) => {
      ensureAuthenticated()
      return posts.unlikePost(agent, likeUri)
    },

    getProfile: async (handle: string) => {
      ensureAuthenticated()
      return profiles.getProfile(agent, handle)
    },

    follow: async (did: string) => {
      ensureAuthenticated()
      return profiles.follow(agent, did)
    },

    unfollow: async (followUri: string) => {
      ensureAuthenticated()
      return profiles.unfollow(agent, followUri)
    },

    getSession: () => currentSession,

    renderTimeline: render.renderTimeline,
    renderProfile: render.renderProfile,
    renderPost: render.renderPost,
  }
}

export { type BlueskyClient, type SessionData, type FeedPost, type ProfileView, type TimelineResponse } from './types'
export { renderTimeline, renderProfile, renderPost } from './render'

