    "plaited": "latest"
  }
}

import type { Expense, ExpenseFilter, MonthlySummary, Category, CategorySummary } from './types'
import { CATEGORIES } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

const readAll = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

const append = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + JSON.stringify(expense) + '\n')
}

const writeAll = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
}

export const createExpense = async (
  data: Omit<Expense, 'id' | 'createdAt'>
): Promise<Expense> => {
  const expense: Expense = {
    ...data,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  }
  await append(expense)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const all = await readAll()
  const filtered = all.filter((e) => e.id !== id)
  if (filtered.length === all.length) return false
  await writeAll(filtered)
  return true
}

export const listExpenses = async (filter?: ExpenseFilter): Promise<Expense[]> => {
  const all = await readAll()
  return applyFilter(all, filter)
}

const applyFilter = (expenses: Expense[], filter?: ExpenseFilter): Expense[] => {
  if (!filter) return expenses
  return expenses.filter((e) => {
    if (filter.from && e.date < filter.from) return false
    if (filter.to && e.date > filter.to) return false
    if (filter.category && e.category !== filter.category) return false
    return true
  })
}

export const getMonthlySummary = async (
  year: number,
  month: number
): Promise<MonthlySummary> => {
  const all = await readAll()
  const monthStr = String(month).padStart(2, '0')
  const prefix = `${year}-${monthStr}`

  const monthExpenses = all.filter((e) => e.date.startsWith(prefix))
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((cat) => {
    const catExpenses = monthExpenses.filter((e) => e.category === cat)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category: cat,
      total: catTotal,
      count: catExpenses.length,
      percentage: total > 0 ? (catTotal / total) * 100 : 0,
    }
  }).filter((c) => c.count > 0)

  return { month, year, total, categories }
}

export const exportCsv = async (filter?: ExpenseFilter): Promise<string> => {
  const expenses = await listExpenses(filter)
  const header = 'id,amount,category,date,notes,createdAt'
  const rows = expenses.map(
    (e) =>
      `${e.id},${e.amount},${e.category},${e.date},"${e.notes.replace(/"/g, '""')}",${e.createdAt}`
  )
  return [header, ...rows].join('\n')
}

import type { CategorySummary } from './types'

const COLORS: Record<string, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
}

type SlicePath = {
  path: string
  color: string
  label: string
  percentage: number
  labelX: number
  labelY: number
}

const describeArc = (
  cx: number,
  cy: number,
  r: number,
  startAngle: number,
  endAngle: number
): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`
}

const polarToCartesian = (
  cx: number,
  cy: number,
  r: number,
  angleDeg: number
): { x: number; y: number } => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const buildSlices = (categories: CategorySummary[]): SlicePath[] => {
  const cx = 120
  const cy = 120
  const r = 100
  const labelR = 65
  let currentAngle = 0
  const slices: SlicePath[] = []

  for (const cat of categories) {
    if (cat.percentage <= 0) continue
    const sliceAngle = (cat.percentage / 100) * 360
    const midAngle = currentAngle + sliceAngle / 2
    const labelPos = polarToCartesian(cx, cy, labelR, midAngle)

    slices.push({
      path: describeArc(cx, cy, r, currentAngle, currentAngle + sliceAngle),
      color: COLORS[cat.category] ?? '#999',
      label: cat.category,
      percentage: cat.percentage,
      labelX: labelPos.x,
      labelY: labelPos.y,
    })
    currentAngle += sliceAngle
  }

  return slices
}

export const renderPieChartSvg = (categories: CategorySummary[]): string => {
  if (categories.length === 0) {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 400 260" width="400" height="260">
      <text x="200" y="130" text-anchor="middle" fill="#9ca3af" font-size="14">No expenses recorded</text>
    </svg>`
  }

  const slices = buildSlices(categories)
  const slicePaths = slices
    .map(
      (s) =>
        `<path d="${s.path}" fill="${s.color}" stroke="#fff" stroke-width="2"><title>${s.label}: ${s.percentage.toFixed(1)}%</title></path>`
    )
    .join('\n    ')

  const labels = slices
    .filter((s) => s.percentage >= 5)
    .map(
      (s) =>
        `<text x="${s.labelX}" y="${s.labelY}" text-anchor="middle" fill="#fff" font-size="11" font-weight="600">${s.percentage.toFixed(0)}%</text>`
    )
    .join('\n    ')

  const legendItems = slices
    .map(
      (s, i) =>
        `<rect x="260" y="${20 + i * 28}" width="14" height="14" rx="3" fill="${s.color}"/>
    <text x="280" y="${32 + i * 28}" fill="#374151" font-size="13">${s.label} (${s.percentage.toFixed(1)}%)</text>`
    )
    .join('\n    ')

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 420 260" width="420" height="260">
    ${slicePaths}
    ${labels}
    ${legendItems}
  </svg>`
}

import { CATEGORIES } from './types'
import type { Category, ExpenseFilter } from './types'
import {
  createExpense,
  deleteExpense,
  listExpenses,
  getMonthlySummary,
  exportCsv,
} from './store'
import { renderDashboard, renderExpenseList } from './views'

const isCategory = (val: string): val is Category =>
  (CATEGORIES as readonly string[]).includes(val)

const parseFilter = (url: URL): ExpenseFilter => {
  const from = url.searchParams.get('from') || undefined
  const to = url.searchParams.get('to') || undefined
  const cat = url.searchParams.get('category') || undefined
  return {
    from,
    to,
    category: cat && isCategory(cat) ? cat : undefined,
  }
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // GET / — Dashboard
    if (method === 'GET' && pathname === '/') {
      const now = new Date()
      const year = now.getFullYear()
      const month = now.getMonth() + 1
      const summary = await getMonthlySummary(year, month)
      const filter = parseFilter(url)
      const expenses = await listExpenses(filter)
      const html = renderDashboard(summary, expenses, {
        from: filter.from,
        to: filter.to,
        category: filter.category,
      })
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    // POST /expenses — Create expense
    if (method === 'POST' && pathname === '/expenses') {
      const formData = await req.formData()
      const amount = parseFloat(formData.get('amount') as string)
      const category = formData.get('category') as string
      const date = formData.get('date') as string
      const notes = (formData.get('notes') as string) || ''

      if (isNaN(amount) || amount <= 0) {
        return new Response('Invalid amount', { status: 400 })
      }
      if (!isCategory(category)) {
        return new Response('Invalid category', { status: 400 })
      }
      if (!date || !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
        return new Response('Invalid date', { status: 400 })
      }

      await createExpense({ amount, category, date, notes })
      return Response.redirect(new URL('/', req.url).toString(), 303)
    }

    // POST /expenses/:id/delete — Delete expense
    const deleteMatch = pathname.match(/^\/expenses\/([^/]+)\/delete$/)
    if (method === 'POST' && deleteMatch) {
      const id = deleteMatch[1]
      const deleted = await deleteExpense(id)
      if (!deleted) {
        return new Response('Expense not found', { status: 404 })
      }
      return Response.redirect(new URL('/', req.url).toString(), 303)
    }

    // GET /expenses — List with filters (HTML)
    if (method === 'GET' && pathname === '/expenses') {
      const filter = parseFilter(url)
      const expenses = await listExpenses(filter)
      const html = renderExpenseList(expenses)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    // GET /summary — Monthly summary JSON
    if (method === 'GET' && pathname === '/summary') {
      const year = parseInt(url.searchParams.get('year') || String(new Date().getFullYear()))
      const month = parseInt(url.searchParams.get('month') || String(new Date().getMonth() + 1))
      const summary = await getMonthlySummary(year, month)
      return Response.json(summary)
    }

    // GET /export — CSV download
    if (method === 'GET' && pathname === '/export') {
      const filter = parseFilter(url)
      const csv = await exportCsv(filter)
      return new Response(csv, {
        headers: {
          'Content-Type': 'text/csv; charset=utf-8',
          'Content-Disposition': 'attachment; filename="expenses.csv"',
        },
      })
    }

    // GET /api/expenses — JSON API
    if (method === 'GET' && pathname === '/api/expenses') {
      const filter = parseFilter(url)
      const expenses = await listExpenses(filter)
      return Response.json(expenses)
    }

    // DELETE /api/expenses/:id — JSON API delete
    const apiDeleteMatch = pathname.match(/^\/api\/expenses\/([^/]+)$/)
    if (method === 'DELETE' && apiDeleteMatch) {
      const id = apiDeleteMatch[1]
      const deleted = await deleteExpense(id)
      if (!deleted) {
        return Response.json({ error: 'Not found' }, { status: 404 })
      }
      return Response.json({ ok: true })
    }

    return new Response('Not found', { status: 404 })
  },
})

