import { type Expense, type ExpenseInput, type FilterParams, type Category, CATEGORIES } from './types'

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

export const readAllExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

export const addExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  }
  const line = JSON.stringify(expense) + '\n'
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + line)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readAllExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], params: FilterParams): Expense[] => {
  let result = expenses
  if (params.from) {
    result = result.filter((e) => e.date >= params.from!)
  }
  if (params.to) {
    result = result.filter((e) => e.date <= params.to!)
  }
  if (params.category && CATEGORIES.includes(params.category)) {
    result = result.filter((e) => e.category === params.category)
  }
  return result.sort((a, b) => b.date.localeCompare(a.date))
}

export const isValidCategory = (cat: string): cat is Category => {
  return CATEGORIES.includes(cat as Category)
}

export const isValidDate = (date: string): boolean => {
  return /^\d{4}-\d{2}-\d{2}$/.test(date) && !isNaN(Date.parse(date))
}

export const isValidAmount = (amount: unknown): amount is number => {
  return typeof amount === 'number' && isFinite(amount) && amount > 0
}

import { h } from 'plaited'
import { type CategorySummary, CATEGORY_COLORS, CATEGORY_LABELS } from './types'

const toRadians = (degrees: number): number => (degrees * Math.PI) / 180

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = {
    x: cx + r * Math.cos(toRadians(startAngle)),
    y: cy + r * Math.sin(toRadians(startAngle)),
  }
  const end = {
    x: cx + r * Math.cos(toRadians(endAngle)),
    y: cy + r * Math.sin(toRadians(endAngle)),
  }
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y} Z`
}

export const renderPieChart = (summaries: CategorySummary[]): ReturnType<typeof h> => {
  const cx = 120
  const cy = 120
  const r = 100
  const nonZero = summaries.filter((s) => s.total > 0)

  if (nonZero.length === 0) {
    return h('div', { style: { textAlign: 'center', padding: '2rem', color: '#6b7280' } }, 'No expenses to chart')
  }

  if (nonZero.length === 1) {
    const s = nonZero[0]
    return h(
      'svg',
      { viewBox: '0 0 240 240', width: '240', height: '240' },
      h('circle', {
        cx: String(cx),
        cy: String(cy),
        r: String(r),
        fill: CATEGORY_COLORS[s.category],
      }),
      h(
        'text',
        {
          x: String(cx),
          y: String(cy),
          'text-anchor': 'middle',
          'dominant-baseline': 'middle',
          fill: '#fff',
          'font-size': '14',
          'font-weight': 'bold',
        },
        `${CATEGORY_LABELS[s.category]} 100%`,
      ),
    )
  }

  let currentAngle = -90
  const slices = nonZero.map((s) => {
    const sliceAngle = (s.percentage / 100) * 360
    const path = describeArc(cx, cy, r, currentAngle, currentAngle + sliceAngle)
    const midAngle = toRadians(currentAngle + sliceAngle / 2)
    const labelR = r * 0.65
    const labelX = cx + labelR * Math.cos(midAngle)
    const labelY = cy + labelR * Math.sin(midAngle)
    currentAngle += sliceAngle
    return { ...s, path, labelX, labelY, sliceAngle }
  })

  return h(
    'svg',
    { viewBox: '0 0 240 240', width: '240', height: '240' },
    ...slices.map((s) =>
      h('path', {
        d: s.path,
        fill: CATEGORY_COLORS[s.category],
        stroke: '#fff',
        'stroke-width': '2',
      }),
    ),
    ...slices
      .filter((s) => s.sliceAngle > 20)
      .map((s) =>
        h(
          'text',
          {
            x: String(Math.round(s.labelX)),
            y: String(Math.round(s.labelY)),
            'text-anchor': 'middle',
            'dominant-baseline': 'middle',
            fill: '#fff',
            'font-size': '11',
            'font-weight': '600',
          },
          `${Math.round(s.percentage)}%`,
        ),
      ),
  )
}

export const renderLegend = (summaries: CategorySummary[]): ReturnType<typeof h> => {
  const nonZero = summaries.filter((s) => s.total > 0)
  return h(
    'div',
    {
      style: {
        display: 'flex',
        flexWrap: 'wrap',
        gap: '0.75rem',
        marginTop: '1rem',
      },
    },
    ...nonZero.map((s) =>
