}

import { type Expense, CATEGORY_LABELS } from './types'

const escapeField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const toCSV = (expenses: Expense[]): string => {
  const header = 'Date,Category,Amount,Notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((e) =>
      [
        e.date,
        escapeField(CATEGORY_LABELS[e.category]),
        e.amount.toFixed(2),
        escapeField(e.notes),
      ].join(','),
    )
  return [header, ...rows].join('\n') + '\n'
}

import { type Expense, type Category, type CategorySummary, CATEGORIES } from './types'

export const computeSummary = (expenses: Expense[]): CategorySummary[] => {
  const totals = new Map<Category, { total: number; count: number }>()
  for (const cat of CATEGORIES) {
    totals.set(cat, { total: 0, count: 0 })
  }
  for (const e of expenses) {
    const entry = totals.get(e.category)!
    entry.total += e.amount
    entry.count += 1
  }
  const grandTotal = Array.from(totals.values()).reduce((sum, v) => sum + v.total, 0)
  return CATEGORIES.map((category) => {
    const { total, count } = totals.get(category)!
    return {
      category,
      total: Math.round(total * 100) / 100,
      count,
      percentage: grandTotal > 0 ? Math.round((total / grandTotal) * 10000) / 100 : 0,
    }
  })
}

export const getMonthExpenses = (expenses: Expense[], month: string): Expense[] => {
  return expenses.filter((e) => e.date.startsWith(month))
}

