  readAllExpenses,
  addExpense,
  deleteExpense,
  filterExpenses,
  isValidCategory,
  isValidDate,
  isValidAmount,
} from './store'
import { type FilterParams, type Category } from './types'
import { renderExpensesPage, renderSummaryPage } from './ui'
import { computeSummary, getMonthExpenses } from './summary'
import { toCSV } from './csv'

const today = (): string => new Date().toISOString().slice(0, 10)
const currentMonth = (): string => today().slice(0, 7)

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('application/json')) {
    return await req.json()
  }
  const form = await req.formData()
  const data: Record<string, string> = {}
  form.forEach((value, key) => {
    data[key] = String(value)
  })
  return data
}

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const redirect = (url: string): Response =>
  new Response(null, { status: 303, headers: { Location: url } })

export default {
  port: 3000,
  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // GET /expenses — list page
    if (path === '/expenses' && method === 'GET') {
      const params: FilterParams = {
        from: url.searchParams.get('from') || undefined,
        to: url.searchParams.get('to') || undefined,
        category: (url.searchParams.get('category') as Category) || undefined,
      }
      const all = await readAllExpenses()
      const filtered = filterExpenses(all, params)
      return htmlResponse(renderExpensesPage(filtered, params, today()))
    }

    // POST /expenses — add expense
    if (path === '/expenses' && method === 'POST') {
      const data = await parseFormData(req)
      const amount = parseFloat(data.amount)
      const category = data.category
      const date = data.date
      const notes = data.notes ?? ''

      if (!isValidAmount(amount)) {
        return jsonResponse({ error: 'Amount must be a positive number' }, 400)
      }
      if (!category || !isValidCategory(category)) {
        return jsonResponse({ error: 'Invalid category' }, 400)
      }
      if (!date || !isValidDate(date)) {
        return jsonResponse({ error: 'Invalid date format (YYYY-MM-DD)' }, 400)
      }

      const expense = await addExpense({ amount, category, date, notes })

      const accept = req.headers.get('accept') ?? ''
      if (accept.includes('application/json')) {
        return jsonResponse(expense, 201)
      }
      return redirect('/expenses')
    }

    // POST /expenses/:id/delete — delete expense
    const deleteMatch = path.match(/^\/expenses\/([^/]+)\/delete$/)
    if (deleteMatch && method === 'POST') {
      const id = deleteMatch[1]
      await deleteExpense(id)
      return redirect('/expenses')
    }

    // GET /summary — monthly summary
    if (path === '/summary' && method === 'GET') {
      const month = url.searchParams.get('month') || currentMonth()
      const all = await readAllExpenses()
      const monthExpenses = getMonthExpenses(all, month)
      const summaries = computeSummary(monthExpenses)
      const grandTotal = summaries.reduce((sum, s) => sum + s.total, 0)
      return htmlResponse(renderSummaryPage(summaries, month, grandTotal, monthExpenses.length))
    }

    // GET /export — CSV download
    if (path === '/export' && method === 'GET') {
      const params: FilterParams = {
        from: url.searchParams.get('from') || undefined,
        to: url.searchParams.get('to') || undefined,
        category: (url.searchParams.get('category') as Category) || undefined,
      }
      const all = await readAllExpenses()
      const filtered = filterExpenses(all, params)
      const csv = toCSV(filtered)
      return new Response(csv, {
        headers: {
          'Content-Type': 'text/csv; charset=utf-8',
          'Content-Disposition': `attachment; filename="expenses-${today()}.csv"`,
        },
      })
    }

    // GET /api/expenses — JSON API
    if (path === '/api/expenses' && method === 'GET') {
      const params: FilterParams = {
        from: url.searchParams.get('from') || undefined,
        to: url.searchParams.get('to') || undefined,
        category: (url.searchParams.get('category') as Category) || undefined,
      }
      const all = await readAllExpenses()
      const filtered = filterExpenses(all, params)
      return jsonResponse(filtered)
    }

    // GET /api/summary — JSON summary
    if (path === '/api/summary' && method === 'GET') {
      const month = url.searchParams.get('month') || currentMonth()
      const all = await readAllExpenses()
      const monthExpenses = getMonthExpenses(all, month)
      const summaries = computeSummary(monthExpenses)
      const grandTotal = summaries.reduce((sum, s) => sum + s.total, 0)
      return jsonResponse({ month, summaries, grandTotal, count: monthExpenses.length })
    }

    // Root redirect
    if (path === '/' || path === '') {
      return redirect('/expenses')
    }

    return htmlResponse('<h1>Not Found</h1>', 404)
  },
}

