export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other'

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other']

export const CATEGORY_COLORS: Record<Category, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
}

export const CATEGORY_LABELS: Record<Category, string> = {
  food: 'Food',
  transport: 'Transport',
  housing: 'Housing',
  entertainment: 'Entertainment',
  utilities: 'Utilities',
  other: 'Other',
}

export type Expense = {
  id: string
  amount: number
  category: Category
  date: string
  notes: string
}

export type DateRange = {
  start: string
  end: string
}

export type FilterParams = {
  category?: Category
  dateRange?: DateRange
}

export type MonthlySummary = {
  month: string
  total: number
  byCategory: Record<Category, number>
}

import type { Expense, Category, FilterParams } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

const generateId = (): string => crypto.randomUUID()

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

export const writeExpense = async (expense: Omit<Expense, 'id'>): Promise<Expense> => {
  const record: Expense = { id: generateId(), ...expense }
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  const newContent = existing.endsWith('\n') || existing === ''
    ? `${existing}${JSON.stringify(record)}\n`
    : `${existing}\n${JSON.stringify(record)}\n`
  await Bun.write(DATA_PATH, newContent)
  return record
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], params: FilterParams): Expense[] => {
  let result = expenses

  if (params.category) {
    result = result.filter((e) => e.category === params.category)
  }

  if (params.dateRange) {
    const { start, end } = params.dateRange
    result = result.filter((e) => {
      if (start && e.date < start) return false
      if (end && e.date > end) return false
      return true
    })
  }

  return result.sort((a, b) => b.date.localeCompare(a.date))
}

export const getMonthlyBreakdown = (expenses: Expense[]): Map<string, Record<Category, number>> => {
  const months = new Map<string, Record<Category, number>>()

  for (const expense of expenses) {
    const month = expense.date.slice(0, 7) // YYYY-MM
    if (!months.has(month)) {
      months.set(month, {
        food: 0, transport: 0, housing: 0,
        entertainment: 0, utilities: 0, other: 0,
      })
    }
    const breakdown = months.get(month)!
    breakdown[expense.category] += expense.amount
  }

  return months
}

export const exportCsv = (expenses: Expense[]): string => {
  const header = 'id,amount,category,date,notes'
  const rows = expenses.map((e) => {
    const notes = e.notes.includes(',') || e.notes.includes('"')
      ? `"${e.notes.replace(/"/g, '""')}"`
      : e.notes
    return `${e.id},${e.amount.toFixed(2)},${e.category},${e.date},${notes}`
  })
  return [header, ...rows].join('\n') + '\n'
}

import { h } from '@plaited/template'
import type { Category } from './types'
import { CATEGORIES, CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type PieSlice = {
  category: Category
  amount: number
  percentage: number
  startAngle: number
  endAngle: number
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

export const renderPieChart = (byCategory: Record<Category, number>) => {
  const total = Object.values(byCategory).reduce((sum, v) => sum + v, 0)
  if (total === 0) {
    return h('p', { style: { color: '#9ca3af', textAlign: 'center', padding: '2rem' } }, 'No expenses to chart')
  }

  const slices: PieSlice[] = []
  let currentAngle = 0

  for (const cat of CATEGORIES) {
    const amount = byCategory[cat]
    if (amount <= 0) continue
    const percentage = (amount / total) * 100
    const sliceAngle = (percentage / 100) * 360
    slices.push({
      category: cat,
      amount,
      percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
    })
    currentAngle += sliceAngle
  }

  const cx = 120
  const cy = 120
  const r = 100

  const paths = slices.map((slice) => {
    if (slice.percentage >= 99.9) {
      return h('circle', {
        cx: String(cx),
        cy: String(cy),
        r: String(r),
        fill: CATEGORY_COLORS[slice.category],
      })
    }
    return h('path', {
      d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
      fill: CATEGORY_COLORS[slice.category],
    })
  })

  const legend = slices.map((slice) =>
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem' } },
      h('span', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: CATEGORY_COLORS[slice.category],
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', {}, `${CATEGORY_LABELS[slice.category]}: $${slice.amount.toFixed(2)} (${slice.percentage.toFixed(1)}%)`),
    )
  )

  return h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '2rem', alignItems: 'center', justifyContent: 'center' } },
    h('svg', { viewBox: '0 0 240 240', width: '240', height: '240' }, ...paths),
    h('div', { style: { display: 'flex', flexDirection: 'column', gap: '0.5rem' } }, ...legend),
  )
}

