import { createSSR } from '@plaited/template'
import type { Category, FilterParams } from './types'
import { CATEGORIES } from './types'
import { readExpenses, writeExpense, deleteExpense, filterExpenses, getMonthlyBreakdown, exportCsv } from './store'
import { renderPage, renderExpenseForm, renderFilterBar, renderExpenseTable, renderMonthlySummary } from './views'

const parseFilterParams = (url: URL): FilterParams => {
  const category = url.searchParams.get('category') as Category | null
  const start = url.searchParams.get('start')
  const end = url.searchParams.get('end')

  const params: FilterParams = {}
  if (category && CATEGORIES.includes(category)) {
    params.category = category
  }
  if (start || end) {
    params.dateRange = { start: start ?? '', end: end ?? '' }
  }
  return params
}

const htmlResponse = (content: string, status = 200) =>
  new Response(`<!DOCTYPE html>${content}`, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (path: string) =>
  new Response(null, { status: 303, headers: { Location: path } })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const method = req.method
  const path = url.pathname

  // GET / — Main page with form, filters, table, and monthly summary
  if (method === 'GET' && path === '/') {
    const params = parseFilterParams(url)
    const allExpenses = await readExpenses()
    const filtered = filterExpenses(allExpenses, params)

    // Build current month summary from all (unfiltered) expenses
    const now = new Date()
    const currentMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`
    const monthlyData = getMonthlyBreakdown(allExpenses)
    const currentBreakdown = monthlyData.get(currentMonth) ?? {
      food: 0, transport: 0, housing: 0,
      entertainment: 0, utilities: 0, other: 0,
    }
    const monthTotal = Object.values(currentBreakdown).reduce((s, v) => s + v, 0)

    const page = renderPage(
      'Expense Logger',
      renderExpenseForm(),
      renderFilterBar(params),
      renderMonthlySummary({ month: currentMonth, total: monthTotal, byCategory: currentBreakdown }),
      renderExpenseTable(filtered),
    )

    const ssr = createSSR()
    return htmlResponse(ssr(page))
  }

  // POST /expenses — Add a new expense
  if (method === 'POST' && path === '/expenses') {
    const form = await req.formData()
    const amount = parseFloat(form.get('amount') as string)
    const category = form.get('category') as Category
    const date = form.get('date') as string
    const notes = (form.get('notes') as string) ?? ''

    if (isNaN(amount) || amount < 0 || !CATEGORIES.includes(category) || !date) {
      return htmlResponse('<p>Invalid input. <a href="/">Go back</a></p>', 400)
    }

    await writeExpense({ amount, category, date, notes })
    return redirect('/')
  }

  // POST /expenses/:id/delete — Delete an expense
  const deleteMatch = path.match(/^\/expenses\/([^/]+)\/delete$/)
  if (method === 'POST' && deleteMatch) {
    const id = deleteMatch[1]
    await deleteExpense(id)
    return redirect('/')
  }

  // GET /export/csv — Download CSV
  if (method === 'GET' && path === '/export/csv') {
    const params = parseFilterParams(url)
    const allExpenses = await readExpenses()
    const filtered = filterExpenses(allExpenses, params)
    const csv = exportCsv(filtered)

    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv; charset=utf-8',
        'Content-Disposition': 'attachment; filename="expenses.csv"',
      },
    })
  }

  return htmlResponse('<p>Not found. <a href="/">Go home</a></p>', 404)
}

