import { createSSR } from 'plaited'
import { h } from 'plaited'
import type { NewItemInput } from './types'
import {
  loadItems,
  addItem,
  bulkImport,
  updateItem,
  deleteItem,
  getItemBySku,
  getLowStockItems,
  getCategories,
  queryItems,
} from './store'
import { renderDashboard, renderMessage } from './dashboard'

const ssr = createSSR()

const htmlPage = (body: ReturnType<typeof h>): string => {
  const rendered = ssr(body)
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Inventory Manager</title>
</head>
<body style="margin:0;background:#f8f9fa">
  ${rendered}
</body>
</html>`
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (body: ReturnType<typeof h>, status = 200) =>
  new Response(htmlPage(body), {
    status,
    headers: { 'Content-Type': 'text/html' },
  })

const redirect = (path: string) =>
  new Response(null, { status: 303, headers: { Location: path } })

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const formData = await req.formData()
  const result: Record<string, string> = {}
  formData.forEach((value, key) => {
    result[key] = String(value)
  })
  return result
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  try {
    // GET / — Dashboard
    if (method === 'GET' && path === '/') {
      const items = await loadItems()
      const lowStockItems = await getLowStockItems()
      const categories = await getCategories()
      const dashboard = renderDashboard(items, lowStockItems, categories)
      return htmlResponse(dashboard)
    }

    // GET /search — Search items
    if (method === 'GET' && path === '/search') {
      const query = url.searchParams.get('q') ?? undefined
      const category = url.searchParams.get('category') ?? undefined
      const lowStockOnly = url.searchParams.get('lowStock') === 'true'
      const sortBy = (url.searchParams.get('sortBy') as 'name' | 'sku' | 'quantity' | 'category') ?? undefined
      const sortOrder = (url.searchParams.get('sortOrder') as 'asc' | 'desc') ?? undefined

      const items = await queryItems({ query, category, lowStockOnly, sortBy, sortOrder })
      const lowStockItems = items.filter((i) => i.quantity <= i.reorderThreshold)
      const categories = await getCategories()
      const dashboard = renderDashboard(items, lowStockItems, categories, query, category)
      return htmlResponse(dashboard)
    }

    // GET /items/barcode?sku= or /items/barcode/:sku — Barcode/SKU lookup
    if (method === 'GET' && path.startsWith('/items/barcode')) {
      const sku = url.searchParams.get('sku') ?? path.split('/items/barcode/')[1] ?? ''
      if (!sku) return jsonResponse({ error: 'SKU is required' }, 400)
      const item = await getItemBySku(sku)
      if (!item) return jsonResponse({ error: `No item found with SKU "${sku}"` }, 404)
      return jsonResponse(item)
    }

    // GET /items/low-stock — Low stock items
    if (method === 'GET' && path === '/items/low-stock') {
      const items = await getLowStockItems()
      return jsonResponse(items)
    }

    // GET /api/items — JSON list of all items
    if (method === 'GET' && path === '/api/items') {
      const items = await loadItems()
      return jsonResponse(items)
    }

    // POST /items — Add single item (form or JSON)
    if (method === 'POST' && path === '/items') {
      const contentType = req.headers.get('content-type') ?? ''
      let input: NewItemInput

      if (contentType.includes('application/json')) {
        input = await req.json()
      } else {
        const form = await parseFormData(req)
        input = {
          name: form.name,
          sku: form.sku,
          quantity: parseInt(form.quantity, 10),
          category: form.category,
          reorderThreshold: parseInt(form.reorderThreshold, 10),
        }
      }

      const item = await addItem(input)

      if (contentType.includes('application/json')) {
        return jsonResponse(item, 201)
      }
      return redirect('/')
    }

    // POST /items/bulk — Bulk import
    if (method === 'POST' && path === '/items/bulk') {
      const contentType = req.headers.get('content-type') ?? ''
      let inputs: NewItemInput[]

      if (contentType.includes('application/json')) {
        inputs = await req.json()
      } else {
        const form = await parseFormData(req)
        inputs = JSON.parse(form.jsonData)
      }

      const result = await bulkImport(inputs)

      if (contentType.includes('application/json')) {
        return jsonResponse(result)
      }
      return redirect('/')
    }

    // PUT /items/:id — Update item (JSON only)
    if (method === 'PUT' && path.match(/^\/items\/[^/]+$/)) {
      const id = path.split('/items/')[1]
      const updates = await req.json()
      const item = await updateItem(id, updates)
      return jsonResponse(item)
    }

    // POST /items/:id/delete — Delete item (form-based)
    if (method === 'POST' && path.match(/^\/items\/[^/]+\/delete$/)) {
      const id = path.split('/items/')[1].split('/delete')[0]
      await deleteItem(id)
      return redirect('/')
    }

    // DELETE /items/:id — Delete item (API)
    if (method === 'DELETE' && path.match(/^\/items\/[^/]+$/)) {
      const id = path.split('/items/')[1]
      await deleteItem(id)
      return jsonResponse({ ok: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Internal server error'
    const accept = req.headers.get('accept') ?? ''
    if (accept.includes('text/html')) {
      const items = await loadItems()
      const lowStockItems = await getLowStockItems()
      const categories = await getCategories()
      const dashboard = h('div', {},
        renderMessage(message, 'error'),
        renderDashboard(items, lowStockItems, categories),
      )
      return htmlResponse(dashboard, 400)
    }
    return jsonResponse({ error: message }, 400)
  }
}

