import type { InventoryItem, NewItemInput, UpdateItemInput, ItemFilters, DashboardStats, StockStatus } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const getStockStatus = (item: InventoryItem): StockStatus => {
  if (item.quantity === 0) return 'out'
  if (item.quantity <= item.reorderThreshold) return 'low'
  return 'ok'
}

const loadItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as InventoryItem[]
}

const saveItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const getAllItems = async (filters?: ItemFilters): Promise<InventoryItem[]> => {
  let items = await loadItems()

  if (filters?.query) {
    const q = filters.query.toLowerCase()
    items = items.filter(
      (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q),
    )
  }

  if (filters?.category) {
    const cat = filters.category.toLowerCase()
    items = items.filter((item) => item.category.toLowerCase() === cat)
  }

  if (filters?.status) {
    items = items.filter((item) => getStockStatus(item) === filters.status)
  }

  const sortField = filters?.sort ?? 'name'
  const sortOrder = filters?.order ?? 'asc'
  const dir = sortOrder === 'asc' ? 1 : -1

  items.sort((a, b) => {
    const aVal = a[sortField]
    const bVal = b[sortField]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return aVal.localeCompare(bVal) * dir
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return (aVal - bVal) * dir
    }
    return 0
  })

  return items
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const createItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await loadItems()

  const existing = items.find((item) => item.sku.toLowerCase() === input.sku.toLowerCase())
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }

  const now = new Date().toISOString()
  const newItem: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku.toUpperCase(),
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now,
    updatedAt: now,
  }

  items.push(newItem)
  await saveItems(items)
  return newItem
}

export const updateItem = async (id: string, input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)

  if (input.sku) {
    const duplicate = items.find(
      (item) => item.sku.toLowerCase() === input.sku!.toLowerCase() && item.id !== id,
    )
    if (duplicate) throw new Error(`Item with SKU "${input.sku}" already exists`)
  }

  const updated: InventoryItem = {
    ...items[index],
    ...input,
    sku: input.sku ? input.sku.toUpperCase() : items[index].sku,
    updatedAt: new Date().toISOString(),
  }

  items[index] = updated
  await saveItems(items)
  return updated
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await loadItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)
  items.splice(index, 1)
  await saveItems(items)
}

export const bulkImport = async (inputs: NewItemInput[]): Promise<{ created: number; skipped: string[] }> => {
  const items = await loadItems()
  const existingSkus = new Set(items.map((item) => item.sku.toLowerCase()))
  const skipped: string[] = []
  const now = new Date().toISOString()

  for (const input of inputs) {
    const skuLower = input.sku.toLowerCase()
    if (existingSkus.has(skuLower)) {
      skipped.push(input.sku)
      continue
    }
    existingSkus.add(skuLower)
    items.push({
      id: generateId(),
      name: input.name,
      sku: input.sku.toUpperCase(),
      quantity: input.quantity,
      category: input.category,
      reorderThreshold: input.reorderThreshold,
      createdAt: now,
      updatedAt: now,
    })
  }

  await saveItems(items)
  return { created: inputs.length - skipped.length, skipped }
}

export const getDashboardStats = async (): Promise<DashboardStats> => {
  const items = await loadItems()
  const categories: Record<string, number> = {}
  const lowStockItems: InventoryItem[] = []
  let totalQuantity = 0
  let lowStockCount = 0
  let outOfStockCount = 0

  for (const item of items) {
    totalQuantity += item.quantity
    categories[item.category] = (categories[item.category] ?? 0) + 1
    const status = getStockStatus(item)
    if (status === 'low') {
      lowStockCount++
      lowStockItems.push(item)
    } else if (status === 'out') {
      outOfStockCount++
      lowStockItems.push(item)
    }
  }

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockCount,
    outOfStockCount,
    categories,
    lowStockItems,
  }
}

