const matchRoute = (method: string, pathname: string): { handler: string; params: Record<string, string> } | null => {
  const routes: Array<{ method: string; pattern: RegExp; handler: string; paramNames: string[] }> = [
    { method: 'GET', pattern: /^\/$/, handler: 'dashboard', paramNames: [] },
    { method: 'GET', pattern: /^\/items\/new$/, handler: 'newItemForm', paramNames: [] },
    { method: 'GET', pattern: /^\/items\/import$/, handler: 'importForm', paramNames: [] },
    { method: 'GET', pattern: /^\/items\/([^/]+)\/edit$/, handler: 'editItemForm', paramNames: ['id'] },
    { method: 'GET', pattern: /^\/items\/([^/]+)$/, handler: 'getItem', paramNames: ['id'] },
    { method: 'GET', pattern: /^\/items$/, handler: 'listItems', paramNames: [] },
    { method: 'GET', pattern: /^\/barcode$/, handler: 'barcodePage', paramNames: [] },
    { method: 'POST', pattern: /^\/items\/bulk$/, handler: 'bulkImport', paramNames: [] },
    { method: 'POST', pattern: /^\/items\/([^/]+)$/, handler: 'updateItem', paramNames: ['id'] },
    { method: 'POST', pattern: /^\/items$/, handler: 'createItem', paramNames: [] },
    { method: 'POST', pattern: /^\/barcode$/, handler: 'barcodeLookup', paramNames: [] },
    { method: 'DELETE', pattern: /^\/items\/([^/]+)$/, handler: 'deleteItem', paramNames: ['id'] },
    // API routes (JSON)
    { method: 'GET', pattern: /^\/api\/items$/, handler: 'apiListItems', paramNames: [] },
    { method: 'GET', pattern: /^\/api\/items\/([^/]+)$/, handler: 'apiGetItem', paramNames: ['id'] },
    { method: 'POST', pattern: /^\/api\/items\/bulk$/, handler: 'apiBulkImport', paramNames: [] },
    { method: 'POST', pattern: /^\/api\/items$/, handler: 'apiCreateItem', paramNames: [] },
    { method: 'PUT', pattern: /^\/api\/items\/([^/]+)$/, handler: 'apiUpdateItem', paramNames: ['id'] },
    { method: 'DELETE', pattern: /^\/api\/items\/([^/]+)$/, handler: 'apiDeleteItem', paramNames: ['id'] },
    { method: 'POST', pattern: /^\/api\/barcode$/, handler: 'apiBarcodeLookup', paramNames: [] },
    { method: 'GET', pattern: /^\/api\/dashboard$/, handler: 'apiDashboard', paramNames: [] },
  ]

  for (const route of routes) {
    if (route.method !== method) continue
    const match = pathname.match(route.pattern)
    if (match) {
      const params: Record<string, string> = {}
      route.paramNames.forEach((name, i) => {
        params[name] = match[i + 1]
      })
      return { handler: route.handler, params }
    }
  }
  return null
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const route = matchRoute(req.method, url.pathname)

  if (!route) {
    return html(views.renderError('Page not found'))
  }

  try {
    switch (route.handler) {
      // HTML routes
      case 'dashboard': {
        const stats = await db.getDashboardStats()
        return html(views.renderDashboard(stats))
      }

      case 'listItems': {
        const filters: ItemFilters = {
          query: url.searchParams.get('q') ?? undefined,
          category: url.searchParams.get('category') ?? undefined,
          status: (url.searchParams.get('status') as StockStatus) ?? undefined,
          sort: (url.searchParams.get('sort') as SortField) ?? undefined,
          order: (url.searchParams.get('order') as SortOrder) ?? undefined,
        }
        const items = await db.getAllItems(filters)
        return html(views.renderItemList(items, filters))
      }

      case 'getItem': {
        const item = await db.getItemById(route.params.id)
        if (!item) return html(views.renderError('Item not found'))
        return html(views.renderItemDetail(item))
      }

      case 'newItemForm': {
        return html(views.renderItemForm())
      }

      case 'editItemForm': {
        const item = await db.getItemById(route.params.id)
        if (!item) return html(views.renderError('Item not found'))
        return html(views.renderItemForm(item))
      }

      case 'createItem': {
        const data = await parseFormData(req)
        const input = parseItemInput(data)
        await db.createItem(input)
        return redirect('/items')
      }

      case 'updateItem': {
        const data = await parseFormData(req)
        const input = parseItemInput(data)
        await db.updateItem(route.params.id, input)
        return redirect(`/items/${route.params.id}`)
      }

      case 'deleteItem': {
        await db.deleteItem(route.params.id)
        return redirect('/items')
      }

      case 'importForm': {
        return html(views.renderBulkImport())
      }

      case 'bulkImport': {
        const data = await parseFormData(req)
        const items: NewItemInput[] = JSON.parse(data.json)
        const result = await db.bulkImport(items)
        return html(views.renderBulkImport(result))
      }

      case 'barcodePage': {
        return html(views.renderBarcodePage())
      }

      case 'barcodeLookup': {
        const data = await parseFormData(req)
        const sku = data.sku?.trim()
        if (!sku) return html(views.renderBarcodePage())
        const item = await db.getItemBySku(sku)
        return html(views.renderBarcodePage(item ?? null, sku))
      }

      // JSON API routes
      case 'apiDashboard': {
        const stats = await db.getDashboardStats()
        return json(stats)
      }

      case 'apiListItems': {
        const filters: ItemFilters = {
          query: url.searchParams.get('q') ?? undefined,
          category: url.searchParams.get('category') ?? undefined,
          status: (url.searchParams.get('status') as StockStatus) ?? undefined,
          sort: (url.searchParams.get('sort') as SortField) ?? undefined,
          order: (url.searchParams.get('order') as SortOrder) ?? undefined,
        }
        const items = await db.getAllItems(filters)
        return json(items)
      }

      case 'apiGetItem': {
        const item = await db.getItemById(route.params.id)
        if (!item) return json({ error: 'Item not found' }, 404)
        return json(item)
      }

      case 'apiCreateItem': {
        const input = (await req.json()) as NewItemInput
        const item = await db.createItem(input)
        return json(item, 201)
      }

      case 'apiUpdateItem': {
        const input = await req.json()
        const item = await db.updateItem(route.params.id, input)
        return json(item)
      }

      case 'apiDeleteItem': {
        await db.deleteItem(route.params.id)
        return json({ ok: true })
      }

      case 'apiBulkImport': {
        const items = (await req.json()) as NewItemInput[]
        const result = await db.bulkImport(items)
        return json(result, 201)
      }

      case 'apiBarcodeLookup': {
        const { sku } = (await req.json()) as { sku: string }
        const item = await db.getItemBySku(sku)
        if (!item) return json({ error: `No item found with SKU "${sku}"` }, 404)
        return json(item)
      }

      default:
        return html(views.renderError('Route handler not found'))
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'An unexpected error occurred'
    const isApi = route.handler.startsWith('api')
    return isApi ? json({ error: message }, 400) : html(views.renderError(message))
  }
}

