import type { InventoryItem, CreateItemInput, UpdateItemInput, BulkImportItem, SearchParams, StockStatus } from './types'

const DATA_PATH = `${import.meta.dir}/data/items.json`

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

const generateId = (): string => crypto.randomUUID()

const getStockStatus = (item: InventoryItem): StockStatus => {
  if (item.quantity === 0) return 'out'
  if (item.quantity < item.reorderThreshold) return 'low'
  return 'ok'
}

const getAll = async (params: SearchParams = {}): Promise<InventoryItem[]> => {
  let items = await readItems()

  if (params.q) {
    const query = params.q.toLowerCase()
    items = items.filter(
      (item) => item.name.toLowerCase().includes(query) || item.sku.toLowerCase().includes(query),
    )
  }

  if (params.category) {
    items = items.filter((item) => item.category === params.category)
  }

  if (params.status) {
    items = items.filter((item) => getStockStatus(item) === params.status)
  }

  const sortBy = params.sortBy ?? 'name'
  const sortOrder = params.sortOrder ?? 'asc'
  items.sort((a, b) => {
    const aVal = a[sortBy]
    const bVal = b[sortBy]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return sortOrder === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return sortOrder === 'asc' ? aVal - bVal : bVal - aVal
    }
    return 0
  })

  return items
}

const getById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.id === id)
}

const getBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.sku === sku)
}

const create = async (input: CreateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((item) => item.sku === input.sku)
  if (existing) throw new Error(`Item with SKU "${input.sku}" already exists`)

  const now = new Date().toISOString()
  const newItem: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now,
    updatedAt: now,
  }
  items.push(newItem)
  await writeItems(items)
  return newItem
}

const update = async (id: string, input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)

  if (input.sku && input.sku !== items[index].sku) {
    const skuConflict = items.find((item) => item.sku === input.sku && item.id !== id)
    if (skuConflict) throw new Error(`Item with SKU "${input.sku}" already exists`)
  }

  items[index] = {
    ...items[index],
    ...input,
    updatedAt: new Date().toISOString(),
  }
  await writeItems(items)
  return items[index]
}

const remove = async (id: string): Promise<void> => {
  const items = await readItems()
  const filtered = items.filter((item) => item.id !== id)
  if (filtered.length === items.length) throw new Error(`Item with id "${id}" not found`)
  await writeItems(filtered)
}

const bulkImport = async (
  incoming: BulkImportItem[],
): Promise<{ created: number; updated: number; errors: string[] }> => {
  const items = await readItems()
  let created = 0
  let updated = 0
  const errors: string[] = []

  for (const entry of incoming) {
    if (!entry.name || !entry.sku || entry.quantity == null || !entry.category || entry.reorderThreshold == null) {
      errors.push(`Skipped invalid entry: ${JSON.stringify(entry)}`)
      continue
    }
    const existingIndex = items.findIndex((item) => item.sku === entry.sku)
    const now = new Date().toISOString()

    if (existingIndex !== -1) {
      items[existingIndex] = {
        ...items[existingIndex],
        name: entry.name,
        quantity: entry.quantity,
        category: entry.category,
        reorderThreshold: entry.reorderThreshold,
        updatedAt: now,
      }
      updated++
    } else {
      items.push({
        id: generateId(),
        ...entry,
        createdAt: now,
        updatedAt: now,
      })
      created++
    }
  }

  await writeItems(items)
  return { created, updated, errors }
}

const getCategories = async (): Promise<string[]> => {
  const items = await readItems()
  return [...new Set(items.map((item) => item.category))].sort()
}

const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await readItems()
  return items.filter((item) => item.quantity < item.reorderThreshold)
}

const getStats = async (): Promise<{
  total: number
  lowStock: number
  outOfStock: number
  categories: number
}> => {
  const items = await readItems()
  return {
    total: items.length,
    lowStock: items.filter((item) => item.quantity > 0 && item.quantity < item.reorderThreshold).length,
    outOfStock: items.filter((item) => item.quantity === 0).length,
    categories: new Set(items.map((item) => item.category)).size,
  }
}

export const store = {
  getAll,
  getById,
  getBySku,
  create,
  update,
  remove,
  bulkImport,
  getCategories,
  getLowStockItems,
  getStockStatus,
  getStats,
}

