import { store } from './store'
import type { CreateItemInput, SearchParams, StockStatus } from './types'
import { renderDashboard, renderBarcodeResult } from './ui'
import { createSSR } from 'plaited'

const ssr = createSSR()

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (template: ReturnType<typeof renderDashboard>, status = 200) =>
  new Response(`<!DOCTYPE html>${ssr(template)}`, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirectResponse = (url: string, message?: string) => {
  const target = message ? `${url}${url.includes('?') ? '&' : '?'}message=${encodeURIComponent(message)}` : url
  return new Response(null, {
    status: 303,
    headers: { Location: target },
  })
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Dashboard
  if (path === '/' && method === 'GET') {
    const q = url.searchParams.get('q') ?? undefined
    const category = url.searchParams.get('category') ?? undefined
    const status = (url.searchParams.get('status') as StockStatus) ?? undefined
    const barcode = url.searchParams.get('barcode') ?? undefined
    const message = url.searchParams.get('message') ?? undefined

    // If barcode is scanned, redirect to barcode lookup
    if (barcode && barcode.trim()) {
      return redirectResponse(`/api/barcode/${encodeURIComponent(barcode.trim())}`)
    }

    const params: SearchParams = {}
    if (q) params.q = q
    if (category) params.category = category
    if (status) params.status = status

    const [items, lowStockItems, stats, categories] = await Promise.all([
      store.getAll(params),
      store.getLowStockItems(),
      store.getStats(),
      store.getCategories(),
    ])

    return htmlResponse(renderDashboard(items, lowStockItems, stats, categories, q, category, message))
  }

  // API: List items
  if (path === '/api/items' && method === 'GET') {
    const q = url.searchParams.get('q') ?? undefined
    const category = url.searchParams.get('category') ?? undefined
    const status = (url.searchParams.get('status') as StockStatus) ?? undefined
    const sortBy = url.searchParams.get('sortBy') as SearchParams['sortBy'] ?? undefined
    const sortOrder = url.searchParams.get('sortOrder') as SearchParams['sortOrder'] ?? undefined

    const params: SearchParams = {}
    if (q) params.q = q
    if (category) params.category = category
    if (status) params.status = status
    if (sortBy) params.sortBy = sortBy
    if (sortOrder) params.sortOrder = sortOrder

    const items = await store.getAll(params)
    return jsonResponse(items)
  }

  // API: Create item (JSON or form)
  if (path === '/api/items' && method === 'POST') {
    try {
      let input: CreateItemInput
      const contentType = req.headers.get('content-type') ?? ''

      if (contentType.includes('application/json')) {
        input = await req.json()
      } else {
        const formData = await req.formData()
        input = {
          name: formData.get('name') as string,
          sku: formData.get('sku') as string,
          quantity: Number(formData.get('quantity')),
          category: formData.get('category') as string,
          reorderThreshold: Number(formData.get('reorderThreshold')),
        }
      }

      if (!input.name || !input.sku || input.quantity == null || !input.category || input.reorderThreshold == null) {
        if (contentType.includes('application/json')) {
          return jsonResponse({ error: 'Missing required fields: name, sku, quantity, category, reorderThreshold' }, 400)
        }
        return redirectResponse('/', 'Missing required fields')
      }

      const item = await store.create(input)

      if (contentType.includes('application/json')) {
        return jsonResponse(item, 201)
      }
      return redirectResponse('/', `Added "${item.name}" (${item.sku})`)
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Unknown error'
      if ((req.headers.get('content-type') ?? '').includes('application/json')) {
        return jsonResponse({ error: msg }, 400)
      }
      return redirectResponse('/', msg)
    }
  }

  // API: Get single item
  const itemMatch = path.match(/^\/api\/items\/([^/]+)$/)
  if (itemMatch && method === 'GET') {
    const item = await store.getById(itemMatch[1])
    if (!item) return jsonResponse({ error: 'Item not found' }, 404)
    return jsonResponse(item)
  }

  // API: Update item
  if (itemMatch && method === 'PUT') {
    try {
      const input = await req.json()
      const item = await store.update(itemMatch[1], input)
      return jsonResponse(item)
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: msg }, 400)
    }
  }

  // API: Delete item
  if (itemMatch && method === 'DELETE') {
    try {
      await store.remove(itemMatch[1])
      return jsonResponse({ success: true })
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: msg }, 404)
    }
  }

  // API: Bulk import
  if (path === '/api/bulk-import' && method === 'POST') {
    try {
      const contentType = req.headers.get('content-type') ?? ''
      let data: unknown[]

      if (contentType.includes('application/json')) {
        data = await req.json()
      } else {
        const formData = await req.formData()
        const raw = formData.get('data') as string
        data = JSON.parse(raw)
      }

      if (!Array.isArray(data)) {
        if (contentType.includes('application/json')) {
          return jsonResponse({ error: 'Expected a JSON array of items' }, 400)
        }
        return redirectResponse('/', 'Expected a JSON array of items')
      }

      const result = await store.bulkImport(data)

      if (contentType.includes('application/json')) {
        return jsonResponse(result)
      }
      const msg = `Imported: ${result.created} created, ${result.updated} updated${result.errors.length > 0 ? `, ${result.errors.length} errors` : ''}`
      return redirectResponse('/', msg)
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Invalid JSON'
      if ((req.headers.get('content-type') ?? '').includes('application/json')) {
        return jsonResponse({ error: msg }, 400)
      }
      return redirectResponse('/', `Import error: ${msg}`)
    }
  }

  // API: Barcode lookup
  const barcodeMatch = path.match(/^\/api\/barcode\/(.+)$/)
  if (barcodeMatch && method === 'GET') {
    const sku = decodeURIComponent(barcodeMatch[1])
    const item = await store.getBySku(sku)

    const accept = req.headers.get('accept') ?? ''
    if (accept.includes('application/json')) {
      if (!item) return jsonResponse({ error: `No item found with SKU "${sku}"` }, 404)
      return jsonResponse(item)
    }

    return htmlResponse(renderBarcodeResult(item, sku))
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

