export type Vote = {
  userId: string
  direction: 1 | -1
}

export type Reply = {
  id: string
  threadId: string
  parentReplyId: string | null
  body: string
  author: string
  createdAt: string
  votes: Vote[]
}

export type Thread = {
  id: string
  title: string
  body: string
  author: string
  createdAt: string
  votes: Vote[]
  replies: Reply[]
}

export type SortMode = 'newest' | 'most-upvoted' | 'most-active'

export type ForumState = {
  threads: Thread[]
}

import type { ForumState, Thread } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

export const loadState = async (): Promise<ForumState> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { threads: [] }
  const text = await file.text()
  return JSON.parse(text) as ForumState
}

export const saveState = async (state: ForumState): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(state, null, 2))
}

export const getThread = async (threadId: string): Promise<Thread | undefined> => {
  const state = await loadState()
  return state.threads.find((t) => t.id === threadId)
}

import type { Thread, Reply, SortMode, Vote } from './types'
import { loadState, saveState } from './store'

const generateId = (): string => crypto.randomUUID()

const getVoteScore = (votes: Vote[]): number =>
  votes.reduce((sum, v) => sum + v.direction, 0)

// --- Thread CRUD ---

export const createThread = async (args: {
  title: string
  body: string
  author: string
}): Promise<Thread> => {
  const state = await loadState()
  const thread: Thread = {
    id: generateId(),
    title: args.title,
    body: args.body,
    author: args.author,
    createdAt: new Date().toISOString(),
    votes: [],
    replies: [],
  }
  state.threads.push(thread)
  await saveState(state)
  return thread
}

// --- Replies ---

export const addReply = async (args: {
  threadId: string
  body: string
  author: string
  parentReplyId?: string | null
}): Promise<Reply> => {
  const state = await loadState()
  const thread = state.threads.find((t) => t.id === args.threadId)
  if (!thread) throw new Error(`Thread ${args.threadId} not found`)

  // Enforce one-level nesting: if parentReplyId itself has a parent, flatten to its parent
  let resolvedParent = args.parentReplyId ?? null
  if (resolvedParent) {
    const parentReply = thread.replies.find((r) => r.id === resolvedParent)
    if (parentReply?.parentReplyId) {
      resolvedParent = parentReply.parentReplyId
    }
  }

  const reply: Reply = {
    id: generateId(),
    threadId: args.threadId,
    parentReplyId: resolvedParent,
    body: args.body,
    author: args.author,
    createdAt: new Date().toISOString(),
    votes: [],
  }
  thread.replies.push(reply)
  await saveState(state)
  return reply
}

// --- Voting ---

export const voteOnThread = async (args: {
  threadId: string
  userId: string
  direction: 1 | -1
}): Promise<number> => {
  const state = await loadState()
  const thread = state.threads.find((t) => t.id === args.threadId)
  if (!thread) throw new Error(`Thread ${args.threadId} not found`)
  applyVote(thread.votes, args.userId, args.direction)
  await saveState(state)
  return getVoteScore(thread.votes)
}

export const voteOnReply = async (args: {
  threadId: string
  replyId: string
  userId: string
  direction: 1 | -1
}): Promise<number> => {
  const state = await loadState()
  const thread = state.threads.find((t) => t.id === args.threadId)
  if (!thread) throw new Error(`Thread ${args.threadId} not found`)
  const reply = thread.replies.find((r) => r.id === args.replyId)
  if (!reply) throw new Error(`Reply ${args.replyId} not found`)
  applyVote(reply.votes, args.userId, args.direction)
  await saveState(state)
  return getVoteScore(reply.votes)
}

const applyVote = (votes: Vote[], userId: string, direction: 1 | -1): void => {
  const existing = votes.find((v) => v.userId === userId)
  if (existing) {
    if (existing.direction === direction) {
      // Toggle off: remove the vote
      const idx = votes.indexOf(existing)
      votes.splice(idx, 1)
    } else {
      existing.direction = direction
    }
  } else {
    votes.push({ userId, direction })
  }
}

// --- Sorting ---

export const sortThreads = (threads: Thread[], mode: SortMode): Thread[] => {
  const sorted = [...threads]
  switch (mode) {
    case 'newest':
      return sorted.sort(
        (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      )
    case 'most-upvoted':
      return sorted.sort((a, b) => getVoteScore(b.votes) - getVoteScore(a.votes))
    case 'most-active': {
      const latestReply = (t: Thread): number => {
        if (t.replies.length === 0) return new Date(t.createdAt).getTime()
        return Math.max(...t.replies.map((r) => new Date(r.createdAt).getTime()))
      }
      return sorted.sort((a, b) => latestReply(b) - latestReply(a))
    }
  }
}

// --- Search ---

export const searchThreads = async (query: string): Promise<Thread[]> => {
  const state = await loadState()
  const lower = query.toLowerCase()
  return state.threads.filter((t) => t.title.toLowerCase().includes(lower))
}

// --- Listing ---

export const listThreads = async (args?: {
  sort?: SortMode
  search?: string
}): Promise<Thread[]> => {
  const state = await loadState()
  let results = state.threads
  if (args?.search) {
    const lower = args.search.toLowerCase()
    results = results.filter((t) => t.title.toLowerCase().includes(lower))
  }
  return sortThreads(results, args?.sort ?? 'newest')
}

