  }
}

export type Reply = {
  id: string;
  threadId: string;
  body: string;
  author: string;
  createdAt: string;
  upvotes: number;
  downvotes: number;
};

export type Thread = {
  id: string;
  title: string;
  body: string;
  author: string;
  createdAt: string;
  updatedAt: string;
  upvotes: number;
  downvotes: number;
  replies: Reply[];
};

export type SortMode = "newest" | "top" | "active";

export type CreateThreadInput = {
  title: string;
  body: string;
  author: string;
};

export type ReplyInput = {
  threadId: string;
  body: string;
  author: string;
};

export type VoteInput = {
  targetId: string;
  direction: "up" | "down";
};

export type ListThreadsInput = {
  sort?: SortMode;
  search?: string;
};

import type { Thread } from "./types";

const DATA_PATH = `${import.meta.dir}/data/threads.json`;

export const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  return JSON.parse(text) as Thread[];
};

export const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2));
};

export const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

import type {
  Thread,
  Reply,
  CreateThreadInput,
  ReplyInput,
  VoteInput,
  ListThreadsInput,
  SortMode,
} from "./types";
import { readThreads, writeThreads, generateId } from "./store";

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await readThreads();
  const now = new Date().toISOString();
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: now,
    updatedAt: now,
    upvotes: 0,
    downvotes: 0,
    replies: [],
  };
  threads.unshift(thread);
  await writeThreads(threads);
  return thread;
};

export const replyToThread = async (input: ReplyInput): Promise<Reply> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === input.threadId);
  if (!thread) throw new Error(`Thread not found: ${input.threadId}`);

  const now = new Date().toISOString();
  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    body: input.body,
    author: input.author,
    createdAt: now,
    upvotes: 0,
    downvotes: 0,
  };
  thread.replies.push(reply);
  thread.updatedAt = now;
  await writeThreads(threads);
  return reply;
};

export const vote = async (input: VoteInput): Promise<{ score: number }> => {
  const threads = await readThreads();

  for (const thread of threads) {
    if (thread.id === input.targetId) {
      if (input.direction === "up") thread.upvotes++;
      else thread.downvotes++;
      await writeThreads(threads);
      return { score: thread.upvotes - thread.downvotes };
    }
    for (const reply of thread.replies) {
      if (reply.id === input.targetId) {
        if (input.direction === "up") reply.upvotes++;
        else reply.downvotes++;
        await writeThreads(threads);
        return { score: reply.upvotes - reply.downvotes };
      }
    }
  }

  throw new Error(`Target not found: ${input.targetId}`);
};

export const getThread = async (threadId: string): Promise<Thread> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) throw new Error(`Thread not found: ${threadId}`);
  return thread;
};

const sortThreads = (threads: Thread[], mode: SortMode): Thread[] => {
  const copy = [...threads];
  switch (mode) {
    case "newest":
      return copy.sort(
        (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
    case "top":
      return copy.sort(
        (a, b) => (b.upvotes - b.downvotes) - (a.upvotes - a.downvotes)
      );
    case "active":
      return copy.sort((a, b) => {
        const aLatest = a.replies.length
          ? new Date(a.replies[a.replies.length - 1].createdAt).getTime()
          : new Date(a.updatedAt).getTime();
        const bLatest = b.replies.length
          ? new Date(b.replies[b.replies.length - 1].createdAt).getTime()
          : new Date(b.updatedAt).getTime();
        return bLatest - aLatest;
      });
  }
};

export const listThreads = async (
  input: ListThreadsInput = {}
): Promise<Thread[]> => {
  const { sort = "newest", search } = input;
  let threads = await readThreads();

  if (search) {
    const query = search.toLowerCase();
    threads = threads.filter((t) => t.title.toLowerCase().includes(query));
  }

  return sortThreads(threads, sort);
};

