import { createSSR } from "plaited";
import {
  createThread,
  replyToThread,
  vote,
  listThreads,
  getThread,
} from "./handlers";
import {
  renderThreadList,
  renderThreadDetail,
} from "./view";
import type { SortMode } from "./types";

export type ForumAction =
  | { type: "list"; sort?: SortMode; search?: string }
  | { type: "view"; threadId: string }
  | { type: "create"; title: string; body: string; author: string }
  | { type: "reply"; threadId: string; body: string; author: string }
  | { type: "vote"; targetId: string; direction: "up" | "down" };

export const handleAction = async (action: ForumAction): Promise<string> => {
  const ssr = createSSR();

  switch (action.type) {
    case "list": {
      const sort = action.sort ?? "newest";
      const search = action.search ?? "";
      const threads = await listThreads({ sort, search });
      return ssr(renderThreadList(threads, sort, search));
    }

    case "view": {
      const thread = await getThread(action.threadId);
      return ssr(renderThreadDetail(thread));
    }

    case "create": {
      await createThread({
        title: action.title,
        body: action.body,
        author: action.author,
      });
      const threads = await listThreads({ sort: "newest" });
      return ssr(renderThreadList(threads, "newest", ""));
    }

    case "reply": {
      await replyToThread({
        threadId: action.threadId,
        body: action.body,
        author: action.author,
      });
      const thread = await getThread(action.threadId);
      return ssr(renderThreadDetail(thread));
    }

    case "vote": {
      await vote({
        targetId: action.targetId,
        direction: action.direction,
      });
      // Return empty string; the caller can re-render the relevant view
      return "";
    }
  }
};

