const DATA_PATH = `${import.meta.dir}/data/forum.json`

export const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { threads: [] }
}

export const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const findThread = (data: ForumData, threadId: string): Thread | undefined =>
  data.threads.find((t) => t.id === threadId)

export const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

{
