import type { Thread, Reply, SortMode, VoteDirection, ThreadSummary } from './types'
import { loadData, saveData, findThread, generateId } from './store'

export const createThread = async (title: string, body: string, author: string): Promise<Thread> => {
  const data = await loadData()
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: [],
    score: 0,
    replies: [],
  }
  data.threads.unshift(thread)
  await saveData(data)
  return thread
}

export const getThread = async (threadId: string): Promise<Thread | null> => {
  const data = await loadData()
  return findThread(data, threadId) ?? null
}

export const deleteThread = async (threadId: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.threads.findIndex((t) => t.id === threadId)
  if (idx === -1) return false
  data.threads.splice(idx, 1)
  await saveData(data)
  return true
}

export const addReply = async (
  threadId: string,
  body: string,
  author: string,
  parentReplyId?: string
): Promise<Reply | null> => {
  const data = await loadData()
  const thread = findThread(data, threadId)
  if (!thread) return null

  if (parentReplyId) {
    const parentReply = thread.replies.find((r) => r.id === parentReplyId)
    if (!parentReply) return null
    if (parentReply.parentReplyId !== null) return null
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId: parentReplyId ?? null,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: [],
    score: 0,
  }
  thread.replies.push(reply)
  await saveData(data)
  return reply
}

export const vote = async (
  threadId: string,
  targetId: string,
  direction: VoteDirection,
  voter: string
): Promise<number | null> => {
  const data = await loadData()
  const thread = findThread(data, threadId)
  if (!thread) return null

  const isThreadVote = thread.id === targetId
  const target = isThreadVote ? thread : thread.replies.find((r) => r.id === targetId)
  if (!target) return null

  const existingIdx = target.votes.findIndex((v) => v.voter === voter)
  if (existingIdx !== -1) {
    const existing = target.votes[existingIdx]
    if (existing.direction === direction) {
      target.votes.splice(existingIdx, 1)
    } else {
      existing.direction = direction
    }
  } else {
    target.votes.push({ voter, direction })
  }

  target.score = target.votes.reduce((sum, v) => sum + (v.direction === 'up' ? 1 : -1), 0)
  await saveData(data)
  return target.score
}

const sortThreads = (threads: Thread[], mode: SortMode): Thread[] => {
  const sorted = [...threads]
  switch (mode) {
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'most-upvoted':
      return sorted.sort((a, b) => b.score - a.score)
    case 'most-active':
      return sorted.sort((a, b) => b.replies.length - a.replies.length)
  }
}

export const listThreads = async (
  sort: SortMode = 'newest',
  search?: string
): Promise<ThreadSummary[]> => {
  const data = await loadData()
  let threads = data.threads

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  return sortThreads(threads, sort).map((t) => ({
    id: t.id,
    title: t.title,
    author: t.author,
    createdAt: t.createdAt,
    score: t.score,
    replyCount: t.replies.length,
  }))
}

