import { createSSR } from 'plaited'
import type { SortMode, VoteDirection } from './types'
import { createThread, getThread, deleteThread, addReply, vote, listThreads } from './handlers'
import { renderThreadList, renderThreadDetail } from './render'

export type ForumAction =
  | { type: 'list-threads'; sort?: SortMode; search?: string }
  | { type: 'view-thread'; threadId: string }
  | { type: 'create-thread'; title: string; body: string; author: string }
  | { type: 'add-reply'; threadId: string; body: string; author: string; parentReplyId?: string }
  | { type: 'vote'; threadId: string; targetId: string; direction: VoteDirection; voter: string }
  | { type: 'delete-thread'; threadId: string }

export type ForumResult =
  | { ok: true; html: string }
  | { ok: true; data: unknown }
  | { ok: false; error: string }

const ssr = createSSR()

export const handleAction = async (action: ForumAction): Promise<ForumResult> => {
  switch (action.type) {
    case 'list-threads': {
      const threads = await listThreads(action.sort, action.search)
      const template = renderThreadList(threads, action.sort ?? 'newest', action.search ?? '')
      const html = ssr(template)
      return { ok: true, html }
    }

    case 'view-thread': {
      const thread = await getThread(action.threadId)
      if (!thread) return { ok: false, error: 'Thread not found' }
      const template = renderThreadDetail(thread)
      const html = ssr(template)
      return { ok: true, html }
    }

    case 'create-thread': {
      if (!action.title.trim()) return { ok: false, error: 'Title is required' }
      if (!action.body.trim()) return { ok: false, error: 'Body is required' }
      if (!action.author.trim()) return { ok: false, error: 'Author is required' }
      const thread = await createThread(action.title.trim(), action.body.trim(), action.author.trim())
      return { ok: true, data: thread }
    }

    case 'add-reply': {
      if (!action.body.trim()) return { ok: false, error: 'Reply body is required' }
      if (!action.author.trim()) return { ok: false, error: 'Author is required' }
      const reply = await addReply(
        action.threadId,
        action.body.trim(),
        action.author.trim(),
        action.parentReplyId,
      )
      if (!reply) return { ok: false, error: 'Thread or parent reply not found' }
      return { ok: true, data: reply }
    }

    case 'vote': {
      const score = await vote(action.threadId, action.targetId, action.direction, action.voter)
      if (score === null) return { ok: false, error: 'Target not found' }
      return { ok: true, data: { score } }
    }

    case 'delete-thread': {
      const deleted = await deleteThread(action.threadId)
      if (!deleted) return { ok: false, error: 'Thread not found' }
      return { ok: true, data: { deleted: true } }
    }
  }
}

