// Conversion factors to base unit per category
// Length -> meters, Weight -> grams, Volume -> milliliters, Time -> seconds
const lengthToBase: Record<string, number> = {
  mm: 0.001,
  cm: 0.01,
  m: 1,
  km: 1000,
  in: 0.0254,
  ft: 0.3048,
  yd: 0.9144,
  mi: 1609.344,
};

const weightToBase: Record<string, number> = {
  mg: 0.001,
  g: 1,
  kg: 1000,
  lb: 453.59237,
  oz: 28.349523125,
};

const volumeToBase: Record<string, number> = {
  ml: 1,
  l: 1000,
  gal: 3785.41178,
  qt: 946.352946,
  pt: 473.176473,
  cup: 236.588236,
  tbsp: 14.7867648,
  tsp: 4.92892159,
};

const timeToBase: Record<string, number> = {
  ms: 0.001,
  s: 1,
  min: 60,
  hr: 3600,
  day: 86400,
  week: 604800,
};

export type ConversionResult = {
  value: number;
  formula: string;
  fromUnit: string;
  toUnit: string;
};

const formatNumber = (n: number): string => {
  if (Number.isInteger(n) && Math.abs(n) < 1e15) return n.toString();
  const result = parseFloat(n.toPrecision(10));
  return result.toString();
};

const convertLinear = (
  value: number,
  from: string,
  to: string,
  toBase: Record<string, number>,
  baseUnitName: string,
): ConversionResult => {
  if (from === to) {
    return { value, formula: `1 ${from} = 1 ${to}`, fromUnit: from, toUnit: to };
  }
  const factor = toBase[from] / toBase[to];
  const result = value * factor;
  return {
    value: result,
    formula: `1 ${from} = ${formatNumber(factor)} ${to}`,
    fromUnit: from,
    toUnit: to,
  };
};

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  if (from === to) {
    return { value, formula: `1 ${from} = 1 ${to}`, fromUnit: from, toUnit: to };
  }

  const key = `${from}->${to}`;
  let result: number;
  let formula: string;

  switch (key) {
    case "C->F":
      result = value * 9 / 5 + 32;
      formula = "F = C \u00D7 9/5 + 32";
      break;
    case "F->C":
      result = (value - 32) * 5 / 9;
      formula = "C = (F \u2212 32) \u00D7 5/9";
      break;
    case "C->K":
      result = value + 273.15;
      formula = "K = C + 273.15";
      break;
    case "K->C":
      result = value - 273.15;
      formula = "C = K \u2212 273.15";
      break;
    case "F->K":
      result = (value - 32) * 5 / 9 + 273.15;
      formula = "K = (F \u2212 32) \u00D7 5/9 + 273.15";
      break;
    case "K->F":
      result = (value - 273.15) * 9 / 5 + 32;
      formula = "F = (K \u2212 273.15) \u00D7 9/5 + 32";
      break;
    default:
      throw new Error(`Unknown temperature conversion: ${key}`);
  }

  return { value: result, formula, fromUnit: from, toUnit: to };
};

export const convert = (
  category: Category,
  value: number,
  from: string,
  to: string,
): ConversionResult => {
  switch (category) {
    case "length":
      return convertLinear(value, from, to, lengthToBase, "m");
    case "weight":
      return convertLinear(value, from, to, weightToBase, "g");
    case "volume":
      return convertLinear(value, from, to, volumeToBase, "ml");
    case "time":
      return convertLinear(value, from, to, timeToBase, "s");
    case "temperature":
      return convertTemperature(value, from, to);
  }
};

