import { convert, categories, type Category } from "./converter.ts";
import { renderConverter } from "./ui.ts";

type ConverterState = {
  category: Category;
  fromUnit: string;
  toUnit: string;
  inputValue: string;
};

const defaultState = (category: Category): ConverterState => {
  const units = categories[category].units;
  return {
    category,
    fromUnit: units[0].symbol,
    toUnit: units.length > 1 ? units[1].symbol : units[0].symbol,
    inputValue: "",
  };
};

const state: ConverterState = defaultState("length");

const performConversion = (st: ConverterState) => {
  const numValue = parseFloat(st.inputValue);
  if (!st.inputValue || isNaN(numValue)) {
    return renderConverter({
      activeCategory: st.category,
      fromUnit: st.fromUnit,
      toUnit: st.toUnit,
      inputValue: st.inputValue,
    });
  }

  try {
    const result = convert(st.category, numValue, st.fromUnit, st.toUnit);
    return renderConverter({
      activeCategory: st.category,
      fromUnit: st.fromUnit,
      toUnit: st.toUnit,
      inputValue: st.inputValue,
      result,
    });
  } catch (e) {
    const msg = e instanceof Error ? e.message : "Conversion error";
    return renderConverter({
      activeCategory: st.category,
      fromUnit: st.fromUnit,
      toUnit: st.toUnit,
      inputValue: st.inputValue,
      error: msg,
    });
  }
};

export const handleSelectCategory = (category: string): string => {
  if (category in categories) {
    const newState = defaultState(category as Category);
    Object.assign(state, newState);
    return performConversion(state);
  }
  return performConversion(state);
};

export const handleInputChanged = (value: string): string => {
  state.inputValue = value;
  return performConversion(state);
};

export const handleFromChanged = (unit: string): string => {
  state.fromUnit = unit;
  return performConversion(state);
};

export const handleToChanged = (unit: string): string => {
  state.toUnit = unit;
  return performConversion(state);
};

export const handleSwapUnits = (): string => {
  const temp = state.fromUnit;
  state.fromUnit = state.toUnit;
  state.toUnit = temp;
  return performConversion(state);
};

export const render = (): string => performConversion(state);

// Save a conversion to history
export const saveToHistory = async (entry: {
  category: string;
  from: string;
  to: string;
  value: number;
  result: number;
}) => {
  const line = JSON.stringify({ ...entry, timestamp: new Date().toISOString() }) + "\n";
  const historyPath = new URL("./data/history.jsonl", import.meta.url).pathname;
  const file = Bun.file(historyPath);
  const existing = (await file.exists()) ? await file.text() : "";
  await Bun.write(file, existing + line);
};

