// Base unit factors: value in base unit = value * factor
// Length base: meter
const lengthToBase: Record<string, number> = {
  mm: 0.001,
  cm: 0.01,
  m: 1,
  km: 1000,
  in: 0.0254,
  ft: 0.3048,
  yd: 0.9144,
  mi: 1609.344,
}

// Weight base: gram
const weightToBase: Record<string, number> = {
  mg: 0.001,
  g: 1,
  kg: 1000,
  lb: 453.59237,
  oz: 28.349523125,
}

// Volume base: milliliter
const volumeToBase: Record<string, number> = {
  ml: 1,
  l: 1000,
  gal: 3785.41,
  qt: 946.353,
  pt: 473.176,
  cup: 236.588,
  tbsp: 14.7868,
  tsp: 4.92892,
}

// Time base: second
const timeToBase: Record<string, number> = {
  ms: 0.001,
  s: 1,
  min: 60,
  hr: 3600,
  day: 86400,
  week: 604800,
}

const factorTables: Record<string, Record<string, number>> = {
  length: lengthToBase,
  weight: weightToBase,
  volume: volumeToBase,
  time: timeToBase,
}

const baseUnitNames: Record<string, string> = {
  length: 'm',
  weight: 'g',
  volume: 'ml',
  time: 's',
}

const convertTemperature = (value: number, from: string, to: string): number => {
  if (from === to) return value
  // Convert to Celsius first
  let celsius: number
  if (from === 'C') celsius = value
  else if (from === 'F') celsius = (value - 32) * 5 / 9
  else celsius = value - 273.15 // K

  // Convert from Celsius to target
  if (to === 'C') return celsius
  if (to === 'F') return celsius * 9 / 5 + 32
  return celsius + 273.15 // K
}

const getTemperatureFormula = (from: string, to: string): string => {
  const key = `${from}-${to}`
  const formulas: Record<string, string> = {
    'C-C': 'C = C',
    'C-F': 'F = C x 9/5 + 32',
    'C-K': 'K = C + 273.15',
    'F-C': 'C = (F - 32) x 5/9',
    'F-F': 'F = F',
    'F-K': 'K = (F - 32) x 5/9 + 273.15',
    'K-C': 'C = K - 273.15',
    'K-F': 'F = (K - 273.15) x 9/5 + 32',
    'K-K': 'K = K',
  }
  return formulas[key] ?? ''
}

const getLinearFormula = (from: string, to: string, category: string): string => {
  const table = factorTables[category]
  if (!table) return ''
  const fromFactor = table[from]
  const toFactor = table[to]
  if (fromFactor === undefined || toFactor === undefined) return ''

  if (from === to) return `${to} = ${from}`

  const ratio = fromFactor / toFactor
  const base = baseUnitNames[category]

  if (ratio === 1) return `${to} = ${from}`

  // Produce a clean ratio string
  const formatRatio = (r: number): string => {
    if (Number.isInteger(r)) return String(r)
    // Show up to 6 significant digits
    return parseFloat(r.toPrecision(6)).toString()
  }

  return `${to} = ${from} x ${formatRatio(ratio)} (via ${base})`
}

export const convert = (category: Category, from: string, to: string, value: number): ConversionResult => {
  let outputValue: number
  let formula: string

  if (category === 'temperature') {
    outputValue = convertTemperature(value, from, to)
    formula = getTemperatureFormula(from, to)
  } else {
    const table = factorTables[category]
    const fromFactor = table[from]
    const toFactor = table[to]
    if (fromFactor === undefined || toFactor === undefined) {
      throw new Error(`Unknown unit: ${from} or ${to} in category ${category}`)
    }
    outputValue = value * fromFactor / toFactor
    formula = getLinearFormula(from, to, category)
  }

  return {
    from,
    to,
    inputValue: value,
    outputValue: Math.round(outputValue * 1e10) / 1e10,
    formula,
    category,
  }
}

