import { convert, categories, type Category } from './converter.ts'
import { renderPage } from './ui.ts'
import { createSSR } from 'plaited'

const validCategories = new Set(Object.keys(categories))

const isValidCategory = (value: string): value is Category =>
  validCategories.has(value)

const renderHTML = (activeCategory: Category, result?: ReturnType<typeof convert>, fromUnit?: string, toUnit?: string, inputValue?: string): Response => {
  const template = renderPage(activeCategory, result, fromUnit, toUnit, inputValue)
  const html = createSSR(template)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export const handleRequest = (req: Request): Response => {
  const url = new URL(req.url)
  const path = url.pathname

  // GET / — render converter UI
  if (req.method === 'GET' && path === '/') {
    const catParam = url.searchParams.get('category') ?? 'length'
    const activeCategory: Category = isValidCategory(catParam) ? catParam : 'length'
    return renderHTML(activeCategory)
  }

  // GET /categories — list all categories and units (JSON API)
  if (req.method === 'GET' && path === '/categories') {
    return Response.json(categories)
  }

  // POST /convert — perform conversion
  if (req.method === 'POST' && path === '/convert') {
    return handleConvert(req)
  }

  return new Response('Not Found', { status: 404 })
}

const handleConvert = async (req: Request): Promise<Response> => {
  const contentType = req.headers.get('content-type') ?? ''

  let category: string
  let from: string
  let to: string
  let value: number

  if (contentType.includes('application/json')) {
    const body = await req.json() as Record<string, unknown>
    category = String(body.category ?? '')
    from = String(body.from ?? '')
    to = String(body.to ?? '')
    value = Number(body.value)
  } else {
    // Handle form submission
    const formData = await req.formData()
    category = String(formData.get('category') ?? '')
    from = String(formData.get('from') ?? '')
    to = String(formData.get('to') ?? '')
    value = Number(formData.get('value'))
  }

  if (!isValidCategory(category)) {
    return Response.json({ error: `Invalid category: ${category}` }, { status: 400 })
  }

  const unitSymbols = categories[category].map(u => u.symbol)
  if (!unitSymbols.includes(from) || !unitSymbols.includes(to)) {
    return Response.json({ error: `Invalid unit for ${category}` }, { status: 400 })
  }

  if (isNaN(value)) {
    return Response.json({ error: 'Invalid numeric value' }, { status: 400 })
  }

  const result = convert(category, from, to, value)

  // If JSON request, return JSON
  if (contentType.includes('application/json')) {
    return Response.json(result)
  }

  // Otherwise re-render the page with the result
  return renderHTML(category, result, from, to, String(value))
}

export default {
  fetch: handleRequest,
}

