export type Category = 'Length' | 'Weight' | 'Temperature' | 'Volume' | 'Time'

export type LengthUnit = 'mm' | 'cm' | 'm' | 'km' | 'in' | 'ft' | 'yd' | 'mi'
export type WeightUnit = 'mg' | 'g' | 'kg' | 'lb' | 'oz'
export type TemperatureUnit = 'C' | 'F' | 'K'
export type VolumeUnit = 'ml' | 'l' | 'gal' | 'qt' | 'pt' | 'cup' | 'tbsp' | 'tsp'
export type TimeUnit = 'ms' | 's' | 'min' | 'hr' | 'day' | 'week'

export type Unit = LengthUnit | WeightUnit | TemperatureUnit | VolumeUnit | TimeUnit

export type ConversionResult = {
  result: number
  formula: string
}

const categoryUnits: Record<Category, readonly Unit[]> = {
  Length: ['mm', 'cm', 'm', 'km', 'in', 'ft', 'yd', 'mi'] as const,
  Weight: ['mg', 'g', 'kg', 'lb', 'oz'] as const,
  Temperature: ['C', 'F', 'K'] as const,
  Volume: ['ml', 'l', 'gal', 'qt', 'pt', 'cup', 'tbsp', 'tsp'] as const,
  Time: ['ms', 's', 'min', 'hr', 'day', 'week'] as const,
}

// Base unit factors — each unit expressed relative to a base unit
// Length base: meter
const lengthToBase: Record<LengthUnit, number> = {
  mm: 0.001,
  cm: 0.01,
  m: 1,
  km: 1000,
  in: 0.0254,
  ft: 0.3048,
  yd: 0.9144,
  mi: 1609.344,
}

// Weight base: gram
const weightToBase: Record<WeightUnit, number> = {
  mg: 0.001,
  g: 1,
  kg: 1000,
  lb: 453.5924,
  oz: 28.3495,
}

// Volume base: milliliter
const volumeToBase: Record<VolumeUnit, number> = {
  ml: 1,
  l: 1000,
  gal: 3785.41,
  qt: 946.353,
  pt: 473.176,
  cup: 236.588,
  tbsp: 14.7868,
  tsp: 4.92892,
}

// Time base: second
const timeToBase: Record<TimeUnit, number> = {
  ms: 0.001,
  s: 1,
  min: 60,
  hr: 3600,
  day: 86400,
  week: 604800,
}

const unitLabels: Record<Unit, string> = {
  mm: 'Millimeters',
  cm: 'Centimeters',
  m: 'Meters',
  km: 'Kilometers',
  in: 'Inches',
  ft: 'Feet',
  yd: 'Yards',
  mi: 'Miles',
  mg: 'Milligrams',
  g: 'Grams',
  kg: 'Kilograms',
  lb: 'Pounds',
  oz: 'Ounces',
  C: 'Celsius',
  F: 'Fahrenheit',
  K: 'Kelvin',
  ml: 'Milliliters',
  l: 'Liters',
  gal: 'Gallons',
  qt: 'Quarts',
  pt: 'Pints',
  cup: 'Cups',
  tbsp: 'Tablespoons',
  tsp: 'Teaspoons',
  ms: 'Milliseconds',
  s: 'Seconds',
  min: 'Minutes',
  hr: 'Hours',
  day: 'Days',
  week: 'Weeks',
}

const convertTemperature = (value: number, from: TemperatureUnit, to: TemperatureUnit): ConversionResult => {
  if (from === to) return { result: value, formula: `${from} = ${to}` }

  const conversions: Record<string, { calc: (v: number) => number; formula: string }> = {
    'C->F': { calc: (v) => v * 9 / 5 + 32, formula: '(C * 9/5) + 32 = F' },
    'C->K': { calc: (v) => v + 273.15, formula: 'C + 273.15 = K' },
    'F->C': { calc: (v) => (v - 32) * 5 / 9, formula: '(F - 32) * 5/9 = C' },
    'F->K': { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: '(F - 32) * 5/9 + 273.15 = K' },
    'K->C': { calc: (v) => v - 273.15, formula: 'K - 273.15 = C' },
    'K->F': { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: '(K - 273.15) * 9/5 + 32 = F' },
  }

  const key = `${from}->${to}`
  const conv = conversions[key]!
  return { result: conv.calc(value), formula: conv.formula }
}

const convertWithFactors = (
  value: number,
  from: Unit,
  to: Unit,
  factors: Record<string, number>,
): ConversionResult => {
  if (from === to) return { result: value, formula: `1 ${from} = 1 ${to}` }

  const fromFactor = factors[from]!
  const toFactor = factors[to]!
  const ratio = fromFactor / toFactor
  const result = value * ratio

  return {
    result,
    formula: `1 ${from} = ${ratio} ${to}`,
  }
}

const getCategoryForUnit = (unit: Unit): Category | null => {
  for (const [category, units] of Object.entries(categoryUnits)) {
    if ((units as readonly string[]).includes(unit)) {
      return category as Category
    }
  }
  return null
}

export const getCategories = (): Category[] => Object.keys(categoryUnits) as Category[]

export const getUnits = (category: Category): readonly Unit[] => categoryUnits[category]

export const getUnitLabel = (unit: Unit): string => unitLabels[unit]

export const convert = (value: number, from: Unit, to: Unit): ConversionResult => {
  const fromCategory = getCategoryForUnit(from)
  const toCategory = getCategoryForUnit(to)

  if (!fromCategory || !toCategory) {
    throw new Error(`Unknown unit: ${!fromCategory ? from : to}`)
  }

  if (fromCategory !== toCategory) {
    throw new Error(`Cannot convert between ${fromCategory} (${from}) and ${toCategory} (${to})`)
  }

  if (fromCategory === 'Temperature') {
    return convertTemperature(value, from as TemperatureUnit, to as TemperatureUnit)
  }

  const factorMap: Record<string, Record<string, number>> = {
    Length: lengthToBase,
    Weight: weightToBase,
    Volume: volumeToBase,
    Time: timeToBase,
  }

  return convertWithFactors(value, from, to, factorMap[fromCategory]!)
}

