export const renderConverter = (state: ConverterState) => {
  const categories = getCategories()
  const units = getUnits(state.activeCategory)
  const numValue = parseFloat(state.value)
  const hasValue = !isNaN(numValue) && state.value.trim() !== ''

  let conversionResult: ConversionResult | null = null
  if (hasValue && state.fromUnit !== state.toUnit) {
    try {
      conversionResult = convert(numValue, state.fromUnit, state.toUnit)
    } catch {
      conversionResult = null
    }
  } else if (hasValue && state.fromUnit === state.toUnit) {
    conversionResult = { result: numValue, formula: `1 ${state.fromUnit} = 1 ${state.toUnit}` }
  }

  return h('div', { style: styles.container },
    h('div', { style: styles.title }, 'Unit Converter'),

    // Category tabs
    h('div', { style: styles.tabs, role: 'tablist' },
      ...categories.map((cat) =>
