        title: 'Swap units',
      }, '\u21C4'),
      renderUnitSelect('toUnit', units, state.toUnit, 'To', 'toUnitChange'),
    ),

    // Result
    conversionResult
      ? h('div', { style: styles.resultBox, 'p-target': 'result' },
          h('div', { style: styles.resultValue },
            formatResult(conversionResult.result),
          ),
          h('div', { style: styles.resultLabel },
