import { convert, getCategories, getUnits } from './conversions.ts'
import { renderToHTML } from './render.ts'
import type { Category, Unit } from './conversions.ts'
import type { ConverterState } from './render.ts'

const defaultState: ConverterState = {
  activeCategory: 'Length',
  value: '1',
  fromUnit: 'm',
  toUnit: 'ft',
}

const saveHistory = async (entry: {
  from: string
  to: string
  value: number
  result: number
  timestamp: string
}) => {
  const historyPath = new URL('../data/history.json', import.meta.url).pathname
  const file = Bun.file(historyPath)
  const existing: unknown[] = await file.json().catch(() => [])
  existing.push(entry)
  // Keep last 100 entries
  const trimmed = existing.slice(-100)
  await Bun.write(historyPath, JSON.stringify(trimmed, null, 2))
}

export const handleConversion = async (
  value: number,
  fromUnit: Unit,
  toUnit: Unit,
): Promise<{ result: number; formula: string; html: string }> => {
  const conversion = convert(value, fromUnit, toUnit)

  await saveHistory({
    from: fromUnit,
    to: toUnit,
    value,
    result: conversion.result,
    timestamp: new Date().toISOString(),
  })

  const state: ConverterState = {
    activeCategory: getCategories().find((cat) =>
      (getUnits(cat) as readonly string[]).includes(fromUnit)
    )!,
    value: String(value),
    fromUnit,
    toUnit,
  }

  const html = renderToHTML(state)

  return {
    result: conversion.result,
    formula: conversion.formula,
    html,
  }
}

export const getDefaultHTML = (): string => renderToHTML(defaultState)

