    temp_max: number
    pressure: number
    humidity: number
  }
  weather: WeatherCondition[]
  wind: { speed: number; deg: number; gust?: number }
  dt_txt: string
}

export type ForecastResponse = {
  list: ForecastEntry[]
  city: {
    name: string
    country: string
    coord: { lat: number; lon: number }
  }
}

export type DayForecast = {
  date: string
  dayName: string
  tempMin: number
  tempMax: number
  condition: WeatherCondition
}

export type WeatherDashboardData = {
  city: string
  current: CurrentWeather
  forecast: ForecastResponse
  dailyForecasts: DayForecast[]
}

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9) / 5 + 32)

export const formatTemp = (celsius: number): string => {
  const f = celsiusToFahrenheit(celsius)
  return `${Math.round(celsius)}°C / ${f}°F`
}

export const formatDate = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
  })
}

export const getDayName = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleDateString('en-US', { weekday: 'long' })
}

export const weatherIconUrl = (icon: string): string =>
  `https://openweathermap.org/img/wn/${icon}@2x.png`

export const windDirection = (deg: number): string => {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  const index = Math.round(deg / 45) % 8
  return directions[index]
}

import type { CurrentWeather, ForecastResponse, DayForecast, WeatherDashboardData } from './types'
import { getDayName, formatDate } from './utils'

const NOW = Math.floor(Date.now() / 1000)
const DAY = 86400

const cityData: Record<string, { lat: number; lon: number; country: string }> = {
  'new york': { lat: 40.71, lon: -74.01, country: 'US' },
  london: { lat: 51.51, lon: -0.13, country: 'GB' },
  tokyo: { lat: 35.68, lon: 139.69, country: 'JP' },
  paris: { lat: 48.86, lon: 2.35, country: 'FR' },
  sydney: { lat: -33.87, lon: 151.21, country: 'AU' },
}

const defaultCity = { lat: 40.71, lon: -74.01, country: 'US' }

const generateCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const coords = cityData[key] ?? defaultCity
  return {
    coord: { lon: coords.lon, lat: coords.lat },
    weather: [
      {
        id: 802,
        main: 'Clouds',
        description: 'scattered clouds',
        icon: '03d',
      },
    ],
    main: {
      temp: 18.5,
      feels_like: 17.2,
      temp_min: 15.0,
      temp_max: 21.0,
      pressure: 1013,
      humidity: 62,
    },
    visibility: 10000,
    wind: { speed: 4.1, deg: 220, gust: 7.2 },
    clouds: { all: 40 },
    dt: NOW,
    sys: {
      country: coords.country,
      sunrise: NOW - 21600,
      sunset: NOW + 21600,
    },
    name: city.charAt(0).toUpperCase() + city.slice(1),
  }
}

const forecastTemps = [
  { min: 14, max: 20, icon: '03d', desc: 'scattered clouds', main: 'Clouds' },
  { min: 16, max: 23, icon: '01d', desc: 'clear sky', main: 'Clear' },
  { min: 13, max: 19, icon: '10d', desc: 'light rain', main: 'Rain' },
  { min: 11, max: 17, icon: '09d', desc: 'shower rain', main: 'Drizzle' },
  { min: 15, max: 22, icon: '02d', desc: 'few clouds', main: 'Clouds' },
]

const generateForecast = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const coords = cityData[key] ?? defaultCity

  const list = forecastTemps.flatMap((day, dayIndex) => {
    const baseTime = NOW + (dayIndex + 1) * DAY
    return [0, 3, 6, 9, 12, 15, 18, 21].map((hourOffset) => {
      const dt = baseTime + hourOffset * 3600
      const hourTemp = day.min + ((day.max - day.min) * Math.sin((hourOffset / 24) * Math.PI))
      return {
        dt,
        main: {
          temp: Math.round(hourTemp * 10) / 10,
          feels_like: Math.round((hourTemp - 1.3) * 10) / 10,
          temp_min: day.min,
          temp_max: day.max,
          pressure: 1013 + dayIndex,
          humidity: 55 + dayIndex * 3,
        },
        weather: [
          {
            id: 800 + dayIndex,
            main: day.main,
            description: day.desc,
            icon: day.icon,
          },
        ],
        wind: { speed: 3.5 + dayIndex * 0.5, deg: 200 + dayIndex * 15 },
        dt_txt: new Date(dt * 1000).toISOString().replace('T', ' ').slice(0, 19),
      }
    })
  })

  return {
    list,
    city: {
      name: city.charAt(0).toUpperCase() + city.slice(1),
      country: coords.country,
      coord: { lat: coords.lat, lon: coords.lon },
    },
  }
}

const extractDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const days = new Map<string, { temps: number[]; condition: typeof forecast.list[0]['weather'][0]; dt: number }>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0]
    const existing = days.get(dateKey)
    if (existing) {
      existing.temps.push(entry.main.temp)
    } else {
      days.set(dateKey, {
        temps: [entry.main.temp],
        condition: entry.weather[0],
        dt: entry.dt,
      })
    }
  }

  const result: DayForecast[] = []
  for (const [dateKey, data] of days) {
    result.push({
      date: dateKey,
      dayName: getDayName(data.dt),
      tempMin: Math.min(...data.temps),
      tempMax: Math.max(...data.temps),
      condition: data.condition,
    })
  }
  return result.slice(0, 5)
}

export const getWeatherData = (city: string): WeatherDashboardData => {
  const current = generateCurrentWeather(city)
  const forecast = generateForecast(city)
  const dailyForecasts = extractDailyForecasts(forecast)
  return {
    city: current.name,
    current,
    forecast,
    dailyForecasts,
  }
}

import { h } from 'plaited'
import type { DayForecast } from './types'
import { celsiusToFahrenheit } from './utils'

const CHART_WIDTH = 600
const CHART_HEIGHT = 200
const PADDING = { top: 20, right: 40, bottom: 40, left: 50 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

const scaleY = (value: number, min: number, max: number): number => {
  const range = max - min || 1
  return PADDING.top + plotHeight - ((value - min) / range) * plotHeight
}

export const renderTempChart = (forecasts: DayForecast[]) => {
  const allTemps = forecasts.flatMap((f) => [f.tempMin, f.tempMax])
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2

  const stepX = plotWidth / Math.max(forecasts.length - 1, 1)

  const highPoints = forecasts.map((f, i) => ({
    x: PADDING.left + i * stepX,
    y: scaleY(f.tempMax, minTemp, maxTemp),
    temp: f.tempMax,
  }))

  const lowPoints = forecasts.map((f, i) => ({
    x: PADDING.left + i * stepX,
    y: scaleY(f.tempMin, minTemp, maxTemp),
    temp: f.tempMin,
  }))

  const highLinePath = highPoints.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')
  const lowLinePath = lowPoints.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')

  const yTicks = 5
  const yStep = (maxTemp - minTemp) / yTicks

  const gridLines = Array.from({ length: yTicks + 1 }, (_, i) => {
    const temp = minTemp + i * yStep
    const y = scaleY(temp, minTemp, maxTemp)
    return { y, label: `${Math.round(temp)}°` }
  })

  return h(
    'div',
    { style: { marginTop: '24px' } },
    h('h3', { style: { margin: '0 0 12px 0', fontSize: '16px', color: '#334155' } }, 'Temperature Trend'),
    h(
      'svg',
      {
        width: String(CHART_WIDTH),
        height: String(CHART_HEIGHT),
        viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
        style: { background: '#f8fafc', borderRadius: '8px', border: '1px solid #e2e8f0' },
      },
      // Grid lines and y-axis labels
      ...gridLines.map((tick) =>
        h(
          'g',
          {},
          h('line', {
            x1: String(PADDING.left),
            y1: String(tick.y),
            x2: String(CHART_WIDTH - PADDING.right),
            y2: String(tick.y),
            stroke: '#e2e8f0',
            'stroke-width': '1',
          }),
          h(
            'text',
            {
              x: String(PADDING.left - 8),
              y: String(tick.y + 4),
              'text-anchor': 'end',
              fill: '#94a3b8',
              'font-size': '11',
            },
            tick.label,
          ),
        ),
      ),
      // X-axis labels
      ...forecasts.map((f, i) =>
        h(
          'text',
          {
            x: String(PADDING.left + i * stepX),
            y: String(CHART_HEIGHT - 8),
            'text-anchor': 'middle',
            fill: '#64748b',
            'font-size': '11',
          },
          f.dayName.slice(0, 3),
        ),
      ),
      // High temp line
      h('path', {
        d: highLinePath,
        fill: 'none',
        stroke: '#ef4444',
        'stroke-width': '2.5',
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
      }),
      // Low temp line
      h('path', {
        d: lowLinePath,
        fill: 'none',
        stroke: '#3b82f6',
        'stroke-width': '2.5',
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
      }),
      // High temp dots and labels
      ...highPoints.map((p) =>
        h(
          'g',
          {},
          h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#ef4444' }),
          h(
            'text',
            {
              x: String(p.x),
              y: String(p.y - 10),
              'text-anchor': 'middle',
              fill: '#ef4444',
              'font-size': '10',
              'font-weight': '600',
            },
            `${Math.round(p.temp)}°`,
          ),
        ),
      ),
      // Low temp dots and labels
      ...lowPoints.map((p) =>
        h(
          'g',
          {},
          h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#3b82f6' }),
          h(
            'text',
            {
              x: String(p.x),
              y: String(p.y + 16),
              'text-anchor': 'middle',
              fill: '#3b82f6',
              'font-size': '10',
              'font-weight': '600',
            },
            `${Math.round(p.temp)}°`,
          ),
        ),
      ),
      // Legend
      h('circle', { cx: String(CHART_WIDTH - PADDING.right - 80), cy: '12', r: '4', fill: '#ef4444' }),
      h(
        'text',
        {
          x: String(CHART_WIDTH - PADDING.right - 72),
          y: '16',
          fill: '#64748b',
          'font-size': '11',
        },
        'High',
      ),
      h('circle', { cx: String(CHART_WIDTH - PADDING.right - 30), cy: '12', r: '4', fill: '#3b82f6' }),
      h(
        'text',
        {
          x: String(CHART_WIDTH - PADDING.right - 22),
          y: '16',
          fill: '#64748b',
          'font-size': '11',
        },
        'Low',
      ),
    ),
  )
}

