import { createSSR } from 'plaited'
import { getWeatherData } from './data'
import { renderDashboard } from './ui'
import type { WeatherDashboardData } from './types'

export type { WeatherDashboardData } from './types'
export { getWeatherData } from './data'
export { renderDashboard } from './ui'
export { celsiusToFahrenheit, formatTemp } from './utils'

const CACHE_PATH = './data/weather-cache.json'

const loadCache = async (): Promise<Record<string, WeatherDashboardData>> => {
  const file = Bun.file(CACHE_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return {}
}

const saveCache = async (cache: Record<string, WeatherDashboardData>): Promise<void> => {
  await Bun.write(CACHE_PATH, JSON.stringify(cache, null, 2))
}

export const getWeatherDashboard = async (city: string): Promise<string> => {
  const normalizedCity = city.trim().toLowerCase()
  if (!normalizedCity) {
    throw new Error('City name is required')
  }

  const cache = await loadCache()
  let data: WeatherDashboardData

  const cached = cache[normalizedCity]
  const fiveMinutes = 5 * 60
  const now = Math.floor(Date.now() / 1000)

  if (cached && now - cached.current.dt < fiveMinutes) {
    data = cached
  } else {
    data = getWeatherData(normalizedCity)
    cache[normalizedCity] = data
    await saveCache(cache)
  }

  const template = renderDashboard(data)
  const { render } = createSSR()
  return render(template)
}

export const serveDashboard = () => {
  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/weather') {
        const city = url.searchParams.get('city') ?? 'New York'
        const html = await getWeatherDashboard(city)

        const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f1f5f9; min-height: 100vh; padding: 32px 16px; }
  </style>
</head>
<body>${html}</body>
</html>`

        return new Response(page, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log('Weather Dashboard running at http://localhost:3000')
  console.log('Try: http://localhost:3000/weather?city=London')
}

// Run server if executed directly
if (import.meta.main) {
  serveDashboard()
}

