export type WeatherDashboardData = {
  city: string
  country: string
  current: CurrentWeather
  forecast: ForecastResponse
  daily: DailyForecast[]
}

import type { CurrentWeather, ForecastResponse, ForecastEntry, DailyForecast, WeatherDashboardData } from './types'

const WEATHER_ICONS: Record<string, string> = {
  '01d': '☀️', '01n': '🌙',
  '02d': '⛅', '02n': '☁️',
  '03d': '☁️', '03n': '☁️',
  '04d': '☁️', '04n': '☁️',
  '09d': '🌧️', '09n': '🌧️',
  '10d': '🌦️', '10n': '🌧️',
  '11d': '⛈️', '11n': '⛈️',
  '13d': '❄️', '13n': '❄️',
  '50d': '🌫️', '50n': '🌫️',
}

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const celsiusToFahrenheit = (c: number): number => Math.round((c * 9) / 5 + 32)

const CITY_DATA: Record<string, { lat: number; lon: number; country: string; baseTemp: number; humidity: number; windSpeed: number; condition: string; icon: string }> = {
  london: { lat: 51.51, lon: -0.13, country: 'GB', baseTemp: 12, humidity: 72, windSpeed: 5.2, condition: 'overcast clouds', icon: '04d' },
  'new york': { lat: 40.71, lon: -74.01, country: 'US', baseTemp: 18, humidity: 58, windSpeed: 4.1, condition: 'scattered clouds', icon: '03d' },
  tokyo: { lat: 35.68, lon: 139.69, country: 'JP', baseTemp: 22, humidity: 65, windSpeed: 3.6, condition: 'clear sky', icon: '01d' },
  paris: { lat: 48.85, lon: 2.35, country: 'FR', baseTemp: 15, humidity: 68, windSpeed: 4.5, condition: 'few clouds', icon: '02d' },
  sydney: { lat: -33.87, lon: 151.21, country: 'AU', baseTemp: 24, humidity: 55, windSpeed: 6.1, condition: 'light rain', icon: '10d' },
  berlin: { lat: 52.52, lon: 13.41, country: 'DE', baseTemp: 10, humidity: 74, windSpeed: 4.8, condition: 'broken clouds', icon: '04d' },
  dubai: { lat: 25.28, lon: 55.30, country: 'AE', baseTemp: 35, humidity: 42, windSpeed: 3.2, condition: 'clear sky', icon: '01d' },
  mumbai: { lat: 19.08, lon: 72.88, country: 'IN', baseTemp: 30, humidity: 78, windSpeed: 4.0, condition: 'haze', icon: '50d' },
}

const generateCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const data = CITY_DATA[key] ?? { lat: 0, lon: 0, country: 'XX', baseTemp: 20, humidity: 60, windSpeed: 3.5, condition: 'few clouds', icon: '02d' }
  const now = Math.floor(Date.now() / 1000)

  return {
    coord: { lon: data.lon, lat: data.lat },
    weather: [{
      id: 802,
      main: data.condition.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
      description: data.condition,
      icon: data.icon,
    }],
    main: {
      temp: data.baseTemp,
      feels_like: data.baseTemp - 2,
      temp_min: data.baseTemp - 3,
      temp_max: data.baseTemp + 3,
      pressure: 1013,
      humidity: data.humidity,
    },
    visibility: 10000,
    wind: { speed: data.windSpeed, deg: 220, gust: data.windSpeed + 2 },
    clouds: { all: 40 },
    dt: now,
    sys: { country: data.country, sunrise: now - 21600, sunset: now + 21600 },
    timezone: 0,
    name: city.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
  }
}

const generateForecast = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const data = CITY_DATA[key] ?? { lat: 0, lon: 0, country: 'XX', baseTemp: 20, humidity: 60, windSpeed: 3.5, condition: 'few clouds', icon: '02d' }
  const now = new Date()
  now.setHours(12, 0, 0, 0)

  const conditions: Array<{ description: string; icon: string }> = [
    { description: 'few clouds', icon: '02d' },
    { description: 'scattered clouds', icon: '03d' },
    { description: 'light rain', icon: '10d' },
    { description: 'clear sky', icon: '01d' },
    { description: 'overcast clouds', icon: '04d' },
  ]

  const list: ForecastEntry[] = []
  for (let day = 1; day <= 5; day++) {
    const hours = [6, 9, 12, 15, 18, 21]
    for (const hour of hours) {
      const entryDate = new Date(now)
      entryDate.setDate(now.getDate() + day)
      entryDate.setHours(hour, 0, 0, 0)
      const variation = Math.sin(hour / 24 * Math.PI * 2) * 4
      const dayVariation = (day - 3) * 1.5
      const temp = Math.round((data.baseTemp + variation + dayVariation) * 10) / 10
      const cond = conditions[(day - 1) % conditions.length]

      list.push({
        dt: Math.floor(entryDate.getTime() / 1000),
        main: {
          temp,
          feels_like: temp - 2,
          temp_min: temp - 1,
          temp_max: temp + 1,
          pressure: 1013 + day,
          humidity: data.humidity + Math.round(variation),
        },
        weather: [{
          id: 802,
          main: cond.description.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
          description: cond.description,
          icon: cond.icon,
        }],
        clouds: { all: 30 + day * 10 },
        wind: { speed: data.windSpeed + day * 0.3, deg: 200 + day * 15 },
        visibility: 10000,
        pop: Math.min(0.9, day * 0.15),
        dt_txt: entryDate.toISOString().replace('T', ' ').slice(0, 19),
      })
    }
  }

  return {
    cnt: list.length,
    list,
    city: {
      name: city.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
      country: data.country,
      coord: { lat: data.lat, lon: data.lon },
      timezone: 0,
    },
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dayMap = new Map<string, ForecastEntry[]>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.slice(0, 10)
    const existing = dayMap.get(dateKey) ?? []
    existing.push(entry)
    dayMap.set(dateKey, existing)
  }

  const dailies: DailyForecast[] = []
  for (const [dateKey, entries] of dayMap) {
    const temps = entries.map(e => e.main.temp)
    const highC = Math.round(Math.max(...temps))
    const lowC = Math.round(Math.min(...temps))
    const midday = entries.find(e => e.dt_txt.includes('12:00')) ?? entries[0]
    const d = new Date(dateKey)

    dailies.push({
      date: dateKey,
      dayName: DAY_NAMES[d.getDay()],
      tempHighC: highC,
      tempLowC: lowC,
      tempHighF: celsiusToFahrenheit(highC),
      tempLowF: celsiusToFahrenheit(lowC),
      description: midday.weather[0].description,
      icon: midday.weather[0].icon,
      humidity: Math.round(entries.reduce((s, e) => s + e.main.humidity, 0) / entries.length),
      windSpeed: Math.round(entries.reduce((s, e) => s + e.wind.speed, 0) / entries.length * 10) / 10,
    })
  }

  return dailies
}

export const getWeatherIcon = (iconCode: string): string => WEATHER_ICONS[iconCode] ?? '🌤️'

export const getWeatherData = async (city: string): Promise<WeatherDashboardData> => {
  const current = generateCurrentWeather(city)
  const forecast = generateForecast(city)
  const daily = aggregateDailyForecasts(forecast)

  const result: WeatherDashboardData = {
    city: current.name,
    country: current.sys.country,
    current,
    forecast,
    daily,
  }

  await Bun.write(
    Bun.file('./data/weather-cache.json'),
    JSON.stringify({ lastUpdated: new Date().toISOString(), city: current.name, current, forecast }, null, 2),
  )

  return result
}

