const styleToString = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/([A-Z])/g, '-$1').toLowerCase()}: ${typeof v === 'number' ? `${v}px` : v}`)
    .join('; ')

const renderTemperatureChart = (daily: DailyForecast[]) => {
  const width = 700
  const height = 180
  const padX = 60
  const padY = 30
  const chartW = width - padX * 2
  const chartH = height - padY * 2

  const allTemps = daily.flatMap(d => [d.tempHighC, d.tempLowC])
  const minT = Math.min(...allTemps) - 2
  const maxT = Math.max(...allTemps) + 2
  const rangeT = maxT - minT || 1

  const xStep = daily.length > 1 ? chartW / (daily.length - 1) : 0

  const highPoints = daily.map((d, i) => ({
    x: padX + i * xStep,
    y: padY + chartH - ((d.tempHighC - minT) / rangeT) * chartH,
  }))

  const lowPoints = daily.map((d, i) => ({
    x: padX + i * xStep,
    y: padY + chartH - ((d.tempLowC - minT) / rangeT) * chartH,
  }))

  const highPath = highPoints.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')
  const lowPath = lowPoints.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')

  const yTicks = 5
  const gridLines = Array.from({ length: yTicks + 1 }, (_, i) => {
    const temp = minT + (rangeT / yTicks) * i
    const y = padY + chartH - ((temp - minT) / rangeT) * chartH
    return { y, label: `${Math.round(temp)}°` }
  })

  return h('svg', { viewBox: `0 0 ${width} ${height}`, style: styleToString(styles.chartSvg) },
    // Grid lines
    ...gridLines.map(g =>
      h(Fragment, {},
        h('line', { x1: String(padX), y1: String(g.y), x2: String(width - padX), y2: String(g.y), stroke: '#e2e8f0', 'stroke-width': '1' }),
        h('text', { x: String(padX - 8), y: String(g.y + 4), 'text-anchor': 'end', fill: '#a0aec0', 'font-size': '11' }, g.label),
      ),
    ),
    // High temperature line
    h('path', { d: highPath, fill: 'none', stroke: '#e53e3e', 'stroke-width': '2.5', 'stroke-linecap': 'round', 'stroke-linejoin': 'round' }),
    // Low temperature line
    h('path', { d: lowPath, fill: 'none', stroke: '#3182ce', 'stroke-width': '2.5', 'stroke-linecap': 'round', 'stroke-linejoin': 'round' }),
    // High temperature dots and labels
    ...highPoints.map((p, i) =>
      h(Fragment, {},
        h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#e53e3e' }),
        h('text', { x: String(p.x), y: String(p.y - 10), 'text-anchor': 'middle', fill: '#e53e3e', 'font-size': '11', 'font-weight': '600' }, `${daily[i].tempHighC}°`),
      ),
    ),
    // Low temperature dots and labels
    ...lowPoints.map((p, i) =>
      h(Fragment, {},
        h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#3182ce' }),
        h('text', { x: String(p.x), y: String(p.y + 16), 'text-anchor': 'middle', fill: '#3182ce', 'font-size': '11', 'font-weight': '600' }, `${daily[i].tempLowC}°`),
      ),
    ),
    // Day labels on x-axis
    ...daily.map((d, i) =>
      h('text', { x: String(padX + i * xStep), y: String(height - 5), 'text-anchor': 'middle', fill: '#4a5568', 'font-size': '12', 'font-weight': '500' }, d.dayName),
    ),
    // Legend
    h('circle', { cx: String(width - 140), cy: '12', r: '4', fill: '#e53e3e' }),
    h('text', { x: String(width - 132), y: '16', fill: '#e53e3e', 'font-size': '11' }, 'High'),
    h('circle', { cx: String(width - 80), cy: '12', r: '4', fill: '#3182ce' }),
    h('text', { x: String(width - 72), y: '16', fill: '#3182ce', 'font-size': '11' }, 'Low'),
  )
}

