import { createSSR } from 'plaited'
import { getWeatherData } from './weather-data'
import { renderDashboard, renderEmptyState } from './weather-ui'
import type { WeatherDashboardData } from './types'

export type { WeatherDashboardData } from './types'
export { getWeatherData } from './weather-data'
export { renderDashboard, renderEmptyState } from './weather-ui'

const defaultCity = 'London'

const renderPage = (content: ReturnType<typeof renderDashboard>) => {
  const ssr = createSSR()
  return ssr(content)
}

export const serve = async (city?: string) => {
  const targetCity = city ?? defaultCity
  const data = await getWeatherData(targetCity)
  const template = renderDashboard(data)
  return renderPage(template)
}

export const serveEmpty = () => {
  const template = renderEmptyState()
  const ssr = createSSR()
  return ssr(template)
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const city = url.searchParams.get('city')

  if (req.method === 'POST') {
    const formData = await req.formData()
    const cityInput = formData.get('city')
    if (typeof cityInput === 'string' && cityInput.trim()) {
      const html = await serve(cityInput.trim())
      return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
    }
  }

  if (city) {
    const html = await serve(city)
    return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
  }

  if (url.pathname === '/api/weather') {
    const apiCity = url.searchParams.get('q') ?? defaultCity
    const data = await getWeatherData(apiCity)
    return Response.json(data)
  }

  const html = await serve()
  return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
}

export default {
  port: 3000,
  fetch: handleRequest,
}

