export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9) / 5 + 32)

export const formatTemp = (celsius: number): string =>
  `${Math.round(celsius)}°C / ${celsiusToFahrenheit(celsius)}°F`

export const formatTempShort = (celsius: number): string =>
  `${Math.round(celsius)}°`

export const windDirection = (deg: number): string => {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  const index = Math.round(deg / 45) % 8
  return directions[index]
}

export const iconToEmoji = (icon: string): string => {
  const map: Record<string, string> = {
    '01d': '☀️', '01n': '🌙',
    '02d': '⛅', '02n': '☁️',
    '03d': '☁️', '03n': '☁️',
    '04d': '☁️', '04n': '☁️',
    '09d': '🌧️', '09n': '🌧️',
    '10d': '🌦️', '10n': '🌧️',
    '11d': '⛈️', '11n': '⛈️',
    '13d': '❄️', '13n': '❄️',
    '50d': '🌫️', '50n': '🌫️',
  }
  return map[icon] ?? '🌡️'
}

export const aggregateDailyForecasts = (entries: ForecastEntry[]): DayForecast[] => {
  const grouped = new Map<string, ForecastEntry[]>()

  for (const entry of entries) {
    const date = entry.dt_txt.split(' ')[0]
    const existing = grouped.get(date) ?? []
    existing.push(entry)
    grouped.set(date, existing)
  }

  const days: DayForecast[] = []
  for (const [date, dayEntries] of grouped) {
    if (days.length >= 5) break

    const temps = dayEntries.map((e) => e.main.temp)
    const midday =
      dayEntries.find((e) => e.dt_txt.includes('12:00:00')) ?? dayEntries[0]
    const d = new Date(date)
    const dayName = d.toLocaleDateString('en-US', { weekday: 'short' })

    days.push({
      date,
      dayName,
      tempMin: Math.min(...temps),
      tempMax: Math.max(...temps),
      condition: midday.weather[0],
    })
  }

  return days
}

import { h } from 'plaited'
import type { DayForecast } from './types.ts'
import { celsiusToFahrenheit } from './utils.ts'

const CHART_WIDTH = 500
const CHART_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

export const renderTempChart = (days: DayForecast[]) => {
  if (days.length === 0) return h('div', {}, 'No forecast data available')

  const allTemps = days.flatMap((d) => [d.tempMax, d.tempMin])
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2
  const tempRange = maxTemp - minTemp || 1

  const xStep = days.length > 1 ? plotWidth / (days.length - 1) : 0

  const toY = (temp: number) =>
    PADDING.top + plotHeight - ((temp - minTemp) / tempRange) * plotHeight

  const toX = (i: number) => PADDING.left + i * xStep

  const highPoints = days.map((d, i) => `${toX(i)},${toY(d.tempMax)}`)
  const lowPoints = days.map((d, i) => `${toX(i)},${toY(d.tempMin)}`)

  const highLine = highPoints.join(' ')
  const lowLine = lowPoints.join(' ')

  const gridLines = 5
  const gridElements = Array.from({ length: gridLines }, (_, i) => {
    const temp = minTemp + (tempRange * i) / (gridLines - 1)
    const y = toY(temp)
    return h('g', {},
      h('line', {
        x1: String(PADDING.left),
        y1: String(y),
        x2: String(CHART_WIDTH - PADDING.right),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(PADDING.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        fill: '#666',
      }, `${Math.round(temp)}°`)
    )
  })

  const dayLabels = days.map((d, i) =>
    h('text', {
      x: String(toX(i)),
      y: String(CHART_HEIGHT - 8),
      'text-anchor': 'middle',
      'font-size': '11',
      fill: '#666',
    }, d.dayName)
  )

  const highDots = days.map((d, i) =>
    h('g', {},
      h('circle', {
        cx: String(toX(i)),
        cy: String(toY(d.tempMax)),
        r: '4',
        fill: '#e74c3c',
      }),
      h('text', {
        x: String(toX(i)),
        y: String(toY(d.tempMax) - 10),
        'text-anchor': 'middle',
        'font-size': '10',
        fill: '#e74c3c',
        'font-weight': 'bold',
      }, `${Math.round(d.tempMax)}°`)
    )
  )

  const lowDots = days.map((d, i) =>
    h('g', {},
      h('circle', {
        cx: String(toX(i)),
        cy: String(toY(d.tempMin)),
        r: '4',
        fill: '#3498db',
      }),
      h('text', {
        x: String(toX(i)),
        y: String(toY(d.tempMin) + 18),
        'text-anchor': 'middle',
        'font-size': '10',
        fill: '#3498db',
        'font-weight': 'bold',
      }, `${Math.round(d.tempMin)}°`)
    )
  )

  return h('div', {
    style: 'margin-top:16px',
  },
    h('h3', {
      style: 'margin:0 0 8px 0;font-size:16px;color:#333',
    }, 'Temperature Trend (°C)'),
    h('svg', {
      width: String(CHART_WIDTH),
      height: String(CHART_HEIGHT),
      viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
      style: 'background:#fafafa;border-radius:8px;border:1px solid #e0e0e0',
    },
      ...gridElements,
      ...dayLabels,
      h('polyline', {
        points: highLine,
        fill: 'none',
        stroke: '#e74c3c',
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
      }),
      h('polyline', {
        points: lowLine,
        fill: 'none',
        stroke: '#3498db',
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
      }),
      ...highDots,
      ...lowDots,
      // Legend
      h('circle', { cx: String(PADDING.left + 10), cy: '14', r: '4', fill: '#e74c3c' }),
      h('text', { x: String(PADDING.left + 20), y: '18', 'font-size': '11', fill: '#666' }, 'High'),
      h('circle', { cx: String(PADDING.left + 60), cy: '14', r: '4', fill: '#3498db' }),
      h('text', { x: String(PADDING.left + 70), y: '18', 'font-size': '11', fill: '#666' }, 'Low'),
    )
  )
}

