const now = Math.floor(Date.now() / 1000)
const DAY = 86400

const makeForecastEntries = (baseTemp: number) => {
  const entries = []
  for (let day = 0; day < 5; day++) {
    for (const hour of [0, 3, 6, 9, 12, 15, 18, 21]) {
      const dt = now + day * DAY + hour * 3600
      const date = new Date(dt * 1000)
      const dtTxt = date.toISOString().replace('T', ' ').slice(0, 19)
      const variation = Math.sin((hour / 24) * Math.PI * 2) * 4
      const dayShift = (day - 2) * 1.5
      const temp = baseTemp + variation + dayShift

      entries.push({
        dt,
        main: {
          temp: Math.round(temp * 10) / 10,
          feels_like: Math.round((temp - 1.5) * 10) / 10,
          temp_min: Math.round((temp - 2) * 10) / 10,
          temp_max: Math.round((temp + 2) * 10) / 10,
          pressure: 1013 + Math.round(Math.random() * 10 - 5),
          humidity: 55 + Math.round(Math.random() * 30),
        },
        weather: [
          {
            id: day < 2 ? 800 : day < 4 ? 802 : 500,
            main: day < 2 ? 'Clear' : day < 4 ? 'Clouds' : 'Rain',
            description:
              day < 2 ? 'clear sky' : day < 4 ? 'scattered clouds' : 'light rain',
            icon: day < 2 ? '01d' : day < 4 ? '03d' : '10d',
          },
        ],
        wind: {
          speed: 3 + Math.round(Math.random() * 5 * 10) / 10,
          deg: Math.round(Math.random() * 360),
        },
        dt_txt: dtTxt,
      })
    }
  }
  return entries
}

