import { getWeatherData, getAvailableCities } from './data.ts'
import { renderDashboard } from './render.ts'
import type { WeatherDashboardData } from './types.ts'

export type WeatherDashboardRequest = {
  city?: string
}

export type WeatherDashboardResponse = {
  html: string
  data: WeatherDashboardData | null
  city: string
  availableCities: string[]
}

export const handleWeatherDashboard = (
  request: WeatherDashboardRequest = {},
): WeatherDashboardResponse => {
  const city = request.city ?? 'London'
  const weatherData = getWeatherData(city)
  const availableCities = getAvailableCities()

  const html = renderDashboard(weatherData, city, availableCities)

  return {
    html,
    data: weatherData,
    city,
    availableCities,
  }
}

const serve = () => {
  const server = Bun.serve({
    port: 3000,
    fetch: (req) => {
      const url = new URL(req.url)
      const city = url.searchParams.get('city') ?? 'London'

      const { html } = handleWeatherDashboard({ city })

      const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>
    * { box-sizing: border-box; }
    body { margin: 0; background: #f0f2f5; min-height: 100vh; }
  </style>
</head>
<body>
  ${html}
  <script>
    document.querySelector('form')?.addEventListener('submit', (e) => {
      e.preventDefault();
      const city = e.target.querySelector('input[name="city"]').value;
      if (city) window.location.search = '?city=' + encodeURIComponent(city);
    });
  </script>
</body>
</html>`

      return new Response(page, {
        headers: { 'Content-Type': 'text/html' },
      })
    },
  })

  console.log(`Weather Dashboard running at http://localhost:${server.port}`)
}

// Run server when executed directly
if (import.meta.main) {
  serve()
}

