import type { MapMarker, MapCircle, MarkerCategory, MarkerInput, CircleInput, CategoryInput } from './types'

const DATA_DIR = new URL('./data/', import.meta.url).pathname

const readJson = async <T>(filename: string): Promise<T[]> => {
  const file = Bun.file(`${DATA_DIR}${filename}`)
  const text = await file.text()
  return JSON.parse(text) as T[]
}

const writeJson = async <T>(filename: string, data: T[]): Promise<void> => {
  await Bun.write(`${DATA_DIR}${filename}`, JSON.stringify(data, null, 2))
}

const generateId = (): string => crypto.randomUUID().slice(0, 8)

// --- Markers ---

export const getMarkers = async (categoryId?: string): Promise<MapMarker[]> => {
  const markers = await readJson<MapMarker>('markers.json')
  if (categoryId) {
    return markers.filter((m) => m.categoryId === categoryId)
  }
  return markers
}

export const addMarker = async (input: MarkerInput): Promise<MapMarker> => {
  const markers = await readJson<MapMarker>('markers.json')
  const marker: MapMarker = { id: generateId(), ...input }
  markers.push(marker)
  await writeJson('markers.json', markers)
  return marker
}

export const deleteMarker = async (id: string): Promise<boolean> => {
  const markers = await readJson<MapMarker>('markers.json')
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await writeJson('markers.json', filtered)
  return true
}

// --- Circles ---

export const getCircles = async (): Promise<MapCircle[]> => {
  return readJson<MapCircle>('circles.json')
}

export const addCircle = async (input: CircleInput): Promise<MapCircle> => {
  const circles = await readJson<MapCircle>('circles.json')
  const circle: MapCircle = { id: generateId(), ...input }
  circles.push(circle)
  await writeJson('circles.json', circles)
  return circle
}

export const deleteCircle = async (id: string): Promise<boolean> => {
  const circles = await readJson<MapCircle>('circles.json')
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await writeJson('circles.json', filtered)
  return true
}

// --- Categories ---

export const getCategories = async (): Promise<MarkerCategory[]> => {
  return readJson<MarkerCategory>('categories.json')
}

export const addCategory = async (input: CategoryInput): Promise<MarkerCategory> => {
  const categories = await readJson<MarkerCategory>('categories.json')
  const category: MarkerCategory = { id: generateId(), ...input }
  categories.push(category)
  await writeJson('categories.json', categories)
  return category
}

export const deleteCategory = async (id: string): Promise<boolean> => {
  const categories = await readJson<MarkerCategory>('categories.json')
  const filtered = categories.filter((c) => c.id !== id)
  if (filtered.length === categories.length) return false
  await writeJson('categories.json', filtered)
  return true
}

