const toStyleStr = (obj: Record<string, string>): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

export const renderPage = (
  markers: MapMarker[],
  circles: MapCircle[],
  categories: MarkerCategory[],
): string => {
  const categoryMap = new Map(categories.map((c) => [c.id, c]))

  const markersByCategory = new Map<string, MapMarker[]>()
  for (const m of markers) {
    const list = markersByCategory.get(m.categoryId) ?? []
    list.push(m)
    markersByCategory.set(m.categoryId, list)
  }

  const categoryOptions = categories.map(
    (c) => h('option', { value: c.id }, c.name),
  )

  const sidebarMarkerList = categories
    .filter((c) => markersByCategory.has(c.id))
    .map((c) => {
      const items = markersByCategory.get(c.id) ?? []
      return h('div', { style: toStyleStr(styles.categoryGroup) },
        h('div', { style: toStyleStr(styles.categoryLabel) },
          h('span', { style: toStyleStr(styles.colorDot(c.color)) }),
          c.name,
        ),
        ...items.map((m) =>
          h('div', {
            style: toStyleStr(styles.markerItem),
            class: 'marker-sidebar-item',
            'data-lat': String(m.lat),
            'data-lng': String(m.lng),
            'data-id': m.id,
            onclick: `window.centerOn(${m.lat},${m.lng})`,
          },
            h('strong', {}, m.title),
            m.description ? h('div', { style: 'color:#7f8c8d;font-size:12px' }, m.description) : '',
            h('button', {
              style: toStyleStr(styles.btnDanger),
              onclick: `event.stopPropagation();window.deleteMarker('${m.id}')`,
            }, 'remove'),
          ),
        ),
      )
    })

  const { head, body } = createSSR()

  head(
    h('meta', { charset: 'utf-8' }),
    h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
    h('title', {}, 'Interactive Map'),
    h('link', {
      rel: 'stylesheet',
      href: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',
    }),
    h('script', { src: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js' }, ''),
    h('style', {}, `
      body { margin:0; padding:0; }
      .marker-sidebar-item:hover { background:#d5dbdb; }
      .leaflet-popup-content { min-width:140px; }
      .category-dot { display:inline-block; width:10px; height:10px; border-radius:50%; }
    `),
  )

  body(
    h('div', { style: toStyleStr(styles.page) },
      // Header with search
      h('div', { style: toStyleStr(styles.header) },
        h('span', { style: toStyleStr(styles.headerTitle) }, 'Interactive Map'),
        h('div', { style: toStyleStr(styles.searchForm) },
          h('input', {
            type: 'text',
            id: 'search-input',
            placeholder: 'Search location...',
            style: toStyleStr(styles.searchInput),
          }),
          h('button', {
            style: toStyleStr(styles.searchBtn),
            onclick: 'window.searchLocation()',
          }, 'Search'),
        ),
      ),
      // Main container
      h('div', { style: toStyleStr(styles.container) },
        // Sidebar
        h('div', { style: toStyleStr(styles.sidebar) },
          h('div', { style: toStyleStr(styles.sidebarSection) },
            h('div', { style: toStyleStr(styles.sidebarHeading) }, 'Markers'),
            ...sidebarMarkerList,
            sidebarMarkerList.length === 0
              ? h('div', { style: 'color:#95a5a6;font-size:13px' }, 'No markers yet. Click the map to add one.')
