          ),
          // Add marker form
          h('div', { style: toStyleStr(styles.addPanel) },
            h('div', { style: toStyleStr(styles.sidebarHeading) }, 'Add Marker'),
            h('div', { style: toStyleStr(styles.formGroup) },
              h('label', { style: toStyleStr(styles.label) }, 'Title'),
              h('input', { type: 'text', id: 'marker-title', style: toStyleStr(styles.input) }),
            ),
            h('div', { style: toStyleStr(styles.formGroup) },
              h('label', { style: toStyleStr(styles.label) }, 'Description'),
              h('input', { type: 'text', id: 'marker-desc', style: toStyleStr(styles.input) }),
            ),
            h('div', { style: toStyleStr(styles.formGroup) },
              h('label', { style: toStyleStr(styles.label) }, 'Category'),
              h('select', { id: 'marker-category', style: toStyleStr(styles.select) }, ...categoryOptions),
            ),
            h('div', { style: 'font-size:12px;color:#7f8c8d;margin-bottom:6px' }, 'Click the map to set coordinates, then click "Add Marker".'),
            h('div', { style: 'display:flex;gap:8px;margin-bottom:6px' },
              h('input', { type: 'number', id: 'marker-lat', placeholder: 'Lat', style: toStyleStr({ ...styles.input, width: '50%' }), step: 'any' }),
              h('input', { type: 'number', id: 'marker-lng', placeholder: 'Lng', style: toStyleStr({ ...styles.input, width: '50%' }), step: 'any' }),
            ),
            h('button', { style: toStyleStr(styles.btnPrimary), onclick: 'window.addMarker()' }, 'Add Marker'),
          ),
          // Add circle form
          h('div', { style: toStyleStr(styles.addPanel) },
            h('div', { style: toStyleStr(styles.sidebarHeading) }, 'Add Circle Highlight'),
            h('div', { style: toStyleStr(styles.formGroup) },
              h('label', { style: toStyleStr(styles.label) }, 'Label'),
              h('input', { type: 'text', id: 'circle-label', style: toStyleStr(styles.input) }),
            ),
            h('div', { style: 'display:flex;gap:8px;margin-bottom:6px' },
              h('input', { type: 'number', id: 'circle-lat', placeholder: 'Lat', style: toStyleStr({ ...styles.input, width: '50%' }), step: 'any' }),
              h('input', { type: 'number', id: 'circle-lng', placeholder: 'Lng', style: toStyleStr({ ...styles.input, width: '50%' }), step: 'any' }),
            ),
