              h('input', { type: 'number', id: 'circle-radius', placeholder: 'Radius (m)', style: toStyleStr({ ...styles.input, width: '50%' }), step: 'any' }),
              h('input', { type: 'color', id: 'circle-color', value: '#3388ff', style: toStyleStr({ ...styles.input, width: '50%' }) }),
            ),
            h('button', {
              style: toStyleStr({ ...styles.btnPrimary, background: '#3498db' }),
              onclick: 'window.addCircle()',
            }, 'Add Circle'),
          ),
        ),
        // Map
        h('div', { id: 'map', style: toStyleStr(styles.mapContainer) }),
      ),
    ),
    // Client-side script
    h('script', {}, `
      var MARKERS = ${JSON.stringify(markers)};
      var CIRCLES = ${JSON.stringify(circles)};
      var CATEGORIES = ${JSON.stringify(categories)};
      var categoryColors = {};
      CATEGORIES.forEach(function(c) { categoryColors[c.id] = c.color; });

      var map = L.map('map').setView([40, -30], 3);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors',
        maxZoom: 19,
      }).addTo(map);

      var markerLayers = {};
      var circleLayers = {};

      var createColorIcon = function(color) {
        return L.divIcon({
          className: '',
          html: '<div style="width:24px;height:24px;position:relative"><svg viewBox="0 0 24 36" xmlns="http://www.w3.org/2000/svg"><path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 24 12 24s12-15 12-24C24 5.4 18.6 0 12 0z" fill="' + color + '" stroke="#fff" stroke-width="1.5"/><circle cx="12" cy="11" r="5" fill="#fff" opacity="0.9"/></svg></div>',
          iconSize: [24, 36],
          iconAnchor: [12, 36],
          popupAnchor: [0, -36],
        });
      };

      MARKERS.forEach(function(m) {
        var color = categoryColors[m.categoryId] || '#3388ff';
        var marker = L.marker([m.lat, m.lng], { icon: createColorIcon(color) })
          .addTo(map)
          .bindPopup('<strong>' + m.title + '</strong>' + (m.description ? '<br>' + m.description : ''));
        markerLayers[m.id] = marker;
      });

      CIRCLES.forEach(function(c) {
        var circle = L.circle([c.lat, c.lng], {
          radius: c.radius, color: c.color, fillOpacity: 0.15, weight: 2,
        }).addTo(map).bindPopup(c.label || 'Area');
        circleLayers[c.id] = circle;
      });

      // Click map to set coordinates
      var tempMarker = null;
      map.on('click', function(e) {
        document.getElementById('marker-lat').value = e.latlng.lat.toFixed(6);
        document.getElementById('marker-lng').value = e.latlng.lng.toFixed(6);
        document.getElementById('circle-lat').value = e.latlng.lat.toFixed(6);
        document.getElementById('circle-lng').value = e.latlng.lng.toFixed(6);
        if (tempMarker) map.removeLayer(tempMarker);
        tempMarker = L.circleMarker(e.latlng, { radius: 5, color: '#e74c3c' }).addTo(map);
      });

      window.centerOn = function(lat, lng) {
        map.setView([lat, lng], 15);
      };

      window.searchLocation = function() {
        var q = document.getElementById('search-input').value.trim();
        if (!q) return;
        fetch('https://nominatim.openstreetmap.org/search?format=json&q=' + encodeURIComponent(q))
          .then(function(r) { return r.json(); })
          .then(function(data) {
            if (data && data.length > 0) {
              var lat = parseFloat(data[0].lat);
              var lng = parseFloat(data[0].lon);
              map.setView([lat, lng], 14);
              L.popup().setLatLng([lat, lng]).setContent(data[0].display_name).openOn(map);
            } else {
              alert('Location not found');
            }
          })
          .catch(function() { alert('Search failed'); });
      };

      document.getElementById('search-input').addEventListener('keydown', function(e) {
        if (e.key === 'Enter') window.searchLocation();
      });

      window.addMarker = function() {
        var title = document.getElementById('marker-title').value.trim();
        var desc = document.getElementById('marker-desc').value.trim();
        var lat = parseFloat(document.getElementById('marker-lat').value);
        var lng = parseFloat(document.getElementById('marker-lng').value);
        var cat = document.getElementById('marker-category').value;
        if (!title || isNaN(lat) || isNaN(lng)) { alert('Title and valid coordinates required'); return; }
        fetch('/api/markers', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ title: title, description: desc, lat: lat, lng: lng, categoryId: cat }),
        }).then(function() { location.reload(); });
      };

      window.deleteMarker = function(id) {
        fetch('/api/markers/' + id, { method: 'DELETE' }).then(function() { location.reload(); });
      };

      window.addCircle = function() {
        var label = document.getElementById('circle-label').value.trim();
        var lat = parseFloat(document.getElementById('circle-lat').value);
        var lng = parseFloat(document.getElementById('circle-lng').value);
        var radius = parseFloat(document.getElementById('circle-radius').value);
        var color = document.getElementById('circle-color').value;
        if (isNaN(lat) || isNaN(lng) || isNaN(radius)) { alert('Valid coordinates and radius required'); return; }
        fetch('/api/circles', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ label: label, lat: lat, lng: lng, radius: radius, color: color }),
        }).then(function() { location.reload(); });
      };
    `),
  )

  return '<!DOCTYPE html>' + head.render() + body.render()
}

import {
  getMarkers,
  addMarker,
  deleteMarker,
  getCircles,
  addCircle,
  deleteCircle,
  getCategories,
  addCategory,
  deleteCategory,
} from './store'
import { renderPage } from './view'
import type { MarkerInput, CircleInput, CategoryInput } from './types'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (content: string) =>
  new Response(content, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // --- Page ---
  if (pathname === '/' && method === 'GET') {
    const [markers, circles, categories] = await Promise.all([
      getMarkers(),
      getCircles(),
      getCategories(),
    ])
    return html(renderPage(markers, circles, categories))
  }

  // --- Markers API ---
  if (pathname === '/api/markers' && method === 'GET') {
    const category = url.searchParams.get('category') ?? undefined
    const markers = await getMarkers(category)
    return json(markers)
  }

  if (pathname === '/api/markers' && method === 'POST') {
    const body = (await req.json()) as MarkerInput
    if (!body.title || typeof body.lat !== 'number' || typeof body.lng !== 'number') {
      return json({ error: 'title, lat, and lng are required' }, 400)
    }
    const marker = await addMarker({
      title: body.title,
      description: body.description ?? '',
      lat: body.lat,
      lng: body.lng,
      categoryId: body.categoryId ?? 'default',
    })
    return json(marker, 201)
  }

  if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
    const id = pathname.split('/').pop()!
    const deleted = await deleteMarker(id)
    return deleted ? json({ ok: true }) : json({ error: 'not found' }, 404)
  }

  // --- Circles API ---
  if (pathname === '/api/circles' && method === 'GET') {
    const circles = await getCircles()
    return json(circles)
  }

  if (pathname === '/api/circles' && method === 'POST') {
    const body = (await req.json()) as CircleInput
    if (typeof body.lat !== 'number' || typeof body.lng !== 'number' || typeof body.radius !== 'number') {
      return json({ error: 'lat, lng, and radius are required' }, 400)
    }
    const circle = await addCircle({
      label: body.label ?? '',
      lat: body.lat,
      lng: body.lng,
      radius: body.radius,
      color: body.color ?? '#3388ff',
    })
    return json(circle, 201)
  }

  if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
    const id = pathname.split('/').pop()!
    const deleted = await deleteCircle(id)
    return deleted ? json({ ok: true }) : json({ error: 'not found' }, 404)
  }

  // --- Categories API ---
  if (pathname === '/api/categories' && method === 'GET') {
    const categories = await getCategories()
    return json(categories)
  }

  if (pathname === '/api/categories' && method === 'POST') {
    const body = (await req.json()) as CategoryInput
    if (!body.name || !body.color) {
      return json({ error: 'name and color are required' }, 400)
    }
    const category = await addCategory({ name: body.name, color: body.color })
    return json(category, 201)
  }

  if (pathname.startsWith('/api/categories/') && method === 'DELETE') {
    const id = pathname.split('/').pop()!
    const deleted = await deleteCategory(id)
    return deleted ? json({ ok: true }) : json({ error: 'not found' }, 404)
  }

  return json({ error: 'not found' }, 404)
}

{
  "name": "@node/interactive-map",
  "version": "1.0.0",
  "modnet": {
    "contentType": "geospatial",
    "structure": "collection",
