export type Marker = {
  id: string;
  title: string;
  description: string;
  lat: number;
  lng: number;
  category: string;
  createdAt: string;
};

export type Circle = {
  id: string;
  lat: number;
  lng: number;
  radius: number;
  color: string;
  label: string;
  createdAt: string;
};

export type Category = {
  id: string;
  label: string;
  color: string;
};

export type GeoSearchResult = {
  lat: number;
  lng: number;
  displayName: string;
};

import type { Marker, Circle, Category } from "./types";

const DATA_DIR = import.meta.dir + "/data";

const readJson = async <T>(filename: string): Promise<T> => {
  const file = Bun.file(`${DATA_DIR}/${filename}`);
  return file.json() as Promise<T>;
};

const writeJson = async <T>(filename: string, data: T): Promise<void> => {
  await Bun.write(`${DATA_DIR}/${filename}`, JSON.stringify(data, null, 2));
};

export const getMarkers = async (category?: string): Promise<Marker[]> => {
  const markers = await readJson<Marker[]>("markers.json");
  if (category) {
    return markers.filter((m) => m.category === category);
  }
  return markers;
};

export const addMarker = async (
  marker: Omit<Marker, "id" | "createdAt">
): Promise<Marker> => {
  const markers = await readJson<Marker[]>("markers.json");
  const newMarker: Marker = {
    ...marker,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  };
  markers.push(newMarker);
  await writeJson("markers.json", markers);
  return newMarker;
};

export const deleteMarker = async (id: string): Promise<boolean> => {
  const markers = await readJson<Marker[]>("markers.json");
  const idx = markers.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  markers.splice(idx, 1);
  await writeJson("markers.json", markers);
  return true;
};

export const getCircles = async (): Promise<Circle[]> => {
  return readJson<Circle[]>("circles.json");
};

export const addCircle = async (
  circle: Omit<Circle, "id" | "createdAt">
): Promise<Circle> => {
  const circles = await readJson<Circle[]>("circles.json");
  const newCircle: Circle = {
    ...circle,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  };
  circles.push(newCircle);
  await writeJson("circles.json", circles);
  return newCircle;
};

export const deleteCircle = async (id: string): Promise<boolean> => {
  const circles = await readJson<Circle[]>("circles.json");
  const idx = circles.findIndex((c) => c.id === id);
  if (idx === -1) return false;
  circles.splice(idx, 1);
  await writeJson("circles.json", circles);
  return true;
};

export const getCategories = async (): Promise<Category[]> => {
  return readJson<Category[]>("categories.json");
};

