document.addEventListener('DOMContentLoaded', function(){
  map = L.map('map').setView([51.505, -0.09], 13);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 19
  }).addTo(map);

  markersLayer = L.layerGroup().addTo(map);
  circlesLayer = L.layerGroup().addTo(map);

  var initialMarkers = ${JSON.stringify(markers)};
  var initialCircles = ${JSON.stringify(circles)};
  initialMarkers.forEach(addMarkerToMap);
  initialCircles.forEach(addCircleToMap);

  map.on('click', function(e){
    document.getElementById('m-lat').value = e.latlng.lat.toFixed(6);
    document.getElementById('m-lng').value = e.latlng.lng.toFixed(6);
    showAddMarkerModal();
  });
});

function makeCatIcon(catId){
  var cat = catMap[catId] || catMap['default'];
  return L.divIcon({
    className: 'cat-icon',
    html: '',
    iconSize: [24, 24],
    iconAnchor: [12, 12],
    popupAnchor: [0, -14]
  });
}

function addMarkerToMap(m){
  var cat = catMap[m.category] || catMap['default'];
  var icon = L.divIcon({
    className: '',
    html: '<div style="width:24px;height:24px;border-radius:50%;border:3px solid '+cat.color+';background:'+cat.color+'44;"></div>',
    iconSize: [24, 24],
    iconAnchor: [12, 12],
    popupAnchor: [0, -14]
  });
  var marker = L.marker([m.lat, m.lng], { icon: icon })
    .bindPopup('<strong>'+escHtml(m.title)+'</strong><br>'+escHtml(m.description||'')+'<br><em style=\"color:'+cat.color+'\">'+cat.label+'</em>');
  marker.addTo(markersLayer);
  markerObjects[m.id] = marker;
}

function addCircleToMap(c){
  var circle = L.circle([c.lat, c.lng], {
    radius: c.radius,
    color: c.color,
    fillColor: c.color,
    fillOpacity: 0.15,
    weight: 2
  });
  if(c.label) circle.bindPopup('<strong>'+escHtml(c.label)+'</strong>');
  circle.addTo(circlesLayer);
}

function escHtml(s){
  var d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
}

function centerOn(lat, lng, id){
  map.setView([lat, lng], 16);
  if(markerObjects[id]) markerObjects[id].openPopup();
}

function searchLocation(){
  var q = document.getElementById('search-input').value.trim();
  if(!q) return;
  fetch('/api/search?q='+encodeURIComponent(q))
    .then(function(r){ return r.json(); })
    .then(function(results){
      if(results.length > 0){
        map.setView([results[0].lat, results[0].lng], 15);
        L.popup()
          .setLatLng([results[0].lat, results[0].lng])
          .setContent(escHtml(results[0].displayName))
          .openOn(map);
      } else {
        alert('No results found for "'+q+'"');
      }
    })
    .catch(function(){ alert('Search failed. Please try again.'); });
}

function filterMarkers(catId){
  var items = document.querySelectorAll('.marker-item');
  items.forEach(function(el){
    var id = el.getAttribute('data-id');
    el.style.display = (!catId || el.querySelector('span').style.backgroundColor === (catMap[catId]||{}).color) ? '' : 'none';
  });
  // Also filter via API for accuracy
  var url = '/api/markers' + (catId ? '?category='+encodeURIComponent(catId) : '');
  fetch(url).then(function(r){ return r.json(); }).then(function(filtered){
    var ids = new Set(filtered.map(function(m){ return m.id; }));
    items.forEach(function(el){
      el.style.display = ids.has(el.getAttribute('data-id')) ? '' : 'none';
    });
  });
}

function showAddMarkerModal(){
  document.getElementById('marker-modal').style.display = 'flex';
}
function showAddCircleModal(){
  var c = map.getCenter();
  document.getElementById('c-lat').value = c.lat.toFixed(6);
  document.getElementById('c-lng').value = c.lng.toFixed(6);
  document.getElementById('circle-modal').style.display = 'flex';
}
function closeModals(){
  document.getElementById('marker-modal').style.display = 'none';
  document.getElementById('circle-modal').style.display = 'none';
}

function submitMarker(){
  var data = {
    title: document.getElementById('m-title').value,
    description: document.getElementById('m-desc').value,
    lat: parseFloat(document.getElementById('m-lat').value),
    lng: parseFloat(document.getElementById('m-lng').value),
    category: document.getElementById('m-category').value
  };
  if(!data.title){ alert('Title is required'); return; }
  if(isNaN(data.lat)||isNaN(data.lng)){ alert('Valid coordinates are required'); return; }
  fetch('/api/markers',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body: JSON.stringify(data)
  }).then(function(r){ return r.json(); }).then(function(){
    closeModals();
    location.reload();
  });
}

function submitCircle(){
  var data = {
    lat: parseFloat(document.getElementById('c-lat').value),
    lng: parseFloat(document.getElementById('c-lng').value),
    radius: parseFloat(document.getElementById('c-radius').value),
    color: document.getElementById('c-color').value,
    label: document.getElementById('c-label').value
  };
  if(isNaN(data.lat)||isNaN(data.lng)||isNaN(data.radius)){ alert('Valid values required'); return; }
  fetch('/api/circles',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body: JSON.stringify(data)
  }).then(function(r){ return r.json(); }).then(function(){
    closeModals();
    location.reload();
  });
}

function deleteMarker(id){
  if(!confirm('Delete this marker?')) return;
  fetch('/api/markers/'+id,{method:'DELETE'}).then(function(){
    location.reload();
  });
}
`
