import {
  getMarkers,
  addMarker,
  deleteMarker,
  getCircles,
  addCircle,
  deleteCircle,
  getCategories,
} from "./store";
import { renderPage } from "./render";
import type { GeoSearchResult } from "./types";

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const html = (body: string) =>
  new Response(body, {
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // Serve the main page
  if (pathname === "/" && method === "GET") {
    const [markers, circles, categories] = await Promise.all([
      getMarkers(),
      getCircles(),
      getCategories(),
    ]);
    return html(renderPage(markers, circles, categories));
  }

  // Markers API
  if (pathname === "/api/markers" && method === "GET") {
    const category = url.searchParams.get("category") || undefined;
    const markers = await getMarkers(category);
    return json(markers);
  }

  if (pathname === "/api/markers" && method === "POST") {
    const body = await req.json();
    const { title, description, lat, lng, category } = body;
    if (!title || typeof lat !== "number" || typeof lng !== "number") {
      return json({ error: "title, lat, and lng are required" }, 400);
    }
    const marker = await addMarker({
      title,
      description: description || "",
      lat,
      lng,
      category: category || "default",
    });
    return json(marker, 201);
  }

  if (pathname.startsWith("/api/markers/") && method === "DELETE") {
    const id = pathname.slice("/api/markers/".length);
    const deleted = await deleteMarker(id);
    if (!deleted) return json({ error: "Marker not found" }, 404);
    return json({ ok: true });
  }

  // Circles API
  if (pathname === "/api/circles" && method === "GET") {
    const circles = await getCircles();
    return json(circles);
  }

  if (pathname === "/api/circles" && method === "POST") {
    const body = await req.json();
    const { lat, lng, radius, color, label } = body;
    if (typeof lat !== "number" || typeof lng !== "number" || typeof radius !== "number") {
      return json({ error: "lat, lng, and radius are required" }, 400);
    }
    const circle = await addCircle({
      lat,
      lng,
      radius,
      color: color || "#3388ff",
      label: label || "",
    });
    return json(circle, 201);
  }

  if (pathname.startsWith("/api/circles/") && method === "DELETE") {
    const id = pathname.slice("/api/circles/".length);
    const deleted = await deleteCircle(id);
    if (!deleted) return json({ error: "Circle not found" }, 404);
    return json({ ok: true });
  }

  // Categories API
  if (pathname === "/api/categories" && method === "GET") {
    const categories = await getCategories();
    return json(categories);
  }

  // Location search via Nominatim
  if (pathname === "/api/search" && method === "GET") {
    const q = url.searchParams.get("q");
    if (!q) return json({ error: "q parameter required" }, 400);
    const nominatimUrl = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(q)}&limit=5`;
    const resp = await fetch(nominatimUrl, {
      headers: { "User-Agent": "interactive-map-module/1.0" },
    });
    const results = (await resp.json()) as Array<{
      lat: string;
      lon: string;
      display_name: string;
    }>;
    const mapped: GeoSearchResult[] = results.map((r) => ({
      lat: parseFloat(r.lat),
      lng: parseFloat(r.lon),
      displayName: r.display_name,
    }));
    return json(mapped);
  }

  return json({ error: "Not found" }, 404);
};

import { handleRequest } from "./handlers";

export type ServeOptions = {
  port?: number;
  hostname?: string;
};

export const serve = (options: ServeOptions = {}) => {
  const port = options.port ?? 3000;
  const hostname = options.hostname ?? "0.0.0.0";

  return Bun.serve({
    port,
    hostname,
    fetch: handleRequest,
  });
};

// Auto-start when run directly
if (import.meta.main) {
  const port = parseInt(process.env.PORT || "3000", 10);
  const server = serve({ port });
  console.log(`Interactive Map running at http://localhost:${server.port}`);
