import type { MapMarker, MapCircle } from './types'

const MARKERS_PATH = './data/markers.json'
const CIRCLES_PATH = './data/circles.json'

const readJson = async <T>(path: string): Promise<T[]> => {
  const file = Bun.file(path)
  if (!(await file.exists())) return []
  return file.json()
}

const writeJson = async <T>(path: string, data: T[]): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

export const getMarkers = async (category?: string): Promise<MapMarker[]> => {
  const markers = await readJson<MapMarker>(MARKERS_PATH)
  if (category) return markers.filter((m) => m.category === category)
  return markers
}

export const addMarker = async (marker: Omit<MapMarker, 'id'>): Promise<MapMarker> => {
  const markers = await readJson<MapMarker>(MARKERS_PATH)
  const newMarker: MapMarker = {
    ...marker,
    id: `m${Date.now()}`,
  }
  markers.push(newMarker)
  await writeJson(MARKERS_PATH, markers)
  return newMarker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const markers = await readJson<MapMarker>(MARKERS_PATH)
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await writeJson(MARKERS_PATH, filtered)
  return true
}

export const getCircles = async (): Promise<MapCircle[]> => {
  return readJson<MapCircle>(CIRCLES_PATH)
}

export const addCircle = async (circle: Omit<MapCircle, 'id'>): Promise<MapCircle> => {
  const circles = await readJson<MapCircle>(CIRCLES_PATH)
  const newCircle: MapCircle = {
    ...circle,
    id: `c${Date.now()}`,
  }
  circles.push(newCircle)
  await writeJson(CIRCLES_PATH, circles)
  return newCircle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const circles = await readJson<MapCircle>(CIRCLES_PATH)
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await writeJson(CIRCLES_PATH, filtered)
  return true
}

import type { SearchResult } from './types'

export const geocode = async (query: string): Promise<SearchResult[]> => {
  const encoded = encodeURIComponent(query)
  const url = `https://nominatim.openstreetmap.org/search?format=json&q=${encoded}&limit=5`
  const response = await fetch(url, {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  })
  if (!response.ok) return []
  const data = (await response.json()) as Array<{ lat: string; lon: string; display_name: string }>
  return data.map((item) => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }))
}

