const clientScript = (markers: MapMarker[], circles: MapCircle[]): string => {
  const categoryColors = JSON.stringify(DEFAULT_CATEGORY_COLORS)
  const markersJson = JSON.stringify(markers)
  const circlesJson = JSON.stringify(circles)

  return `
(function() {
  var CATEGORY_COLORS = ${categoryColors};
  var initialMarkers = ${markersJson};
  var initialCircles = ${circlesJson};
  var hiddenCategories = {};

  var map = L.map('map').setView([40.7128, -74.0060], 12);

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 19
  }).addTo(map);

  var markerLayers = {};
  var circleLayers = {};

  function getCategoryColor(cat) {
    return CATEGORY_COLORS[cat] || CATEGORY_COLORS['default'] || '#7f8c8d';
  }

  function createIcon(color) {
    return L.divIcon({
      className: 'custom-marker',
      html: '<div style="width:24px;height:24px;border-radius:50% 50% 50% 0;background:' + color + ';transform:rotate(-45deg);border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.3);position:relative;top:-12px;left:-6px;"></div>',
      iconSize: [24, 24],
      iconAnchor: [12, 24],
      popupAnchor: [0, -24]
    });
  }

  function addMarkerToMap(m) {
    var color = getCategoryColor(m.category);
    var icon = createIcon(color);
    var layer = L.marker([m.lat, m.lng], { icon: icon })
      .bindPopup('<strong>' + m.title + '</strong><br>' + m.description + '<br><em style=\"color:' + color + '\">' + m.category + '</em>')
      .addTo(map);
    markerLayers[m.id] = layer;
    if (hiddenCategories[m.category]) {
      map.removeLayer(layer);
    }
  }

  function addCircleToMap(c) {
    var layer = L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2
    }).bindPopup('<strong>' + c.title + '</strong><br>Radius: ' + c.radius + 'm').addTo(map);
    circleLayers[c.id] = layer;
  }

  initialMarkers.forEach(addMarkerToMap);
  initialCircles.forEach(addCircleToMap);

  // Search
  document.getElementById('search-form').addEventListener('submit', function(e) {
    e.preventDefault();
    var q = document.getElementById('search-input').value.trim();
    if (!q) return;
    fetch('/api/search?q=' + encodeURIComponent(q))
      .then(function(r) { return r.json(); })
      .then(function(results) {
        if (results.length > 0) {
          map.flyTo([results[0].lat, results[0].lng], 14);
          L.popup()
            .setLatLng([results[0].lat, results[0].lng])
            .setContent(results[0].displayName)
            .openOn(map);
        } else {
          alert('Location not found');
        }
      });
  });

  // Sidebar marker click
  document.getElementById('marker-list').addEventListener('click', function(e) {
    var item = e.target.closest('[data-lat]');
    if (!item) return;
    var lat = parseFloat(item.getAttribute('data-lat'));
    var lng = parseFloat(item.getAttribute('data-lng'));
    var id = item.getAttribute('data-id');
    map.flyTo([lat, lng], 16);
    if (markerLayers[id]) markerLayers[id].openPopup();
  });

  // Category toggle
  document.getElementById('marker-list').addEventListener('click', function(e) {
    var header = e.target.closest('[style*="cursor"]');
    if (!header || !header.parentElement || !header.parentElement.getAttribute('data-category')) return;
    // only toggle if clicking the header row, not a marker item
    if (e.target.closest('[data-id]')) return;
    var cat = header.parentElement.getAttribute('data-category');
    hiddenCategories[cat] = !hiddenCategories[cat];
    Object.keys(markerLayers).forEach(function(mid) {
      var mkr = initialMarkers.find(function(m) { return m.id === mid; });
      if (mkr && mkr.category === cat) {
        if (hiddenCategories[cat]) {
          map.removeLayer(markerLayers[mid]);
        } else {
          map.addLayer(markerLayers[mid]);
        }
      }
    });
    header.parentElement.style.opacity = hiddenCategories[cat] ? '0.4' : '1';
  });

  // Add marker
  document.getElementById('add-marker-btn').addEventListener('click', function() {
    var title = document.getElementById('add-title').value.trim();
    var desc = document.getElementById('add-desc').value.trim();
    var cat = document.getElementById('add-category').value;
    var lat = parseFloat(document.getElementById('add-lat').value);
    var lng = parseFloat(document.getElementById('add-lng').value);
    if (!title || isNaN(lat) || isNaN(lng)) {
      alert('Title, latitude, and longitude are required');
      return;
    }
    fetch('/api/markers', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: title, description: desc || '', lat: lat, lng: lng, category: cat })
    })
    .then(function(r) { return r.json(); })
    .then(function(m) {
      initialMarkers.push(m);
      addMarkerToMap(m);
      map.flyTo([m.lat, m.lng], 14);
      // Add to sidebar
      var section = document.querySelector('[data-category=\"' + m.category + '\"]');
      if (section) {
        var div = document.createElement('div');
        div.style.cssText = 'padding:8px 12px;margin-bottom:4px;background-color:#fff;border-radius:6px;cursor:pointer;border:1px solid #e9ecef';
        div.setAttribute('data-lat', m.lat);
        div.setAttribute('data-lng', m.lng);
        div.setAttribute('data-id', m.id);
        div.innerHTML = '<p style=\"font-size:14px;font-weight:500;color:#212529;margin:0 0 2px 0\">' + m.title + '</p><p style=\"font-size:12px;color:#6c757d;margin:0\">' + m.description + '</p>';
        section.appendChild(div);
      }
      document.getElementById('add-title').value = '';
      document.getElementById('add-desc').value = '';
      document.getElementById('add-lat').value = '';
      document.getElementById('add-lng').value = '';
    });
  });

  // Click map to fill lat/lng
  map.on('click', function(e) {
    document.getElementById('add-lat').value = e.latlng.lat.toFixed(6);
    document.getElementById('add-lng').value = e.latlng.lng.toFixed(6);
  });

  // Add circle at current center
  document.getElementById('add-circle-btn').addEventListener('click', function() {
    var center = map.getCenter();
    var title = prompt('Circle title:', 'Highlighted Area');
    var radius = prompt('Radius in meters:', '1000');
    var color = prompt('Color (hex):', '#3388ff');
    if (!title || !radius) return;
    fetch('/api/circles', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: title, lat: center.lat, lng: center.lng, radius: parseFloat(radius), color: color || '#3388ff' })
    })
    .then(function(r) { return r.json(); })
    .then(function(c) {
      initialCircles.push(c);
      addCircleToMap(c);
    });
  });
})();
`
}

import { getMarkers, addMarker, removeMarker, getCircles, addCircle, removeCircle } from './store'
import { geocode } from './search'
import { renderPage } from './render'

const PORT = Number(process.env.PORT) || 3000

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Serve main page
    if (path === '/' && method === 'GET') {
      const [markers, circles] = await Promise.all([getMarkers(), getCircles()])
      return htmlResponse(renderPage(markers, circles))
    }

    // Markers API
    if (path === '/api/markers' && method === 'GET') {
      const category = url.searchParams.get('category') ?? undefined
      const markers = await getMarkers(category)
      return jsonResponse(markers)
    }

    if (path === '/api/markers' && method === 'POST') {
      const body = await req.json()
      const { title, description, lat, lng, category } = body as {
        title: string
        description: string
        lat: number
        lng: number
        category: string
      }
      if (!title || lat == null || lng == null) {
        return jsonResponse({ error: 'title, lat, and lng are required' }, 400)
      }
      const marker = await addMarker({
        title,
        description: description || '',
        lat: Number(lat),
        lng: Number(lng),
        category: category || 'default',
      })
      return jsonResponse(marker, 201)
    }

    if (path.startsWith('/api/markers/') && method === 'DELETE') {
      const id = path.split('/').pop()!
      const removed = await removeMarker(id)
      if (!removed) return jsonResponse({ error: 'Marker not found' }, 404)
      return jsonResponse({ ok: true })
    }

    // Circles API
    if (path === '/api/circles' && method === 'GET') {
      const circles = await getCircles()
      return jsonResponse(circles)
    }

    if (path === '/api/circles' && method === 'POST') {
      const body = await req.json()
      const { title, lat, lng, radius, color } = body as {
        title: string
        lat: number
        lng: number
        radius: number
        color: string
      }
      if (!title || lat == null || lng == null || radius == null) {
        return jsonResponse({ error: 'title, lat, lng, and radius are required' }, 400)
      }
      const circle = await addCircle({
        title,
        lat: Number(lat),
        lng: Number(lng),
        radius: Number(radius),
        color: color || '#3388ff',
      })
      return jsonResponse(circle, 201)
    }

    if (path.startsWith('/api/circles/') && method === 'DELETE') {
      const id = path.split('/').pop()!
      const removed = await removeCircle(id)
      if (!removed) return jsonResponse({ error: 'Circle not found' }, 404)
      return jsonResponse({ ok: true })
    }

    // Search API
    if (path === '/api/search' && method === 'GET') {
      const q = url.searchParams.get('q')
      if (!q) return jsonResponse({ error: 'q parameter required' }, 400)
      const results = await geocode(q)
      return jsonResponse(results)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

