import type { CalendarEvent, EventCategory, RecurrenceRule } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.json`

const generateId = (): string => crypto.randomUUID()

const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const getAllEvents = async (): Promise<CalendarEvent[]> => {
  return readEvents()
}

export const getEventById = async (id: string): Promise<CalendarEvent | undefined> => {
  const events = await readEvents()
  return events.find((e) => e.id === id)
}

export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await readEvents()
  const matching = events.filter((e) => {
    if (e.date === date) return true
    return isRecurrenceMatch(e, date)
  })
  return matching.sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const getEventsForMonth = async (year: number, month: number): Promise<Map<string, CalendarEvent[]>> => {
  const events = await readEvents()
  const map = new Map<string, CalendarEvent[]>()
  const daysInMonth = new Date(year, month, 0).getDate()

  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`
    const dayEvents = events.filter((e) => {
      if (e.date === dateStr) return true
      return isRecurrenceMatch(e, dateStr)
    })
    if (dayEvents.length > 0) {
      map.set(dateStr, dayEvents.sort((a, b) => a.startTime.localeCompare(b.startTime)))
    }
  }

  return map
}

export const createEvent = async (input: {
  title: string
  date: string
  startTime: string
  endTime: string
  description: string
  category: EventCategory
  recurrence?: RecurrenceRule
}): Promise<CalendarEvent> => {
  const events = await readEvents()
  const now = new Date().toISOString()
  const event: CalendarEvent = {
    id: generateId(),
    title: input.title,
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description,
    category: input.category,
    recurrence: input.recurrence ?? 'none',
    createdAt: now,
    updatedAt: now,
  }
  events.push(event)
  await writeEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id' | 'createdAt' | 'updatedAt'>>,
): Promise<CalendarEvent | undefined> => {
  const events = await readEvents()
  const index = events.findIndex((e) => e.id === id)
  if (index === -1) return undefined

  events[index] = {
    ...events[index],
    ...updates,
    updatedAt: new Date().toISOString(),
  }
  await writeEvents(events)
  return events[index]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readEvents()
  const index = events.findIndex((e) => e.id === id)
  if (index === -1) return false

  events.splice(index, 1)
  await writeEvents(events)
  return true
}

export const getEventsByCategory = async (category: EventCategory): Promise<CalendarEvent[]> => {
  const events = await readEvents()
  return events.filter((e) => e.category === category)
}

const isRecurrenceMatch = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.recurrence === 'none') return false

  const eventDate = new Date(event.date + 'T00:00:00')
  const target = new Date(targetDate + 'T00:00:00')

  if (target < eventDate) return false

  switch (event.recurrence) {
    case 'daily':
      return true
    case 'weekly': {
      return eventDate.getDay() === target.getDay()
    }
    case 'monthly': {
      return eventDate.getDate() === target.getDate()
    }
    default:
      return false
  }
}

import type { DayCell, MonthGrid, CalendarEvent } from './types'
import { getEventsForMonth } from './events'

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const toDateStr = (year: number, month: number, day: number): string =>
  `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`

const getTodayStr = (): string => {
  const now = new Date()
  return toDateStr(now.getFullYear(), now.getMonth() + 1, now.getDate())
}

export const buildMonthGrid = async (year: number, month: number): Promise<MonthGrid> => {
  const eventsMap = await getEventsForMonth(year, month)
  const today = getTodayStr()

  const firstDay = new Date(year, month - 1, 1)
  const startDow = firstDay.getDay()
  const daysInMonth = new Date(year, month, 0).getDate()
  const prevMonthDays = new Date(year, month - 1, 0).getDate()

  const cells: DayCell[] = []

  // Previous month trailing days
  for (let i = startDow - 1; i >= 0; i--) {
    const day = prevMonthDays - i
    const prevMonth = month === 1 ? 12 : month - 1
    const prevYear = month === 1 ? year - 1 : year
    const dateStr = toDateStr(prevYear, prevMonth, day)
    cells.push({
      date: dateStr,
      day,
      isCurrentMonth: false,
      isToday: dateStr === today,
      events: [],
    })
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = toDateStr(year, month, day)
    cells.push({
      date: dateStr,
      day,
      isCurrentMonth: true,
      isToday: dateStr === today,
      events: eventsMap.get(dateStr) ?? [],
    })
  }

  // Next month leading days to fill final week
  const remainder = cells.length % 7
  if (remainder > 0) {
    const fill = 7 - remainder
    const nextMonth = month === 12 ? 1 : month + 1
    const nextYear = month === 12 ? year + 1 : year
    for (let day = 1; day <= fill; day++) {
      const dateStr = toDateStr(nextYear, nextMonth, day)
      cells.push({
        date: dateStr,
        day,
        isCurrentMonth: false,
        isToday: dateStr === today,
        events: [],
      })
    }
  }

  // Group into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month - 1]} ${year}`,
    weeks,
  }
}

export const getNextMonth = (year: number, month: number): { year: number; month: number } => {
  return month === 12 ? { year: year + 1, month: 1 } : { year, month: month + 1 }
}

export const getPrevMonth = (year: number, month: number): { year: number; month: number } => {
  return month === 1 ? { year: year - 1, month: 12 } : { year, month: month - 1 }
}

