  const cellStyle = {
    ...styles.dayCell,
    ...(!cell.isCurrentMonth ? styles.dayCellOutside : {}),
    ...(cell.isToday ? styles.dayCellToday : {}),
  }

  const numberStyle = cell.isToday
    ? { ...styles.dayNumber, ...styles.dayNumberToday }
