import type { CalendarEvent, EventCategory, Recurrence } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.json`

const generateId = (): string => crypto.randomUUID()

const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const getAllEvents = async (): Promise<CalendarEvent[]> => {
  return readEvents()
}

export const createEvent = async (input: {
  title: string
  date: string
  startTime: string
  endTime: string
  description: string
  category: EventCategory
  recurrence: Recurrence
}): Promise<CalendarEvent> => {
  const events = await readEvents()
  const event: CalendarEvent = {
    id: generateId(),
    ...input,
    createdAt: new Date().toISOString(),
  }
  events.push(event)
  await writeEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id' | 'createdAt'>>
): Promise<CalendarEvent | null> => {
  const events = await readEvents()
  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return null
  events[idx] = { ...events[idx], ...updates }
  await writeEvents(events)
  return events[idx]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readEvents()
  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return false
  events.splice(idx, 1)
  await writeEvents(events)
  return true
}

export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await readEvents()
  const target = new Date(dateStr + 'T00:00:00')
  const matched: CalendarEvent[] = []

  for (const event of events) {
    if (matchesDate(event, target)) {
      matched.push(event)
    }
  }

  return matched.sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const getEventsForMonth = async (
  year: number,
  month: number
): Promise<Map<string, CalendarEvent[]>> => {
  const events = await readEvents()
  const daysInMonth = new Date(year, month, 0).getDate()
  const result = new Map<string, CalendarEvent[]>()

  for (let day = 1; day <= daysInMonth; day++) {
    const date = new Date(year, month - 1, day)
    const dateStr = formatDate(date)
    const dayEvents: CalendarEvent[] = []

    for (const event of events) {
      if (matchesDate(event, date)) {
        dayEvents.push(event)
      }
    }

    if (dayEvents.length > 0) {
      result.set(dateStr, dayEvents.sort((a, b) => a.startTime.localeCompare(b.startTime)))
    }
  }

  return result
}

const matchesDate = (event: CalendarEvent, target: Date): boolean => {
  const eventDate = new Date(event.date + 'T00:00:00')
  const targetStr = formatDate(target)
  const eventStr = event.date

  if (eventStr === targetStr) return true
  if (event.recurrence === 'none') return false
  if (target < eventDate) return false

  switch (event.recurrence) {
    case 'daily':
      return true
    case 'weekly': {
      return eventDate.getDay() === target.getDay()
    }
    case 'monthly': {
      return eventDate.getDate() === target.getDate()
    }
    default:
      return false
  }
}

const formatDate = (d: Date): string => {
  const y = d.getFullYear()
  const m = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  return `${y}-${m}-${day}`
}

import type { CalendarEvent, DayCell, MonthGrid } from './types'

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const formatDate = (d: Date): string => {
  const y = d.getFullYear()
  const m = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  return `${y}-${m}-${day}`
}

const todayStr = (): string => formatDate(new Date())

export const buildMonthGrid = (
  year: number,
  month: number,
  eventsByDate: Map<string, CalendarEvent[]>
): MonthGrid => {
  const firstDay = new Date(year, month - 1, 1)
  const daysInMonth = new Date(year, month, 0).getDate()
  const startDow = firstDay.getDay()
  const today = todayStr()

  const prevMonth = month === 1 ? 12 : month - 1
  const prevYear = month === 1 ? year - 1 : year
  const daysInPrev = new Date(prevYear, prevMonth, 0).getDate()

  const cells: DayCell[] = []

  // Previous month trailing days
  for (let i = startDow - 1; i >= 0; i--) {
    const day = daysInPrev - i
    const date = formatDate(new Date(prevYear, prevMonth - 1, day))
    cells.push({
      date,
      day,
      isCurrentMonth: false,
      isToday: date === today,
      events: eventsByDate.get(date) ?? [],
    })
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const date = formatDate(new Date(year, month - 1, day))
    cells.push({
      date,
      day,
      isCurrentMonth: true,
      isToday: date === today,
      events: eventsByDate.get(date) ?? [],
    })
  }

  // Next month leading days
  const remaining = 7 - (cells.length % 7)
  if (remaining < 7) {
    const nextMonth = month === 12 ? 1 : month + 1
    const nextYear = month === 12 ? year + 1 : year
    for (let day = 1; day <= remaining; day++) {
      const date = formatDate(new Date(nextYear, nextMonth - 1, day))
      cells.push({
        date,
        day,
        isCurrentMonth: false,
        isToday: date === today,
        events: eventsByDate.get(date) ?? [],
      })
    }
  }

  // Split into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month - 1]} ${year}`,
    weeks,
  }
}

