const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (c) => `-${c.toLowerCase()}`)}:${typeof v === 'number' ? `${v}px` : v}`)
    .join(';')

const prevMonth = (year: number, month: number): { year: number; month: number } =>
  month === 1 ? { year: year - 1, month: 12 } : { year, month: month - 1 }

const nextMonth = (year: number, month: number): { year: number; month: number } =>
  month === 12 ? { year: year + 1, month: 1 } : { year, month: month + 1 }

export const renderMonthView = (grid: MonthGrid): string => {
  const prev = prevMonth(grid.year, grid.month)
  const next = nextMonth(grid.year, grid.month)

  const template = h('div', { style: styleStr(styles.page) },
    h('div', { style: styleStr(styles.header) },
      h('h1', { style: styleStr(styles.title) }, grid.label),
      h('div', { style: styleStr(styles.nav) },
        h('a', { href: `/calendar?year=${prev.year}&month=${prev.month}`, style: styleStr(styles.navBtn) }, '\u2190 Prev'),
        h('a', { href: `/calendar?year=${grid.year}&month=${grid.month}`, style: styleStr(styles.navBtn) }, 'Today'),
        h('a', { href: `/calendar?year=${next.year}&month=${next.month}`, style: styleStr(styles.navBtn) }, 'Next \u2192'),
      ),
    ),
    h('div', { style: styleStr(styles.legend) },
      ...(['work', 'personal', 'health', 'social'] as EventCategory[]).map((cat) =>
        h('span', { style: styleStr(styles.legendItem) },
          h('span', { style: styleStr({ ...styles.legendDot, backgroundColor: CATEGORY_COLORS[cat].border }) }),
          cat.charAt(0).toUpperCase() + cat.slice(1),
        )
      ),
    ),
    h('div', { style: styleStr(styles.grid) },
      ...DAY_NAMES.map((name) =>
        h('div', { style: styleStr(styles.dayHeader) }, name)
      ),
      ...grid.weeks.flatMap((week) =>
        week.map((cell) => renderCell(cell))
      ),
    ),
  )

  return createSSR(
    h('html', { lang: 'en' },
      h('head', {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, grid.label),
        h('style', {}, 'body{margin:0}a{color:inherit}*{box-sizing:border-box}'),
      ),
      h('body', {}, template),
    )
  )
}

const renderCell = (cell: DayCell): ReturnType<typeof h> => {
  const cellStyle = {
    ...styles.cell,
    ...(cell.isCurrentMonth ? {} : styles.cellMuted),
    ...(cell.isToday ? styles.cellToday : {}),
  }

  const maxShow = 3
  const shown = cell.events.slice(0, maxShow)
  const remaining = cell.events.length - maxShow

  return h('div', { style: styleStr(cellStyle) },
    h('div', { style: styleStr(cell.isToday ? styles.todayNum : styles.dayNum) },
      h('a', {
        href: `/calendar/day?date=${cell.date}`,
        style: 'text-decoration:none;color:inherit',
      }, String(cell.day)),
    ),
    ...shown.map((evt) => {
      const colors = CATEGORY_COLORS[evt.category]
      return h('a', {
        href: `/calendar/day?date=${cell.date}`,
        style: styleStr({
          ...styles.eventDot,
          backgroundColor: colors.bg,
          color: colors.text,
        }),
      }, evt.title)
    }),
    ...(remaining > 0
      ? [h('div', { style: styleStr(styles.moreLabel) }, `+${remaining} more`)]
      : []),
  )
}

