        h('input', { type: 'hidden', name: 'returnDate', value: returnDate }),
        h('button', { type: 'submit', style: styleStr({ ...styles.submitBtn, backgroundColor: '#ef4444' }) }, 'Yes, Delete'),
      ),
      h('a', { href: `/calendar/day?date=${returnDate}`, style: styleStr(styles.cancelBtn) }, 'Cancel'),
    ),
  )

  return createSSR(
    h('html', { lang: 'en' },
      h('head', {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, 'Delete Event'),
        h('style', {}, 'body{margin:0}*{box-sizing:border-box}'),
      ),
      h('body', {}, template),
    )
  )
}

const formatTime = (time: string): string => {
  const [h, m] = time.split(':').map(Number)
  const period = h >= 12 ? 'PM' : 'AM'
  const hour = h === 0 ? 12 : h > 12 ? h - 12 : h
  return `${hour}:${String(m).padStart(2, '0')} ${period}`
}

import { buildMonthGrid } from './calendar'
import { getAllEvents, createEvent, updateEvent, deleteEvent, getEventsForDate, getEventsForMonth } from './store'
import { renderMonthView, renderDayView, renderEventForm, renderDeleteConfirm } from './render'
import type { EventCategory, Recurrence } from './types'

const VALID_CATEGORIES: EventCategory[] = ['work', 'personal', 'health', 'social']
const VALID_RECURRENCES: Recurrence[] = ['none', 'daily', 'weekly', 'monthly']

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((v, k) => { result[k] = v })
  return result
}

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, { status, headers: { 'Content-Type': 'text/html; charset=utf-8' } })

const redirect = (url: string): Response =>
  new Response(null, { status: 303, headers: { Location: url } })

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), { status, headers: { 'Content-Type': 'application/json' } })

export default {
  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // GET /calendar — Month view
    if (path === '/calendar' && method === 'GET') {
      const now = new Date()
      const year = Number(url.searchParams.get('year')) || now.getFullYear()
      const month = Number(url.searchParams.get('month')) || now.getMonth() + 1
      const eventsByDate = await getEventsForMonth(year, month)
      const grid = buildMonthGrid(year, month, eventsByDate)
      return htmlResponse(renderMonthView(grid))
    }

    // GET /calendar/day — Day view
    if (path === '/calendar/day' && method === 'GET') {
      const date = url.searchParams.get('date')
      if (!date) return redirect('/calendar')
      const events = await getEventsForDate(date)
      const d = new Date(date + 'T00:00:00')
      return htmlResponse(renderDayView(date, events, d.getFullYear(), d.getMonth() + 1))
    }

    // GET /calendar/events/new — New event form
    if (path === '/calendar/events/new' && method === 'GET') {
      const date = url.searchParams.get('date') ?? undefined
      return htmlResponse(renderEventForm({ date }))
    }

    // POST /calendar/events — Create event
    if (path === '/calendar/events' && method === 'POST') {
      const body = await parseFormBody(req)
      const { title, date, startTime, endTime, description, category, recurrence, returnDate } = body

      if (!title || !date || !startTime || !endTime) {
        return htmlResponse(renderEventForm({
          date,
          error: 'Title, date, start time, and end time are required.',
        }), 400)
      }

      const cat = VALID_CATEGORIES.includes(category as EventCategory) ? category as EventCategory : 'work'
      const rec = VALID_RECURRENCES.includes(recurrence as Recurrence) ? recurrence as Recurrence : 'none'

      await createEvent({
        title: title.trim(),
        date,
        startTime,
        endTime,
        description: (description ?? '').trim(),
        category: cat,
        recurrence: rec,
      })

      return redirect(returnDate ? `/calendar/day?date=${returnDate}` : `/calendar/day?date=${date}`)
    }

    // GET /calendar/events/:id/edit — Edit event form
    const editMatch = path.match(/^\/calendar\/events\/([^/]+)\/edit$/)
    if (editMatch && method === 'GET') {
      const id = editMatch[1]
      const events = await getAllEvents()
      const event = events.find((e) => e.id === id)
      if (!event) return htmlResponse('<p>Event not found</p>', 404)
      const returnDate = url.searchParams.get('returnDate') ?? event.date
      return htmlResponse(renderEventForm({ event, returnDate }))
    }

    // POST /calendar/events/:id — Update event (via form with _method=PUT)
    const updateMatch = path.match(/^\/calendar\/events\/([^/]+)$/)
    if (updateMatch && method === 'POST') {
      const id = updateMatch[1]
      const body = await parseFormBody(req)

      if (body._method === 'PUT') {
        const { title, date, startTime, endTime, description, category, recurrence, returnDate } = body

        if (!title || !date || !startTime || !endTime) {
          const events = await getAllEvents()
          const event = events.find((e) => e.id === id)
          return htmlResponse(renderEventForm({
            event: event ?? undefined,
            returnDate,
            error: 'Title, date, start time, and end time are required.',
          }), 400)
        }

        const cat = VALID_CATEGORIES.includes(category as EventCategory) ? category as EventCategory : 'work'
        const rec = VALID_RECURRENCES.includes(recurrence as Recurrence) ? recurrence as Recurrence : 'none'

        await updateEvent(id, {
          title: title.trim(),
          date,
          startTime,
          endTime,
          description: (description ?? '').trim(),
          category: cat,
          recurrence: rec,
        })

        return redirect(returnDate ? `/calendar/day?date=${returnDate}` : `/calendar/day?date=${date}`)
      }

      return htmlResponse('<p>Method not allowed</p>', 405)
    }

    // PUT /calendar/events/:id — API update
    if (updateMatch && method === 'PUT') {
      const id = updateMatch![1]
      const body = await req.json()
      const updated = await updateEvent(id, body)
      if (!updated) return jsonResponse({ error: 'Event not found' }, 404)
      return jsonResponse(updated)
    }

    // DELETE /calendar/events/:id — API delete
    if (updateMatch && method === 'DELETE') {
      const id = updateMatch![1]
      const deleted = await deleteEvent(id)
      if (!deleted) return jsonResponse({ error: 'Event not found' }, 404)
      return jsonResponse({ success: true })
    }

    // GET /calendar/events/:id/delete — Delete confirmation page
    const deleteMatch = path.match(/^\/calendar\/events\/([^/]+)\/delete$/)
    if (deleteMatch && method === 'GET') {
      const id = deleteMatch[1]
      const events = await getAllEvents()
      const event = events.find((e) => e.id === id)
      if (!event) return htmlResponse('<p>Event not found</p>', 404)
      const returnDate = url.searchParams.get('returnDate') ?? event.date
      return htmlResponse(renderDeleteConfirm(event, returnDate))
    }

    // POST /calendar/events/:id/delete — Execute delete (form submission)
    if (deleteMatch && method === 'POST') {
      const id = deleteMatch[1]
      const body = await parseFormBody(req)
      await deleteEvent(id)
      const returnDate = body.returnDate
      return redirect(returnDate ? `/calendar/day?date=${returnDate}` : '/calendar')
    }

    // API: POST /calendar/api/events — JSON create
    if (path === '/calendar/api/events' && method === 'POST') {
      const body = await req.json()
      const { title, date, startTime, endTime, description, category, recurrence } = body

      if (!title || !date || !startTime || !endTime) {
        return jsonResponse({ error: 'Missing required fields' }, 400)
      }

      const cat = VALID_CATEGORIES.includes(category) ? category : 'work'
      const rec = VALID_RECURRENCES.includes(recurrence) ? recurrence : 'none'

      const event = await createEvent({
        title, date, startTime, endTime,
        description: description ?? '',
        category: cat,
        recurrence: rec,
      })
      return jsonResponse(event, 201)
    }

    // API: GET /calendar/api/events — List all events
    if (path === '/calendar/api/events' && method === 'GET') {
      const date = url.searchParams.get('date')
      if (date) {
        const events = await getEventsForDate(date)
        return jsonResponse(events)
      }
      const events = await getAllEvents()
      return jsonResponse(events)
    }

    // Fallback: redirect to calendar
    if (path === '/' || path === '') {
      return redirect('/calendar')
    }

    return htmlResponse('<p>Not found</p>', 404)
  },
}

