export type Category = 'work' | 'personal' | 'health' | 'social';

export type Recurrence = 'daily' | 'weekly' | 'monthly' | 'none';

export type CalendarEvent = {
  id: string;
  title: string;
  date: string; // YYYY-MM-DD
  startTime: string; // HH:MM
  endTime: string; // HH:MM
  description: string;
  category: Category;
  recurrence: Recurrence;
};

export type CreateEventInput = Omit<CalendarEvent, 'id'>;

export type UpdateEventInput = Partial<Omit<CalendarEvent, 'id'>> & { id: string };

export type MonthViewParams = {
  year: number;
  month: number; // 1-12
};

export type DayViewParams = {
  date: string; // YYYY-MM-DD
};

export const CATEGORY_COLORS: Record<Category, string> = {
  work: '#3b82f6',
  personal: '#a855f7',
  health: '#22c55e',
  social: '#f97316',
};

import type { CalendarEvent, CreateEventInput, UpdateEventInput } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.json`;

const generateId = (): string => crypto.randomUUID();

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return JSON.parse(text) as CalendarEvent[];
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const event: CalendarEvent = { id: generateId(), ...input };
  events.push(event);
  await saveEvents(events);
  return event;
};

export const updateEvent = async (input: UpdateEventInput): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === input.id);
  if (idx === -1) return null;
  const updated = { ...events[idx], ...input };
  events[idx] = updated;
  await saveEvents(events);
  return updated;
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) return false;
  events.splice(idx, 1);
  await saveEvents(events);
  return true;
};

export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return expandRecurring(events, date, date);
};

export const getEventsForMonth = async (year: number, month: number): Promise<Map<string, CalendarEvent[]>> => {
  const events = await loadEvents();
  const daysInMonth = new Date(year, month, 0).getDate();
  const startDate = `${year}-${String(month).padStart(2, '0')}-01`;
  const endDate = `${year}-${String(month).padStart(2, '0')}-${String(daysInMonth).padStart(2, '0')}`;

  const expanded = expandRecurring(events, startDate, endDate);
  const byDate = new Map<string, CalendarEvent[]>();

  for (const event of expanded) {
    const existing = byDate.get(event.date) ?? [];
    existing.push(event);
    byDate.set(event.date, existing);
  }

  return byDate;
};

const expandRecurring = (events: CalendarEvent[], startDate: string, endDate: string): CalendarEvent[] => {
  const result: CalendarEvent[] = [];
  const start = new Date(startDate + 'T00:00:00');
  const end = new Date(endDate + 'T23:59:59');

  for (const event of events) {
    const eventDate = new Date(event.date + 'T00:00:00');

    if (event.recurrence === 'none') {
      if (eventDate >= start && eventDate <= end) {
        result.push(event);
      }
      continue;
    }

    const cursor = new Date(eventDate);
    while (cursor <= end) {
      if (cursor >= start) {
        const dateStr = formatDate(cursor);
        result.push({ ...event, date: dateStr });
      }

      switch (event.recurrence) {
        case 'daily':
          cursor.setDate(cursor.getDate() + 1);
          break;
        case 'weekly':
          cursor.setDate(cursor.getDate() + 7);
          break;
        case 'monthly':
          cursor.setMonth(cursor.getMonth() + 1);
          break;
      }
    }
  }

  return result.sort((a, b) => {
    const dateCmp = a.date.localeCompare(b.date);
    if (dateCmp !== 0) return dateCmp;
    return a.startTime.localeCompare(b.startTime);
  });
};

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

