const monthName = (month: number): string => {
  const names = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December',
  ];
  return names[month - 1];
};

const formatDisplayDate = (dateStr: string): string => {
  const [y, m, d] = dateStr.split('-').map(Number);
  const date = new Date(y, m - 1, d);
  return date.toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });
};

const padDate = (n: number): string => String(n).padStart(2, '0');

export const renderMonthView = async ({ year, month }: MonthViewParams) => {
  const eventsByDate = await getEventsForMonth(year, month);
  const firstDay = new Date(year, month - 1, 1).getDay();
  const daysInMonth = new Date(year, month, 0).getDate();
  const daysInPrevMonth = new Date(year, month - 1, 0).getDate();

  const todayStr = new Date().toISOString().slice(0, 10);

  const prevMonth = month === 1 ? 12 : month - 1;
  const prevYear = month === 1 ? year - 1 : year;
  const nextMonth = month === 12 ? 1 : month + 1;
  const nextYear = month === 12 ? year + 1 : year;

  const cells = [];

  // Leading days from previous month
  for (let i = firstDay - 1; i >= 0; i--) {
    const day = daysInPrevMonth - i;
    cells.push(
      h('div', { style: styles.dayCellOutside },
        h('div', { style: styles.dayNumber }, String(day))
      )
    );
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${padDate(month)}-${padDate(day)}`;
    const dayEvents = eventsByDate.get(dateStr) ?? [];
    const isToday = dateStr === todayStr;

    const cellStyle = isToday ? styles.dayCellToday : styles.dayCell;
    const numberStyle = isToday ? styles.todayNumber : styles.dayNumber;

    const eventIndicators = dayEvents.slice(0, 3).map((ev) =>
      h('div', { style: styles.eventChip(CATEGORY_COLORS[ev.category]) }, ev.title)
    );

    const overflow = dayEvents.length > 3
      ? h('div', { style: { fontSize: '11px', color: '#6b7280', marginTop: '2px' } },
          `+${dayEvents.length - 3} more`)
      : null;

    cells.push(
      h('div', {
        style: cellStyle,
        'p-trigger': JSON.stringify({ type: 'selectDay', detail: { date: dateStr } }),
      },
        h('div', { style: numberStyle }, String(day)),
        ...eventIndicators,
        ...(overflow ? [overflow] : [])
      )
    );
  }

  // Trailing days
  const totalCells = cells.length;
  const remaining = (7 - (totalCells % 7)) % 7;
  for (let i = 1; i <= remaining; i++) {
    cells.push(
      h('div', { style: styles.dayCellOutside },
        h('div', { style: styles.dayNumber }, String(i))
      )
    );
  }

  const dayHeaders = DAYS_OF_WEEK.map((d) =>
    h('div', { style: styles.dayHeader }, d)
  );

  return h('div', { style: styles.calendar },
    h('div', { style: styles.header },
      h('div', { style: styles.nav },
        h('button', {
          style: styles.navBtn,
          'p-trigger': JSON.stringify({ type: 'navigateMonth', detail: { year: prevYear, month: prevMonth } }),
        }, '\u2190 Prev'),
      ),
      h('div', { style: styles.title }, `${monthName(month)} ${year}`),
      h('div', { style: styles.nav },
        h('button', {
          style: styles.navBtn,
          'p-trigger': JSON.stringify({ type: 'navigateMonth', detail: { year: nextYear, month: nextMonth } }),
        }, 'Next \u2192'),
      ),
    ),
    h('div', { style: styles.grid },
      ...dayHeaders,
      ...cells
    )
  );
};

export const renderDayView = async (date: string) => {
  const events = await getEventsForDate(date);

  const eventCards = events.length > 0
    ? events.map((ev) =>
        h('div', {
          style: {
            ...styles.eventCard,
