import type { CalendarEvent, CreateEventInput, UpdateEventInput, Category, Recurrence } from './types';
import { createEvent, updateEvent, deleteEvent, loadEvents } from './store';
import { renderMonthView, renderDayView, renderEventForm } from './views';

export const handleNavigateMonth = async (detail: { year: number; month: number }) => {
  return renderMonthView({ year: detail.year, month: detail.month });
};

export const handleSelectDay = async (detail: { date: string }) => {
  return renderDayView(detail.date);
};

export const handleShowCreateForm = (detail: { date: string }) => {
  return renderEventForm({
    date: detail.date,
    startTime: '09:00',
    endTime: '10:00',
    category: 'work' as Category,
    recurrence: 'none' as Recurrence,
  });
};

export const handleShowEditForm = async (detail: { id: string }) => {
  const events = await loadEvents();
  const event = events.find((e) => e.id === detail.id);
  if (!event) return null;
  return renderEventForm({ ...event, formMode: 'edit' });
};

export const handleSubmitCreate = async (formData: {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description: string;
  category: string;
  recurrence: string;
}) => {
  const input: CreateEventInput = {
    title: formData.title,
    date: formData.date,
    startTime: formData.startTime,
    endTime: formData.endTime,
    description: formData.description,
    category: formData.category as Category,
    recurrence: (formData.recurrence || 'none') as Recurrence,
  };

  await createEvent(input);
  return renderDayView(input.date);
};

export const handleSubmitEdit = async (formData: {
  id: string;
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description: string;
  category: string;
  recurrence: string;
}) => {
  const input: UpdateEventInput = {
    id: formData.id,
    title: formData.title,
    date: formData.date,
    startTime: formData.startTime,
    endTime: formData.endTime,
    description: formData.description,
    category: formData.category as Category,
    recurrence: (formData.recurrence || 'none') as Recurrence,
  };

  const updated = await updateEvent(input);
  if (!updated) return null;
  return renderDayView(updated.date);
};

export const handleDeleteEvent = async (detail: { id: string }) => {
  const events = await loadEvents();
  const event = events.find((e) => e.id === detail.id);
  if (!event) return null;
  const date = event.date;
  await deleteEvent(detail.id);
  return renderDayView(date);
};

