{
  "name": "@node/chart-generator",
  "version": "1.0.0",
  "description": "Generate bar, line, and pie charts from JSON data with auto-detection of field types",
  "modnet": {
    "contentType": "data-visualization",
    "structure": "form",
    "mechanics": ["chart", "filter"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { DetectedSchema, FieldInfo } from './types'

const isNumericValue = (value: unknown): boolean => {
  if (typeof value === 'number' && !Number.isNaN(value)) return true
  if (typeof value === 'string' && value.trim() !== '' && !Number.isNaN(Number(value))) return true
  return false
}

export const detectSchema = (data: Record<string, unknown>[]): DetectedSchema => {
  if (data.length === 0) return { fields: [], numericFields: [], categoricalFields: [] }

  const allKeys = [...new Set(data.flatMap((row) => Object.keys(row)))]

  const fields: FieldInfo[] = allKeys.map((name) => {
    const values = data.map((row) => row[name]).filter((v) => v !== undefined && v !== null)
    const numericCount = values.filter(isNumericValue).length
    const isNumeric = values.length > 0 && numericCount / values.length >= 0.8
    return { name, type: isNumeric ? 'numeric' : 'categorical' }
  })

  return {
    fields,
    numericFields: fields.filter((f) => f.type === 'numeric').map((f) => f.name),
    categoricalFields: fields.filter((f) => f.type === 'categorical').map((f) => f.name),
  }
}

export const parseNumeric = (value: unknown): number => {
  if (typeof value === 'number') return value
  if (typeof value === 'string') return Number(value)
  return 0
}

import type { ChartConfig } from './types'
import { CHART_DEFAULTS, DEFAULT_COLORS } from './types'
import { parseNumeric } from './detect'

const escapeXml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

const formatNumber = (n: number): string => {
  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`
  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`
  if (Number.isInteger(n)) return String(n)
  return n.toFixed(1)
}

const niceScale = (min: number, max: number, ticks: number): number[] => {
  if (min === max) {
    const v = min === 0 ? 1 : Math.abs(min) * 0.5
    min = min - v
    max = max + v
  }
  const range = max - min
  const roughStep = range / ticks
  const magnitude = Math.pow(10, Math.floor(Math.log10(roughStep)))
  const residual = roughStep / magnitude
  const niceStep = residual <= 1.5 ? magnitude : residual <= 3 ? 2 * magnitude : residual <= 7 ? 5 * magnitude : 10 * magnitude
  const niceMin = Math.floor(min / niceStep) * niceStep
  const niceMax = Math.ceil(max / niceStep) * niceStep
  const result: number[] = []
  for (let v = niceMin; v <= niceMax + niceStep * 0.5; v += niceStep) {
    result.push(Math.round(v * 1e10) / 1e10)
  }
  return result
}

export const renderBarChart = (config: ChartConfig): string => {
  const { data, categoryField, valueFields, title, xLabel, yLabel, colors = DEFAULT_COLORS } = config
  const width = config.width ?? CHART_DEFAULTS.width
  const height = config.height ?? CHART_DEFAULTS.height
  const pad = CHART_DEFAULTS.padding

  const categories = data.map((row) => String(row[categoryField] ?? ''))
  const allValues = data.flatMap((row) => valueFields.map((f) => parseNumeric(row[f])))
  const minVal = Math.min(0, ...allValues)
  const maxVal = Math.max(0, ...allValues)
  const ticks = niceScale(minVal, maxVal, 5)
  const scaleMin = ticks[0]
  const scaleMax = ticks[ticks.length - 1]

  const plotW = width - pad.left - pad.right
  const plotH = height - pad.top - pad.bottom
  const groupWidth = plotW / categories.length
  const barWidth = (groupWidth * 0.7) / valueFields.length
  const barGap = groupWidth * 0.3 / (valueFields.length + 1)

  const yScale = (v: number) => pad.top + plotH - ((v - scaleMin) / (scaleMax - scaleMin)) * plotH
  const zeroY = yScale(0)

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">\n`
  svg += `<rect width="${width}" height="${height}" fill="#fff"/>\n`

  // Title
  if (title) {
    svg += `<text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">${escapeXml(title)}</text>\n`
  }

  // Y-axis gridlines and labels
  for (const tick of ticks) {
    const y = yScale(tick)
    svg += `<line x1="${pad.left}" y1="${y}" x2="${width - pad.right}" y2="${y}" stroke="#e0e0e0" stroke-width="1"/>\n`
    svg += `<text x="${pad.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${formatNumber(tick)}</text>\n`
  }

  // Axes
  svg += `<line x1="${pad.left}" y1="${pad.top}" x2="${pad.left}" y2="${height - pad.bottom}" stroke="#999" stroke-width="1"/>\n`
  svg += `<line x1="${pad.left}" y1="${zeroY}" x2="${width - pad.right}" y2="${zeroY}" stroke="#999" stroke-width="1"/>\n`

  // Bars
  categories.forEach((cat, i) => {
    const groupX = pad.left + i * groupWidth
    valueFields.forEach((field, j) => {
      const value = parseNumeric(data[i][field])
      const color = colors[j % colors.length]
      const barX = groupX + barGap * (j + 1) + barWidth * j
      const barY = value >= 0 ? yScale(value) : zeroY
      const barH = Math.abs(yScale(value) - zeroY)
      svg += `<rect x="${barX.toFixed(2)}" y="${barY.toFixed(2)}" width="${barWidth.toFixed(2)}" height="${barH.toFixed(2)}" fill="${color}" rx="2">\n`
      svg += `<title>${escapeXml(field)}: ${value}</title></rect>\n`
    })
    // X-axis label
    const labelX = groupX + groupWidth / 2
    svg += `<text x="${labelX.toFixed(2)}" y="${height - pad.bottom + 18}" text-anchor="middle" font-size="11" fill="#666">${escapeXml(cat)}</text>\n`
  })

  // Axis labels
  if (xLabel) {
    svg += `<text x="${width / 2}" y="${height - 8}" text-anchor="middle" font-size="12" fill="#555">${escapeXml(xLabel)}</text>\n`
  }
  if (yLabel) {
    svg += `<text x="16" y="${height / 2}" text-anchor="middle" font-size="12" fill="#555" transform="rotate(-90,16,${height / 2})">${escapeXml(yLabel)}</text>\n`
  }

  // Legend
  if (valueFields.length > 1) {
    const legendX = pad.left + 10
    const legendY = pad.top + 10
    valueFields.forEach((field, j) => {
      const y = legendY + j * 18
      const color = colors[j % colors.length]
      svg += `<rect x="${legendX}" y="${y - 9}" width="12" height="12" fill="${color}" rx="2"/>\n`
      svg += `<text x="${legendX + 18}" y="${y + 1}" font-size="11" fill="#555">${escapeXml(field)}</text>\n`
    })
  }

  svg += '</svg>'
  return svg
}

export const renderLineChart = (config: ChartConfig): string => {
  const { data, categoryField, valueFields, title, xLabel, yLabel, colors = DEFAULT_COLORS } = config
  const width = config.width ?? CHART_DEFAULTS.width
  const height = config.height ?? CHART_DEFAULTS.height
  const pad = CHART_DEFAULTS.padding

  const categories = data.map((row) => String(row[categoryField] ?? ''))
  const allValues = data.flatMap((row) => valueFields.map((f) => parseNumeric(row[f])))
  const minVal = Math.min(...allValues)
  const maxVal = Math.max(...allValues)
  const ticks = niceScale(minVal, maxVal, 5)
  const scaleMin = ticks[0]
  const scaleMax = ticks[ticks.length - 1]

  const plotW = width - pad.left - pad.right
  const plotH = height - pad.top - pad.bottom

  const xScale = (i: number) => pad.left + (categories.length > 1 ? (i / (categories.length - 1)) * plotW : plotW / 2)
  const yScale = (v: number) => pad.top + plotH - ((v - scaleMin) / (scaleMax - scaleMin)) * plotH

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">\n`
  svg += `<rect width="${width}" height="${height}" fill="#fff"/>\n`

  if (title) {
    svg += `<text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">${escapeXml(title)}</text>\n`
  }

  // Gridlines
  for (const tick of ticks) {
    const y = yScale(tick)
    svg += `<line x1="${pad.left}" y1="${y}" x2="${width - pad.right}" y2="${y}" stroke="#e0e0e0" stroke-width="1"/>\n`
    svg += `<text x="${pad.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${formatNumber(tick)}</text>\n`
  }

  // Axes
  svg += `<line x1="${pad.left}" y1="${pad.top}" x2="${pad.left}" y2="${height - pad.bottom}" stroke="#999" stroke-width="1"/>\n`
  svg += `<line x1="${pad.left}" y1="${height - pad.bottom}" x2="${width - pad.right}" y2="${height - pad.bottom}" stroke="#999" stroke-width="1"/>\n`

  // Lines and dots
  valueFields.forEach((field, j) => {
    const color = colors[j % colors.length]
    const points = data.map((row, i) => ({
      x: xScale(i),
      y: yScale(parseNumeric(row[field])),
      value: parseNumeric(row[field]),
    }))

    // Line path
    const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x.toFixed(2)},${p.y.toFixed(2)}`).join(' ')
    svg += `<path d="${pathD}" fill="none" stroke="${color}" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>\n`

    // Dots
    points.forEach((p, i) => {
      svg += `<circle cx="${p.x.toFixed(2)}" cy="${p.y.toFixed(2)}" r="4" fill="${color}" stroke="#fff" stroke-width="1.5">\n`
      svg += `<title>${escapeXml(field)} (${escapeXml(categories[i])}): ${p.value}</title></circle>\n`
    })
  })

  // X-axis labels
  const maxLabels = Math.floor(plotW / 50)
  const step = Math.max(1, Math.ceil(categories.length / maxLabels))
  categories.forEach((cat, i) => {
    if (i % step === 0) {
      svg += `<text x="${xScale(i).toFixed(2)}" y="${height - pad.bottom + 18}" text-anchor="middle" font-size="11" fill="#666">${escapeXml(cat)}</text>\n`
    }
  })

  if (xLabel) {
    svg += `<text x="${width / 2}" y="${height - 8}" text-anchor="middle" font-size="12" fill="#555">${escapeXml(xLabel)}</text>\n`
  }
  if (yLabel) {
    svg += `<text x="16" y="${height / 2}" text-anchor="middle" font-size="12" fill="#555" transform="rotate(-90,16,${height / 2})">${escapeXml(yLabel)}</text>\n`
  }

  // Legend
  if (valueFields.length > 1) {
    const legendX = pad.left + 10
    const legendY = pad.top + 10
    valueFields.forEach((field, j) => {
      const y = legendY + j * 18
      const color = colors[j % colors.length]
      svg += `<line x1="${legendX}" y1="${y - 3}" x2="${legendX + 12}" y2="${y - 3}" stroke="${color}" stroke-width="2.5"/>\n`
      svg += `<circle cx="${legendX + 6}" cy="${y - 3}" r="3" fill="${color}"/>\n`
      svg += `<text x="${legendX + 18}" y="${y + 1}" font-size="11" fill="#555">${escapeXml(field)}</text>\n`
    })
  }

  svg += '</svg>'
  return svg
}

export const renderPieChart = (config: ChartConfig): string => {
  const { data, categoryField, valueFields, title, colors = DEFAULT_COLORS } = config
  const width = config.width ?? CHART_DEFAULTS.width
  const height = config.height ?? CHART_DEFAULTS.height

  const valueField = valueFields[0]
  const slices = data
    .map((row) => ({
      label: String(row[categoryField] ?? ''),
      value: Math.max(0, parseNumeric(row[valueField])),
    }))
    .filter((s) => s.value > 0)

  const total = slices.reduce((sum, s) => sum + s.value, 0)
  if (total === 0) {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}"><text x="${width / 2}" y="${height / 2}" text-anchor="middle" fill="#999">No data</text></svg>`
  }

  const cx = width / 2
  const cy = height / 2 + 10
  const radius = Math.min(width, height) * 0.35

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">\n`
  svg += `<rect width="${width}" height="${height}" fill="#fff"/>\n`

  if (title) {
    svg += `<text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">${escapeXml(title)}</text>\n`
  }

  let currentAngle = -Math.PI / 2
  slices.forEach((slice, i) => {
    const sliceAngle = (slice.value / total) * 2 * Math.PI
    const startX = cx + radius * Math.cos(currentAngle)
    const startY = cy + radius * Math.sin(currentAngle)
    const endX = cx + radius * Math.cos(currentAngle + sliceAngle)
    const endY = cy + radius * Math.sin(currentAngle + sliceAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0
    const color = colors[i % colors.length]

    if (slices.length === 1) {
      svg += `<circle cx="${cx}" cy="${cy}" r="${radius}" fill="${color}">\n`
      svg += `<title>${escapeXml(slice.label)}: ${slice.value} (100%)</title></circle>\n`
    } else {
      svg += `<path d="M${cx},${cy} L${startX.toFixed(2)},${startY.toFixed(2)} A${radius},${radius} 0 ${largeArc},1 ${endX.toFixed(2)},${endY.toFixed(2)} Z" fill="${color}" stroke="#fff" stroke-width="2">\n`
      svg += `<title>${escapeXml(slice.label)}: ${slice.value} (${((slice.value / total) * 100).toFixed(1)}%)</title></path>\n`
    }

    // Percentage label on slice
    const midAngle = currentAngle + sliceAngle / 2
    const labelRadius = radius * 0.65
    const lx = cx + labelRadius * Math.cos(midAngle)
    const ly = cy + labelRadius * Math.sin(midAngle)
    const pct = (slice.value / total) * 100
    if (pct >= 5) {
      svg += `<text x="${lx.toFixed(2)}" y="${ly.toFixed(2)}" text-anchor="middle" dominant-baseline="central" font-size="12" font-weight="bold" fill="#fff">${pct.toFixed(0)}%</text>\n`
    }

    currentAngle += sliceAngle
  })

  // Legend
  const legendX = 16
  const legendY = height - slices.length * 18 - 8
  slices.forEach((slice, i) => {
    const y = legendY + i * 18
    const color = colors[i % colors.length]
    svg += `<rect x="${legendX}" y="${y - 9}" width="12" height="12" fill="${color}" rx="2"/>\n`
    svg += `<text x="${legendX + 18}" y="${y + 1}" font-size="11" fill="#555">${escapeXml(slice.label)}</text>\n`
  })

  svg += '</svg>'
  return svg
}

export const renderChart = (config: ChartConfig): string => {
  switch (config.chartType) {
    case 'bar':
      return renderBarChart(config)
    case 'line':
      return renderLineChart(config)
    case 'pie':
      return renderPieChart(config)
    default:
      throw new Error(`Unsupported chart type: ${config.chartType}`)
  }
}

