const SYNTAX_COLORS = {
  key: '#9876aa',
  string: '#6a8759',
  number: '#6897bb',
  boolean: '#cc7832',
  null: '#cc7832',
  brace: '#a9b7c6',
  comma: '#a9b7c6',
} as const

const highlightJson = (json: string): string => {
  return json.replace(
    /("(?:\\.|[^"\\])*")\s*(:)?|(\b(?:true|false)\b)|(\bnull\b)|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|([{}[\]])|([,:])/g,
    (match, str, colon, bool, nil, num, brace, punct) => {
      if (str) {
        const color = colon ? SYNTAX_COLORS.key : SYNTAX_COLORS.string
        return `<span style="color:${color}">${str}</span>${colon ? ':' : ''}`
      }
      if (bool) return `<span style="color:${SYNTAX_COLORS.boolean}">${match}</span>`
      if (nil) return `<span style="color:${SYNTAX_COLORS.null}">${match}</span>`
      if (num) return `<span style="color:${SYNTAX_COLORS.number}">${match}</span>`
      if (brace) return `<span style="color:${SYNTAX_COLORS.brace}">${match}</span>`
      if (punct) return `<span style="color:${SYNTAX_COLORS.comma}">${match}</span>`
      return match
    }
  )
}

