import { renderChart } from './charts'
import { detectSchema } from './detect'
import { renderPage } from './ui'
import type { ChartConfig, ChartType } from './types'
import { DEFAULT_COLORS } from './types'

const SAMPLE_DATA = JSON.stringify(
  [
    { month: 'Jan', revenue: 4200, expenses: 3100 },
    { month: 'Feb', revenue: 4800, expenses: 3400 },
    { month: 'Mar', revenue: 5100, expenses: 2900 },
    { month: 'Apr', revenue: 4600, expenses: 3200 },
    { month: 'May', revenue: 5800, expenses: 3800 },
    { month: 'Jun', revenue: 6200, expenses: 4100 },
  ],
  null,
  2
)

let lastSvg = ''

const dataDir = new URL('./data/', import.meta.url).pathname

const saveChart = async (svg: string, name: string) => {
  await Bun.write(`${dataDir}${name}.svg`, svg)
}

const parseFormBody = async (req: Request): Promise<Record<string, string | string[]>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string | string[]> = {}
  for (const [key, value] of params) {
    const existing = result[key]
    if (existing !== undefined) {
      result[key] = Array.isArray(existing) ? [...existing, value] : [existing, value]
    } else {
      result[key] = value
    }
  }
  return result
}

const parseColors = (colorsStr: string): string[] | undefined => {
  if (!colorsStr.trim()) return undefined
  return colorsStr
    .split(',')
    .map((c) => c.trim())
    .filter((c) => /^#[0-9a-fA-F]{3,8}$/.test(c))
}

const handleGenerate = async (req: Request): Promise<Response> => {
  const form = await parseFormBody(req)
  const jsonData = (form.jsonData as string) ?? SAMPLE_DATA
  const chartType = ((form.chartType as string) ?? 'bar') as ChartType
  const title = (form.title as string) ?? ''
  const xLabel = (form.xLabel as string) ?? ''
  const yLabel = (form.yLabel as string) ?? ''
  const colorsStr = (form.colors as string) ?? ''

  let data: Record<string, unknown>[]
  let jsonError: string | undefined

  try {
    const parsed = JSON.parse(jsonData)
    if (!Array.isArray(parsed)) throw new Error('Data must be a JSON array of objects')
    if (parsed.length === 0) throw new Error('Array must not be empty')
    if (typeof parsed[0] !== 'object' || parsed[0] === null) throw new Error('Array items must be objects')
    data = parsed
  } catch (e) {
    return new Response(
      renderPage({
        jsonData,
        chartType,
        categoryField: '',
        valueFields: [],
        title,
        xLabel,
        yLabel,
        colors: colorsStr,
        jsonError: e instanceof Error ? e.message : 'Invalid JSON',
      }),
      { headers: { 'Content-Type': 'text/html' } }
    )
  }

  const schema = detectSchema(data)
  const categoryField = (form.categoryField as string) || schema.categoricalFields[0] || schema.fields[0]?.name || ''
  const valueFieldsRaw = form.valueFields
  const valueFields = valueFieldsRaw
    ? Array.isArray(valueFieldsRaw)
      ? valueFieldsRaw
      : [valueFieldsRaw]
    : schema.numericFields.length > 0
      ? schema.numericFields
      : [schema.fields[1]?.name ?? schema.fields[0]?.name ?? '']

  const colors = parseColors(colorsStr)

  const config: ChartConfig = {
    data,
    chartType,
    categoryField,
    valueFields,
    title: title || undefined,
    xLabel: xLabel || undefined,
    yLabel: yLabel || undefined,
    colors: colors && colors.length > 0 ? colors : DEFAULT_COLORS,
  }

  const svg = renderChart(config)
  lastSvg = svg

  const timestamp = new Date().toISOString().replace(/[:.]/g, '-')
  await saveChart(svg, `chart-${timestamp}`)

  return new Response(
    renderPage({
      jsonData,
      chartType,
      categoryField,
      valueFields,
      title,
      xLabel,
      yLabel,
      colors: colorsStr,
      schema,
      svgOutput: svg,
    }),
    { headers: { 'Content-Type': 'text/html' } }
  )
}

const handleApiChart = async (req: Request): Promise<Response> => {
  try {
    const body = await req.json()
    const { data, chartType, categoryField, valueFields, title, xLabel, yLabel, colors } = body

    if (!Array.isArray(data) || data.length === 0) {
      return Response.json({ error: 'data must be a non-empty array' }, { status: 400 })
    }

    const schema = detectSchema(data)
    const config: ChartConfig = {
      data,
      chartType: chartType ?? 'bar',
      categoryField: categoryField ?? schema.categoricalFields[0] ?? schema.fields[0]?.name,
      valueFields: valueFields ?? schema.numericFields,
      title,
      xLabel,
      yLabel,
      colors: colors ?? DEFAULT_COLORS,
    }

    const svg = renderChart(config)
    lastSvg = svg
    return new Response(svg, {
      headers: { 'Content-Type': 'image/svg+xml' },
    })
  } catch (e) {
    return Response.json({ error: e instanceof Error ? e.message : 'Unknown error' }, { status: 400 })
  }
}

const handleDetect = async (req: Request): Promise<Response> => {
  try {
    const data = await req.json()
    if (!Array.isArray(data)) {
      return Response.json({ error: 'Must be an array' }, { status: 400 })
    }
    return Response.json(detectSchema(data))
  } catch (e) {
    return Response.json({ error: e instanceof Error ? e.message : 'Invalid JSON' }, { status: 400 })
  }
}

export default {
  port: 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const path = url.pathname

    if (req.method === 'GET' && path === '/') {
      const schema = detectSchema(JSON.parse(SAMPLE_DATA))
      return new Response(
        renderPage({
          jsonData: SAMPLE_DATA,
          chartType: 'bar',
          categoryField: schema.categoricalFields[0] ?? '',
          valueFields: schema.numericFields,
          title: '',
          xLabel: '',
          yLabel: '',
          colors: '',
          schema,
        }),
        { headers: { 'Content-Type': 'text/html' } }
      )
    }

    if (req.method === 'POST' && path === '/generate') {
      return handleGenerate(req)
    }

    if (req.method === 'POST' && path === '/api/chart') {
      return handleApiChart(req)
    }

    if (req.method === 'POST' && path === '/api/detect') {
      return handleDetect(req)
    }

    if (req.method === 'GET' && path === '/download') {
      if (!lastSvg) {
        return new Response('No chart generated yet', { status: 404 })
      }
      return new Response(lastSvg, {
        headers: {
          'Content-Type': 'image/svg+xml',
          'Content-Disposition': 'attachment; filename="chart.svg"',
        },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
}

