import type { DataRow, FieldInfo, AnalyzedData, FieldType } from './types'

const detectFieldType = (values: (string | number)[]): FieldType => {
  const numericCount = values.filter((v) => {
    if (typeof v === 'number') return true
    if (typeof v === 'string') {
      const trimmed = v.trim()
      return trimmed !== '' && !isNaN(Number(trimmed))
    }
    return false
  }).length
  return numericCount / values.length > 0.8 ? 'numeric' : 'categorical'
}

export const parseJsonInput = (input: string): DataRow[] => {
  const parsed = JSON.parse(input)
  if (!Array.isArray(parsed)) {
    throw new Error('Input must be a JSON array')
  }
  if (parsed.length === 0) {
    throw new Error('Array must not be empty')
  }
  if (typeof parsed[0] !== 'object' || parsed[0] === null) {
    throw new Error('Array items must be objects')
  }
  return parsed as DataRow[]
}

export const analyzeData = (rows: DataRow[]): AnalyzedData => {
  if (rows.length === 0) {
    return { rows, fields: [], numericFields: [], categoricalFields: [] }
  }

  const keys = Object.keys(rows[0])
  const fields: FieldInfo[] = keys.map((name) => {
    const values = rows.map((row) => row[name])
    const type = detectFieldType(values)
    return { name, type }
  })

  const numericFields = fields.filter((f) => f.type === 'numeric').map((f) => f.name)
  const categoricalFields = fields.filter((f) => f.type === 'categorical').map((f) => f.name)

  return { rows, fields, numericFields, categoricalFields }
}

export const coerceNumeric = (value: string | number): number => {
  if (typeof value === 'number') return value
  const n = Number(value)
  return isNaN(n) ? 0 : n
}

import { h } from 'plaited'
import type { ChartConfig, DataRow, ChartMargins } from './types'
import { coerceNumeric } from './analyze'

const MARGINS: ChartMargins = { top: 40, right: 20, bottom: 60, left: 60 }

const niceMax = (max: number): number => {
  if (max <= 0) return 10
  const magnitude = Math.pow(10, Math.floor(Math.log10(max)))
  const normalized = max / magnitude
  if (normalized <= 1) return magnitude
  if (normalized <= 2) return 2 * magnitude
  if (normalized <= 5) return 5 * magnitude
  return 10 * magnitude
}

const generateTicks = (max: number, count: number = 5): number[] => {
  const step = max / count
  return Array.from({ length: count + 1 }, (_, i) => Math.round(i * step))
}

const formatNumber = (n: number): string => {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`
  return String(n)
}

export const renderBarChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, xAxisLabel, yAxisLabel, categoryField, valueFields, colors } = config
  const plotW = width - MARGINS.left - MARGINS.right
  const plotH = height - MARGINS.top - MARGINS.bottom

  const allValues = data.flatMap((row) => valueFields.map((f) => coerceNumeric(row[f])))
  const maxVal = niceMax(Math.max(...allValues, 0))
  const ticks = generateTicks(maxVal)

  const groupCount = data.length
  const seriesCount = valueFields.length
  const groupWidth = plotW / groupCount
  const barPadding = 0.2
  const barGroupWidth = groupWidth * (1 - barPadding)
  const barWidth = barGroupWidth / seriesCount

  const bars = data.flatMap((row, gi) =>
    valueFields.map((field, si) => {
      const val = coerceNumeric(row[field])
      const barH = (val / maxVal) * plotH
      const x = MARGINS.left + gi * groupWidth + (groupWidth - barGroupWidth) / 2 + si * barWidth
      const y = MARGINS.top + plotH - barH
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth - 1),
        height: String(barH),
        fill: colors[si % colors.length],
      })
    }),
  )

  const xLabels = data.map((row, i) => {
    const cx = MARGINS.left + i * groupWidth + groupWidth / 2
    return h(
      'text',
      {
        x: String(cx),
        y: String(MARGINS.top + plotH + 20),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#555',
      },
      String(row[categoryField] ?? i),
    )
  })

  const yTickEls = ticks.map((t) => {
    const y = MARGINS.top + plotH - (t / maxVal) * plotH
    return h(
      'g',
      {},
      h('line', {
        x1: String(MARGINS.left),
        y1: String(y),
        x2: String(MARGINS.left + plotW),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h(
        'text',
        {
          x: String(MARGINS.left - 8),
          y: String(y + 4),
          'text-anchor': 'end',
          'font-size': '11',
          fill: '#555',
        },
        formatNumber(t),
      ),
    )
  })

  const legend =
    seriesCount > 1
      ? valueFields.map((field, i) =>
          h(
            'g',
            { transform: `translate(${MARGINS.left + i * 100}, ${height - 10})` },
            h('rect', { width: '12', height: '12', fill: colors[i % colors.length] }),
            h('text', { x: '16', y: '11', 'font-size': '11', fill: '#333' }, field),
          ),
        )
      : []

  return renderSvgWrapper(width, height, title, xAxisLabel, yAxisLabel, [
    ...yTickEls,
    ...bars,
    ...xLabels,
    ...legend,
  ])
}

export const renderLineChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, xAxisLabel, yAxisLabel, categoryField, valueFields, colors } = config
  const plotW = width - MARGINS.left - MARGINS.right
  const plotH = height - MARGINS.top - MARGINS.bottom

  const allValues = data.flatMap((row) => valueFields.map((f) => coerceNumeric(row[f])))
  const maxVal = niceMax(Math.max(...allValues, 0))
  const ticks = generateTicks(maxVal)

  const stepX = data.length > 1 ? plotW / (data.length - 1) : plotW / 2

  const lines = valueFields.map((field, si) => {
    const points = data.map((row, i) => {
      const x = MARGINS.left + i * stepX
      const y = MARGINS.top + plotH - (coerceNumeric(row[field]) / maxVal) * plotH
      return `${x},${y}`
    })
    return h(
      'g',
      {},
      h('polyline', {
        points: points.join(' '),
        fill: 'none',
        stroke: colors[si % colors.length],
        'stroke-width': '2',
        'stroke-linejoin': 'round',
      }),
      ...data.map((row, i) => {
        const x = MARGINS.left + i * stepX
        const y = MARGINS.top + plotH - (coerceNumeric(row[field]) / maxVal) * plotH
        return h('circle', {
          cx: String(x),
          cy: String(y),
          r: '4',
          fill: colors[si % colors.length],
        })
      }),
    )
  })

  const xLabels = data.map((row, i) => {
    const cx = MARGINS.left + i * stepX
    return h(
      'text',
      {
        x: String(cx),
        y: String(MARGINS.top + plotH + 20),
        'text-anchor': 'middle',
        'font-size': '11',
        fill: '#555',
      },
      String(row[categoryField] ?? i),
    )
  })

  const yTickEls = ticks.map((t) => {
    const y = MARGINS.top + plotH - (t / maxVal) * plotH
    return h(
      'g',
      {},
      h('line', {
        x1: String(MARGINS.left),
        y1: String(y),
        x2: String(MARGINS.left + plotW),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h(
        'text',
        {
          x: String(MARGINS.left - 8),
          y: String(y + 4),
          'text-anchor': 'end',
          'font-size': '11',
          fill: '#555',
        },
        formatNumber(t),
      ),
    )
  })

  const legend =
    valueFields.length > 1
      ? valueFields.map((field, i) =>
          h(
            'g',
            { transform: `translate(${MARGINS.left + i * 100}, ${height - 10})` },
            h('rect', { width: '12', height: '12', fill: colors[i % colors.length] }),
            h('text', { x: '16', y: '11', 'font-size': '11', fill: '#333' }, field),
          ),
        )
      : []

  return renderSvgWrapper(width, height, title, xAxisLabel, yAxisLabel, [
    ...yTickEls,
    ...lines,
    ...xLabels,
    ...legend,
  ])
}

export const renderPieChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, title, categoryField, valueFields, colors } = config
  const field = valueFields[0]
  if (!field) return '<svg></svg>'

  const cx = width / 2
  const cy = height / 2 + 10
  const radius = Math.min(width, height) / 2 - 60

  const values = data.map((row) => coerceNumeric(row[field]))
  const total = values.reduce((sum, v) => sum + v, 0)

  if (total === 0) return '<svg></svg>'

  let currentAngle = -Math.PI / 2
  const slices = data.map((row, i) => {
    const value = values[i]
    const sliceAngle = (value / total) * 2 * Math.PI
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const midAngle = startAngle + sliceAngle / 2
    const labelR = radius + 20
    const lx = cx + labelR * Math.cos(midAngle)
    const ly = cy + labelR * Math.sin(midAngle)
    const pct = ((value / total) * 100).toFixed(1)

    return h(
      'g',
      {},
      h('path', {
        d: `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`,
        fill: colors[i % colors.length],
        stroke: '#fff',
        'stroke-width': '2',
      }),
      h(
        'text',
        {
          x: String(lx),
          y: String(ly),
          'text-anchor': 'middle',
          'font-size': '11',
          fill: '#333',
        },
        `${String(row[categoryField] ?? i)} (${pct}%)`,
      ),
    )
  })

  const titleEl = title
    ? h(
        'text',
        {
          x: String(width / 2),
          y: '24',
          'text-anchor': 'middle',
          'font-size': '16',
          'font-weight': 'bold',
          fill: '#222',
        },
        title,
      )
    : ''

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">${titleEl}${slices.join('')}</svg>`
}

const renderSvgWrapper = (
  width: number,
  height: number,
  title: string,
  xAxisLabel: string,
  yAxisLabel: string,
  children: string[],
): string => {
  const plotH = height - MARGINS.top - MARGINS.bottom

  const titleEl = title
    ? h(
        'text',
        {
          x: String(width / 2),
          y: '24',
          'text-anchor': 'middle',
          'font-size': '16',
          'font-weight': 'bold',
          fill: '#222',
        },
        title,
      )
    : ''

  const xLabelEl = xAxisLabel
    ? h(
        'text',
        {
          x: String(width / 2),
          y: String(MARGINS.top + plotH + 45),
          'text-anchor': 'middle',
          'font-size': '13',
          fill: '#333',
        },
        xAxisLabel,
      )
    : ''

  const yLabelEl = yAxisLabel
    ? h(
        'text',
        {
          x: '15',
          y: String(MARGINS.top + plotH / 2),
          'text-anchor': 'middle',
          'font-size': '13',
          fill: '#333',
          transform: `rotate(-90, 15, ${MARGINS.top + plotH / 2})`,
        },
        yAxisLabel,
      )
    : ''

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">${titleEl}${xLabelEl}${yLabelEl}${children.join('')}</svg>`
}

import { h } from 'plaited'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'brace' | 'punctuation'

type Token = {
  type: TokenType
  value: string
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#9876AA',
  string: '#6A8759',
  number: '#6897BB',
  boolean: '#CC7832',
  null: '#CC7832',
  brace: '#A9B7C6',
  punctuation: '#A9B7C6',
}

const escapeHtml = (text: string): string =>
  text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

const tokenizeLine = (line: string): Token[] => {
  const tokens: Token[] = []
  let i = 0
  const src = line

  while (i < src.length) {
    if (src[i] === ' ' || src[i] === '\t') {
      let ws = ''
      while (i < src.length && (src[i] === ' ' || src[i] === '\t')) {
        ws += src[i]
        i++
      }
      tokens.push({ type: 'punctuation', value: ws })
      continue
    }

    if (src[i] === '{' || src[i] === '}' || src[i] === '[' || src[i] === ']') {
      tokens.push({ type: 'brace', value: src[i] })
      i++
      continue
    }

    if (src[i] === ',' || src[i] === ':') {
      tokens.push({ type: 'punctuation', value: src[i] })
      i++
      continue
    }

    if (src[i] === '"') {
      let str = '"'
      i++
      while (i < src.length && src[i] !== '"') {
        if (src[i] === '\\') {
          str += src[i]
          i++
        }
        if (i < src.length) {
          str += src[i]
          i++
        }
      }
      if (i < src.length) {
        str += '"'
        i++
      }
      const rest = src.slice(i).trimStart()
      const isKey = rest.startsWith(':')
      tokens.push({ type: isKey ? 'key' : 'string', value: str })
      continue
    }

    if (src.slice(i, i + 4) === 'true') {
      tokens.push({ type: 'boolean', value: 'true' })
      i += 4
      continue
    }
    if (src.slice(i, i + 5) === 'false') {
      tokens.push({ type: 'boolean', value: 'false' })
      i += 5
      continue
    }
    if (src.slice(i, i + 4) === 'null') {
      tokens.push({ type: 'null', value: 'null' })
      i += 4
      continue
    }

    if (src[i] === '-' || (src[i] >= '0' && src[i] <= '9')) {
      let num = ''
      while (i < src.length && /[0-9eE.+\-]/.test(src[i])) {
        num += src[i]
        i++
      }
      tokens.push({ type: 'number', value: num })
      continue
    }

    tokens.push({ type: 'punctuation', value: src[i] })
    i++
  }

  return tokens
}

export const highlightJson = (json: string): string => {
  const lines = json.split('\n')
  const highlighted = lines.map((line) => {
    const tokens = tokenizeLine(line)
    const spans = tokens.map((t) => {
      if (t.type === 'punctuation' && t.value.trim() === '') return escapeHtml(t.value)
      return h('span', { style: `color:${TOKEN_COLORS[t.type]}` }, escapeHtml(t.value))
    })
    return spans.join('')
  })
  return highlighted.join('\n')
}

export const renderJsonEditor = (value: string, errorMsg: string): string => {
  const editorStyles = {
    container: 'display:flex;flex-direction:column;gap:8px;width:100%',
    wrapper:
      'position:relative;border:1px solid #ccc;border-radius:6px;overflow:hidden;background:#2B2B2B',
    textarea:
      'width:100%;min-height:240px;padding:12px;font-family:monospace;font-size:13px;' +
      'line-height:1.5;border:none;resize:vertical;background:transparent;color:transparent;' +
      'caret-color:#A9B7C6;position:absolute;top:0;left:0;right:0;bottom:0;z-index:2;' +
      'white-space:pre;overflow:auto;outline:none;tab-size:2',
    highlight:
      'padding:12px;font-family:monospace;font-size:13px;line-height:1.5;white-space:pre;' +
      'overflow:auto;min-height:240px;color:#A9B7C6',
    error: 'color:#E45756;font-size:12px;padding:4px 8px;min-height:20px',
    label: 'font-weight:600;font-size:14px;color:#333',
  }

  const highlighted = highlightJson(value)

  return h(
    'div',
    { style: editorStyles.container },
    h('label', { style: editorStyles.label }, 'JSON Data Input'),
    h(
      'div',
      { style: editorStyles.wrapper },
      h('div', { style: editorStyles.highlight }, highlighted),
      h('textarea', {
        style: editorStyles.textarea,
        'p-target': 'json-input',
        'p-trigger': 'input:onJsonInput',
        spellcheck: 'false',
        autocomplete: 'off',
        autocorrect: 'off',
        autocapitalize: 'off',
      }, value),
    ),
    h('div', { style: editorStyles.error, 'p-target': 'json-error' }, errorMsg),
  )
}

