export const renderPage = (
  jsonInput: string,
  config: ChartConfig,
  errorMsg: string = '',
): string => {
  let chartSvg = ''
  let catFields: string[] = []
  let numFields: string[] = []
  let data: DataRow[] = []

  try {
    data = parseJsonInput(jsonInput)
    const analyzed = analyzeData(data)
    catFields = analyzed.categoricalFields
    numFields = analyzed.numericFields

    const resolvedConfig = { ...config }
    if (!resolvedConfig.categoryField && catFields.length > 0) {
      resolvedConfig.categoryField = catFields[0]
    }
    if (resolvedConfig.valueFields.length === 0 && numFields.length > 0) {
      resolvedConfig.valueFields = [numFields[0]]
    }

    chartSvg = renderChart(data, resolvedConfig)
  } catch (e) {
    errorMsg = e instanceof Error ? e.message : 'Invalid JSON'
  }

  const pageStyle =
    'max-width:960px;margin:0 auto;padding:24px;font-family:system-ui,-apple-system,sans-serif'
  const sectionStyle =
    'background:#fff;border:1px solid #e5e5e5;border-radius:8px;padding:20px;' +
    'display:flex;flex-direction:column;gap:16px'
  const headingStyle = 'font-size:24px;font-weight:700;color:#222;margin:0 0 8px 0'

  return h(
    'div',
    { style: `${pageStyle};display:flex;flex-direction:column;gap:20px;background:#f8f9fa` },
    h('h1', { style: headingStyle }, 'Chart Generator'),
    h(
      'div',
      { style: sectionStyle },
      renderJsonEditor(jsonInput, errorMsg),
    ),
    h(
      'div',
      { style: sectionStyle },
      h('span', { style: 'font-weight:600;font-size:14px;color:#333' }, 'Chart Type'),
      renderChartTypeSelector(config.chartType),
      renderFieldSelectors(catFields, numFields, config),
      renderCustomization(config),
      renderColorPicker(config.colors),
    ),
    h(
      'div',
      { style: `${sectionStyle};align-items:center` },
      h(
        'div',
        {
          style: 'width:100%;overflow-x:auto;display:flex;justify-content:center',
          'p-target': 'chart-output',
        },
        chartSvg,
      ),
      renderDownloadButton(),
    ),
  )
}

