const port = Number(Bun.env.PORT) || 3000

Bun.serve({
  port,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/api/render' && req.method === 'POST') {
      try {
        const body = await req.json() as { json: string; config: ChartConfig }
        const data = parseJsonInput(body.json)
        const analyzed = analyzeData(data)

        const config = { ...body.config }
        if (!config.categoryField && analyzed.categoricalFields.length > 0) {
          config.categoryField = analyzed.categoricalFields[0]
        }
        if (config.valueFields.length === 0 && analyzed.numericFields.length > 0) {
          config.valueFields = [analyzed.numericFields[0]]
        }

        const svg = renderChart(data, config)
        return new Response(
          JSON.stringify({
            svg,
            fields: analyzed.fields,
            numericFields: analyzed.numericFields,
            categoricalFields: analyzed.categoricalFields,
          }),
          { headers: { 'content-type': 'application/json' } },
        )
      } catch (e) {
        const msg = e instanceof Error ? e.message : 'Invalid request'
        return new Response(JSON.stringify({ error: msg }), {
          status: 400,
          headers: { 'content-type': 'application/json' },
        })
      }
    }

    if (url.pathname === '/api/download' && req.method === 'POST') {
      try {
        const body = await req.json() as { json: string; config: ChartConfig }
        const data = parseJsonInput(body.json)

        const config = { ...body.config }
        const analyzed = analyzeData(data)
        if (!config.categoryField && analyzed.categoricalFields.length > 0) {
          config.categoryField = analyzed.categoricalFields[0]
        }
        if (config.valueFields.length === 0 && analyzed.numericFields.length > 0) {
          config.valueFields = [analyzed.numericFields[0]]
        }

        const svg = renderChart(data, config)
        return new Response(svg, {
          headers: {
            'content-type': 'image/svg+xml',
            'content-disposition': `attachment; filename="chart-${config.chartType}.svg"`,
          },
        })
      } catch (e) {
        return new Response('Invalid data', { status: 400 })
      }
    }

    if (url.pathname === '/api/save' && req.method === 'POST') {
      try {
        const body = await req.json() as { name: string; json: string; config: ChartConfig }
        const savePath = `./data/${body.name.replace(/[^a-zA-Z0-9_-]/g, '_')}.json`
        await Bun.write(savePath, JSON.stringify({ json: body.json, config: body.config }, null, 2))
        return new Response(JSON.stringify({ saved: savePath }), {
          headers: { 'content-type': 'application/json' },
        })
      } catch (e) {
        return new Response(JSON.stringify({ error: 'Save failed' }), { status: 500 })
      }
    }

    const body = renderPage(SAMPLE_DATA, DEFAULT_CONFIG)
    return new Response(htmlShell(body), {
      headers: { 'content-type': 'text/html; charset=utf-8' },
    })
  },
})

