import type { ChartConfig, ChartType } from './types'
import { DEFAULT_CONFIG, DEFAULT_COLORS } from './types'

/**
 * Client-side interactivity for the chart generator.
 * Handles JSON input changes, chart type switching, field selection,
 * customization inputs, and SVG download.
 */

type AppState = {
  json: string
  config: ChartConfig
}

const state: AppState = {
  json: '',
  config: { ...DEFAULT_CONFIG, colors: [...DEFAULT_COLORS] },
}

const debounce = <T extends (...args: unknown[]) => void>(fn: T, ms: number): T => {
  let timer: ReturnType<typeof setTimeout>
  return ((...args: unknown[]) => {
    clearTimeout(timer)
    timer = setTimeout(() => fn(...args), ms)
  }) as unknown as T
}

const updateChart = async (): Promise<void> => {
  try {
    const res = await fetch('/api/render', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ json: state.json, config: state.config }),
    })
    const data = await res.json()

    const chartOutput = document.querySelector('[p-target="chart-output"]')
    const errorOutput = document.querySelector('[p-target="json-error"]')

    if (data.error) {
      if (errorOutput) errorOutput.textContent = data.error
      return
    }

    if (errorOutput) errorOutput.textContent = ''
    if (chartOutput) chartOutput.innerHTML = data.svg
  } catch {
    // Network error — silently ignore during typing
  }
}

const debouncedUpdate = debounce(updateChart, 300)

const initEventListeners = (): void => {
  document.addEventListener('input', (e) => {
    const target = e.target as HTMLElement

    if (target.matches('[p-trigger*="onJsonInput"]')) {
      state.json = (target as HTMLTextAreaElement).value
      debouncedUpdate()
      return
    }

    if (target.matches('[p-trigger*="onTitleChange"]')) {
      state.config.title = (target as HTMLInputElement).value
      debouncedUpdate()
      return
    }

    if (target.matches('[p-trigger*="onXLabelChange"]')) {
      state.config.xAxisLabel = (target as HTMLInputElement).value
      debouncedUpdate()
      return
    }

    if (target.matches('[p-trigger*="onYLabelChange"]')) {
      state.config.yAxisLabel = (target as HTMLInputElement).value
      debouncedUpdate()
      return
    }

    if (target.matches('[p-trigger*="onColorChange"]')) {
      const input = target as HTMLInputElement
      const index = Number(input.dataset.index)
      if (!isNaN(index)) {
        state.config.colors[index] = input.value
        debouncedUpdate()
      }
      return
    }
  })

  document.addEventListener('change', (e) => {
    const target = e.target as HTMLElement

    if (target.matches('[p-trigger*="onCategoryChange"]')) {
      state.config.categoryField = (target as HTMLSelectElement).value
      updateChart()
      return
    }

    if (target.matches('[p-trigger*="onValueFieldToggle"]')) {
      const checkbox = target as HTMLInputElement
      const field = checkbox.value
      if (checkbox.checked) {
        if (!state.config.valueFields.includes(field)) {
          state.config.valueFields.push(field)
        }
      } else {
        state.config.valueFields = state.config.valueFields.filter((f) => f !== field)
      }
      updateChart()
      return
    }
  })

  document.addEventListener('click', (e) => {
    const target = e.target as HTMLElement

    if (target.matches('[p-trigger*="onChartType"]')) {
      const type = target.dataset.type as ChartType
      if (type) {
        state.config.chartType = type
        document.querySelectorAll('[p-trigger*="onChartType"]').forEach((btn) => {
          const el = btn as HTMLElement
          const isActive = el.dataset.type === type
          el.style.background = isActive ? '#4C78A8' : '#fff'
          el.style.color = isActive ? '#fff' : '#4C78A8'
        })
        updateChart()
      }
      return
    }

    if (target.matches('[p-trigger*="onDownloadSvg"]')) {
      const chartOutput = document.querySelector('[p-target="chart-output"]')
      const svgContent = chartOutput?.innerHTML
      if (svgContent) {
        const blob = new Blob([svgContent], { type: 'image/svg+xml' })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = `chart-${state.config.chartType}.svg`
        a.click()
        URL.revokeObjectURL(url)
      }
      return
    }
  })
}

const initFromPage = (): void => {
  const textarea = document.querySelector('[p-target="json-input"]') as HTMLTextAreaElement | null
  if (textarea) {
    state.json = textarea.value
  }
}

if (typeof document !== 'undefined') {
  document.addEventListener('DOMContentLoaded', () => {
    initFromPage()
    initEventListeners()
  })
}

