import type { DataRecord, DetectedFields, FieldInfo } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

export const detectFields = (data: DataRecord[]): DetectedFields => {
  if (data.length === 0) return { numeric: [], categorical: [] }

  const fields = Object.keys(data[0])
  const numeric: string[] = []
  const categorical: string[] = []

  for (const field of fields) {
    const allNumeric = data.every((row) => isNumeric(row[field]))
    if (allNumeric) {
      numeric.push(field)
    } else {
      categorical.push(field)
    }
  }

  return { numeric, categorical }
}

export const getFieldInfos = (data: DataRecord[]): FieldInfo[] => {
  const detected = detectFields(data)
  return [
    ...detected.numeric.map((name) => ({ name, type: 'numeric' as const })),
    ...detected.categorical.map((name) => ({ name, type: 'categorical' as const })),
  ]
}

export const pickDefaults = (
  detected: DetectedFields,
): { categoryField: string | undefined; valueField: string | undefined } => {
  const categoryField = detected.categorical[0] ?? detected.numeric[0]
  const valueField =
    detected.numeric.find((f) => f !== categoryField) ?? detected.numeric[0]
  return { categoryField, valueField }
}

