export const PADDING = {
  top: 60,
  right: 40,
  bottom: 80,
  left: 70,
}

export const extractValues = (data: DataRecord[], field: string): number[] =>
  data.map((row) => {
    const v = row[field]
    return typeof v === 'number' ? v : Number(v)
  })

export const extractLabels = (data: DataRecord[], field: string): string[] =>
  data.map((row) => String(row[field]))

export const niceMax = (values: number[]): number => {
  const max = Math.max(...values)
  if (max === 0) return 10
  const magnitude = Math.pow(10, Math.floor(Math.log10(max)))
  return Math.ceil(max / magnitude) * magnitude
}

export const generateTicks = (max: number, count = 5): number[] => {
  const step = max / count
  return Array.from({ length: count + 1 }, (_, i) => Math.round(i * step))
}

export const escapeHtml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

import { h } from 'plaited'
import type { ChartConfig, DataRecord } from '../types'
import { DEFAULT_COLORS, DEFAULT_WIDTH, DEFAULT_HEIGHT } from '../types'
import { extractValues, extractLabels, escapeHtml } from './utils'

const polarToCartesian = (cx: number, cy: number, r: number, angle: number) => ({
  x: cx + r * Math.cos(angle),
  y: cy + r * Math.sin(angle),
})

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

export const renderPieChart = (data: DataRecord[], config: ChartConfig): string => {
  const {
    title = '',
    colors = DEFAULT_COLORS,
    categoryField = '',
    valueField = '',
    width = DEFAULT_WIDTH,
    height = DEFAULT_HEIGHT,
  } = config

  const labels = extractLabels(data, categoryField)
  const values = extractValues(data, valueField)
  const total = values.reduce((sum, v) => sum + Math.abs(v), 0)

  const cx = width / 2 - 80
  const cy = height / 2 + (title ? 15 : 0)
  const radius = Math.min(cx - 40, cy - 60, 180)

  let currentAngle = -Math.PI / 2

  const slices = values.map((v, i) => {
    const sliceAngle = total > 0 ? (Math.abs(v) / total) * 2 * Math.PI : 0
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const midAngle = startAngle + sliceAngle / 2
    const labelR = radius * 0.65
    const labelPos = polarToCartesian(cx, cy, labelR, midAngle)
    const pct = total > 0 ? Math.round((Math.abs(v) / total) * 100) : 0

    const color = colors[i % colors.length]

    return h('g', {},
      h('path', {
        d: describeArc(cx, cy, radius, startAngle, endAngle),
        fill: color,
        stroke: '#fff',
        'stroke-width': '2',
      }),
      pct >= 5
        ? h('text', {
            x: String(labelPos.x),
            y: String(labelPos.y),
            'text-anchor': 'middle',
            'dominant-baseline': 'central',
            'font-size': '12',
            'font-weight': 'bold',
            'font-family': 'system-ui, sans-serif',
            fill: '#fff',
          }, `${pct}%`)
        : '',
    )
  })

  const legendX = width - 200
  const legendStartY = LEGEND_TOP(height, labels.length)

  const legendItems = labels.map((label, i) => {
    const y = legendStartY + i * 24
    const color = colors[i % colors.length]
    const pct = total > 0 ? Math.round((Math.abs(values[i]) / total) * 100) : 0

    return h('g', {},
      h('rect', {
        x: String(legendX),
        y: String(y),
        width: '14',
        height: '14',
        rx: '3',
        fill: color,
      }),
      h('text', {
        x: String(legendX + 20),
        y: String(y + 11),
        'font-size': '12',
        'font-family': 'system-ui, sans-serif',
        fill: '#444',
      }, `${escapeHtml(label)} (${pct}%)`),
    )
  })

  const titleEl = title
    ? h('text', {
        x: String(width / 2),
        y: '30',
        'text-anchor': 'middle',
        'font-size': '18',
        'font-weight': 'bold',
        'font-family': 'system-ui, sans-serif',
        fill: '#222',
      }, escapeHtml(title))
    : ''

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
  },
    h('rect', { width: String(width), height: String(height), fill: '#fafafa' }),
    titleEl,
    ...slices,
    ...legendItems,
  )
}

const LEGEND_TOP = (height: number, count: number): number => {
  const totalLegendH = count * 24
  return Math.max(60, (height - totalLegendH) / 2)
}

