const syntaxHighlight = (json: string): string => {
  const escaped = json
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')

  return escaped.replace(
    /("(\\u[a-fA-F0-9]{4}|\\[^u]|[^\\"])*"(\s*:)?|\b(true|false|null)\b|-?\d+(?:\.\d*)?(?:[eE][+\-]?\d+)?)/g,
    (match) => {
      let cls = 'json-number'
      if (/^"/.test(match)) {
        cls = /:$/.test(match) ? 'json-key' : 'json-string'
      } else if (/true|false/.test(match)) {
        cls = 'json-boolean'
      } else if (/null/.test(match)) {
        cls = 'json-null'
      }
      return `<span class="${cls}">${match}</span>`
    },
  )
}

export const renderJsonEditor = (value: string, error?: string): string => {
  let highlighted = ''
  try {
    const parsed = JSON.parse(value)
    highlighted = syntaxHighlight(JSON.stringify(parsed, null, 2))
  } catch {
    highlighted = value
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
  }

  return h('div', { class: 'json-editor' },
    h('div', { class: 'editor-header' },
      h('span', { class: 'editor-title' }, 'JSON Data Input'),
      error ? h('span', { class: 'editor-error' }, error) : '',
    ),
    h('div', { class: 'editor-container' },
      h('div', { class: 'editor-highlight' },
        h('pre', {}, highlighted),
      ),
      h('textarea', {
        name: 'jsonData',
        class: 'editor-textarea',
        spellcheck: 'false',
        'p-trigger': 'input:updatePreview',
      }, value),
    ),
  )
}

