const renderPage = (
  jsonData: string,
  chartType: ChartType,
  config: Partial<ChartConfig>,
  error?: string,
): string => {
  let chartSvg = ''
  let fieldInfoHtml = ''
  let detectedCat: string[] = []
  let detectedNum: string[] = []

  try {
    const data: DataRecord[] = JSON.parse(jsonData)
    if (!Array.isArray(data) || data.length === 0) throw new Error('Data must be a non-empty array')

    const detected = detectFields(data)
    detectedCat = detected.categorical
    detectedNum = detected.numeric
    const defaults = pickDefaults(detected)

    const fullConfig: ChartConfig = {
      type: chartType,
      categoryField: config.categoryField || defaults.categoryField || '',
      valueField: config.valueField || defaults.valueField || '',
      title: config.title || '',
      xLabel: config.xLabel || '',
      yLabel: config.yLabel || '',
      colors: config.colors || DEFAULT_COLORS,
      width: config.width || 800,
      height: config.height || 500,
    }

    chartSvg = renderChart(data, fullConfig)
    fieldInfoHtml = h('div', { class: 'field-info' },
      h('strong', {}, 'Detected: '),
      `Numeric: ${detected.numeric.join(', ') || 'none'} | `,
