const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const extractConfig = (form: Record<string, string>): { jsonData: string; chartType: ChartType; config: Partial<ChartConfig> } => {
  const jsonData = form.jsonData || sampleData
  const chartType = (form.chartType || 'bar') as ChartType
  return {
    jsonData,
    chartType,
    config: {
      title: form.title,
      xLabel: form.xLabel,
      yLabel: form.yLabel,
      categoryField: form.categoryField,
      valueField: form.valueField,
    },
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'GET' && url.pathname === '/') {
      const html = renderPage(sampleData, 'bar', {})
      return new Response(html, { headers: { 'Content-Type': 'text/html' } })
    }

    if (req.method === 'POST' && url.pathname === '/') {
      const form = await parseForm(req)
      const { jsonData, chartType, config } = extractConfig(form)
      const html = renderPage(jsonData, chartType, config)
      return new Response(html, { headers: { 'Content-Type': 'text/html' } })
    }

    if (req.method === 'POST' && url.pathname === '/download') {
      const form = await parseForm(req)
      const { jsonData, chartType, config } = extractConfig(form)

      try {
        const data: DataRecord[] = JSON.parse(jsonData)
        const detected = detectFields(data)
        const defaults = pickDefaults(detected)

        const fullConfig: ChartConfig = {
          type: chartType,
          categoryField: config.categoryField || defaults.categoryField || '',
          valueField: config.valueField || defaults.valueField || '',
          title: config.title || '',
          xLabel: config.xLabel || '',
          yLabel: config.yLabel || '',
          colors: DEFAULT_COLORS,
        }

        const svg = renderChart(data, fullConfig)
        const svgContent = `<?xml version="1.0" encoding="UTF-8"?>\n${svg}`

        return new Response(svgContent, {
          headers: {
            'Content-Type': 'image/svg+xml',
            'Content-Disposition': `attachment; filename="chart-${chartType}.svg"`,
          },
        })
      } catch (e) {
        const html = renderPage(jsonData, chartType, config, e instanceof Error ? e.message : 'Error generating chart')
        return new Response(html, { headers: { 'Content-Type': 'text/html' } })
      }
    }

    if (req.method === 'POST' && url.pathname === '/api/chart') {
      try {
        const body = await req.json() as { data: DataRecord[]; config: ChartConfig }
        const { data, config } = body
        const detected = detectFields(data)
        const defaults = pickDefaults(detected)

        const fullConfig: ChartConfig = {
          ...config,
          categoryField: config.categoryField || defaults.categoryField || '',
          valueField: config.valueField || defaults.valueField || '',
        }

        const svg = renderChart(data, fullConfig)
        return new Response(JSON.stringify({ svg, fields: detected }), {
          headers: { 'Content-Type': 'application/json' },
        })
      } catch (e) {
        return new Response(JSON.stringify({ error: e instanceof Error ? e.message : 'Unknown error' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' },
        })
      }
    }

    return new Response('Not Found', { status: 404 })
  },
})

