export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export type ColorValue = {
  hex: string
  rgb: RGB
  hsl: HSL
}

export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.max(0, Math.min(255, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const toColorValue = (hex: string): ColorValue => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: hex.toLowerCase().startsWith('#') ? hex.toLowerCase() : `#${hex.toLowerCase()}`, rgb, hsl }
}

export const hslShift = (base: HSL, degrees: number): HSL => ({
  h: ((base.h + degrees) % 360 + 360) % 360,
  s: base.s,
  l: base.l,
})

export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

import { type ColorValue, type HSL, hslShift, hslToRgb, rgbToHex, rgbToHsl, hexToRgb, toColorValue } from './color-utils'

export type HarmonyType =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  name: HarmonyType
  base: ColorValue
  colors: ColorValue[]
}

const hslToColorValue = (hsl: HSL): ColorValue => {
  const rgb = hslToRgb(hsl)
  const hex = rgbToHex(rgb)
  return { hex, rgb, hsl: rgbToHsl(rgb) }
}

const generateComplementary = (baseHsl: HSL): HSL[] => [
  baseHsl,
  hslShift(baseHsl, 180),
]

const generateAnalogous = (baseHsl: HSL): HSL[] => [
  hslShift(baseHsl, -30),
  baseHsl,
  hslShift(baseHsl, 30),
]

const generateTriadic = (baseHsl: HSL): HSL[] => [
  baseHsl,
  hslShift(baseHsl, 120),
  hslShift(baseHsl, 240),
]

const generateSplitComplementary = (baseHsl: HSL): HSL[] => [
  baseHsl,
  hslShift(baseHsl, 150),
  hslShift(baseHsl, 210),
]

const generateTetradic = (baseHsl: HSL): HSL[] => [
  baseHsl,
  hslShift(baseHsl, 60),
  hslShift(baseHsl, 180),
  hslShift(baseHsl, 240),
]

const generators: Record<HarmonyType, (hsl: HSL) => HSL[]> = {
  complementary: generateComplementary,
  analogous: generateAnalogous,
  triadic: generateTriadic,
  'split-complementary': generateSplitComplementary,
  tetradic: generateTetradic,
}

export const generatePalette = (hexColor: string, harmony: HarmonyType): Palette => {
  const base = toColorValue(hexColor)
  const baseHsl: HSL = { h: base.hsl.h, s: base.hsl.s, l: base.hsl.l }
  const hslColors = generators[harmony](baseHsl)
  const colors = hslColors.map(hslToColorValue)
  return { name: harmony, base, colors }
}

export const generateAllPalettes = (hexColor: string): Palette[] => {
  const types: HarmonyType[] = [
    'complementary',
    'analogous',
    'triadic',
    'split-complementary',
    'tetradic',
  ]
  return types.map((type) => generatePalette(hexColor, type))
}

export const HARMONY_TYPES: HarmonyType[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

import type { RGB, ColorValue } from './color-utils'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioText: string
  normalTextAA: boolean
  normalTextAAA: boolean
  largeTextAA: boolean
  largeTextAAA: boolean
  uiComponentAA: boolean
  level: WcagLevel
}

const relativeLuminance = (rgb: RGB): number => {
  const [rs, gs, bs] = [rgb.r, rgb.g, rgb.b].map((c) => {
    const s = c / 255
    return s <= 0.03928 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4)
  })
  return 0.2126 * rs + 0.7152 * gs + 0.0722 * bs
}

export const contrastRatio = (color1: RGB, color2: RGB): number => {
  const l1 = relativeLuminance(color1)
  const l2 = relativeLuminance(color2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

export const checkContrast = (color1: ColorValue, color2: ColorValue): ContrastResult => {
  const ratio = contrastRatio(color1.rgb, color2.rgb)
  const rounded = Math.round(ratio * 100) / 100

  const normalTextAA = ratio >= 4.5
  const normalTextAAA = ratio >= 7
  const largeTextAA = ratio >= 3
  const largeTextAAA = ratio >= 4.5
  const uiComponentAA = ratio >= 3

  const level: WcagLevel = normalTextAAA ? 'AAA' : normalTextAA ? 'AA' : 'Fail'

  return {
    ratio: rounded,
    ratioText: `${rounded.toFixed(2)}:1`,
    normalTextAA,
    normalTextAAA,
    largeTextAA,
    largeTextAAA,
    uiComponentAA,
    level,
  }
}

