import { isValidHex, toColorValue, formatRgb, formatHsl } from './color-utils'
import type { ColorValue } from './color-utils'
import { generatePalette, generateAllPalettes, HARMONY_TYPES } from './palette'
import type { HarmonyType, Palette } from './palette'
import { checkContrast, contrastRatio } from './contrast'
import type { ContrastResult } from './contrast'
import { renderFullPage, renderPalette } from './render'

export type PaletteRequest = {
  baseColor: string
  harmony?: HarmonyType | 'all'
}

export type PaletteResponse = {
  palettes: Palette[]
  html: string
}

const DEFAULT_BASE_COLOR = '#3a86ff'
const SAVED_PALETTES_PATH = './data/saved-palettes.json'

export const generate = (request: PaletteRequest): PaletteResponse => {
  const hex = request.baseColor.startsWith('#') ? request.baseColor : `#${request.baseColor}`

  if (!isValidHex(hex)) {
    throw new Error(`Invalid hex color: ${hex}. Expected format: #RGB or #RRGGBB`)
  }

  const harmony = request.harmony ?? 'all'
  const palettes =
    harmony === 'all' ? generateAllPalettes(hex) : [generatePalette(hex, harmony)]

  const html = renderFullPage(palettes, hex)
  return { palettes, html }
}

export const getContrastBetween = (hex1: string, hex2: string): ContrastResult => {
  if (!isValidHex(hex1) || !isValidHex(hex2)) {
    throw new Error('Invalid hex color provided')
  }
  const c1 = toColorValue(hex1)
  const c2 = toColorValue(hex2)
  return checkContrast(c1, c2)
}

export const savePalette = async (palette: Palette, label?: string) => {
  const entry = {
    label: label ?? `${palette.name}-${palette.base.hex}`,
    createdAt: new Date().toISOString(),
    harmony: palette.name,
    baseColor: palette.base.hex,
    colors: palette.colors.map((c) => c.hex),
  }

  const file = Bun.file(SAVED_PALETTES_PATH)
  const existing = (await file.exists()) ? await file.json() : []
  existing.push(entry)
  await Bun.write(SAVED_PALETTES_PATH, JSON.stringify(existing, null, 2))
  return entry
}

export const loadSavedPalettes = async () => {
  const file = Bun.file(SAVED_PALETTES_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

// CLI entrypoint
const main = async () => {
  const args = process.argv.slice(2)
  const baseColor = args[0] ?? DEFAULT_BASE_COLOR
  const harmony = (args[1] as HarmonyType | 'all') ?? 'all'

  const { palettes, html } = generate({ baseColor, harmony })

  // Write HTML output
  const outputPath = './data/palette.html'
  await Bun.write(outputPath, html)

  // Print palette summary to console
  for (const palette of palettes) {
    console.log(`\n${palette.name.toUpperCase()} palette:`)
    for (const color of palette.colors) {
      console.log(`  ${color.hex}  ${formatRgb(color.rgb)}  ${formatHsl(color.hsl)}`)
    }

    // Show contrast between all pairs
    console.log('  Contrast:')
    for (let i = 0; i < palette.colors.length; i++) {
      for (let j = i + 1; j < palette.colors.length; j++) {
        const result = checkContrast(palette.colors[i], palette.colors[j])
        console.log(
          `    ${palette.colors[i].hex} vs ${palette.colors[j].hex}: ${result.ratioText} [${result.level}]`
        )
      }
    }
  }

  console.log(`\nHTML output written to ${outputPath}`)
}

main().catch(console.error)

