          },
          ...harmonyModes.map((m) => renderModeOption(m, selectedMode)),
        ),
      ),
      h(
        'button',
        { style: styles.generateBtn, 'p-trigger': 'generate' },
        'Generate',
      ),
    ),
    palette
      ? h(
