          ),
        )
      : null,
    palette ? renderContrastChecker(color1, color2, contrastResult) : null,
  )
}

export const renderToHtml = async (
  palette: Palette | null,
  selectedMode: HarmonyMode,
  baseHex: string,
  selectedIndices: number[],
  contrastResult: ContrastResult | null,
): Promise<string> => {
  const ssr = createSSR()
  const template = renderPage(palette, selectedMode, baseHex, selectedIndices, contrastResult)
  const body = ssr(template)
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
