}

import { createColor, isValidHex } from './color.ts'
import type { Color } from './color.ts'
import { generatePalette, harmonyModes } from './harmony.ts'
import type { HarmonyMode, Palette } from './harmony.ts'
import { checkContrast } from './contrast.ts'
import type { ContrastResult } from './contrast.ts'
import { renderToHtml } from './ui.ts'

export type AppState = {
  baseHex: string
  mode: HarmonyMode
  palette: Palette | null
  selectedIndices: number[]
  contrastResult: ContrastResult | null
}

const DATA_PATH = './data/palettes.json'

const createInitialState = (baseHex = '#3a86ff', mode: HarmonyMode = 'complementary'): AppState => {
  const base = createColor(baseHex)
  const palette = generatePalette(base, mode)
  return {
    baseHex,
    mode,
    palette,
    selectedIndices: [],
    contrastResult: null,
  }
}

export const generate = (baseHex: string, mode: HarmonyMode): AppState => {
  if (!isValidHex(baseHex)) {
    throw new Error(`Invalid hex color: ${baseHex}`)
  }
  const normalized = baseHex.startsWith('#') ? baseHex : `#${baseHex}`
  const base = createColor(normalized)
  const palette = generatePalette(base, mode)
  return {
    baseHex: normalized,
    mode,
    palette,
    selectedIndices: [],
    contrastResult: null,
  }
}

export const selectColor = (state: AppState, colorIndex: number): AppState => {
  if (!state.palette) return state
  const indices = [...state.selectedIndices]
  const existing = indices.indexOf(colorIndex)
  if (existing >= 0) {
    indices.splice(existing, 1)
  } else {
    if (indices.length >= 2) indices.shift()
    indices.push(colorIndex)
  }
  let contrastResult: ContrastResult | null = null
  if (indices.length === 2) {
    const c1 = state.palette.colors[indices[0]]
    const c2 = state.palette.colors[indices[1]]
    contrastResult = checkContrast(c1.rgb, c2.rgb)
  }
  return { ...state, selectedIndices: indices, contrastResult }
}

export const savePalette = async (state: AppState): Promise<void> => {
  if (!state.palette) return
  const file = Bun.file(DATA_PATH)
  let palettes: Palette[] = []
  if (await file.exists()) {
    palettes = await file.json()
  }
  palettes.push(state.palette)
  await Bun.write(DATA_PATH, JSON.stringify(palettes, null, 2))
}

export const loadPalettes = async (): Promise<Palette[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

export const render = async (state: AppState): Promise<string> =>
  renderToHtml(state.palette, state.mode, state.baseHex, state.selectedIndices, state.contrastResult)

const serve = () => {
  let state = createInitialState()

  return Bun.serve({
    port: 3000,
    async fetch(req) {
      const url = new URL(req.url)

      if (url.pathname === '/api/generate' && req.method === 'POST') {
        const body = await req.json() as { hex?: string; mode?: HarmonyMode }
        const hex = body.hex ?? state.baseHex
        const mode = body.mode && harmonyModes.includes(body.mode) ? body.mode : state.mode
        state = generate(hex, mode)
        return Response.json({ palette: state.palette })
      }

      if (url.pathname === '/api/select' && req.method === 'POST') {
        const body = await req.json() as { index: number }
        state = selectColor(state, body.index)
        return Response.json({
          selectedIndices: state.selectedIndices,
          contrastResult: state.contrastResult,
        })
      }

      if (url.pathname === '/api/save' && req.method === 'POST') {
        await savePalette(state)
        return Response.json({ ok: true })
      }

      if (url.pathname === '/api/palettes') {
        const palettes = await loadPalettes()
        return Response.json(palettes)
      }

      const html = await render(state)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    },
  })
}

export {
  createColor,
  isValidHex,
  generatePalette,
  checkContrast,
  harmonyModes,
  serve,
}
export type { Color, HarmonyMode, Palette, ContrastResult }

if (import.meta.main) {
  const server = serve()
  console.log(`Color Palette Generator running at http://localhost:${server.port}`)
}

