// Color type definitions and conversion utilities

export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export type Color = {
  hex: string
  rgb: RGB
  hsl: HSL
}

export type HarmonyType =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  id: string
  baseColor: Color
  harmony: HarmonyType
  colors: Color[]
  createdAt: string
}

export type ContrastResult = {
  ratio: number
  aa: { normalText: boolean; largeText: boolean }
  aaa: { normalText: boolean; largeText: boolean }
}

// --- Hex parsing ---

const parseHex = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean

  if (!/^[0-9a-fA-F]{6}$/.test(full)) {
    throw new Error(`Invalid hex color: ${hex}`)
  }

  return {
    r: parseInt(full.slice(0, 2), 16),
    g: parseInt(full.slice(2, 4), 16),
    b: parseInt(full.slice(4, 6), 16),
  }
}

// --- RGB ↔ HSL ---

const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255

  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const delta = max - min

  let h = 0
  const l = (max + min) / 2
  let s = 0

  if (delta !== 0) {
    s = l > 0.5 ? delta / (2 - max - min) : delta / (max + min)

    if (max === rn) {
      h = ((gn - bn) / delta + (gn < bn ? 6 : 0)) / 6
    } else if (max === gn) {
      h = ((bn - rn) / delta + 2) / 6
    } else {
      h = ((rn - gn) / delta + 4) / 6
    }
  }

  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const sn = s / 100
  const ln = l / 100

  const c = (1 - Math.abs(2 * ln - 1)) * sn
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = ln - c / 2

  let rn: number, gn: number, bn: number

  if (h < 60) {
    ;[rn, gn, bn] = [c, x, 0]
  } else if (h < 120) {
    ;[rn, gn, bn] = [x, c, 0]
  } else if (h < 180) {
    ;[rn, gn, bn] = [0, c, x]
  } else if (h < 240) {
    ;[rn, gn, bn] = [0, x, c]
  } else if (h < 300) {
    ;[rn, gn, bn] = [x, 0, c]
  } else {
    ;[rn, gn, bn] = [c, 0, x]
  }

  return {
    r: Math.round((rn + m) * 255),
    g: Math.round((gn + m) * 255),
    b: Math.round((bn + m) * 255),
  }
}

const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (n: number) => n.toString(16).padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

// --- Public converters ---

export const hexToColor = (hex: string): Color => {
  const rgb = parseHex(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

export const hslToColor = (hsl: HSL): Color => {
  const normalizedH = ((hsl.h % 360) + 360) % 360
  const normalizedHsl = { h: normalizedH, s: hsl.s, l: hsl.l }
  const rgb = hslToRgb(normalizedHsl)
  return { hex: rgbToHex(rgb), rgb, hsl: normalizedHsl }
}

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`

export const formatHsl = ({ h, s, l }: HSL): string => `hsl(${h}, ${s}%, ${l}%)`

// Color harmony generation using color theory rules

import { hexToColor, hslToColor } from './color.ts'
import type { Color, HarmonyType } from './color.ts'

const rotateHue = (base: Color, degrees: number): Color =>
  hslToColor({
    h: base.hsl.h + degrees,
    s: base.hsl.s,
    l: base.hsl.l,
  })

// Two colors opposite on the color wheel
const complementary = (base: Color): Color[] => [base, rotateHue(base, 180)]

// Three colors adjacent on the color wheel
const analogous = (base: Color): Color[] => [rotateHue(base, -30), base, rotateHue(base, 30)]

// Three colors evenly spaced at 120deg intervals
const triadic = (base: Color): Color[] => [base, rotateHue(base, 120), rotateHue(base, 240)]

// Base color plus two colors flanking its complement
const splitComplementary = (base: Color): Color[] => [
  base,
  rotateHue(base, 150),
  rotateHue(base, 210),
]

// Four colors forming a rectangle on the wheel
const tetradic = (base: Color): Color[] => [
  base,
  rotateHue(base, 60),
  rotateHue(base, 180),
  rotateHue(base, 240),
]

const generators: Record<HarmonyType, (base: Color) => Color[]> = {
  complementary,
  analogous,
  triadic,
  'split-complementary': splitComplementary,
  tetradic,
}

export const generatePalette = (baseHex: string, harmony: HarmonyType): Color[] => {
  const base = hexToColor(baseHex)
  const generator = generators[harmony]
  if (!generator) {
    throw new Error(`Unknown harmony type: ${harmony}`)
  }
  return generator(base)
}

export const harmonyTypes: HarmonyType[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

export const harmonyDescriptions: Record<HarmonyType, string> = {
  complementary: 'Two colors opposite on the color wheel',
  analogous: 'Three adjacent colors on the color wheel',
  triadic: 'Three colors evenly spaced at 120\u00b0',
  'split-complementary': 'Base color plus two flanking its complement',
  tetradic: 'Four colors forming a rectangle on the wheel',
}

// WCAG contrast ratio calculation

import type { Color, ContrastResult } from './color.ts'

// Relative luminance per WCAG 2.1 spec
// https://www.w3.org/TR/WCAG21/#dfn-relative-luminance
const relativeLuminance = (color: Color): number => {
  const linearize = (channel: number): number => {
    const srgb = channel / 255
    return srgb <= 0.03928 ? srgb / 12.92 : Math.pow((srgb + 0.055) / 1.055, 2.4)
  }

  const r = linearize(color.rgb.r)
  const g = linearize(color.rgb.g)
  const b = linearize(color.rgb.b)

  return 0.2126 * r + 0.7152 * g + 0.0722 * b
}

// Contrast ratio per WCAG 2.1 spec
// https://www.w3.org/TR/WCAG21/#dfn-contrast-ratio
const contrastRatio = (color1: Color, color2: Color): number => {
  const l1 = relativeLuminance(color1)
  const l2 = relativeLuminance(color2)

  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)

  return (lighter + 0.05) / (darker + 0.05)
}

export const checkContrast = (color1: Color, color2: Color): ContrastResult => {
  const ratio = Math.round(contrastRatio(color1, color2) * 100) / 100

  return {
    ratio,
    aa: {
      normalText: ratio >= 4.5,
      largeText: ratio >= 3,
    },
    aaa: {
      normalText: ratio >= 7,
      largeText: ratio >= 4.5,
    },
  }
}

export const formatRatio = (ratio: number): string => `${ratio.toFixed(2)}:1`

// Palette persistence using Bun file APIs

import type { Palette, HarmonyType } from './color.ts'
import { hexToColor } from './color.ts'
import { generatePalette } from './harmony.ts'

const DATA_PATH = new URL('./data/palettes.json', import.meta.url).pathname

const readPalettes = async (): Promise<Palette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Palette[]
}

const writePalettes = async (palettes: Palette[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(palettes, null, 2))
}

export const createPalette = async (baseHex: string, harmony: HarmonyType): Promise<Palette> => {
  const palettes = await readPalettes()
  const baseColor = hexToColor(baseHex)
  const colors = generatePalette(baseHex, harmony)

  const palette: Palette = {
    id: crypto.randomUUID(),
    baseColor,
    harmony,
    colors,
    createdAt: new Date().toISOString(),
  }

  palettes.push(palette)
  await writePalettes(palettes)
  return palette
}

export const listPalettes = async (): Promise<Palette[]> => {
  return readPalettes()
}

export const getPalette = async (id: string): Promise<Palette | undefined> => {
  const palettes = await readPalettes()
  return palettes.find((p) => p.id === id)
}

export const deletePalette = async (id: string): Promise<boolean> => {
  const palettes = await readPalettes()
  const filtered = palettes.filter((p) => p.id !== id)
  if (filtered.length === palettes.length) return false
  await writePalettes(filtered)
  return true
}

