// HTTP server for the color palette generator

import { createSSR } from 'plaited'
import { hexToColor } from './color.ts'
import type { HarmonyType } from './color.ts'
import { generatePalette, harmonyTypes } from './harmony.ts'
import { checkContrast, formatRatio } from './contrast.ts'
import { createPalette, listPalettes, deletePalette } from './store.ts'
import { renderPage } from './render.ts'
import type { RenderState } from './render.ts'

const ssr = createSSR()

const defaultState: RenderState = {
  baseHex: '#4361ee',
  harmony: 'complementary',
  colors: [],
  selectedColors: [null, null],
}

const htmlShell = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Color Palette Generator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #fafafa; min-height: 100vh; }
    button:hover { opacity: 0.85; }
    .swatch-card:hover { transform: translateY(-2px); box-shadow: 0 4px 16px rgba(0,0,0,0.12); }
  </style>
  <script>
    const copyToClipboard = async (text) => {
      try {
        await navigator.clipboard.writeText(text);
        const toast = document.createElement('div');
        toast.textContent = 'Copied: ' + text;
        toast.style.cssText = 'position:fixed;bottom:24px;right:24px;background:#333;color:#fff;padding:10px 20px;border-radius:8px;font-size:14px;z-index:1000;animation:fadeout 2s forwards';
        document.body.appendChild(toast);
        setTimeout(() => toast.remove(), 2000);
      } catch(e) { /* clipboard not available */ }
    };

    document.addEventListener('click', (e) => {
      const copyBtn = e.target.closest('[p-trigger*="copy-value"]');
      if (copyBtn) {
        e.preventDefault();
        copyToClipboard(copyBtn.dataset.value);
        return;
      }

      const selectBtn = e.target.closest('[p-trigger*="select-color"]');
      if (selectBtn) {
        const hex = selectBtn.dataset.hex;
        const allSwatches = document.querySelectorAll('[p-trigger*="select-color"]');
        const selected = document.querySelectorAll('[p-trigger*="select-color"].selected');

        if (selectBtn.classList.contains('selected')) {
          selectBtn.classList.remove('selected');
          selectBtn.style.outline = '';
          return;
        }

        if (selected.length >= 2) {
          selected[0].classList.remove('selected');
          selected[0].style.outline = '';
        }

        selectBtn.classList.add('selected');
        selectBtn.style.outline = '3px solid #4361ee';

        const nowSelected = document.querySelectorAll('[p-trigger*="select-color"].selected');
        if (nowSelected.length === 2) {
          const hex1 = nowSelected[0].dataset.hex;
          const hex2 = nowSelected[1].dataset.hex;
          window.location.href = window.location.pathname + window.location.search + '&c1=' + encodeURIComponent(hex1) + '&c2=' + encodeURIComponent(hex2);
        }
      }
    });
  </script>
  <style>
    @keyframes fadeout { 0% { opacity: 1; } 70% { opacity: 1; } 100% { opacity: 0; } }
  </style>
</head>
<body>${body}</body>
</html>`

const isValidHex = (hex: string): boolean => /^#?[0-9a-fA-F]{3,6}$/.test(hex)

const normalizeHex = (hex: string): string => {
  const clean = hex.startsWith('#') ? hex : `#${hex}`
  return clean.length === 4
    ? `#${clean[1]}${clean[1]}${clean[2]}${clean[2]}${clean[3]}${clean[3]}`
    : clean
}

const handleGenerate = (url: URL): RenderState => {
  const rawHex = url.searchParams.get('hex') ?? '#4361ee'
  const harmony = (url.searchParams.get('harmony') ?? 'complementary') as HarmonyType

  if (!harmonyTypes.includes(harmony)) {
    return { ...defaultState, colors: generatePalette(defaultState.baseHex, defaultState.harmony) }
  }

  const hex = isValidHex(rawHex) ? normalizeHex(rawHex) : '#4361ee'
  const colors = generatePalette(hex, harmony)

  const c1Raw = url.searchParams.get('c1')
  const c2Raw = url.searchParams.get('c2')
  const selectedColors: [ReturnType<typeof hexToColor> | null, ReturnType<typeof hexToColor> | null] = [
    c1Raw && isValidHex(c1Raw) ? hexToColor(normalizeHex(c1Raw)) : null,
    c2Raw && isValidHex(c2Raw) ? hexToColor(normalizeHex(c2Raw)) : null,
  ]

  return { baseHex: hex, harmony, colors, selectedColors }
}

// --- API routes ---

const handleApiContrast = (url: URL): Response => {
  const hex1 = url.searchParams.get('hex1')
  const hex2 = url.searchParams.get('hex2')

  if (!hex1 || !hex2 || !isValidHex(hex1) || !isValidHex(hex2)) {
    return Response.json({ error: 'Provide valid hex1 and hex2 query params' }, { status: 400 })
  }

  const color1 = hexToColor(normalizeHex(hex1))
  const color2 = hexToColor(normalizeHex(hex2))
  const result = checkContrast(color1, color2)

  return Response.json({ color1, color2, contrast: result, formatted: formatRatio(result.ratio) })
}

const handleApiGenerate = async (url: URL): Promise<Response> => {
  const hex = url.searchParams.get('hex')
  const harmony = url.searchParams.get('harmony') as HarmonyType

  if (!hex || !isValidHex(hex)) {
    return Response.json({ error: 'Provide a valid hex query param' }, { status: 400 })
  }

  if (!harmony || !harmonyTypes.includes(harmony)) {
    return Response.json({ error: `Provide a valid harmony: ${harmonyTypes.join(', ')}` }, { status: 400 })
  }

  const palette = await createPalette(normalizeHex(hex), harmony)
  return Response.json(palette)
}

const handleApiPalettes = async (): Promise<Response> => {
  const palettes = await listPalettes()
  return Response.json(palettes)
}

const handleApiDelete = async (url: URL): Promise<Response> => {
  const id = url.searchParams.get('id')
  if (!id) return Response.json({ error: 'Provide an id query param' }, { status: 400 })
  const deleted = await deletePalette(id)
  return Response.json({ deleted })
}

// --- Server ---

export const serve = (port = 3200) =>
  Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)

      // API endpoints
      if (url.pathname === '/api/contrast') return handleApiContrast(url)
      if (url.pathname === '/api/generate') return handleApiGenerate(url)
      if (url.pathname === '/api/palettes' && req.method === 'GET') return handleApiPalettes()
      if (url.pathname === '/api/palettes' && req.method === 'DELETE') return handleApiDelete(url)

      // HTML page
      const state = handleGenerate(url)
      const rendered = ssr(renderPage(state))
      return new Response(htmlShell(rendered), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    },
  })

// Auto-start when run directly
if (import.meta.main) {
  const server = serve()
  console.log(`Color Palette Generator running at http://localhost:${server.port}`)
}

