import type { Document } from './types'

const DATA_PATH = `${import.meta.dir}/data/documents.json`

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

export const listDocuments = async (): Promise<Document[]> => {
  const docs = await readDocuments()
  return docs.sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
  )
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id)
}

export const createDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  title: string,
  content: string
): Promise<Document | undefined> => {
  const docs = await readDocuments()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return undefined
  docs[idx] = {
    ...docs[idx],
    title,
    content,
    updatedAt: new Date().toISOString(),
  }
  await writeDocuments(docs)
  return docs[idx]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const filtered = docs.filter((d) => d.id !== id)
  if (filtered.length === docs.length) return false
  await writeDocuments(filtered)
  return true
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (must come before links)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  result = result.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  result = result.replace(/__(.+?)__/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  result = result.replace(/_(.+?)_/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): string => {
  const headerCells = lines[0]
    .split('|')
    .map((c) => c.trim())
    .filter(Boolean)
  const alignments = lines[1]
    .split('|')
    .map((c) => c.trim())
    .filter(Boolean)
    .map((c) => {
      if (c.startsWith(':') && c.endsWith(':')) return 'center'
      if (c.endsWith(':')) return 'right'
      return 'left'
    })

  let html = '<table>\n<thead>\n<tr>\n'
  headerCells.forEach((cell, i) => {
    const align = alignments[i] || 'left'
    html += `<th style="text-align:${align}">${parseInline(cell)}</th>\n`
  })
  html += '</tr>\n</thead>\n<tbody>\n'

  for (let i = 2; i < lines.length; i++) {
    const cells = lines[i]
      .split('|')
      .map((c) => c.trim())
      .filter(Boolean)
    html += '<tr>\n'
    cells.forEach((cell, j) => {
      const align = alignments[j] || 'left'
      html += `<td style="text-align:${align}">${parseInline(cell)}</td>\n`
    })
    html += '</tr>\n'
  }
  html += '</tbody>\n</table>'
  return html
}

const isTableSeparator = (line: string): boolean =>
  /^\|?[\s-:|]+\|[\s-:|]+\|?$/.test(line)

export const renderMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0
  let inList: 'ul' | 'ol' | null = null

  const closeList = () => {
    if (inList) {
      output.push(inList === 'ul' ? '</ul>' : '</ol>')
      inList = null
    }
  }

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    if (line.startsWith('```')) {
      closeList()
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      i++
      continue
    }

    // Table
    if (
      i + 1 < lines.length &&
      line.includes('|') &&
      isTableSeparator(lines[i + 1])
    ) {
      closeList()
      const tableLines: string[] = [line, lines[i + 1]]
      i += 2
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      output.push(parseTable(tableLines))
      continue
    }

    // Blank line
    if (line.trim() === '') {
      closeList()
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      closeList()
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})$/.test(line.trim())) {
      closeList()
      output.push('<hr />')
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('>')) {
      closeList()
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${parseInline(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    const ulMatch = line.match(/^(\s*)[*+-]\s+(.+)$/)
    if (ulMatch) {
      if (inList !== 'ul') {
        closeList()
        output.push('<ul>')
        inList = 'ul'
      }
      output.push(`<li>${parseInline(ulMatch[2])}</li>`)
      i++
      continue
    }

    // Ordered list
    const olMatch = line.match(/^(\s*)\d+\.\s+(.+)$/)
    if (olMatch) {
      if (inList !== 'ol') {
        closeList()
        output.push('<ol>')
        inList = 'ol'
      }
      output.push(`<li>${parseInline(olMatch[2])}</li>`)
      i++
      continue
    }

    // Paragraph
    closeList()
    const paraLines: string[] = []
    while (
      i < lines.length &&
      lines[i].trim() !== '' &&
      !lines[i].startsWith('#') &&
      !lines[i].startsWith('>') &&
      !lines[i].startsWith('```') &&
      !/^(\*{3,}|-{3,}|_{3,})$/.test(lines[i].trim()) &&
      !lines[i].match(/^[*+-]\s+/) &&
      !lines[i].match(/^\d+\.\s+/)
    ) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(paraLines.join('\n'))}</p>`)
    }
  }

  closeList()
  return output.join('\n')
}

