const toStyleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

