const clientScript = (): string => `
  let debounceTimer;
  const editor = document.getElementById('editor');
  const preview = document.getElementById('preview');

  const updatePreview = () => {
    const content = editor.value;
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(async () => {
      const res = await fetch('/api/render', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content }),
      });
      const data = await res.json();
      preview.innerHTML = data.html;
    }, 150);
  };

  editor.addEventListener('input', updatePreview);
  updatePreview();
  loadDocumentList();

  function wrap(marker) {
    const start = editor.selectionStart;
    const end = editor.selectionEnd;
    const selected = editor.value.substring(start, end) || 'text';
    const before = editor.value.substring(0, start);
    const after = editor.value.substring(end);
    editor.value = before + marker + selected + marker + after;
    editor.selectionStart = start + marker.length;
    editor.selectionEnd = start + marker.length + selected.length;
    editor.focus();
    updatePreview();
  }

  function insert(prefix, suffix) {
    const start = editor.selectionStart;
    const end = editor.selectionEnd;
    const selected = editor.value.substring(start, end) || 'text';
    const before = editor.value.substring(0, start);
    const after = editor.value.substring(end);
    editor.value = before + prefix + selected + suffix + after;
    editor.selectionStart = start + prefix.length;
    editor.selectionEnd = start + prefix.length + selected.length;
    editor.focus();
    updatePreview();
  }

  function insertBlock(prefix, suffix) {
    const start = editor.selectionStart;
    const before = editor.value.substring(0, start);
    const after = editor.value.substring(start);
    const needsNewline = before.length > 0 && !before.endsWith('\\n') ? '\\n' : '';
    editor.value = before + needsNewline + prefix + suffix + '\\n' + after;
    editor.focus();
    updatePreview();
  }

  function insertTable() {
    const table = '| Column 1 | Column 2 | Column 3 |\\n| -------- | -------- | -------- |\\n| Cell 1   | Cell 2   | Cell 3   |\\n';
    const start = editor.selectionStart;
    const before = editor.value.substring(0, start);
    const after = editor.value.substring(start);
    const needsNewline = before.length > 0 && !before.endsWith('\\n') ? '\\n' : '';
    editor.value = before + needsNewline + table + after;
    editor.focus();
    updatePreview();
  }

  async function saveDocument() {
    const title = document.getElementById('doc-title').value.trim();
    const content = editor.value;
    const id = document.getElementById('doc-id').value;

    if (!title) { alert('Please enter a document title'); return; }

    const method = id ? 'PUT' : 'POST';
    const url = id ? '/api/documents/' + id : '/api/documents';

    const res = await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title, content }),
    });
    const doc = await res.json();
    document.getElementById('doc-id').value = doc.id;
    loadDocumentList();
  }

  function newDocument() {
    document.getElementById('doc-title').value = '';
    document.getElementById('doc-id').value = '';
    editor.value = '';
    updatePreview();
  }

  async function loadDocumentList() {
    const res = await fetch('/api/documents');
    const docs = await res.json();
    const list = document.getElementById('doc-list');
    list.innerHTML = docs.map(d =>
      '<div style="padding:8px 12px;cursor:pointer;font-size:13px;border-bottom:1px solid #313244;display:flex;justify-content:space-between;align-items:center" onmouseover="this.style.background=\\'#313244\\'" onmouseout="this.style.background=\\'none\\'">' +
        '<span onclick="loadDocument(\\'' + d.id + '\\')">' + escapeForHtml(d.title) + '</span>' +
        '<button onclick="deleteDocument(\\'' + d.id + '\\')" style="background:none;border:none;color:#f38ba8;cursor:pointer;font-size:14px;padding:0 4px" title="Delete">x</button>' +
      '</div>'
    ).join('');
  }

  function escapeForHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  async function loadDocument(id) {
    const res = await fetch('/api/documents/' + id);
    const doc = await res.json();
    document.getElementById('doc-title').value = doc.title;
    document.getElementById('doc-id').value = doc.id;
    editor.value = doc.content;
    updatePreview();
  }

  async function deleteDocument(id) {
    if (!confirm('Delete this document?')) return;
    await fetch('/api/documents/' + id, { method: 'DELETE' });
    const currentId = document.getElementById('doc-id').value;
    if (currentId === id) newDocument();
    loadDocumentList();
  }

  editor.addEventListener('keydown', (e) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const start = editor.selectionStart;
      editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(editor.selectionEnd);
      editor.selectionStart = editor.selectionEnd = start + 2;
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 's') {
      e.preventDefault();
      saveDocument();
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'b') {
      e.preventDefault();
      wrap('**');
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'i') {
      e.preventDefault();
      wrap('*');
    }
  });
`

import { renderPage } from './ui'
import { renderMarkdown } from './markdown'
import {
  listDocuments,
  getDocument,
  createDocument,
  updateDocument,
  deleteDocument,
} from './store'

const PORT = Number(process.env.PORT) || 3000

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Serve editor page
    if (path === '/' && method === 'GET') {
      const html = renderPage()
      return htmlResponse(html)
    }

    // Render markdown to HTML (for live preview)
    if (path === '/api/render' && method === 'POST') {
      const body = (await req.json()) as { content: string }
      const html = renderMarkdown(body.content || '')
      return jsonResponse({ html })
    }

    // List documents
    if (path === '/api/documents' && method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // Create document
    if (path === '/api/documents' && method === 'POST') {
      const body = (await req.json()) as { title: string; content: string }
      const doc = await createDocument(body.title, body.content)
      return jsonResponse(doc, 201)
    }

    // Document routes with ID
    const docMatch = path.match(/^\/api\/documents\/([^/]+)$/)
    if (docMatch) {
      const id = docMatch[1]

      if (method === 'GET') {
        const doc = await getDocument(id)
        if (!doc) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(doc)
      }

      if (method === 'PUT') {
        const body = (await req.json()) as { title: string; content: string }
        const doc = await updateDocument(id, body.title, body.content)
        if (!doc) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(doc)
      }

      if (method === 'DELETE') {
        const ok = await deleteDocument(id)
        if (!ok) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse({ ok: true })
      }
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

