const escapeHtml = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images: ![alt](url)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links: [text](url)
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  result = result.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  result = result.replace(/__(.+?)__/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  result = result.replace(/_(.+?)_/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const parseRow = (line: string): string[] =>
    line
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((cell) => cell.trim())

  const headerCells = parseRow(lines[0])
  const separatorLine = lines[1].trim()
  if (!/^\|?[\s-:|]+\|?$/.test(separatorLine)) return { html: '', consumed: 0 }

  const alignments = parseRow(separatorLine).map((cell) => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return ''
  })

  const styleFor = (i: number): string => {
    const a = alignments[i]
    return a ? ` style="text-align:${a}"` : ''
  }

  let html = '<table>\n<thead>\n<tr>\n'
  headerCells.forEach((cell, i) => {
    html += `<th${styleFor(i)}>${parseInline(cell)}</th>\n`
  })
  html += '</tr>\n</thead>\n<tbody>\n'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i].trim()
    if (!line.includes('|')) break
    const cells = parseRow(line)
    html += '<tr>\n'
    cells.forEach((cell, ci) => {
      html += `<td${styleFor(ci)}>${parseInline(cell)}</td>\n`
    })
    html += '</tr>\n'
    consumed++
  }

  html += '</tbody>\n</table>'
  return { html, consumed }
}

export const renderMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    const fenceMatch = line.match(/^```(\w*)/)
    if (fenceMatch) {
      const lang = fenceMatch[1]
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${lang}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line.trim())) {
      output.push('<hr />')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Table
    if (line.includes('|') && i + 1 < lines.length && /^\|?[\s-:|]+\|?$/.test(lines[i + 1].trim())) {
      const { html, consumed } = parseTable(lines.slice(i))
      if (consumed > 0) {
        output.push(html)
        i += consumed
        continue
      }
    }

    // Blockquote
    if (line.startsWith('>')) {
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${renderMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\s]*[-*+]\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*[-*+]\s/, ''))
        i++
      }
      output.push(
        '<ul>\n' + listItems.map((item) => `<li>${parseInline(item)}</li>`).join('\n') + '\n</ul>',
      )
      continue
    }

    // Ordered list
    if (/^[\s]*\d+\.\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*\d+\.\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*\d+\.\s/, ''))
        i++
      }
      output.push(
        '<ol>\n' + listItems.map((item) => `<li>${parseInline(item)}</li>`).join('\n') + '\n</ol>',
      )
      continue
    }

    // Empty line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph — collect consecutive non-empty lines
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !/^#{1,6}\s/.test(lines[i]) && !/^```/.test(lines[i]) && !/^>\s/.test(lines[i]) && !/^[-*+]\s/.test(lines[i]) && !/^\d+\.\s/.test(lines[i]) && !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i].trim())) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(paraLines.join('\n'))}</p>`)
    }
  }

  return output.join('\n')
}

import type { Document } from './types'

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const listDocuments = async (): Promise<Document[]> => {
  const docs = await readDocuments()
  return docs.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id)
}

export const createDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  updates: { title?: string; content?: string },
): Promise<Document | undefined> => {
  const docs = await readDocuments()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return undefined
  if (updates.title !== undefined) docs[idx].title = updates.title
  if (updates.content !== undefined) docs[idx].content = updates.content
  docs[idx].updatedAt = new Date().toISOString()
  await writeDocuments(docs)
  return docs[idx]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return false
  docs.splice(idx, 1)
  await writeDocuments(docs)
  return true
}

