import { h, Fragment } from '@plaited/template'
import { css } from './styles'

const toolbarButtons = [
  { label: 'H1', action: 'h1' },
  { label: 'H2', action: 'h2' },
  { label: 'H3', action: 'h3' },
  { label: '|', action: 'sep' },
  { label: 'B', action: 'bold' },
  { label: 'I', action: 'italic' },
  { label: 'S', action: 'strikethrough' },
  { label: '|', action: 'sep' },
  { label: 'Link', action: 'link' },
  { label: 'Image', action: 'image' },
  { label: 'Code', action: 'code' },
  { label: 'Block', action: 'codeblock' },
  { label: '|', action: 'sep' },
  { label: 'UL', action: 'ul' },
  { label: 'OL', action: 'ol' },
  { label: 'Quote', action: 'quote' },
  { label: 'HR', action: 'hr' },
  { label: '|', action: 'sep' },
  { label: 'Table', action: 'table' },
]

export const renderPage = (): string => {
  const toolbarHtml = toolbarButtons
    .map((btn) =>
      btn.action === 'sep'
        ? '<div class="separator"></div>'
        : `<button type="button" data-action="${btn.action}" onclick="insertFormat('${btn.action}')">${btn.label}</button>`,
    )
    .join('')

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Markdown Editor</title>
  <style>${css}</style>
</head>
<body>
  <div class="header">
    <h1>MD Editor</h1>
    <input type="text" class="title-input" id="doc-title" placeholder="Document title..." value="Untitled" />
    <div class="header-actions">
      <button class="btn btn-primary" onclick="saveDocument()">Save</button>
      <button class="btn btn-secondary" onclick="newDocument()">New</button>
      <button class="btn btn-secondary" onclick="toggleDocPanel()">Documents</button>
    </div>
  </div>

  <div class="toolbar">${toolbarHtml}</div>

  <div class="main">
    <div class="editor-pane">
      <div class="pane-label">Markdown</div>
      <textarea id="editor" spellcheck="false" placeholder="Start writing markdown..."></textarea>
    </div>
    <div class="divider" id="divider"></div>
    <div class="preview-pane">
      <div class="pane-label">Preview</div>
      <div class="preview-content" id="preview"></div>
    </div>
  </div>

  <div class="status-bar">
    <span id="status-left">Ready</span>
    <span id="status-right">Lines: 0 | Chars: 0</span>
  </div>

  <div class="overlay" id="overlay" onclick="toggleDocPanel()"></div>
  <div class="doc-panel" id="doc-panel">
    <div class="doc-panel-header">
      <h2>Saved Documents</h2>
      <button class="doc-panel-close" onclick="toggleDocPanel()">&times;</button>
    </div>
    <div class="doc-list" id="doc-list"></div>
  </div>

  <script>
    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const titleInput = document.getElementById('doc-title');
    const statusLeft = document.getElementById('status-left');
    const statusRight = document.getElementById('status-right');
    const docPanel = document.getElementById('doc-panel');
    const overlay = document.getElementById('overlay');
    const docList = document.getElementById('doc-list');

    let currentDocId = null;
    let debounceTimer = null;

    const updatePreview = () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const content = editor.value;
        const lines = content.split('\\n').length;
        const chars = content.length;
        statusRight.textContent = 'Lines: ' + lines + ' | Chars: ' + chars;
        try {
          const res = await fetch('/api/preview', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ content }),
          });
          const data = await res.json();
          preview.innerHTML = data.html;
        } catch (e) {
          console.error('Preview error:', e);
        }
      }, 150);
    };

    editor.addEventListener('input', updatePreview);

    editor.addEventListener('keydown', (e) => {
      if (e.key === 'Tab') {
        e.preventDefault();
        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(end);
        editor.selectionStart = editor.selectionEnd = start + 2;
        updatePreview();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        saveDocument();
      }
    });

    const insertFormat = (action) => {
      const start = editor.selectionStart;
      const end = editor.selectionEnd;
      const selected = editor.value.substring(start, end);
      let insert = '';
      let cursorOffset = 0;

      const formats = {
        h1: { before: '# ', after: '', placeholder: 'Heading 1' },
        h2: { before: '## ', after: '', placeholder: 'Heading 2' },
        h3: { before: '### ', after: '', placeholder: 'Heading 3' },
        bold: { before: '**', after: '**', placeholder: 'bold text' },
        italic: { before: '*', after: '*', placeholder: 'italic text' },
        strikethrough: { before: '~~', after: '~~', placeholder: 'strikethrough' },
        code: { before: '\`', after: '\`', placeholder: 'code' },
        link: { before: '[', after: '](url)', placeholder: 'link text' },
        image: { before: '![', after: '](url)', placeholder: 'alt text' },
        quote: { before: '> ', after: '', placeholder: 'quote' },
        hr: { before: '\\n---\\n', after: '', placeholder: '' },
        ul: { before: '- ', after: '', placeholder: 'list item' },
        ol: { before: '1. ', after: '', placeholder: 'list item' },
        codeblock: { before: '\\n\`\`\`\\n', after: '\\n\`\`\`\\n', placeholder: 'code' },
        table: { before: '\\n| Header 1 | Header 2 | Header 3 |\\n|----------|----------|----------|\\n| Cell 1   | Cell 2   | Cell 3   |\\n', after: '', placeholder: '' },
      };

      const fmt = formats[action];
      if (!fmt) return;

      const text = selected || fmt.placeholder;
      insert = fmt.before + text + fmt.after;

      editor.value = editor.value.substring(0, start) + insert + editor.value.substring(end);

      if (!selected && fmt.placeholder) {
        editor.selectionStart = start + fmt.before.length;
        editor.selectionEnd = start + fmt.before.length + fmt.placeholder.length;
      } else {
        editor.selectionStart = editor.selectionEnd = start + insert.length;
      }

      editor.focus();
      updatePreview();
    };

    const saveDocument = async () => {
      const title = titleInput.value.trim() || 'Untitled';
      const content = editor.value;

      try {
        let res;
        if (currentDocId) {
          res = await fetch('/api/documents/' + currentDocId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, content }),
          });
        } else {
          res = await fetch('/api/documents', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, content }),
          });
        }
        const doc = await res.json();
        currentDocId = doc.id;
        statusLeft.textContent = 'Saved at ' + new Date().toLocaleTimeString();
      } catch (e) {
        statusLeft.textContent = 'Save failed';
        console.error('Save error:', e);
      }
    };

    const newDocument = () => {
      currentDocId = null;
      titleInput.value = 'Untitled';
      editor.value = '';
      preview.innerHTML = '';
      statusLeft.textContent = 'New document';
      statusRight.textContent = 'Lines: 0 | Chars: 0';
    };

    const loadDocument = async (id) => {
      try {
        const res = await fetch('/api/documents/' + id);
        const doc = await res.json();
        currentDocId = doc.id;
        titleInput.value = doc.title;
        editor.value = doc.content;
        updatePreview();
        toggleDocPanel();
        statusLeft.textContent = 'Loaded: ' + doc.title;
      } catch (e) {
        console.error('Load error:', e);
      }
    };

    const deleteDoc = async (id, e) => {
      e.stopPropagation();
      if (!confirm('Delete this document?')) return;
      try {
        await fetch('/api/documents/' + id, { method: 'DELETE' });
        if (currentDocId === id) newDocument();
        loadDocList();
      } catch (e) {
        console.error('Delete error:', e);
      }
    };

    const loadDocList = async () => {
      try {
        const res = await fetch('/api/documents');
        const docs = await res.json();
        docList.innerHTML = docs.length === 0
          ? '<p style="padding:16px;color:#888;text-align:center;">No saved documents</p>'
          : docs.map(d =>
              '<div class="doc-item" onclick="loadDocument(\\'' + d.id + '\\')">' +
                '<div class="doc-item-info">' +
                  '<h3>' + escapeForHtml(d.title) + '</h3>' +
                  '<p>' + new Date(d.updatedAt).toLocaleString() + '</p>' +
                '</div>' +
                '<button class="doc-item-delete" onclick="deleteDoc(\\'' + d.id + '\\', event)" title="Delete">&times;</button>' +
              '</div>'
            ).join('');
      } catch (e) {
        console.error('List error:', e);
      }
    };

    const escapeForHtml = (str) =>
      str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    const toggleDocPanel = () => {
      const isOpen = docPanel.classList.contains('open');
      if (isOpen) {
        docPanel.classList.remove('open');
        overlay.classList.remove('open');
      } else {
        loadDocList();
        docPanel.classList.add('open');
        overlay.classList.add('open');
      }
    };

    // Resizable divider
    const divider = document.getElementById('divider');
    let isResizing = false;
    divider.addEventListener('mousedown', () => { isResizing = true; });
    document.addEventListener('mousemove', (e) => {
      if (!isResizing) return;
      const main = document.querySelector('.main');
      const rect = main.getBoundingClientRect();
      const pct = ((e.clientX - rect.left) / rect.width) * 100;
      const editorPane = document.querySelector('.editor-pane');
      const previewPane = document.querySelector('.preview-pane');
      editorPane.style.flex = 'none';
      editorPane.style.width = Math.max(20, Math.min(80, pct)) + '%';
      previewPane.style.flex = '1';
    });
    document.addEventListener('mouseup', () => { isResizing = false; });

    // Initial state
    updatePreview();
  </script>
</body>
</html>`
}

import { renderPage } from './page'
import { renderMarkdown } from './markdown'
import { listDocuments, getDocument, createDocument, updateDocument, deleteDocument } from './store'

const PORT = 3000

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve the editor page
    if (pathname === '/' && method === 'GET') {
      return new Response(renderPage(), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Preview endpoint
    if (pathname === '/api/preview' && method === 'POST') {
      const body = (await req.json()) as { content: string }
      const html = renderMarkdown(body.content ?? '')
      return jsonResponse({ html })
    }

    // List documents
    if (pathname === '/api/documents' && method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // Get single document
    const docMatch = pathname.match(/^\/api\/documents\/([^/]+)$/)
    if (docMatch && method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Create document
    if (pathname === '/api/documents' && method === 'POST') {
      const body = (await req.json()) as { title: string; content: string }
      const doc = await createDocument(body.title ?? 'Untitled', body.content ?? '')
      return jsonResponse(doc, 201)
    }

    // Update document
    if (docMatch && method === 'PUT') {
      const body = (await req.json()) as { title?: string; content?: string }
      const doc = await updateDocument(docMatch[1], body)
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Delete document
    if (docMatch && method === 'DELETE') {
      const deleted = await deleteDocument(docMatch[1])
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

