const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (before links to avoid conflict)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold+italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const parseRow = (line: string): string[] =>
    line
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((cell) => cell.trim())

  const headerCells = parseRow(lines[0])
  const separatorLine = lines[1]

  if (!/^\|?[\s-:|]+\|?$/.test(separatorLine)) return { html: '', consumed: 0 }

  const alignments = parseRow(separatorLine).map((cell) => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return ''
  })

  const alignAttr = (i: number): string =>
    alignments[i] ? ` style="text-align:${alignments[i]}"` : ''

  let html = '<table>\n<thead>\n<tr>\n'
  headerCells.forEach((cell, i) => {
    html += `<th${alignAttr(i)}>${parseInline(cell)}</th>\n`
  })
  html += '</tr>\n</thead>\n<tbody>\n'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i]
    if (!line.includes('|')) break
    const cells = parseRow(line)
    html += '<tr>\n'
    cells.forEach((cell, ci) => {
      html += `<td${alignAttr(ci)}>${parseInline(cell)}</td>\n`
    })
    html += '</tr>\n'
    consumed++
  }

  html += '</tbody>\n</table>'
  return { html, consumed }
}

export const parseMarkdown = (markdown: string): string => {
  const lines = markdown.split('\n')
  const output: string[] = []
  let i = 0
  let inCodeBlock = false
  let codeBlockContent: string[] = []
  let codeBlockLang = ''

  const flushParagraph = (text: string) => {
    if (text.trim()) {
      output.push(`<p>${parseInline(text.trim())}</p>`)
    }
  }

  let paragraphBuffer = ''

  const flushBuffer = () => {
    if (paragraphBuffer.trim()) {
      flushParagraph(paragraphBuffer)
      paragraphBuffer = ''
    }
  }

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code blocks
    if (/^```/.test(line)) {
      if (!inCodeBlock) {
        flushBuffer()
        inCodeBlock = true
        codeBlockLang = line.slice(3).trim()
        codeBlockContent = []
        i++
        continue
      } else {
        const langAttr = codeBlockLang ? ` class="language-${escapeHtml(codeBlockLang)}"` : ''
        output.push(
          `<pre><code${langAttr}>${escapeHtml(codeBlockContent.join('\n'))}</code></pre>`
        )
        inCodeBlock = false
        codeBlockContent = []
        codeBlockLang = ''
        i++
        continue
      }
    }

    if (inCodeBlock) {
      codeBlockContent.push(line)
      i++
      continue
    }

    // Blank line
    if (/^\s*$/.test(line)) {
      flushBuffer()
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      flushBuffer()
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})\s*$/.test(line)) {
      flushBuffer()
      output.push('<hr />')
      i++
      continue
    }

    // Table
    if (line.includes('|') && i + 1 < lines.length && /^\|?[\s-:|]+\|?$/.test(lines[i + 1])) {
      flushBuffer()
      const tableLines = lines.slice(i)
      const { html, consumed } = parseTable(tableLines)
      if (consumed > 0) {
        output.push(html)
        i += consumed
        continue
      }
    }

    // Blockquote
    if (/^>\s?/.test(line)) {
      flushBuffer()
      const quoteLines: string[] = []
      while (i < lines.length && /^>\s?/.test(lines[i])) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${parseInline(quoteLines.join(' '))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\-\*\+]\s+/.test(line)) {
      flushBuffer()
      const items: string[] = []
      while (i < lines.length && /^[\-\*\+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\-\*\+]\s+/, ''))
        i++
      }
      output.push(
        '<ul>\n' + items.map((item) => `<li>${parseInline(item)}</li>`).join('\n') + '\n</ul>'
      )
      continue
    }

    // Ordered list
    if (/^\d+\.\s+/.test(line)) {
      flushBuffer()
      const items: string[] = []
      while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\d+\.\s+/, ''))
        i++
      }
      output.push(
        '<ol>\n' + items.map((item) => `<li>${parseInline(item)}</li>`).join('\n') + '\n</ol>'
      )
      continue
    }

    // Regular text — accumulate into paragraph
    paragraphBuffer += (paragraphBuffer ? ' ' : '') + line
    i++
  }

  // Flush remaining
  if (inCodeBlock) {
    const langAttr = codeBlockLang ? ` class="language-${escapeHtml(codeBlockLang)}"` : ''
    output.push(
      `<pre><code${langAttr}>${escapeHtml(codeBlockContent.join('\n'))}</code></pre>`
    )
  }
  flushBuffer()

  return output.join('\n')
}

import type { Document, DocumentInput } from './types'

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

const generateId = (): string =>
  `doc_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const listDocuments = async (): Promise<Document[]> => {
  const docs = await readDocuments()
  return docs.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id) ?? null
}

export const createDocument = async (input: DocumentInput): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: generateId(),
    title: input.title,
    content: input.content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  input: DocumentInput
): Promise<Document | null> => {
  const docs = await readDocuments()
  const index = docs.findIndex((d) => d.id === id)
  if (index === -1) return null
  docs[index] = {
    ...docs[index],
    title: input.title,
    content: input.content,
    updatedAt: new Date().toISOString(),
  }
  await writeDocuments(docs)
  return docs[index]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const index = docs.findIndex((d) => d.id === id)
  if (index === -1) return false
  docs.splice(index, 1)
  await writeDocuments(docs)
  return true
}

