      ),
      // Hidden input for current document ID
      h('input', { type: 'hidden', id: 'doc-id', value: currentId }),
      // Client-side script
      h('script', {}, `
        const editor = document.getElementById('editor');
        const preview = document.getElementById('preview');
        const titleInput = document.getElementById('doc-title');
        const docIdInput = document.getElementById('doc-id');
        const sidebar = document.getElementById('sidebar');
        const docList = document.getElementById('doc-list');

        const updatePreview = () => {
          fetch('/api/preview', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ content: editor.value }),
          })
            .then(r => r.json())
            .then(data => { preview.innerHTML = data.html; })
            .catch(() => { preview.textContent = 'Preview error'; });
        };

        const insertFormat = (action) => {
          const start = editor.selectionStart;
          const end = editor.selectionEnd;
          const selected = editor.value.substring(start, end);
          let before = '', after = '', insert = '';

          const formats = {
            h1: { before: '# ', after: '' },
            h2: { before: '## ', after: '' },
            h3: { before: '### ', after: '' },
            bold: { before: '**', after: '**' },
            italic: { before: '*', after: '*' },
            link: { before: '[', after: '](url)' },
            image: { before: '![', after: '](url)' },
            code: { before: '\`', after: '\`' },
            codeblock: { before: '\`\`\`\\n', after: '\\n\`\`\`' },
            ul: { before: '- ', after: '' },
            ol: { before: '1. ', after: '' },
            blockquote: { before: '> ', after: '' },
            hr: { insert: '\\n---\\n' },
            table: { insert: '\\n| Header 1 | Header 2 | Header 3 |\\n| --- | --- | --- |\\n| Cell 1 | Cell 2 | Cell 3 |\\n' },
          };

          const fmt = formats[action];
          if (!fmt) return;

          if (fmt.insert) {
            editor.value = editor.value.substring(0, start) + fmt.insert + editor.value.substring(end);
            editor.selectionStart = editor.selectionEnd = start + fmt.insert.length;
          } else {
            const wrapped = fmt.before + (selected || 'text') + fmt.after;
            editor.value = editor.value.substring(0, start) + wrapped + editor.value.substring(end);
            if (!selected) {
              editor.selectionStart = start + fmt.before.length;
              editor.selectionEnd = start + fmt.before.length + 4;
            } else {
              editor.selectionStart = start;
              editor.selectionEnd = start + wrapped.length;
            }
          }
          editor.focus();
          updatePreview();
        };

        const saveDocument = () => {
          const id = docIdInput.value;
          const title = titleInput.value || 'Untitled';
          const content = editor.value;
          const method = id ? 'PUT' : 'POST';
          const url = id ? '/api/documents/' + id : '/api/documents';

          fetch(url, {
            method,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, content }),
          })
            .then(r => r.json())
            .then(doc => {
              docIdInput.value = doc.id;
              titleInput.value = doc.title;
            })
            .catch(() => alert('Save failed'));
        };

        const newDocument = () => {
          docIdInput.value = '';
          titleInput.value = '';
          editor.value = '';
          preview.innerHTML = '';
        };

        const loadDocument = (id) => {
          fetch('/api/documents/' + id)
            .then(r => r.json())
            .then(doc => {
              docIdInput.value = doc.id;
              titleInput.value = doc.title;
              editor.value = doc.content;
              updatePreview();
              sidebar.style.display = 'none';
            })
            .catch(() => alert('Load failed'));
        };

        const deleteDoc = (id, event) => {
          event.stopPropagation();
          if (!confirm('Delete this document?')) return;
          fetch('/api/documents/' + id, { method: 'DELETE' })
            .then(() => {
              if (docIdInput.value === id) newDocument();
              refreshDocList();
            })
            .catch(() => alert('Delete failed'));
        };

        const refreshDocList = () => {
          fetch('/api/documents')
            .then(r => r.json())
            .then(docs => {
              if (docs.length === 0) {
                docList.innerHTML = '<div style="padding:24px 16px;text-align:center;color:#999;font-size:14px;">No saved documents</div>';
                return;
              }
              docList.innerHTML = docs.map(doc =>
                '<div class="doc-item" style="padding:10px 12px;border-radius:4px;cursor:pointer;border-bottom:1px solid #f0f0f0;display:flex;justify-content:space-between;align-items:center;" onclick="loadDocument(\\'' + doc.id + '\\')">' +
                  '<div>' +
                    '<div style="font-weight:500;font-size:14px;">' + (doc.title || 'Untitled') + '</div>' +
                    '<div style="font-size:11px;color:#999;">' + new Date(doc.updatedAt).toLocaleDateString() + '</div>' +
                  '</div>' +
                  '<button class="delete-btn" style="background:none;border:none;color:#ef4444;cursor:pointer;font-size:16px;padding:2px 6px;" onclick="deleteDoc(\\'' + doc.id + '\\', event)">&times;</button>' +
                '</div>'
              ).join('');
            })
            .catch(() => {
              docList.innerHTML = '<div style="padding:24px;text-align:center;color:#ef4444;">Failed to load documents</div>';
            });
        };

        const toggleSidebar = () => {
          const isVisible = sidebar.style.display !== 'none';
          sidebar.style.display = isVisible ? 'none' : 'flex';
          if (!isVisible) refreshDocList();
        };

        // Initial preview render
        if (editor.value) updatePreview();
      `),
    ),
  )
}

import { createSSR } from 'plaited'
import { parseMarkdown } from './markdown'
import { renderEditor } from './editor'
import {
  listDocuments,
  getDocument,
  createDocument,
  updateDocument,
  deleteDocument,
} from './documents'
import type { DocumentInput } from './types'

const ssr = createSSR()

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve the editor page
    if (pathname === '/' && method === 'GET') {
      const docId = url.searchParams.get('doc')
      const doc = docId ? await getDocument(docId) : null
      const html = ssr(renderEditor(doc))
      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Preview endpoint — renders markdown to HTML
    if (pathname === '/api/preview' && method === 'POST') {
      const body = (await req.json()) as { content: string }
      const html = parseMarkdown(body.content ?? '')
      return jsonResponse({ html })
    }

    // List documents
    if (pathname === '/api/documents' && method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // Get single document
    const docMatch = pathname.match(/^\/api\/documents\/(.+)$/)
    if (docMatch && method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Create document
    if (pathname === '/api/documents' && method === 'POST') {
      const input = (await req.json()) as DocumentInput
      if (!input.title && !input.content) {
        return jsonResponse({ error: 'Title or content required' }, 400)
      }
      const doc = await createDocument({
        title: input.title || 'Untitled',
        content: input.content || '',
      })
      return jsonResponse(doc, 201)
    }

    // Update document
    if (docMatch && method === 'PUT') {
      const input = (await req.json()) as DocumentInput
      const doc = await updateDocument(docMatch[1], {
        title: input.title || 'Untitled',
        content: input.content || '',
      })
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Delete document
    if (docMatch && method === 'DELETE') {
      const deleted = await deleteDocument(docMatch[1])
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ success: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

