export const GalleryPage = ({
  projects,
  allTags,
  activeTag,
  query,
  sort,
}: {
  projects: Project[]
  allTags: string[]
  activeTag?: string
  query?: string
  sort: SortOption
}) => {
  const buildTagHref = (tag: string) => {
    const params = new URLSearchParams()
    if (activeTag === tag) {
      // clicking active tag clears it
    } else {
      params.set('tag', tag)
    }
    if (query) params.set('q', query)
    if (sort !== 'date-desc') params.set('sort', sort)
    const qs = params.toString()
    return qs ? `/?${qs}` : '/'
  }

  const sortOptions: { value: SortOption; label: string }[] = [
    { value: 'date-desc', label: 'Newest First' },
    { value: 'date-asc', label: 'Oldest First' },
    { value: 'alpha-asc', label: 'A → Z' },
    { value: 'alpha-desc', label: 'Z → A' },
  ]

  return h(
    'html',
    { lang: 'en' },
    h(
      'head',
      {},
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }),
      h('title', {}, 'Portfolio Gallery'),
      h('style', {}, `
        * { box-sizing: border-box; }
        body { margin: 0; }
        a { color: inherit; }
        a[style]:hover { transform: translateY(-4px); box-shadow: 0 8px 24px rgba(0,0,0,0.12) !important; }
      `)
    ),
    h(
      'body',
      {},
      h(
        'div',
        { style: styleAttr(styles.gallery) },
        h(
          'div',
          { style: styleAttr(styles.header) },
          h('h1', { style: styleAttr(styles.title) }, 'Portfolio'),
          h(
            'form',
            { method: 'get', action: '/', style: styleAttr(styles.controls) },
            h('input', {
              type: 'text',
              name: 'q',
              placeholder: 'Search projects...',
              value: query ?? '',
              style: styleAttr(styles.searchInput),
            }),
            activeTag ? h('input', { type: 'hidden', name: 'tag', value: activeTag }) : '',
            h(
              'select',
              { name: 'sort', style: styleAttr(styles.sortSelect), onchange: 'this.form.submit()' },
              ...sortOptions.map((opt) =>
                h(
                  'option',
                  { value: opt.value, ...(opt.value === sort ? { selected: 'selected' } : {}) },
                  opt.label
                )
              )
            ),
            h(
              'button',
              {
                type: 'submit',
                style: styleAttr({
                  ...styles.tagButtonActive,
                  cursor: 'pointer',
                }),
              },
              'Search'
            )
          ),
          allTags.length > 0
            ? h(
                'div',
                { style: styleAttr(styles.tagBar) },
                ...allTags.map((tag) =>
                  TagPill({ tag, active: activeTag === tag, href: buildTagHref(tag) })
                )
              )
            : ''
        ),
        projects.length > 0
          ? h(
              'div',
              { style: styleAttr(styles.grid) },
              ...projects.map((project) => ProjectCard({ project }))
            )
          : EmptyState({ query, tag: activeTag })
      )
    )
  )
}

