import { createSSR } from 'plaited'
import { getProjects, getProjectById, getAllTags } from './data-store'
import { GalleryPage, DetailPage, NotFoundPage } from './templates'
import type { SortOption } from './types'

const validSorts = new Set<SortOption>(['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc'])

const parseSort = (value: string | null): SortOption => {
  if (value && validSorts.has(value as SortOption)) return value as SortOption
  return 'date-desc'
}

const renderHtml = (template: ReturnType<typeof GalleryPage>): string => {
  const ssr = createSSR()
  return `<!DOCTYPE html>${ssr(template)}`
}

const handleGallery = async (url: URL): Promise<Response> => {
  const tag = url.searchParams.get('tag') ?? undefined
  const query = url.searchParams.get('q') ?? undefined
  const sort = parseSort(url.searchParams.get('sort'))

  const [projects, allTags] = await Promise.all([
    getProjects({ tag, query, sort }),
    getAllTags(),
  ])

  const html = renderHtml(GalleryPage({ projects, allTags, activeTag: tag, query, sort }))
  return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
}

const handleDetail = async (id: string, url: URL): Promise<Response> => {
  const project = await getProjectById(id)
  if (!project) {
    const html = renderHtml(NotFoundPage())
    return new Response(html, { status: 404, headers: { 'content-type': 'text/html; charset=utf-8' } })
  }

  const imgParam = url.searchParams.get('img')
  const currentImage = imgParam ? Math.max(0, Math.min(Number(imgParam), project.images.length - 1)) : 0

  const html = renderHtml(DetailPage({ project, currentImage }))
  return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
}

const handleApiProjects = async (url: URL): Promise<Response> => {
  const tag = url.searchParams.get('tag') ?? undefined
  const query = url.searchParams.get('q') ?? undefined
  const sort = parseSort(url.searchParams.get('sort'))

  const projects = await getProjects({ tag, query, sort })
  return Response.json(projects)
}

export const serve = () =>
  Bun.serve({
    port: Number(process.env.PORT ?? 3000),
    fetch: async (req) => {
      const url = new URL(req.url)
      const path = url.pathname

      // Gallery grid
      if (path === '/' && req.method === 'GET') {
        return handleGallery(url)
      }

      // Project detail
      const detailMatch = path.match(/^\/project\/([a-z0-9-]+)$/)
      if (detailMatch && req.method === 'GET') {
        return handleDetail(detailMatch[1], url)
      }

      // JSON API
      if (path === '/api/projects' && req.method === 'GET') {
        return handleApiProjects(url)
      }

      return new Response('Not Found', { status: 404 })
    },
  })

