import type { Project, SortMode, GalleryQuery } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.jsonl`

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Project)
}

const saveProjects = async (projects: Project[]): Promise<void> => {
  const content = projects.map((p) => JSON.stringify(p)).join('\n') + '\n'
  await Bun.write(DATA_PATH, content)
}

const sortProjects = (projects: Project[], mode: SortMode): Project[] => {
  const sorted = [...projects]
  if (mode === 'alpha') {
    sorted.sort((a, b) => a.title.localeCompare(b.title))
  } else {
    sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
  }
  return sorted
}

const filterProjects = (projects: Project[], query: GalleryQuery): Project[] => {
  let result = [...projects]

  if (query.tag) {
    const tag = query.tag.toLowerCase()
    result = result.filter((p) => p.tags.some((t) => t.toLowerCase() === tag))
  }

  if (query.q) {
    const search = query.q.toLowerCase()
    result = result.filter((p) => p.title.toLowerCase().includes(search))
  }

  const sortMode: SortMode = query.sort === 'alpha' ? 'alpha' : 'date'
  return sortProjects(result, sortMode)
}

const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

export const getProjects = async (query: GalleryQuery): Promise<{ projects: Project[]; allTags: string[] }> => {
  const all = await loadProjects()
  return {
    projects: filterProjects(all, query),
    allTags: getAllTags(all),
  }
}

export const getProject = async (id: string): Promise<Project | undefined> => {
  const all = await loadProjects()
  return all.find((p) => p.id === id)
}

export const addProject = async (project: Project): Promise<Project> => {
  const all = await loadProjects()
  all.push(project)
  await saveProjects(all)
  return project
}

export const updateProject = async (id: string, updates: Partial<Project>): Promise<Project | undefined> => {
  const all = await loadProjects()
  const idx = all.findIndex((p) => p.id === id)
  if (idx === -1) return undefined
  all[idx] = { ...all[idx], ...updates, id }
  await saveProjects(all)
  return all[idx]
}

export const deleteProject = async (id: string): Promise<boolean> => {
  const all = await loadProjects()
  const idx = all.findIndex((p) => p.id === id)
  if (idx === -1) return false
  all.splice(idx, 1)
  await saveProjects(all)
  return true
}

