import { h, Fragment } from 'plaited'
import type { Project, GalleryQuery } from './types'
import { cssVars, layoutStyles, cardStyles, detailStyles, emptyStyles } from './styles'

const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/([A-Z])/g, '-$1').toLowerCase()
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

const cssVarsStr = styleStr(cssVars as unknown as Record<string, string>)

const renderTag = (tag: string, activeTag?: string) => {
  const isActive = activeTag?.toLowerCase() === tag.toLowerCase()
  const combinedStyle = isActive
    ? { ...layoutStyles.tagFilter, ...layoutStyles.tagFilterActive }
    : layoutStyles.tagFilter
  return h('a', {
    href: isActive ? '/' : `/?tag=${encodeURIComponent(tag)}`,
    style: styleStr(combinedStyle),
  }, tag)
}

const renderCard = (project: Project) =>
  h('a', { href: `/project/${project.id}`, style: styleStr(cardStyles.card) },
    h('img', {
      src: project.thumbnail,
      alt: project.title,
      style: styleStr(cardStyles.thumbnail),
      loading: 'lazy',
    }),
    h('div', { style: styleStr(cardStyles.body) },
      h('h3', { style: styleStr(cardStyles.cardTitle) }, project.title),
      h('p', { style: styleStr(cardStyles.description) }, project.description),
      h('div', { style: styleStr(cardStyles.tags) },
        ...project.tags.map((t) => h('span', { style: styleStr(cardStyles.tag) }, t)),
      ),
      h('div', {
        style: styleStr(cardStyles.links),
        onclick: 'event.stopPropagation()',
      },
        h('a', {
          href: project.demoUrl,
          target: '_blank',
          rel: 'noopener',
          style: styleStr(cardStyles.link),
        }, 'Live Demo'),
        h('a', {
          href: project.sourceUrl,
          target: '_blank',
          rel: 'noopener',
          style: styleStr(cardStyles.link),
        }, 'Source'),
      ),
    ),
  )

