              onclick: 'closeLightbox()',
              'aria-label': 'Close lightbox',
            }, '\u00D7'),
          ),
        ),
        h('script', {}, `
          let current = 0;
          const imgs = document.querySelectorAll('.carousel-img');
          const dots = document.querySelectorAll('.dot');
          const total = imgs.length;

          const goTo = (idx) => {
            imgs.forEach((img, i) => img.style.display = i === idx ? 'block' : 'none');
            dots.forEach((dot, i) => dot.style.backgroundColor = i === idx ? 'var(--pg-accent)' : 'var(--pg-border)');
            current = idx;
          };

          const navigate = (dir) => {
            goTo((current + dir + total) % total);
          };

          const openLightbox = (src) => {
            document.getElementById('lightbox-img').src = src;
            document.getElementById('lightbox').style.display = 'block';
          };

          const closeLightbox = () => {
            document.getElementById('lightbox').style.display = 'none';
          };

          document.addEventListener('keydown', (e) => {
            if (document.getElementById('lightbox').style.display === 'block') {
              if (e.key === 'Escape') closeLightbox();
            }
            if (e.key === 'ArrowLeft') navigate(-1);
            if (e.key === 'ArrowRight') navigate(1);
          });
        `),
      ),
    ),
  )

  return `<!DOCTYPE html>${content}`
}

import { getProjects, getProject, addProject, updateProject, deleteProject } from './store'
import { renderGallery, renderDetail } from './templates'
import type { Project, GalleryQuery } from './types'

const parseQuery = (url: URL): GalleryQuery => ({
  tag: url.searchParams.get('tag') ?? undefined,
  q: url.searchParams.get('q') ?? undefined,
  sort: (url.searchParams.get('sort') as GalleryQuery['sort']) ?? undefined,
})

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export default {
  port: 3000,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Gallery listing
    if (path === '/' && method === 'GET') {
      const query = parseQuery(url)
      const { projects, allTags } = await getProjects(query)
      return html(renderGallery(projects, allTags, query))
    }

    // Project detail view
    const detailMatch = path.match(/^\/project\/([a-zA-Z0-9_-]+)$/)

    if (detailMatch && method === 'GET') {
      const project = await getProject(detailMatch[1])
      if (!project) return html('<h1>Project not found</h1>', 404)
      return html(renderDetail(project))
    }

    // API: Create project
    if (path === '/project' && method === 'POST') {
      const body = (await req.json()) as Project
      if (!body.id || !body.title) {
        return json({ error: 'id and title are required' }, 400)
      }
      const project = await addProject({
        ...body,
        dateAdded: body.dateAdded ?? new Date().toISOString().split('T')[0],
        images: body.images ?? [],
        tags: body.tags ?? [],
      })
      return json(project, 201)
    }

    // API: Update project
    if (detailMatch && method === 'PUT') {
      const body = (await req.json()) as Partial<Project>
      const updated = await updateProject(detailMatch[1], body)
      if (!updated) return json({ error: 'Project not found' }, 404)
      return json(updated)
    }

    // API: Delete project
    if (detailMatch && method === 'DELETE') {
      const deleted = await deleteProject(detailMatch[1])
      if (!deleted) return json({ error: 'Project not found' }, 404)
      return json({ ok: true })
    }

    return json({ error: 'Not found' }, 404)
  },
}

