import type { Project, SortOption, GalleryQuery } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.jsonl`

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Project)
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => b.dateAdded.localeCompare(a.dateAdded))
    case 'date-asc':
      return sorted.sort((a, b) => a.dateAdded.localeCompare(b.dateAdded))
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

export const getProjects = async (query: GalleryQuery): Promise<Project[]> => {
  let projects = await loadProjects()

  if (query.tag) {
    const tag = query.tag.toLowerCase()
    projects = projects.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === tag)
    )
  }

  if (query.q) {
    const q = query.q.toLowerCase()
    projects = projects.filter((p) => p.title.toLowerCase().includes(q))
  }

  const sort = query.sort ?? 'date-desc'
  projects = sortProjects(projects, sort)

  return projects
}

export const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.id === id)
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

