const clientScript = `
  document.addEventListener('DOMContentLoaded', () => {
    const form = document.getElementById('controls-form');
    const searchInput = document.getElementById('search-input');
    const sortSelect = document.getElementById('sort-select');

    const submitForm = () => { form && form.submit(); };
    if (searchInput) {
      let timer;
      searchInput.addEventListener('input', () => {
        clearTimeout(timer);
        timer = setTimeout(submitForm, 350);
      });
    }
    if (sortSelect) {
      sortSelect.addEventListener('change', submitForm);
    }

    // Lightbox carousel
    const carouselImages = document.querySelectorAll('.carousel-img');
    const overlay = document.getElementById('lightbox-overlay');
    const lightboxImg = document.getElementById('lightbox-img');

    carouselImages.forEach(img => {
      img.addEventListener('click', () => {
        if (overlay && lightboxImg) {
          lightboxImg.src = img.src;
          overlay.style.display = 'flex';
        }
      });
    });

    if (overlay) {
      overlay.addEventListener('click', () => { overlay.style.display = 'none'; });
    }

    // Carousel navigation
    const slides = document.querySelectorAll('.carousel-slide');
    const dots = document.querySelectorAll('.carousel-dot');
    let current = 0;

    const showSlide = (i) => {
      slides.forEach((s, idx) => { s.style.display = idx === i ? 'block' : 'none'; });
      dots.forEach((d, idx) => {
        d.style.backgroundColor = idx === i ? '#58a6ff' : '#30363d';
      });
      current = i;
    };

    const prevBtn = document.getElementById('carousel-prev');
    const nextBtn = document.getElementById('carousel-next');
    if (prevBtn) prevBtn.addEventListener('click', () => showSlide((current - 1 + slides.length) % slides.length));
    if (nextBtn) nextBtn.addEventListener('click', () => showSlide((current + 1) % slides.length));
    dots.forEach((d, i) => d.addEventListener('click', () => showSlide(i)));

    if (slides.length > 0) showSlide(0);
  });
`

