        h('a', { href: '/', style: styleAttr(styles.cardLink) }, '\u2190 Back to Gallery'),
      ),
    ),
  )
  return `<!DOCTYPE html>${template}`
}

import type { SortOption, GalleryQuery } from './types'
import { getProjects, getProjectById, getAllTags } from './store'
import { renderGalleryPage, renderDetailPage, renderNotFound } from './templates'

const isValidSort = (v: string | null): v is SortOption =>
  v !== null && ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc'].includes(v)

export const createServer = ({ port = 3000 }: { port?: number } = {}) => {
  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)
      const { pathname } = url

      // Gallery listing
      if (pathname === '/' || pathname === '') {
        const tag = url.searchParams.get('tag') ?? undefined
        const q = url.searchParams.get('q') ?? undefined
        const sortParam = url.searchParams.get('sort')
        const sort = isValidSort(sortParam) ? sortParam : 'date-desc'

        const query: GalleryQuery = { tag, q, sort }
        const [projects, allTags] = await Promise.all([
          getProjects(query),
          getAllTags(),
        ])

        const html = renderGalleryPage(projects, allTags, query)
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      // Project detail
      const detailMatch = pathname.match(/^\/project\/([a-z0-9-]+)$/)
      if (detailMatch) {
        const project = await getProjectById(detailMatch[1])
        if (!project) {
          return new Response(renderNotFound(), {
            status: 404,
            headers: { 'Content-Type': 'text/html; charset=utf-8' },
          })
        }
        const html = renderDetailPage(project)
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      // 404 fallback
      return new Response(renderNotFound(), {
        status: 404,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    },
  })

  console.log(`Portfolio Gallery running at http://localhost:${server.port}`)
  return server
}

// Auto-start when run directly
createServer()

