export type Tool = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type Stroke = {
  tool: Tool
  points: Point[]
  color: string
  size: number
}

export type ShapeStroke = Stroke & {
  tool: 'rectangle' | 'circle' | 'line'
  start: Point
  end: Point
}

export type DrawAction = {
  layerId: string
  stroke: Stroke | ShapeStroke
}

export type Layer = {
  id: string
  name: string
  visible: boolean
  opacity: number
  actions: DrawAction[]
}

export type CanvasState = {
  width: number
  height: number
  layers: Layer[]
  activeLayerId: string
  currentTool: Tool
  currentColor: string
