import type { Layer, DrawAction } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter++
  return {
    id: `layer-${layerCounter}-${Date.now()}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    opacity: 1,
    actions: [],
  }
}

export const addActionToLayer = (layer: Layer, action: DrawAction): Layer => ({
  ...layer,
  actions: [...layer.actions, action],
})

export const removeLastAction = (layer: Layer): { layer: Layer; removed: DrawAction | undefined } => {
  const actions = [...layer.actions]
  const removed = actions.pop()
  return {
    layer: { ...layer, actions },
    removed,
  }
}

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const setLayerOpacity = (layer: Layer, opacity: number): Layer => ({
  ...layer,
  opacity: Math.max(0, Math.min(1, opacity)),
})

export const renameLayer = (layer: Layer, name: string): Layer => ({
  ...layer,
  name,
})

export const clearLayer = (layer: Layer): Layer => ({
  ...layer,
  actions: [],
})

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

import type { CanvasState, DrawAction } from './types'
import { removeLastAction } from './layers'

const MAX_HISTORY = 100

export const pushHistory = (state: CanvasState, snapshot: DrawAction[]): CanvasState => {
  const history = [...state.history, snapshot]
  if (history.length > MAX_HISTORY) {
    history.shift()
  }
  return {
    ...state,
    history,
    redoStack: [],
  }
}

export const undo = (state: CanvasState): CanvasState => {
  if (state.history.length === 0) return state

  const history = [...state.history]
  const lastBatch = history.pop()!

  const layers = [...state.layers]
  for (const action of lastBatch) {
    const layerIndex = layers.findIndex((l) => l.id === action.layerId)
    if (layerIndex === -1) continue
    const { layer } = removeLastAction(layers[layerIndex])
    layers[layerIndex] = layer
  }

  return {
    ...state,
    layers,
    history,
    redoStack: [...state.redoStack, lastBatch],
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.redoStack.length === 0) return state

  const redoStack = [...state.redoStack]
  const batch = redoStack.pop()!

  const layers = [...state.layers]
  for (const action of batch) {
    const layerIndex = layers.findIndex((l) => l.id === action.layerId)
    if (layerIndex === -1) continue
    layers[layerIndex] = {
      ...layers[layerIndex],
      actions: [...layers[layerIndex].actions, action],
    }
  }

  return {
    ...state,
    layers,
    history: [...state.history, batch],
    redoStack,
  }
}

export const canUndo = (state: CanvasState): boolean => state.history.length > 0

export const canRedo = (state: CanvasState): boolean => state.redoStack.length > 0

import type { CanvasState, DrawAction, Layer, Stroke, ShapeStroke, Point } from './types'

export const renderStroke = (ctx: CanvasRenderingContext2D, stroke: Stroke | ShapeStroke): void => {
  ctx.save()

  if (stroke.tool === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out'
    ctx.strokeStyle = 'rgba(0,0,0,1)'
  } else {
    ctx.globalCompositeOperation = 'source-over'
    ctx.strokeStyle = stroke.color
  }

  ctx.lineWidth = stroke.size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  if (stroke.tool === 'freehand' || stroke.tool === 'eraser') {
    renderFreehand(ctx, stroke.points)
  } else {
    const shape = stroke as ShapeStroke
    renderShape(ctx, shape)
  }

  ctx.restore()
}

const renderFreehand = (ctx: CanvasRenderingContext2D, points: Point[]): void => {
  if (points.length === 0) return

  ctx.beginPath()

  if (points.length === 1) {
    ctx.arc(points[0].x, points[0].y, ctx.lineWidth / 2, 0, Math.PI * 2)
    ctx.fillStyle = ctx.strokeStyle
    ctx.fill()
    return
  }

  ctx.moveTo(points[0].x, points[0].y)
  for (let i = 1; i < points.length; i++) {
    const midX = (points[i - 1].x + points[i].x) / 2
    const midY = (points[i - 1].y + points[i].y) / 2
    ctx.quadraticCurveTo(points[i - 1].x, points[i - 1].y, midX, midY)
  }
  const last = points[points.length - 1]
  ctx.lineTo(last.x, last.y)
  ctx.stroke()
}

const renderShape = (ctx: CanvasRenderingContext2D, shape: ShapeStroke): void => {
  ctx.beginPath()

  switch (shape.tool) {
    case 'rectangle': {
      const w = shape.end.x - shape.start.x
      const h = shape.end.y - shape.start.y
      ctx.strokeRect(shape.start.x, shape.start.y, w, h)
      break
    }
    case 'circle': {
      const dx = shape.end.x - shape.start.x
      const dy = shape.end.y - shape.start.y
      const radius = Math.sqrt(dx * dx + dy * dy)
      ctx.arc(shape.start.x, shape.start.y, radius, 0, Math.PI * 2)
      ctx.stroke()
      break
    }
    case 'line': {
      ctx.moveTo(shape.start.x, shape.start.y)
      ctx.lineTo(shape.end.x, shape.end.y)
      ctx.stroke()
      break
    }
  }
}

export const renderLayer = (
  ctx: CanvasRenderingContext2D,
  layer: Layer,
  width: number,
  height: number,
): void => {
  if (!layer.visible) return

  const offscreen = new OffscreenCanvas(width, height)
  const offCtx = offscreen.getContext('2d')!
  offCtx.clearRect(0, 0, width, height)

  for (const action of layer.actions) {
    renderStroke(offCtx, action.stroke)
  }

  ctx.save()
  ctx.globalAlpha = layer.opacity
  ctx.drawImage(offscreen, 0, 0)
  ctx.restore()
}

export const renderAllLayers = (
  ctx: CanvasRenderingContext2D,
  state: CanvasState,
): void => {
  ctx.clearRect(0, 0, state.width, state.height)

  // White background
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, state.width, state.height)

  for (const layer of state.layers) {
    renderLayer(ctx, layer, state.width, state.height)
  }
}

export const renderLayerThumbnail = (
  layer: Layer,
  width: number,
  height: number,
  thumbWidth: number,
  thumbHeight: number,
): OffscreenCanvas => {
  const thumb = new OffscreenCanvas(thumbWidth, thumbHeight)
  const ctx = thumb.getContext('2d')!

  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, thumbWidth, thumbHeight)

  const scaleX = thumbWidth / width
  const scaleY = thumbHeight / height
  ctx.scale(scaleX, scaleY)

  for (const action of layer.actions) {
    renderStroke(ctx, action.stroke)
  }

  return thumb
}

import type { CanvasState, DrawingManifest, DrawingManifestEntry } from './types'

const DATA_DIR = 'data/drawings'
const MANIFEST_PATH = `${DATA_DIR}/manifest.json`

const ensureDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR)
  try {
    await Bun.$`mkdir -p ${DATA_DIR}`
  } catch {
    // directory exists
  }
}

const readManifest = async (): Promise<DrawingManifest> => {
  try {
    const file = Bun.file(MANIFEST_PATH)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // no manifest yet
  }
  return { drawings: [] }
}

const writeManifest = async (manifest: DrawingManifest): Promise<void> => {
  await Bun.write(MANIFEST_PATH, JSON.stringify(manifest, null, 2))
}

export const saveDrawing = async (
  name: string,
  pngData: Uint8Array,
  state: CanvasState,
): Promise<string> => {
  await ensureDir()

  const id = name.replace(/[^a-zA-Z0-9-_]/g, '_').toLowerCase()
  const filePath = `${DATA_DIR}/${id}.png`
  const statePath = `${DATA_DIR}/${id}.state.json`
  const now = new Date().toISOString()

  await Bun.write(filePath, pngData)

  const stateData = {
    width: state.width,
    height: state.height,
    layers: state.layers,
    activeLayerId: state.activeLayerId,
  }
  await Bun.write(statePath, JSON.stringify(stateData, null, 2))

  const manifest = await readManifest()
  const existingIndex = manifest.drawings.findIndex((d) => d.id === id)

  const entry: DrawingManifestEntry = {
    id,
    name,
    createdAt: existingIndex >= 0 ? manifest.drawings[existingIndex].createdAt : now,
    updatedAt: now,
    width: state.width,
    height: state.height,
    layerCount: state.layers.length,
  }

  if (existingIndex >= 0) {
    manifest.drawings[existingIndex] = entry
  } else {
    manifest.drawings.push(entry)
  }

  await writeManifest(manifest)
  return id
}

export const loadDrawingPng = async (id: string): Promise<Uint8Array | null> => {
  const filePath = `${DATA_DIR}/${id}.png`
  const file = Bun.file(filePath)
  if (!(await file.exists())) return null
  return new Uint8Array(await file.arrayBuffer())
}

export const loadDrawingState = async (id: string): Promise<{
  width: number
  height: number
  layers: CanvasState['layers']
  activeLayerId: string
} | null> => {
  const statePath = `${DATA_DIR}/${id}.state.json`
  const file = Bun.file(statePath)
  if (!(await file.exists())) return null
  return await file.json()
}

export const listDrawings = async (): Promise<DrawingManifestEntry[]> => {
  const manifest = await readManifest()
  return manifest.drawings
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const manifest = await readManifest()
  const index = manifest.drawings.findIndex((d) => d.id === id)
  if (index < 0) return false

  manifest.drawings.splice(index, 1)
  await writeManifest(manifest)

  try {
    await Bun.$`rm -f ${DATA_DIR}/${id}.png ${DATA_DIR}/${id}.state.json`
  } catch {
    // files may not exist
  }

  return true
}

