import type { CanvasState, Tool, Point, Stroke, ShapeStroke, DrawAction } from './types'
import { createLayer, addActionToLayer, toggleLayerVisibility, clearLayer } from './layers'
import { pushHistory, undo as undoHistory, redo as redoHistory, canUndo, canRedo } from './history'
import { renderAllLayers, renderStroke } from './renderer'
import { saveDrawing, loadDrawingState, loadDrawingPng } from './storage'

export type CanvasApp = {
  getState: () => CanvasState
  setState: (state: CanvasState) => void
  setTool: (tool: Tool) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  undo: () => void
  redo: () => void
  clear: () => void
  addLayer: (name?: string) => void
  removeLayer: (id?: string) => void
  selectLayer: (id: string) => void
  toggleLayerVisibility: (id: string) => void
  save: (name: string) => Promise<string>
  load: (id: string) => Promise<boolean>
  render: () => void
  mount: (container: HTMLElement) => void
  destroy: () => void
}

export const createCanvasApp = (config?: { width?: number; height?: number }): CanvasApp => {
  const width = config?.width ?? 800
  const height = config?.height ?? 600

  const initialLayer = createLayer('Background')

  let state: CanvasState = {
    width,
    height,
    layers: [initialLayer],
    activeLayerId: initialLayer.id,
    currentTool: 'freehand',
    currentColor: '#000000',
    brushSize: 3,
    history: [],
    redoStack: [],
  }

  let canvas: HTMLCanvasElement | null = null
  let ctx: CanvasRenderingContext2D | null = null
  let container: HTMLElement | null = null
  let isDrawing = false
  let currentPoints: Point[] = []
  let startPoint: Point | null = null

  const getActiveLayer = () => state.layers.find((l) => l.id === state.activeLayerId)

  const getCanvasPoint = (e: MouseEvent): Point => {
    if (!canvas) return { x: 0, y: 0 }
    const rect = canvas.getBoundingClientRect()
    const scaleX = state.width / rect.width
    const scaleY = state.height / rect.height
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY,
    }
  }

  const handleMouseDown = (e: MouseEvent) => {
    if (!canvas || !ctx) return
    const point = getCanvasPoint(e)
    isDrawing = true
    currentPoints = [point]
    startPoint = point

    if (state.currentTool === 'freehand' || state.currentTool === 'eraser') {
      ctx.save()
      if (state.currentTool === 'eraser') {
        ctx.globalCompositeOperation = 'destination-out'
        ctx.strokeStyle = 'rgba(0,0,0,1)'
      } else {
        ctx.strokeStyle = state.currentColor
      }
      ctx.lineWidth = state.brushSize
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'
      ctx.beginPath()
      ctx.moveTo(point.x, point.y)
    }
  }

  const handleMouseMove = (e: MouseEvent) => {
    if (!isDrawing || !canvas || !ctx) return
    const point = getCanvasPoint(e)
    currentPoints.push(point)

    if (state.currentTool === 'freehand' || state.currentTool === 'eraser') {
      const prev = currentPoints[currentPoints.length - 2]
      const midX = (prev.x + point.x) / 2
      const midY = (prev.y + point.y) / 2
      ctx.quadraticCurveTo(prev.x, prev.y, midX, midY)
      ctx.stroke()
      ctx.beginPath()
      ctx.moveTo(midX, midY)
    } else if (startPoint) {
      // Re-render for shape preview
      render()
      ctx.save()
      ctx.strokeStyle = state.currentColor
      ctx.lineWidth = state.brushSize
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'
      ctx.beginPath()

      switch (state.currentTool) {
        case 'rectangle': {
          const w = point.x - startPoint.x
          const h = point.y - startPoint.y
          ctx.strokeRect(startPoint.x, startPoint.y, w, h)
          break
        }
        case 'circle': {
          const dx = point.x - startPoint.x
          const dy = point.y - startPoint.y
          const radius = Math.sqrt(dx * dx + dy * dy)
          ctx.arc(startPoint.x, startPoint.y, radius, 0, Math.PI * 2)
          ctx.stroke()
          break
        }
        case 'line': {
          ctx.moveTo(startPoint.x, startPoint.y)
          ctx.lineTo(point.x, point.y)
          ctx.stroke()
          break
        }
      }
      ctx.restore()
    }
  }

  const handleMouseUp = (e: MouseEvent) => {
    if (!isDrawing || !ctx) return
    isDrawing = false

    const point = getCanvasPoint(e)
    const activeLayer = getActiveLayer()
    if (!activeLayer) return

    let stroke: Stroke | ShapeStroke

    if (state.currentTool === 'freehand' || state.currentTool === 'eraser') {
      ctx.restore()
      stroke = {
        tool: state.currentTool,
        points: currentPoints,
        color: state.currentColor,
        size: state.brushSize,
      }
    } else {
      stroke = {
        tool: state.currentTool,
        points: currentPoints,
        color: state.currentColor,
        size: state.brushSize,
        start: startPoint!,
        end: point,
      } as ShapeStroke
    }

    const action: DrawAction = {
      layerId: activeLayer.id,
      stroke,
    }

    const layerIndex = state.layers.findIndex((l) => l.id === activeLayer.id)
    const updatedLayers = [...state.layers]
    updatedLayers[layerIndex] = addActionToLayer(activeLayer, action)

    state = pushHistory(
      { ...state, layers: updatedLayers },
      [action],
    )

    currentPoints = []
    startPoint = null
    render()
  }

  const render = () => {
    if (!ctx) return
    renderAllLayers(ctx, state)
  }

  const setupCanvas = () => {
    if (!container) return

    container.innerHTML = ''

    // Build layout
    const wrapper = document.createElement('div')
    wrapper.style.cssText = 'display:flex;height:100%;font-family:system-ui,sans-serif;font-size:14px;color:#333;user-select:none;'

    // Sidebar
    const sidebar = buildSidebar()
    wrapper.appendChild(sidebar)

    // Canvas area
    const canvasArea = document.createElement('div')
    canvasArea.style.cssText = 'flex:1;display:flex;align-items:center;justify-content:center;background:#e0e0e0;overflow:auto;padding:20px;'

    canvas = document.createElement('canvas')
    canvas.width = state.width
    canvas.height = state.height
    canvas.style.cssText = 'border:1px solid #999;background:#fff;cursor:crosshair;box-shadow:0 2px 8px rgba(0,0,0,.15);'
    ctx = canvas.getContext('2d')!

    canvas.addEventListener('mousedown', handleMouseDown)
    canvas.addEventListener('mousemove', handleMouseMove)
    canvas.addEventListener('mouseup', handleMouseUp)
    canvas.addEventListener('mouseleave', () => {
      if (isDrawing) {
        isDrawing = false
        currentPoints = []
        startPoint = null
        render()
      }
    })

    canvasArea.appendChild(canvas)
    wrapper.appendChild(canvasArea)

    // Layers panel
    const layersPanel = buildLayersPanel()
    wrapper.appendChild(layersPanel)

    container.appendChild(wrapper)
    render()
  }

  const buildSidebar = (): HTMLElement => {
    const sidebar = document.createElement('div')
    sidebar.style.cssText = 'width:220px;background:#f5f5f5;border-right:1px solid #ddd;display:flex;flex-direction:column;overflow-y:auto;'

    // Tools section
    sidebar.appendChild(buildSection('Tools', buildToolGrid()))
    sidebar.appendChild(buildSection('Color', buildColorPicker()))
    sidebar.appendChild(buildSection(`Brush Size: ${state.brushSize}px`, buildBrushSlider()))
    sidebar.appendChild(buildSection('Actions', buildActionButtons()))
    sidebar.appendChild(buildSection('File', buildFileControls()))

    return sidebar
  }

  const buildSection = (title: string, content: HTMLElement): HTMLElement => {
    const section = document.createElement('div')
    section.style.cssText = 'padding:12px;border-bottom:1px solid #ddd;'
    const label = document.createElement('div')
    label.style.cssText = 'font-size:11px;font-weight:600;text-transform:uppercase;color:#888;margin-bottom:8px;letter-spacing:.5px;'
    label.textContent = title
    section.appendChild(label)
    section.appendChild(content)
    return section
  }

  const TOOLS: { id: Tool; label: string; icon: string }[] = [
    { id: 'freehand', label: 'Brush', icon: '\u270F' },
    { id: 'rectangle', label: 'Rectangle', icon: '\u25AD' },
    { id: 'circle', label: 'Circle', icon: '\u25CB' },
    { id: 'line', label: 'Line', icon: '\u2571' },
    { id: 'eraser', label: 'Eraser', icon: '\u232B' },
  ]

  const PRESET_COLORS = [
    '#000000', '#ffffff', '#ff0000', '#00ff00', '#0000ff',
    '#ffff00', '#ff00ff', '#00ffff', '#ff8800', '#8800ff',
    '#008800', '#880000', '#888888', '#cccccc', '#ff4444',
    '#44ff44', '#4444ff', '#ffaa00', '#aa00ff', '#00aaff',
  ]

  const buildToolGrid = (): HTMLElement => {
    const grid = document.createElement('div')
    grid.style.cssText = 'display:grid;grid-template-columns:repeat(5,1fr);gap:4px;'
    for (const tool of TOOLS) {
      const btn = document.createElement('button')
      btn.textContent = tool.icon
      btn.title = tool.label
      btn.style.cssText = tool.id === state.currentTool
        ? 'padding:8px 4px;border:2px solid #2196f3;border-radius:4px;background:#e3f2fd;cursor:pointer;text-align:center;font-size:16px;'
        : 'padding:8px 4px;border:1px solid #ccc;border-radius:4px;background:#fff;cursor:pointer;text-align:center;font-size:16px;'
      btn.addEventListener('click', () => {
        state.currentTool = tool.id
        setupCanvas()
      })
      grid.appendChild(btn)
    }
    return grid
  }

  const buildColorPicker = (): HTMLElement => {
    const wrapper = document.createElement('div')

    const grid = document.createElement('div')
    grid.style.cssText = 'display:grid;grid-template-columns:repeat(10,1fr);gap:2px;'
    for (const color of PRESET_COLORS) {
      const swatch = document.createElement('div')
      const isActive = color === state.currentColor
      swatch.style.cssText = `width:18px;height:18px;border-radius:3px;cursor:pointer;background:${color};border:${isActive ? '2px solid #2196f3' : '1px solid #ccc'};${isActive ? 'box-shadow:0 0 4px rgba(33,150,243,.5);' : ''}`
      swatch.addEventListener('click', () => {
        state.currentColor = color
        setupCanvas()
      })
      grid.appendChild(swatch)
    }
    wrapper.appendChild(grid)

    const row = document.createElement('div')
    row.style.cssText = 'margin-top:8px;display:flex;gap:4px;align-items:center;'

    const colorInput = document.createElement('input')
    colorInput.type = 'color'
    colorInput.value = state.currentColor
    colorInput.style.cssText = 'width:30px;height:30px;border:none;cursor:pointer;'
    colorInput.addEventListener('input', (e) => {
      state.currentColor = (e.target as HTMLInputElement).value
      setupCanvas()
    })
    row.appendChild(colorInput)

    const hexInput = document.createElement('input')
    hexInput.type = 'text'
    hexInput.value = state.currentColor
    hexInput.maxLength = 7
    hexInput.style.cssText = 'flex:1;padding:4px 8px;border:1px solid #ccc;border-radius:4px;font-size:12px;width:80px;'
    hexInput.addEventListener('change', (e) => {
      const val = (e.target as HTMLInputElement).value
      if (/^#[0-9a-fA-F]{6}$/.test(val)) {
        state.currentColor = val
        setupCanvas()
      }
    })
    row.appendChild(hexInput)
    wrapper.appendChild(row)

    return wrapper
  }

  const buildBrushSlider = (): HTMLElement => {
    const slider = document.createElement('input')
    slider.type = 'range'
    slider.min = '1'
    slider.max = '50'
    slider.value = String(state.brushSize)
    slider.style.cssText = 'width:100%;margin-top:4px;'
    slider.addEventListener('input', (e) => {
      state.brushSize = Number((e.target as HTMLInputElement).value)
      const section = slider.parentElement
      if (section) {
        const label = section.querySelector('div')
        if (label) label.textContent = `Brush Size: ${state.brushSize}px`
      }
    })
    return slider
  }

  const buildActionButtons = (): HTMLElement => {
    const row = document.createElement('div')
    row.style.cssText = 'display:flex;gap:4px;flex-wrap:wrap;'

    const makeBtn = (text: string, disabled: boolean, handler: () => void) => {
      const btn = document.createElement('button')
      btn.textContent = text
      btn.disabled = disabled
      btn.style.cssText = disabled
        ? 'padding:6px 10px;border:1px solid #eee;border-radius:4px;background:#f9f9f9;color:#bbb;cursor:default;font-size:12px;'
        : 'padding:6px 10px;border:1px solid #ccc;border-radius:4px;background:#fff;cursor:pointer;font-size:12px;'
      if (!disabled) btn.addEventListener('click', handler)
      return btn
    }

    row.appendChild(makeBtn('Undo', !canUndo(state), () => {
      state = undoHistory(state)
      setupCanvas()
    }))
    row.appendChild(makeBtn('Redo', !canRedo(state), () => {
      state = redoHistory(state)
      setupCanvas()
    }))
    row.appendChild(makeBtn('Clear', false, () => {
      const activeLayer = getActiveLayer()
      if (!activeLayer) return
      const layerIndex = state.layers.findIndex((l) => l.id === activeLayer.id)
      const updatedLayers = [...state.layers]
      updatedLayers[layerIndex] = clearLayer(activeLayer)
      state = { ...state, layers: updatedLayers, history: [], redoStack: [] }
      setupCanvas()
    }))

    return row
  }

  const buildFileControls = (): HTMLElement => {
    const wrapper = document.createElement('div')

    const nameInput = document.createElement('input')
    nameInput.type = 'text'
    nameInput.placeholder = 'Drawing name'
    nameInput.style.cssText = 'width:100%;padding:4px 8px;border:1px solid #ccc;border-radius:4px;font-size:12px;box-sizing:border-box;'

    wrapper.appendChild(nameInput)

    const row = document.createElement('div')
    row.style.cssText = 'display:flex;gap:4px;margin-top:4px;'

    const saveBtn = document.createElement('button')
    saveBtn.textContent = 'Save PNG'
    saveBtn.style.cssText = 'padding:6px 10px;border:1px solid #ccc;border-radius:4px;background:#fff;cursor:pointer;font-size:12px;'
    saveBtn.addEventListener('click', async () => {
      const name = nameInput.value.trim()
      if (!name) {
        nameInput.style.borderColor = '#f44'
        return
      }
      nameInput.style.borderColor = '#ccc'
      await app.save(name)
    })
    row.appendChild(saveBtn)

    const loadBtn = document.createElement('button')
    loadBtn.textContent = 'Load'
    loadBtn.style.cssText = 'padding:6px 10px;border:1px solid #ccc;border-radius:4px;background:#fff;cursor:pointer;font-size:12px;'
    loadBtn.addEventListener('click', async () => {
      const name = nameInput.value.trim()
      if (!name) {
        nameInput.style.borderColor = '#f44'
        return
      }
      nameInput.style.borderColor = '#ccc'
      const id = name.replace(/[^a-zA-Z0-9-_]/g, '_').toLowerCase()
      await app.load(id)
    })
    row.appendChild(loadBtn)

    wrapper.appendChild(row)
    return wrapper
  }

  const buildLayersPanel = (): HTMLElement => {
    const panel = document.createElement('div')
    panel.style.cssText = 'width:200px;background:#f5f5f5;border-left:1px solid #ddd;display:flex;flex-direction:column;overflow:hidden;'

    // Header
    const header = document.createElement('div')
    header.style.cssText = 'display:flex;justify-content:space-between;align-items:center;padding:8px 12px;border-bottom:1px solid #ddd;'

    const title = document.createElement('div')
    title.style.cssText = 'font-size:11px;font-weight:600;text-transform:uppercase;color:#888;letter-spacing:.5px;'
    title.textContent = 'Layers'
    header.appendChild(title)

    const btnGroup = document.createElement('div')
    btnGroup.style.cssText = 'display:flex;gap:4px;'

    const addBtn = document.createElement('button')
    addBtn.textContent = '+'
    addBtn.style.cssText = 'padding:4px 8px;border:1px solid #ccc;border-radius:3px;background:#fff;cursor:pointer;font-size:12px;'
    addBtn.addEventListener('click', () => app.addLayer())
    btnGroup.appendChild(addBtn)

    const rmBtn = document.createElement('button')
    rmBtn.textContent = '-'
    rmBtn.style.cssText = 'padding:4px 8px;border:1px solid #ccc;border-radius:3px;background:#fff;cursor:pointer;font-size:12px;'
    rmBtn.addEventListener('click', () => app.removeLayer())
    btnGroup.appendChild(rmBtn)

    header.appendChild(btnGroup)
    panel.appendChild(header)

    // Layer list (reversed so top layer is first)
    const list = document.createElement('div')
    list.style.cssText = 'flex:1;overflow-y:auto;padding:4px;'

    const reversedLayers = [...state.layers].reverse()
    for (const layer of reversedLayers) {
      const isActive = layer.id === state.activeLayerId
      const item = document.createElement('div')
      item.style.cssText = isActive
        ? 'display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:4px;cursor:pointer;margin-bottom:2px;border:1px solid #2196f3;background:#e3f2fd;'
        : 'display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:4px;cursor:pointer;margin-bottom:2px;border:1px solid transparent;'

      // Thumbnail
      const thumbCanvas = document.createElement('canvas')
      thumbCanvas.width = 40
      thumbCanvas.height = 30
      thumbCanvas.style.cssText = 'width:40px;height:30px;border:1px solid #ccc;border-radius:2px;background:#fff;flex-shrink:0;'
      const thumbCtx = thumbCanvas.getContext('2d')!
      thumbCtx.fillStyle = '#fff'
      thumbCtx.fillRect(0, 0, 40, 30)
      const sx = 40 / state.width
      const sy = 30 / state.height
      thumbCtx.scale(sx, sy)
      for (const action of layer.actions) {
        renderStroke(thumbCtx, action.stroke)
      }
      item.appendChild(thumbCanvas)

      // Name
      const nameSpan = document.createElement('span')
      nameSpan.style.cssText = 'flex:1;font-size:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;'
      nameSpan.textContent = layer.name
      item.appendChild(nameSpan)

      // Visibility toggle
      const visBtn = document.createElement('button')
      visBtn.textContent = layer.visible ? '\u{1F441}' : '\u2014'
      visBtn.style.cssText = 'padding:2px 6px;border:1px solid #ccc;border-radius:3px;background:#fff;cursor:pointer;font-size:12px;'
      visBtn.addEventListener('click', (e) => {
        e.stopPropagation()
        app.toggleLayerVisibility(layer.id)
      })
      item.appendChild(visBtn)

      item.addEventListener('click', () => app.selectLayer(layer.id))
      list.appendChild(item)
    }

    panel.appendChild(list)
    return panel
  }

  const app: CanvasApp = {
    getState: () => state,
    setState: (newState: CanvasState) => {
      state = newState
      setupCanvas()
    },
    setTool: (tool: Tool) => {
      state.currentTool = tool
      setupCanvas()
    },
    setColor: (color: string) => {
      state.currentColor = color
      setupCanvas()
    },
    setBrushSize: (size: number) => {
      state.brushSize = Math.max(1, Math.min(50, size))
      setupCanvas()
    },
    undo: () => {
      state = undoHistory(state)
      setupCanvas()
    },
    redo: () => {
      state = redoHistory(state)
      setupCanvas()
    },
    clear: () => {
      const activeLayer = getActiveLayer()
      if (!activeLayer) return
      const layerIndex = state.layers.findIndex((l) => l.id === activeLayer.id)
      const updatedLayers = [...state.layers]
      updatedLayers[layerIndex] = clearLayer(activeLayer)
      state = { ...state, layers: updatedLayers, history: [], redoStack: [] }
      setupCanvas()
    },
    addLayer: (name?: string) => {
      const newLayer = createLayer(name)
      state = {
        ...state,
        layers: [...state.layers, newLayer],
        activeLayerId: newLayer.id,
      }
      setupCanvas()
    },
    removeLayer: (id?: string) => {
      const targetId = id ?? state.activeLayerId
      if (state.layers.length <= 1) return
      const remaining = state.layers.filter((l) => l.id !== targetId)
      state = {
        ...state,
        layers: remaining,
        activeLayerId: remaining[remaining.length - 1].id,
      }
      setupCanvas()
    },
    selectLayer: (id: string) => {
      state.activeLayerId = id
      setupCanvas()
    },
    toggleLayerVisibility: (id: string) => {
      const layerIndex = state.layers.findIndex((l) => l.id === id)
      if (layerIndex === -1) return
      const updatedLayers = [...state.layers]
      updatedLayers[layerIndex] = toggleLayerVisibility(updatedLayers[layerIndex])
      state = { ...state, layers: updatedLayers }
      setupCanvas()
    },
    save: async (name: string) => {
      if (!canvas) return ''
      const blob = await new Promise<Blob | null>((resolve) => canvas!.toBlob(resolve, 'image/png'))
      if (!blob) return ''
      const arrayBuf = await blob.arrayBuffer()
      const data = new Uint8Array(arrayBuf)
      return saveDrawing(name, data, state)
    },
    load: async (id: string) => {
      const savedState = await loadDrawingState(id)
      if (!savedState) return false
      state = {
        ...state,
        width: savedState.width,
        height: savedState.height,
        layers: savedState.layers,
        activeLayerId: savedState.activeLayerId,
        history: [],
        redoStack: [],
      }
      setupCanvas()
      return true
    },
    render,
    mount: (el: HTMLElement) => {
      container = el
      setupCanvas()
    },
    destroy: () => {
      if (canvas) {
        canvas.removeEventListener('mousedown', handleMouseDown)
        canvas.removeEventListener('mousemove', handleMouseMove)
        canvas.removeEventListener('mouseup', handleMouseUp)
      }
      if (container) container.innerHTML = ''
      canvas = null
      ctx = null
      container = null
    },
  }

  return app
}

{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "modnet": {
    "contentType": "graphic",
    "structure": "object",
    "mechanics": ["track"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type ToolType = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser';

export type Point = {
  x: number;
  y: number;
};

export type DrawAction = {
  tool: ToolType;
  points: Point[];
  color: string;
  brushSize: number;
  layerId: string;
};

export type Layer = {
  id: string;
  name: string;
  visible: boolean;
  opacity: number;
  dataUrl: string | null;
};

export type CanvasState = {
  layers: Layer[];
  activeLayerId: string;
  history: DrawAction[][];
  historyIndex: number;
  currentTool: ToolType;
  currentColor: string;
  brushSize: number;
  canvasWidth: number;
  canvasHeight: number;
};

export type SavedDrawing = {
  id: string;
  name: string;
  createdAt: string;
  filename: string;
};

import type { CanvasState, Layer, DrawAction } from './types';

const generateId = (): string => crypto.randomUUID();

const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  opacity: 1,
  dataUrl: null,
});

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background');
  return {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    history: [[]],
    historyIndex: 0,
    currentTool: 'freehand',
    currentColor: '#000000',
    brushSize: 3,
    canvasWidth: width,
    canvasHeight: height,
  };
};

export const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name ?? `Layer ${state.layers.length + 1}`);
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  };
};

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state;
  const filtered = state.layers.filter((l) => l.id !== layerId);
  return {
    ...state,
    layers: filtered,
    activeLayerId:
      state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId,
  };
};

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
});

export const setLayerData = (state: CanvasState, layerId: string, dataUrl: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, dataUrl } : l)),
});

export const pushHistory = (state: CanvasState, actions: DrawAction[]): CanvasState => {
  const trimmed = state.history.slice(0, state.historyIndex + 1);
  return {
    ...state,
    history: [...trimmed, actions],
    historyIndex: trimmed.length,
  };
};

export const undo = (state: CanvasState): CanvasState => {
  if (state.historyIndex <= 0) return state;
  return { ...state, historyIndex: state.historyIndex - 1 };
};

export const redo = (state: CanvasState): CanvasState => {
  if (state.historyIndex >= state.history.length - 1) return state;
  return { ...state, historyIndex: state.historyIndex + 1 };
};

import type { Point, ToolType } from './types';

export const drawFreehand = (
  ctx: CanvasRenderingContext2D,
  points: Point[],
  color: string,
  size: number,
): void => {
  if (points.length < 2) return;
  ctx.strokeStyle = color;
  ctx.lineWidth = size;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(points[0].x, points[0].y);
  for (let i = 1; i < points.length; i++) {
    ctx.lineTo(points[i].x, points[i].y);
  }
  ctx.stroke();
};

export const drawRectangle = (
  ctx: CanvasRenderingContext2D,
  start: Point,
  end: Point,
  color: string,
  size: number,
): void => {
  ctx.strokeStyle = color;
  ctx.lineWidth = size;
  ctx.strokeRect(start.x, start.y, end.x - start.x, end.y - start.y);
};

export const drawCircle = (
  ctx: CanvasRenderingContext2D,
  start: Point,
  end: Point,
  color: string,
  size: number,
): void => {
  const rx = (end.x - start.x) / 2;
  const ry = (end.y - start.y) / 2;
  const cx = start.x + rx;
  const cy = start.y + ry;
  const radius = Math.sqrt(rx * rx + ry * ry);
  ctx.strokeStyle = color;
  ctx.lineWidth = size;
  ctx.beginPath();
  ctx.arc(cx, cy, radius, 0, Math.PI * 2);
  ctx.stroke();
};

export const drawLine = (
  ctx: CanvasRenderingContext2D,
  start: Point,
  end: Point,
  color: string,
  size: number,
): void => {
  ctx.strokeStyle = color;
  ctx.lineWidth = size;
  ctx.lineCap = 'round';
  ctx.beginPath();
  ctx.moveTo(start.x, start.y);
  ctx.lineTo(end.x, end.y);
  ctx.stroke();
};

export const erase = (
  ctx: CanvasRenderingContext2D,
  points: Point[],
  size: number,
): void => {
  if (points.length < 2) return;
  ctx.globalCompositeOperation = 'destination-out';
  ctx.lineWidth = size;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(points[0].x, points[0].y);
  for (let i = 1; i < points.length; i++) {
    ctx.lineTo(points[i].x, points[i].y);
  }
  ctx.stroke();
  ctx.globalCompositeOperation = 'source-over';
};

export const executeDrawAction = (
  ctx: CanvasRenderingContext2D,
  tool: ToolType,
  points: Point[],
  color: string,
  size: number,
): void => {
  if (points.length === 0) return;
  switch (tool) {
    case 'freehand':
      drawFreehand(ctx, points, color, size);
      break;
    case 'rectangle':
      drawRectangle(ctx, points[0], points[points.length - 1], color, size);
      break;
    case 'circle':
      drawCircle(ctx, points[0], points[points.length - 1], color, size);
      break;
    case 'line':
      drawLine(ctx, points[0], points[points.length - 1], color, size);
      break;
    case 'eraser':
      erase(ctx, points, size);
      break;
  }
};

