import { renderPage } from './render';
import { createInitialState } from './canvas-state';
import type { SavedDrawing } from './types';

const DATA_DIR = `${import.meta.dir}/../data`;
const DRAWINGS_INDEX = `${DATA_DIR}/drawings.json`;

const loadDrawingsIndex = async (): Promise<SavedDrawing[]> => {
  const file = Bun.file(DRAWINGS_INDEX);
  if (await file.exists()) {
    return file.json();
  }
  return [];
};

const saveDrawingsIndex = async (drawings: SavedDrawing[]): Promise<void> => {
  await Bun.write(DRAWINGS_INDEX, JSON.stringify(drawings, null, 2));
};

const state = createInitialState();

export const server = Bun.serve({
  port: 3000,
  async fetch(req) {
    const url = new URL(req.url);

    // Serve the main page
    if (url.pathname === '/' && req.method === 'GET') {
      const html = renderPage(
        state.canvasWidth,
        state.canvasHeight,
        state.currentTool,
        state.currentColor,
        state.brushSize,
        state.layers,
        state.activeLayerId,
      );
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      });
    }

    // Serve client JS
    if (url.pathname === '/client.js' && req.method === 'GET') {
      const file = Bun.file(`${import.meta.dir}/client.js`);
      return new Response(file, {
        headers: { 'Content-Type': 'application/javascript' },
      });
    }

    // Save drawing as PNG
    if (url.pathname === '/api/save' && req.method === 'POST') {
      const body = await req.json() as { name: string; dataUrl: string };
      const base64Data = body.dataUrl.replace(/^data:image\/png;base64,/, '');
      const buffer = Buffer.from(base64Data, 'base64');
      const id = crypto.randomUUID();
      const filename = `${id}.png`;

      await Bun.write(`${DATA_DIR}/${filename}`, buffer);

      const drawings = await loadDrawingsIndex();
      const drawing: SavedDrawing = {
        id,
        name: body.name || `Drawing ${drawings.length + 1}`,
        createdAt: new Date().toISOString(),
        filename,
      };
      drawings.push(drawing);
      await saveDrawingsIndex(drawings);

      return Response.json({ ok: true, drawing });
    }

    // Load a saved drawing
    if (url.pathname.startsWith('/api/load/') && req.method === 'GET') {
      const id = url.pathname.split('/').pop();
      const drawings = await loadDrawingsIndex();
      const drawing = drawings.find((d) => d.id === id);
      if (!drawing) {
        return Response.json({ error: 'Drawing not found' }, { status: 404 });
      }
      const file = Bun.file(`${DATA_DIR}/${drawing.filename}`);
      if (!(await file.exists())) {
        return Response.json({ error: 'File not found' }, { status: 404 });
      }
      return new Response(file, {
        headers: { 'Content-Type': 'image/png' },
      });
    }

    // List saved drawings
    if (url.pathname === '/api/drawings' && req.method === 'GET') {
      const drawings = await loadDrawingsIndex();
      return Response.json(drawings);
    }

    return new Response('Not Found', { status: 404 });
  },
});

