// Client-side drawing canvas logic
// This file runs in the browser and handles all canvas interactions

type ToolType = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser';
type Point = { x: number; y: number };

type LayerState = {
  id: string;
  name: string;
  visible: boolean;
  canvas: HTMLCanvasElement;
};

type AppState = {
  tool: ToolType;
  color: string;
  brushSize: number;
  layers: LayerState[];
  activeLayerId: string;
  drawing: boolean;
  points: Point[];
  undoStack: ImageData[][];
  redoStack: ImageData[][];
};

const mainCanvas = document.getElementById('main-canvas') as HTMLCanvasElement;
const ctx = mainCanvas.getContext('2d')!;

const createOffscreenCanvas = (width: number, height: number): HTMLCanvasElement => {
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  return canvas;
};

const createLayerState = (id: string, name: string): LayerState => ({
  id,
  name,
  visible: true,
  canvas: createOffscreenCanvas(mainCanvas.width, mainCanvas.height),
});

// Initialize state
const firstLayerId = document.querySelector('[data-layer-id]')?.getAttribute('data-layer-id') ?? 'layer-0';
const state: AppState = {
  tool: 'freehand',
  color: '#000000',
  brushSize: 3,
  layers: [createLayerState(firstLayerId, 'Background')],
  activeLayerId: firstLayerId,
  drawing: false,
  points: [],
  undoStack: [],
  redoStack: [],
};

// Composite all visible layers onto main canvas
const compositeToMain = () => {
  ctx.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, mainCanvas.width, mainCanvas.height);
  for (const layer of state.layers) {
    if (layer.visible) {
      ctx.drawImage(layer.canvas, 0, 0);
    }
  }
};

// Update layer thumbnails
const updateThumbnails = () => {
  for (const layer of state.layers) {
    const thumb = document.querySelector(`[data-thumbnail="${layer.id}"]`) as HTMLCanvasElement | null;
    if (thumb) {
      const tctx = thumb.getContext('2d');
      if (tctx) {
        tctx.clearRect(0, 0, thumb.width, thumb.height);
        tctx.fillStyle = '#ffffff';
        tctx.fillRect(0, 0, thumb.width, thumb.height);
        tctx.drawImage(layer.canvas, 0, 0, thumb.width, thumb.height);
      }
    }
  }
};

// Get active layer
const getActiveLayer = (): LayerState | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId);

// Save state for undo
const saveUndoState = () => {
  const snapshot = state.layers.map((layer) => {
    const layerCtx = layer.canvas.getContext('2d')!;
    return layerCtx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
  });
  state.undoStack.push(snapshot);
  state.redoStack.length = 0;
  // Limit undo stack
  if (state.undoStack.length > 50) {
    state.undoStack.shift();
  }
};

// Restore from snapshot
const restoreSnapshot = (snapshot: ImageData[]) => {
  for (let i = 0; i < state.layers.length && i < snapshot.length; i++) {
    const layerCtx = state.layers[i].canvas.getContext('2d')!;
    layerCtx.putImageData(snapshot[i], 0, 0);
  }
  compositeToMain();
  updateThumbnails();
};

// Get canvas-relative coordinates
const getCanvasPoint = (e: PointerEvent): Point => {
  const rect = mainCanvas.getBoundingClientRect();
  return {
    x: e.clientX - rect.left,
    y: e.clientY - rect.top,
  };
};

// Draw functions
const drawFreehand = (targetCtx: CanvasRenderingContext2D, points: Point[], color: string, size: number) => {
  if (points.length < 2) return;
  targetCtx.strokeStyle = color;
  targetCtx.lineWidth = size;
  targetCtx.lineCap = 'round';
  targetCtx.lineJoin = 'round';
  targetCtx.beginPath();
  targetCtx.moveTo(points[0].x, points[0].y);
  for (let i = 1; i < points.length; i++) {
    targetCtx.lineTo(points[i].x, points[i].y);
  }
  targetCtx.stroke();
};

const drawRectangle = (targetCtx: CanvasRenderingContext2D, start: Point, end: Point, color: string, size: number) => {
  targetCtx.strokeStyle = color;
  targetCtx.lineWidth = size;
  targetCtx.strokeRect(start.x, start.y, end.x - start.x, end.y - start.y);
};

const drawCircle = (targetCtx: CanvasRenderingContext2D, start: Point, end: Point, color: string, size: number) => {
  const rx = (end.x - start.x) / 2;
  const ry = (end.y - start.y) / 2;
  const cx = start.x + rx;
  const cy = start.y + ry;
  const radius = Math.sqrt(rx * rx + ry * ry);
  targetCtx.strokeStyle = color;
  targetCtx.lineWidth = size;
  targetCtx.beginPath();
  targetCtx.arc(cx, cy, Math.abs(radius), 0, Math.PI * 2);
  targetCtx.stroke();
};

const drawLine = (targetCtx: CanvasRenderingContext2D, start: Point, end: Point, color: string, size: number) => {
  targetCtx.strokeStyle = color;
  targetCtx.lineWidth = size;
  targetCtx.lineCap = 'round';
  targetCtx.beginPath();
  targetCtx.moveTo(start.x, start.y);
  targetCtx.lineTo(end.x, end.y);
  targetCtx.stroke();
};

const erase = (targetCtx: CanvasRenderingContext2D, points: Point[], size: number) => {
  if (points.length < 2) return;
  targetCtx.globalCompositeOperation = 'destination-out';
  targetCtx.lineWidth = size;
  targetCtx.lineCap = 'round';
  targetCtx.lineJoin = 'round';
  targetCtx.beginPath();
  targetCtx.moveTo(points[0].x, points[0].y);
  for (let i = 1; i < points.length; i++) {
    targetCtx.lineTo(points[i].x, points[i].y);
  }
  targetCtx.stroke();
  targetCtx.globalCompositeOperation = 'source-over';
};

// Draw preview on main canvas (for shapes while dragging)
const drawPreview = () => {
  compositeToMain();
  if (state.points.length < 2) return;
  const start = state.points[0];
  const end = state.points[state.points.length - 1];

  switch (state.tool) {
    case 'freehand':
      drawFreehand(ctx, state.points, state.color, state.brushSize);
      break;
    case 'rectangle':
      drawRectangle(ctx, start, end, state.color, state.brushSize);
      break;
    case 'circle':
      drawCircle(ctx, start, end, state.color, state.brushSize);
      break;
    case 'line':
      drawLine(ctx, start, end, state.color, state.brushSize);
      break;
    case 'eraser':
      // For eraser preview, draw on composite directly
      erase(ctx, state.points, state.brushSize);
      break;
  }
};

// Commit drawing to active layer
const commitDraw = () => {
  const layer = getActiveLayer();
  if (!layer || state.points.length < 2) return;

  const layerCtx = layer.canvas.getContext('2d')!;
  const start = state.points[0];
  const end = state.points[state.points.length - 1];

  switch (state.tool) {
    case 'freehand':
      drawFreehand(layerCtx, state.points, state.color, state.brushSize);
      break;
    case 'rectangle':
      drawRectangle(layerCtx, start, end, state.color, state.brushSize);
      break;
    case 'circle':
      drawCircle(layerCtx, start, end, state.color, state.brushSize);
      break;
    case 'line':
      drawLine(layerCtx, start, end, state.color, state.brushSize);
      break;
    case 'eraser':
      erase(layerCtx, state.points, state.brushSize);
      break;
  }
  compositeToMain();
  updateThumbnails();
};

// Canvas pointer events
mainCanvas.addEventListener('pointerdown', (e: PointerEvent) => {
  state.drawing = true;
  state.points = [getCanvasPoint(e)];
  saveUndoState();
  mainCanvas.setPointerCapture(e.pointerId);
});

mainCanvas.addEventListener('pointermove', (e: PointerEvent) => {
  if (!state.drawing) return;
  state.points.push(getCanvasPoint(e));
  drawPreview();
});

mainCanvas.addEventListener('pointerup', (_e: PointerEvent) => {
  if (!state.drawing) return;
  state.drawing = false;
  commitDraw();
  state.points = [];
});

// Tool selection
const updateToolButtons = () => {
  document.querySelectorAll('[data-tool]').forEach((btn) => {
    const tool = btn.getAttribute('data-tool') as ToolType;
    const el = btn as HTMLElement;
    if (tool === state.tool) {
      el.style.backgroundColor = '#89b4fa';
      el.style.color = '#1e1e2e';
      el.style.border = '1px solid #89b4fa';
    } else {
      el.style.backgroundColor = '#45475a';
