// Undo
const undoBtn = Array.from(document.querySelectorAll('button')).find((b) => b.textContent === 'Undo');
undoBtn?.addEventListener('click', () => {
  if (state.undoStack.length === 0) return;
  const current = state.layers.map((layer) => {
    const layerCtx = layer.canvas.getContext('2d')!;
    return layerCtx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
  });
  state.redoStack.push(current);
  const snapshot = state.undoStack.pop()!;
  restoreSnapshot(snapshot);
});

// Redo
const redoBtn = Array.from(document.querySelectorAll('button')).find((b) => b.textContent === 'Redo');
redoBtn?.addEventListener('click', () => {
  if (state.redoStack.length === 0) return;
  const current = state.layers.map((layer) => {
    const layerCtx = layer.canvas.getContext('2d')!;
    return layerCtx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
  });
  state.undoStack.push(current);
  const snapshot = state.redoStack.pop()!;
