});

// Clear canvas
const clearBtn = Array.from(document.querySelectorAll('button')).find((b) => b.textContent === 'Clear');
clearBtn?.addEventListener('click', () => {
  saveUndoState();
  const layer = getActiveLayer();
  if (layer) {
    const layerCtx = layer.canvas.getContext('2d')!;
    layerCtx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
  }
  compositeToMain();
  updateThumbnails();
});

// Save PNG
const saveBtn = Array.from(document.querySelectorAll('button')).find((b) => b.textContent === 'Save PNG');
saveBtn?.addEventListener('click', async () => {
  // Composite final image
  const exportCanvas = createOffscreenCanvas(mainCanvas.width, mainCanvas.height);
  const exportCtx = exportCanvas.getContext('2d')!;
  exportCtx.fillStyle = '#ffffff';
  exportCtx.fillRect(0, 0, exportCanvas.width, exportCanvas.height);
  for (const layer of state.layers) {
    if (layer.visible) {
      exportCtx.drawImage(layer.canvas, 0, 0);
    }
  }
  const dataUrl = exportCanvas.toDataURL('image/png');

  // Save to server
  try {
    const res = await fetch('/api/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: `Drawing ${Date.now()}`, dataUrl }),
    });
    const result = await res.json();
    if (result.ok) {
      // Also trigger download
      const a = document.createElement('a');
      a.href = dataUrl;
      a.download = `${result.drawing.id}.png`;
      a.click();
    }
  } catch (err) {
    // Fallback: direct download
    const a = document.createElement('a');
    a.href = dataUrl;
    a.download = `drawing-${Date.now()}.png`;
    a.click();
  }
});

// Load PNG
const fileInput = document.querySelector('input[type="file"]') as HTMLInputElement;
fileInput?.addEventListener('change', () => {
  const file = fileInput.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    const img = new Image();
    img.onload = () => {
      saveUndoState();
      const layer = getActiveLayer();
      if (layer) {
        const layerCtx = layer.canvas.getContext('2d')!;
        layerCtx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
        layerCtx.drawImage(img, 0, 0, mainCanvas.width, mainCanvas.height);
      }
      compositeToMain();
      updateThumbnails();
    };
    img.src = reader.result as string;
  };
  reader.readAsDataURL(file);
  fileInput.value = '';
});

// Layer management
const addLayerBtn = Array.from(document.querySelectorAll('button')).find((b) => b.textContent === '+ Add Layer');
addLayerBtn?.addEventListener('click', () => {
  const id = `layer-${Date.now()}`;
  const name = `Layer ${state.layers.length + 1}`;
  state.layers.push(createLayerState(id, name));
  state.activeLayerId = id;
  refreshLayersPanel();
});

const removeLayerBtn = Array.from(document.querySelectorAll('button')).find((b) => b.textContent === 'Remove Layer');
removeLayerBtn?.addEventListener('click', () => {
  if (state.layers.length <= 1) return;
  saveUndoState();
  const idx = state.layers.findIndex((l) => l.id === state.activeLayerId);
  state.layers.splice(idx, 1);
  state.activeLayerId = state.layers[state.layers.length - 1].id;
  compositeToMain();
  refreshLayersPanel();
});

// Refresh the layers panel UI
const refreshLayersPanel = () => {
  const panel = document.querySelector('[data-layer-id]')?.parentElement;
  if (!panel) return;

  panel.innerHTML = '';
  [...state.layers].reverse().forEach((layer) => {
    const isActive = layer.id === state.activeLayerId;
    const item = document.createElement('div');
    item.style.cssText = `display:flex;align-items:center;gap:8px;padding:6px;border-radius:4px;cursor:pointer;font-size:12px;${isActive ? 'background-color:#45475a;' : ''}`;
    item.setAttribute('data-layer-id', layer.id);

    const visBtn = document.createElement('button');
    visBtn.style.cssText = 'width:20px;height:20px;border:none;background:none;color:#cdd6f4;cursor:pointer;font-size:14px;padding:0;';
    visBtn.textContent = layer.visible ? '\uD83D\uDC41' : '\u2014';
    visBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      layer.visible = !layer.visible;
      visBtn.textContent = layer.visible ? '\uD83D\uDC41' : '\u2014';
      compositeToMain();
    });

    const thumb = document.createElement('canvas');
    thumb.width = 40;
    thumb.height = 30;
    thumb.style.cssText = 'width:40px;height:30px;border:1px solid #585b70;border-radius:3px;background:#fff;';
    thumb.setAttribute('data-thumbnail', layer.id);

    const nameSpan = document.createElement('span');
    nameSpan.style.flex = '1';
    nameSpan.textContent = layer.name;

    item.appendChild(visBtn);
    item.appendChild(thumb);
    item.appendChild(nameSpan);

    item.addEventListener('click', () => {
      state.activeLayerId = layer.id;
      refreshLayersPanel();
    });

    panel.appendChild(item);
  });

  updateThumbnails();
};

