// Keyboard shortcuts
document.addEventListener('keydown', (e: KeyboardEvent) => {
  if (e.ctrlKey || e.metaKey) {
    if (e.key === 'z' && !e.shiftKey) {
      e.preventDefault();
      undoBtn?.click();
    } else if ((e.key === 'z' && e.shiftKey) || e.key === 'y') {
      e.preventDefault();
      redoBtn?.click();
    }
  }
  // Tool shortcuts
  if (!e.ctrlKey && !e.metaKey) {
    switch (e.key) {
      case 'b': state.tool = 'freehand'; updateToolButtons(); break;
      case 'r': state.tool = 'rectangle'; updateToolButtons(); break;
      case 'c': state.tool = 'circle'; updateToolButtons(); break;
      case 'l': state.tool = 'line'; updateToolButtons(); break;
      case 'e': state.tool = 'eraser'; updateToolButtons(); break;
    }
  }
});

// Initial composite
compositeToMain();
updateThumbnails();

// Drawing Canvas - Client-side logic
// Runs in the browser, handles all canvas interactions

(() => {
  const mainCanvas = document.getElementById('main-canvas');
  const ctx = mainCanvas.getContext('2d');

  const createOffscreenCanvas = (width, height) => {
    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    return canvas;
  };

  const createLayerState = (id, name) => ({
    id,
    name,
    visible: true,
    canvas: createOffscreenCanvas(mainCanvas.width, mainCanvas.height),
  });

  const firstLayerEl = document.querySelector('[data-layer-id]');
  const firstLayerId = firstLayerEl ? firstLayerEl.getAttribute('data-layer-id') : 'layer-0';

  const state = {
    tool: 'freehand',
    color: '#000000',
    brushSize: 3,
    layers: [createLayerState(firstLayerId, 'Background')],
    activeLayerId: firstLayerId,
    drawing: false,
    points: [],
    undoStack: [],
    redoStack: [],
  };

  // --- Compositing ---

  const compositeToMain = () => {
    ctx.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, mainCanvas.width, mainCanvas.height);
    for (const layer of state.layers) {
      if (layer.visible) {
        ctx.drawImage(layer.canvas, 0, 0);
      }
    }
  };

  const updateThumbnails = () => {
    for (const layer of state.layers) {
      const thumb = document.querySelector(`[data-thumbnail="${layer.id}"]`);
      if (thumb) {
        const tctx = thumb.getContext('2d');
        if (tctx) {
          tctx.clearRect(0, 0, thumb.width, thumb.height);
          tctx.fillStyle = '#ffffff';
          tctx.fillRect(0, 0, thumb.width, thumb.height);
          tctx.drawImage(layer.canvas, 0, 0, thumb.width, thumb.height);
        }
      }
    }
  };

  const getActiveLayer = () => state.layers.find((l) => l.id === state.activeLayerId);

  // --- Undo / Redo ---

  const saveUndoState = () => {
    const snapshot = state.layers.map((layer) => {
      const layerCtx = layer.canvas.getContext('2d');
      return layerCtx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
    });
    state.undoStack.push(snapshot);
    state.redoStack.length = 0;
    if (state.undoStack.length > 50) state.undoStack.shift();
  };

  const restoreSnapshot = (snapshot) => {
    for (let i = 0; i < state.layers.length && i < snapshot.length; i++) {
      const layerCtx = state.layers[i].canvas.getContext('2d');
      layerCtx.putImageData(snapshot[i], 0, 0);
    }
    compositeToMain();
    updateThumbnails();
  };

  // --- Drawing functions ---

  const getCanvasPoint = (e) => {
    const rect = mainCanvas.getBoundingClientRect();
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  const drawFreehand = (targetCtx, points, color, size) => {
    if (points.length < 2) return;
    targetCtx.strokeStyle = color;
    targetCtx.lineWidth = size;
    targetCtx.lineCap = 'round';
    targetCtx.lineJoin = 'round';
    targetCtx.beginPath();
    targetCtx.moveTo(points[0].x, points[0].y);
    for (let i = 1; i < points.length; i++) {
      targetCtx.lineTo(points[i].x, points[i].y);
    }
    targetCtx.stroke();
  };

  const drawRectangle = (targetCtx, start, end, color, size) => {
    targetCtx.strokeStyle = color;
    targetCtx.lineWidth = size;
    targetCtx.strokeRect(start.x, start.y, end.x - start.x, end.y - start.y);
  };

  const drawCircle = (targetCtx, start, end, color, size) => {
    const rx = (end.x - start.x) / 2;
    const ry = (end.y - start.y) / 2;
    const cx = start.x + rx;
    const cy = start.y + ry;
    const radius = Math.sqrt(rx * rx + ry * ry);
    targetCtx.strokeStyle = color;
    targetCtx.lineWidth = size;
    targetCtx.beginPath();
    targetCtx.arc(cx, cy, Math.abs(radius), 0, Math.PI * 2);
    targetCtx.stroke();
  };

  const drawLine = (targetCtx, start, end, color, size) => {
    targetCtx.strokeStyle = color;
    targetCtx.lineWidth = size;
    targetCtx.lineCap = 'round';
    targetCtx.beginPath();
    targetCtx.moveTo(start.x, start.y);
    targetCtx.lineTo(end.x, end.y);
    targetCtx.stroke();
  };

  const erase = (targetCtx, points, size) => {
    if (points.length < 2) return;
    targetCtx.globalCompositeOperation = 'destination-out';
    targetCtx.lineWidth = size;
    targetCtx.lineCap = 'round';
    targetCtx.lineJoin = 'round';
    targetCtx.beginPath();
    targetCtx.moveTo(points[0].x, points[0].y);
    for (let i = 1; i < points.length; i++) {
      targetCtx.lineTo(points[i].x, points[i].y);
    }
    targetCtx.stroke();
    targetCtx.globalCompositeOperation = 'source-over';
  };

  // --- Drawing preview and commit ---

  const drawPreview = () => {
    compositeToMain();
    if (state.points.length < 2) return;
    const start = state.points[0];
    const end = state.points[state.points.length - 1];

    switch (state.tool) {
      case 'freehand':
        drawFreehand(ctx, state.points, state.color, state.brushSize);
        break;
      case 'rectangle':
        drawRectangle(ctx, start, end, state.color, state.brushSize);
        break;
      case 'circle':
        drawCircle(ctx, start, end, state.color, state.brushSize);
        break;
      case 'line':
        drawLine(ctx, start, end, state.color, state.brushSize);
        break;
      case 'eraser':
        erase(ctx, state.points, state.brushSize);
        break;
    }
  };

  const commitDraw = () => {
    const layer = getActiveLayer();
    if (!layer || state.points.length < 2) return;
    const layerCtx = layer.canvas.getContext('2d');
    const start = state.points[0];
    const end = state.points[state.points.length - 1];

    switch (state.tool) {
      case 'freehand':
        drawFreehand(layerCtx, state.points, state.color, state.brushSize);
        break;
      case 'rectangle':
        drawRectangle(layerCtx, start, end, state.color, state.brushSize);
        break;
      case 'circle':
        drawCircle(layerCtx, start, end, state.color, state.brushSize);
        break;
      case 'line':
        drawLine(layerCtx, start, end, state.color, state.brushSize);
        break;
      case 'eraser':
        erase(layerCtx, state.points, state.brushSize);
        break;
    }
    compositeToMain();
    updateThumbnails();
  };

  // --- Canvas pointer events ---

  mainCanvas.addEventListener('pointerdown', (e) => {
    state.drawing = true;
    state.points = [getCanvasPoint(e)];
    saveUndoState();
    mainCanvas.setPointerCapture(e.pointerId);
  });

  mainCanvas.addEventListener('pointermove', (e) => {
    if (!state.drawing) return;
    state.points.push(getCanvasPoint(e));
    drawPreview();
  });

  mainCanvas.addEventListener('pointerup', () => {
    if (!state.drawing) return;
    state.drawing = false;
    commitDraw();
    state.points = [];
  });

  // --- Tool selection ---

  const updateToolButtons = () => {
    document.querySelectorAll('[data-tool]').forEach((btn) => {
      const tool = btn.getAttribute('data-tool');
      if (tool === state.tool) {
        btn.style.backgroundColor = '#89b4fa';
        btn.style.color = '#1e1e2e';
        btn.style.border = '1px solid #89b4fa';
      } else {
        btn.style.backgroundColor = '#45475a';
        btn.style.color = '#cdd6f4';
        btn.style.border = '1px solid #585b70';
      }
    });
  };

  document.querySelectorAll('[data-tool]').forEach((btn) => {
    btn.addEventListener('click', () => {
      state.tool = btn.getAttribute('data-tool');
      updateToolButtons();
    });
  });

  // --- Color picker ---

  const colorInput = document.querySelector('input[type="color"]');
  if (colorInput) {
    colorInput.addEventListener('input', () => {
      state.color = colorInput.value;
    });
  }

  // --- Brush size ---

  const sizeInput = document.querySelector('input[type="range"]');
  const sizeLabel = sizeInput ? sizeInput.nextElementSibling : null;
  if (sizeInput) {
    sizeInput.addEventListener('input', () => {
      state.brushSize = Number(sizeInput.value);
      if (sizeLabel) sizeLabel.textContent = sizeInput.value;
    });
  }

  // --- Action buttons (find by text content) ---

  const findButton = (text) => Array.from(document.querySelectorAll('button')).find((b) => b.textContent.trim() === text);

  // Undo
  const undoBtn = findButton('Undo');
  undoBtn?.addEventListener('click', () => {
    if (state.undoStack.length === 0) return;
    const current = state.layers.map((layer) => {
      const layerCtx = layer.canvas.getContext('2d');
      return layerCtx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
    });
    state.redoStack.push(current);
    restoreSnapshot(state.undoStack.pop());
  });

  // Redo
  const redoBtn = findButton('Redo');
  redoBtn?.addEventListener('click', () => {
    if (state.redoStack.length === 0) return;
    const current = state.layers.map((layer) => {
      const layerCtx = layer.canvas.getContext('2d');
      return layerCtx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
    });
    state.undoStack.push(current);
    restoreSnapshot(state.redoStack.pop());
  });

  // Clear
  const clearBtn = findButton('Clear');
  clearBtn?.addEventListener('click', () => {
    saveUndoState();
    const layer = getActiveLayer();
    if (layer) {
      const layerCtx = layer.canvas.getContext('2d');
      layerCtx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
    }
    compositeToMain();
    updateThumbnails();
  });

  // Save PNG
  const saveBtn = findButton('Save PNG');
  saveBtn?.addEventListener('click', async () => {
    const exportCanvas = createOffscreenCanvas(mainCanvas.width, mainCanvas.height);
    const exportCtx = exportCanvas.getContext('2d');
    exportCtx.fillStyle = '#ffffff';
    exportCtx.fillRect(0, 0, exportCanvas.width, exportCanvas.height);
    for (const layer of state.layers) {
      if (layer.visible) {
        exportCtx.drawImage(layer.canvas, 0, 0);
      }
    }
    const dataUrl = exportCanvas.toDataURL('image/png');

    try {
      const res = await fetch('/api/save', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: 'Drawing ' + Date.now(), dataUrl }),
      });
      const result = await res.json();
      if (result.ok) {
        const a = document.createElement('a');
        a.href = dataUrl;
        a.download = result.drawing.id + '.png';
        a.click();
      }
