        }
      });
    }
  });

  // --- Keyboard shortcuts ---

  document.addEventListener('keydown', (e) => {
    // Don't intercept if typing in an input
    if (e.target.tagName === 'INPUT') return;

    if (e.ctrlKey || e.metaKey) {
      if (e.key === 'z' && !e.shiftKey) {
        e.preventDefault();
        undoBtn?.click();
      } else if ((e.key === 'z' && e.shiftKey) || e.key === 'y') {
        e.preventDefault();
        redoBtn?.click();
      }
    }
    if (!e.ctrlKey && !e.metaKey) {
      switch (e.key) {
        case 'b': state.tool = 'freehand'; updateToolButtons(); break;
        case 'r': state.tool = 'rectangle'; updateToolButtons(); break;
        case 'c': state.tool = 'circle'; updateToolButtons(); break;
        case 'l': state.tool = 'line'; updateToolButtons(); break;
        case 'e': state.tool = 'eraser'; updateToolButtons(); break;
      }
    }
  });

  // --- Init ---
  compositeToMain();
  updateThumbnails();
})();

{
  "name": "@node/drawing-canvas",
