export type ToolKind = "freehand" | "rectangle" | "circle" | "line" | "eraser";

export type Point = { x: number; y: number };

export type ShapeStroke = {
  tool: ToolKind;
  color: string;
  size: number;
  points: Point[];
};

export type Layer = {
  id: string;
  name: string;
  visible: boolean;
  strokes: ShapeStroke[];
};

export type CanvasDocument = {
  id: string;
  name: string;
  width: number;
  height: number;
  layers: Layer[];
  activeLayerId: string;
  createdAt: string;
  updatedAt: string;
};

export type HistoryEntry = {
  layers: Layer[];
  activeLayerId: string;
};

export type DrawingState = {
  doc: CanvasDocument;
  undoStack: HistoryEntry[];
  redoStack: HistoryEntry[];
  currentTool: ToolKind;
  currentColor: string;
  brushSize: number;
};

export type SavedDrawing = {
  id: string;
  name: string;
  filename: string;
  savedAt: string;
};

export type SavedDrawingsIndex = {
  drawings: SavedDrawing[];
};

import type { CanvasDocument, DrawingState, HistoryEntry, Layer, ToolKind } from "./types";

const MAX_UNDO = 50;

const makeId = (): string => crypto.randomUUID();

export const createLayer = (name: string): Layer => ({
  id: makeId(),
  name,
  visible: true,
  strokes: [],
});

export const createDocument = (
  name: string,
  width = 800,
  height = 600,
): CanvasDocument => {
  const layer = createLayer("Layer 1");
  return {
    id: makeId(),
    name,
    width,
    height,
    layers: [layer],
    activeLayerId: layer.id,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
};

export const createDrawingState = (doc: CanvasDocument): DrawingState => ({
  doc,
  undoStack: [],
  redoStack: [],
  currentTool: "freehand",
  currentColor: "#000000",
  brushSize: 4,
});

const snapshot = (doc: CanvasDocument): HistoryEntry => ({
  layers: JSON.parse(JSON.stringify(doc.layers)),
  activeLayerId: doc.activeLayerId,
});

export const pushUndo = (state: DrawingState): void => {
  state.undoStack.push(snapshot(state.doc));
  if (state.undoStack.length > MAX_UNDO) {
    state.undoStack.shift();
  }
  state.redoStack = [];
};

export const undo = (state: DrawingState): boolean => {
  const entry = state.undoStack.pop();
  if (!entry) return false;
  state.redoStack.push(snapshot(state.doc));
  state.doc.layers = entry.layers;
  state.doc.activeLayerId = entry.activeLayerId;
  state.doc.updatedAt = new Date().toISOString();
  return true;
};

export const redo = (state: DrawingState): boolean => {
  const entry = state.redoStack.pop();
  if (!entry) return false;
  state.undoStack.push(snapshot(state.doc));
  state.doc.layers = entry.layers;
  state.doc.activeLayerId = entry.activeLayerId;
  state.doc.updatedAt = new Date().toISOString();
  return true;
};

export const setTool = (state: DrawingState, tool: ToolKind): void => {
  state.currentTool = tool;
};

export const setColor = (state: DrawingState, color: string): void => {
  state.currentColor = color;
};

export const setBrushSize = (state: DrawingState, size: number): void => {
  state.brushSize = Math.max(1, Math.min(100, size));
};

export const addLayer = (state: DrawingState): Layer => {
  pushUndo(state);
  const layer = createLayer(`Layer ${state.doc.layers.length + 1}`);
  state.doc.layers.push(layer);
  state.doc.activeLayerId = layer.id;
  state.doc.updatedAt = new Date().toISOString();
  return layer;
};

export const removeLayer = (state: DrawingState, layerId: string): boolean => {
  if (state.doc.layers.length <= 1) return false;
  pushUndo(state);
  const idx = state.doc.layers.findIndex((l) => l.id === layerId);
  if (idx === -1) return false;
  state.doc.layers.splice(idx, 1);
  if (state.doc.activeLayerId === layerId) {
    state.doc.activeLayerId = state.doc.layers[Math.max(0, idx - 1)].id;
  }
  state.doc.updatedAt = new Date().toISOString();
  return true;
};

export const toggleLayerVisibility = (state: DrawingState, layerId: string): boolean => {
  const layer = state.doc.layers.find((l) => l.id === layerId);
  if (!layer) return false;
  layer.visible = !layer.visible;
  return true;
};

export const setActiveLayer = (state: DrawingState, layerId: string): boolean => {
  const layer = state.doc.layers.find((l) => l.id === layerId);
  if (!layer) return false;
  state.doc.activeLayerId = layerId;
  return true;
};

export const clearActiveLayer = (state: DrawingState): void => {
  pushUndo(state);
  const layer = state.doc.layers.find((l) => l.id === state.doc.activeLayerId);
  if (layer) {
    layer.strokes = [];
  }
  state.doc.updatedAt = new Date().toISOString();
};

export const getActiveLayer = (state: DrawingState): Layer | undefined =>
  state.doc.layers.find((l) => l.id === state.doc.activeLayerId);

import type { CanvasDocument, SavedDrawingsIndex } from "./types";

const DATA_DIR = new URL("../data/", import.meta.url).pathname;
const INDEX_PATH = `${DATA_DIR}index.json`;

const ensureDataDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR);
  if (!(await dir.exists())) {
    await Bun.$`mkdir -p ${DATA_DIR}`;
  }
};

const readIndex = async (): Promise<SavedDrawingsIndex> => {
  const file = Bun.file(INDEX_PATH);
  if (await file.exists()) {
    return (await file.json()) as SavedDrawingsIndex;
  }
  return { drawings: [] };
};

const writeIndex = async (index: SavedDrawingsIndex): Promise<void> => {
  await Bun.write(INDEX_PATH, JSON.stringify(index, null, 2));
};

export const saveDocument = async (doc: CanvasDocument): Promise<string> => {
  await ensureDataDir();
  const filename = `${doc.id}.json`;
  const filepath = `${DATA_DIR}${filename}`;
  await Bun.write(filepath, JSON.stringify(doc, null, 2));

  const index = await readIndex();
  const existing = index.drawings.find((d) => d.id === doc.id);
  if (existing) {
    existing.name = doc.name;
    existing.savedAt = new Date().toISOString();
  } else {
    index.drawings.push({
      id: doc.id,
      name: doc.name,
      filename,
      savedAt: new Date().toISOString(),
    });
  }
  await writeIndex(index);
  return filepath;
};

export const loadDocument = async (id: string): Promise<CanvasDocument | null> => {
  const filepath = `${DATA_DIR}${id}.json`;
  const file = Bun.file(filepath);
  if (!(await file.exists())) return null;
  return (await file.json()) as CanvasDocument;
};

export const listDocuments = async (): Promise<SavedDrawingsIndex> => {
  await ensureDataDir();
  return readIndex();
};

export const savePng = async (id: string, pngData: Buffer): Promise<string> => {
  await ensureDataDir();
  const filepath = `${DATA_DIR}${id}.png`;
  await Bun.write(filepath, pngData);
  return filepath;
};

export const loadPng = async (id: string): Promise<Uint8Array | null> => {
  const filepath = `${DATA_DIR}${id}.png`;
  const file = Bun.file(filepath);
  if (!(await file.exists())) return null;
  return new Uint8Array(await file.arrayBuffer());
};

export const deleteDocument = async (id: string): Promise<boolean> => {
  const index = await readIndex();
  const idx = index.drawings.findIndex((d) => d.id === id);
  if (idx === -1) return false;
  index.drawings.splice(idx, 1);
  await writeIndex(index);

  const jsonFile = Bun.file(`${DATA_DIR}${id}.json`);
  if (await jsonFile.exists()) await Bun.$`rm ${DATA_DIR}${id}.json`;
  const pngFile = Bun.file(`${DATA_DIR}${id}.png`);
  if (await pngFile.exists()) await Bun.$`rm ${DATA_DIR}${id}.png`;
  return true;
};

