const clientScript = (state: DrawingState) => `
(()=>{
const STATE = ${JSON.stringify({
  doc: state.doc,
  undoStack: [],
  redoStack: [],
  currentTool: state.currentTool,
  currentColor: state.currentColor,
  brushSize: state.brushSize,
})};

const mainCanvas = document.getElementById("main-canvas");
const previewCanvas = document.getElementById("preview-canvas");
const ctx = mainCanvas.getContext("2d");
const pctx = previewCanvas.getContext("2d");

// Position canvases
const positionCanvases = () => {
  const container = document.querySelector(".canvas-container");
  const rect = container.getBoundingClientRect();
  const cx = (rect.width - mainCanvas.width) / 2;
  const cy = (rect.height - mainCanvas.height) / 2;
  mainCanvas.style.left = cx + "px";
  mainCanvas.style.top = cy + "px";
  previewCanvas.style.left = cx + "px";
  previewCanvas.style.top = cy + "px";
  previewCanvas.style.position = "absolute";
};
positionCanvases();
window.addEventListener("resize", positionCanvases);

let drawing = false;
let startPt = null;
let currentPoints = [];

const getActiveLayer = () => STATE.doc.layers.find(l => l.id === STATE.doc.activeLayerId);

const snapshot = () => ({
  layers: JSON.parse(JSON.stringify(STATE.doc.layers)),
  activeLayerId: STATE.doc.activeLayerId
});

const pushUndo = () => {
  STATE.undoStack.push(snapshot());
  if (STATE.undoStack.length > 50) STATE.undoStack.shift();
  STATE.redoStack = [];
};

// Rendering
const renderAll = () => {
  ctx.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, mainCanvas.width, mainCanvas.height);
  for (const layer of STATE.doc.layers) {
    if (!layer.visible) continue;
    for (const stroke of layer.strokes) {
      drawStroke(ctx, stroke);
    }
  }
  updateThumbnails();
};

const drawStroke = (context, stroke) => {
  context.save();
  context.strokeStyle = stroke.tool === "eraser" ? "#ffffff" : stroke.color;
  context.lineWidth = stroke.size;
  context.lineCap = "round";
  context.lineJoin = "round";

  if (stroke.tool === "freehand" || stroke.tool === "eraser") {
    if (stroke.points.length < 2) { context.restore(); return; }
    context.beginPath();
    context.moveTo(stroke.points[0].x, stroke.points[0].y);
    for (let i = 1; i < stroke.points.length; i++) {
      context.lineTo(stroke.points[i].x, stroke.points[i].y);
    }
    context.stroke();
  } else if (stroke.tool === "rectangle") {
    if (stroke.points.length < 2) { context.restore(); return; }
    const [p1, p2] = [stroke.points[0], stroke.points[stroke.points.length - 1]];
    context.beginPath();
    context.rect(p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
    context.stroke();
  } else if (stroke.tool === "circle") {
    if (stroke.points.length < 2) { context.restore(); return; }
    const [p1, p2] = [stroke.points[0], stroke.points[stroke.points.length - 1]];
    const rx = Math.abs(p2.x - p1.x) / 2;
    const ry = Math.abs(p2.y - p1.y) / 2;
    const cx = (p1.x + p2.x) / 2;
    const cy = (p1.y + p2.y) / 2;
    context.beginPath();
    context.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
    context.stroke();
  } else if (stroke.tool === "line") {
    if (stroke.points.length < 2) { context.restore(); return; }
    const [p1, p2] = [stroke.points[0], stroke.points[stroke.points.length - 1]];
    context.beginPath();
    context.moveTo(p1.x, p1.y);
    context.lineTo(p2.x, p2.y);
    context.stroke();
  }
  context.restore();
};

const updateThumbnails = () => {
  const thumbs = document.querySelectorAll(".layer-thumb-canvas");
  for (const thumb of thumbs) {
    const layerId = thumb.dataset.layerId;
    const layer = STATE.doc.layers.find(l => l.id === layerId);
    if (!layer) continue;
    const tctx = thumb.getContext("2d");
    tctx.clearRect(0, 0, 60, 45);
    tctx.fillStyle = "#181825";
    tctx.fillRect(0, 0, 60, 45);
    tctx.save();
    tctx.scale(60 / mainCanvas.width, 45 / mainCanvas.height);
    for (const stroke of layer.strokes) {
      drawStroke(tctx, stroke);
    }
    tctx.restore();
  }
};

// Mouse coords relative to canvas
const getPos = (e) => {
  const rect = mainCanvas.getBoundingClientRect();
  return { x: e.clientX - rect.left, y: e.clientY - rect.top };
};

// Event handling via p-trigger pattern
const handleTrigger = (el, action, detail) => {
  if (action === "select-tool") {
    STATE.currentTool = detail;
    document.querySelectorAll(".tool-btn").forEach(b => b.classList.remove("active"));
    el.classList.add("active");
  } else if (action === "change-color") {
    STATE.currentColor = el.value;
  } else if (action === "change-size") {
    STATE.brushSize = parseInt(el.value);
    document.querySelector(".size-label").textContent = "Size: " + STATE.brushSize;
  } else if (action === "undo") {
    const entry = STATE.undoStack.pop();
    if (entry) {
      STATE.redoStack.push(snapshot());
      STATE.doc.layers = entry.layers;
      STATE.doc.activeLayerId = entry.activeLayerId;
      renderAll();
      rebuildLayersPanel();
    }
  } else if (action === "redo") {
    const entry = STATE.redoStack.pop();
    if (entry) {
      STATE.undoStack.push(snapshot());
      STATE.doc.layers = entry.layers;
      STATE.doc.activeLayerId = entry.activeLayerId;
      renderAll();
      rebuildLayersPanel();
    }
  } else if (action === "clear") {
    pushUndo();
    const layer = getActiveLayer();
    if (layer) layer.strokes = [];
    renderAll();
  } else if (action === "save") {
    savePng();
  } else if (action === "load-png") {
    loadPng(el);
  } else if (action === "add-layer") {
    pushUndo();
    const newLayer = {
      id: crypto.randomUUID(),
      name: "Layer " + (STATE.doc.layers.length + 1),
      visible: true,
      strokes: []
    };
    STATE.doc.layers.push(newLayer);
    STATE.doc.activeLayerId = newLayer.id;
    rebuildLayersPanel();
    renderAll();
  } else if (action === "toggle-visibility") {
    const layer = STATE.doc.layers.find(l => l.id === detail);
    if (layer) {
      layer.visible = !layer.visible;
      renderAll();
      rebuildLayersPanel();
    }
  } else if (action === "select-layer") {
    STATE.doc.activeLayerId = detail;
    rebuildLayersPanel();
  } else if (action === "remove-layer") {
    if (STATE.doc.layers.length <= 1) return;
    pushUndo();
    const idx = STATE.doc.layers.findIndex(l => l.id === detail);
    if (idx === -1) return;
    STATE.doc.layers.splice(idx, 1);
    if (STATE.doc.activeLayerId === detail) {
      STATE.doc.activeLayerId = STATE.doc.layers[Math.max(0, idx - 1)].id;
    }
    renderAll();
    rebuildLayersPanel();
  }
};

// Delegate click/input events via p-trigger
document.addEventListener("click", (e) => {
  const el = e.target.closest("[p-trigger]");
  if (!el) return;
  const trigger = el.getAttribute("p-trigger");
  if (!trigger) return;
  const parts = trigger.split(":");
  if (parts[0] !== "click") return;
  handleTrigger(el, parts[1], parts[2]);
});

document.addEventListener("input", (e) => {
  const el = e.target.closest("[p-trigger]");
  if (!el) return;
  const trigger = el.getAttribute("p-trigger");
  if (!trigger) return;
  const parts = trigger.split(":");
  if (parts[0] !== "input") return;
  handleTrigger(el, parts[1], parts[2]);
});

document.addEventListener("change", (e) => {
  const el = e.target.closest("[p-trigger]");
  if (!el) return;
  const trigger = el.getAttribute("p-trigger");
  if (!trigger) return;
  const parts = trigger.split(":");
  if (parts[0] !== "change") return;
  handleTrigger(el, parts[1], parts[2]);
});

// Canvas drawing events
mainCanvas.addEventListener("pointerdown", (e) => {
  const layer = getActiveLayer();
  if (!layer || !layer.visible) return;
  drawing = true;
  const pos = getPos(e);
  startPt = pos;
  currentPoints = [pos];
  mainCanvas.setPointerCapture(e.pointerId);
});

mainCanvas.addEventListener("pointermove", (e) => {
  if (!drawing) return;
  const pos = getPos(e);
  currentPoints.push(pos);

  pctx.clearRect(0, 0, previewCanvas.width, previewCanvas.height);
  const previewStroke = {
    tool: STATE.currentTool,
    color: STATE.currentColor,
    size: STATE.brushSize,
    points: STATE.currentTool === "freehand" || STATE.currentTool === "eraser"
      ? currentPoints
      : [startPt, pos]
  };
  drawStroke(pctx, previewStroke);
});

mainCanvas.addEventListener("pointerup", (e) => {
  if (!drawing) return;
  drawing = false;
  pctx.clearRect(0, 0, previewCanvas.width, previewCanvas.height);

  const layer = getActiveLayer();
  if (!layer) return;
  if (currentPoints.length < 2) return;

  pushUndo();
  const finalPoints = STATE.currentTool === "freehand" || STATE.currentTool === "eraser"
    ? [...currentPoints]
    : [startPt, currentPoints[currentPoints.length - 1]];

  layer.strokes.push({
    tool: STATE.currentTool,
    color: STATE.currentColor,
    size: STATE.brushSize,
    points: finalPoints
  });
  renderAll();
  currentPoints = [];
  startPt = null;
});

// Save as PNG
const savePng = () => {
  const tmpCanvas = document.createElement("canvas");
  tmpCanvas.width = mainCanvas.width;
  tmpCanvas.height = mainCanvas.height;
  const tmpCtx = tmpCanvas.getContext("2d");
  tmpCtx.fillStyle = "#ffffff";
  tmpCtx.fillRect(0, 0, tmpCanvas.width, tmpCanvas.height);
  for (const layer of STATE.doc.layers) {
    if (!layer.visible) continue;
    for (const stroke of layer.strokes) {
      drawStroke(tmpCtx, stroke);
    }
  }
  const link = document.createElement("a");
  link.download = (STATE.doc.name || "drawing") + ".png";
  link.href = tmpCanvas.toDataURL("image/png");
  link.click();

  // Also save to server
  tmpCanvas.toBlob(async (blob) => {
    if (!blob) return;
    const formData = new FormData();
    formData.append("png", blob, STATE.doc.id + ".png");
    formData.append("doc", JSON.stringify(STATE.doc));
    try {
      await fetch("/api/save", { method: "POST", body: formData });
    } catch(e) { console.warn("Server save failed:", e); }
  }, "image/png");
};

// Load PNG onto active layer
const loadPng = (input) => {
  const file = input.files[0];
  if (!file) return;
  const img = new Image();
  img.onload = () => {
    pushUndo();
    // Draw image to a temporary canvas and capture as the active layer background
    const tmpCanvas = document.createElement("canvas");
    tmpCanvas.width = mainCanvas.width;
    tmpCanvas.height = mainCanvas.height;
    const tmpCtx = tmpCanvas.getContext("2d");
    tmpCtx.drawImage(img, 0, 0, mainCanvas.width, mainCanvas.height);

    // Overwrite the main canvas content then re-render
    ctx.drawImage(tmpCanvas, 0, 0);
    URL.revokeObjectURL(img.src);
  };
  img.src = URL.createObjectURL(file);
  input.value = "";
};

// Rebuild layers panel DOM
const rebuildLayersPanel = () => {
  const list = document.getElementById("layers-list");
  list.innerHTML = "";
  const reversed = [...STATE.doc.layers].reverse();
  for (const layer of reversed) {
    const isActive = layer.id === STATE.doc.activeLayerId;
    const item = document.createElement("div");
    item.className = "layer-item" + (isActive ? " active" : "");
    item.dataset.layerId = layer.id;
    item.innerHTML =
      '<button class="visibility-toggle' + (layer.visible ? " visible" : "") + '" p-trigger="click:toggle-visibility:' + layer.id + '" title="' + (layer.visible ? "Hide" : "Show") + '">' + (layer.visible ? "\u{1F441}" : "\u25CB") + '</button>' +
      '<div class="layer-thumbnail" p-trigger="click:select-layer:' + layer.id + '"><canvas class="layer-thumb-canvas" data-layer-id="' + layer.id + '" width="60" height="45"></canvas></div>' +
      '<span class="layer-name" p-trigger="click:select-layer:' + layer.id + '">' + layer.name + '</span>' +
      '<button class="layer-delete" p-trigger="click:remove-layer:' + layer.id + '" title="Delete">\u00D7</button>';
    list.appendChild(item);
  }
  updateThumbnails();
};

// Keyboard shortcuts
document.addEventListener("keydown", (e) => {
  if (e.ctrlKey || e.metaKey) {
    if (e.key === "z" && !e.shiftKey) {
      e.preventDefault();
      handleTrigger(null, "undo");
    } else if ((e.key === "z" && e.shiftKey) || e.key === "y") {
      e.preventDefault();
      handleTrigger(null, "redo");
    }
  }
});

renderAll();
})();
`;

import { createDocument, createDrawingState } from "./state";
import { renderPage } from "./render";
import { saveDocument, savePng, loadDocument, listDocuments, deleteDocument } from "./storage";
import type { CanvasDocument } from "./types";

const PORT = Number(process.env.PORT) || 3000;

const defaultState = () => {
  const doc = createDocument("Untitled Drawing");
  return createDrawingState(doc);
};

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;

  // Serve the main page
  if (pathname === "/" && req.method === "GET") {
    const docId = url.searchParams.get("doc");
    let state;
    if (docId) {
      const doc = await loadDocument(docId);
      state = doc ? createDrawingState(doc) : defaultState();
    } else {
      state = defaultState();
    }
    const html = renderPage(state);
    return new Response(html, {
      headers: { "Content-Type": "text/html; charset=utf-8" },
    });
  }

  // Save drawing + PNG
  if (pathname === "/api/save" && req.method === "POST") {
    const formData = await req.formData();
    const pngBlob = formData.get("png") as Blob | null;
    const docJson = formData.get("doc") as string | null;

    if (docJson) {
      const doc: CanvasDocument = JSON.parse(docJson);
      await saveDocument(doc);
      if (pngBlob) {
        const buffer = Buffer.from(await pngBlob.arrayBuffer());
        await savePng(doc.id, buffer);
      }
      return Response.json({ ok: true, id: doc.id });
    }
    return Response.json({ error: "Missing document data" }, { status: 400 });
  }

  // List saved drawings
  if (pathname === "/api/drawings" && req.method === "GET") {
    const index = await listDocuments();
    return Response.json(index);
  }

  // Load a specific drawing
  if (pathname.startsWith("/api/drawings/") && req.method === "GET") {
    const id = pathname.split("/").pop()!;
    const doc = await loadDocument(id);
    if (!doc) return Response.json({ error: "Not found" }, { status: 404 });
    return Response.json(doc);
  }

  // Delete a drawing
  if (pathname.startsWith("/api/drawings/") && req.method === "DELETE") {
    const id = pathname.split("/").pop()!;
    const ok = await deleteDocument(id);
    return Response.json({ ok });
  }

  return new Response("Not Found", { status: 404 });
};

Bun.serve({
  port: PORT,
  fetch: handleRequest,
});

