export type Stats = {
  count: number
  mean: number
  median: number
  mode: number[]
  stddev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

export type NamedStats = {
  name: string
  data: number[]
  stats: Stats
}

const sorted = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const sum = (arr: number[]): number => arr.reduce((acc, v) => acc + v, 0)

const calcMean = (arr: number[]): number => sum(arr) / arr.length

const calcMedian = (arr: number[]): number => {
  const s = sorted(arr)
  const mid = Math.floor(s.length / 2)
  return s.length % 2 === 0 ? (s[mid - 1] + s[mid]) / 2 : s[mid]
}

const calcMode = (arr: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of arr) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return []
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return sorted(modes)
}

const calcVariance = (arr: number[], mean: number): number => {
  const squaredDiffs = arr.map((v) => (v - mean) ** 2)
  return sum(squaredDiffs) / arr.length
}

const calcQuartile = (arr: number[], q: 0.25 | 0.75): number => {
  const s = sorted(arr)
  const pos = (s.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return s[lo]
  return s[lo] + (s[hi] - s[lo]) * (pos - lo)
}

export const computeStats = (data: number[]): Stats => {
  if (data.length === 0) {
    return {
      count: 0,
      mean: 0,
      median: 0,
      mode: [],
      stddev: 0,
      variance: 0,
      min: 0,
      max: 0,
      range: 0,
      q1: 0,
      q3: 0,
      iqr: 0,
    }
  }

  const mean = calcMean(data)
  const variance = calcVariance(data, mean)
  const s = sorted(data)
  const q1 = calcQuartile(data, 0.25)
  const q3 = calcQuartile(data, 0.75)

  return {
    count: data.length,
    mean,
    median: calcMedian(data),
    mode: calcMode(data),
    stddev: Math.sqrt(variance),
    variance,
    min: s[0],
    max: s[s.length - 1],
    range: s[s.length - 1] - s[0],
    q1,
    q3,
    iqr: q3 - q1,
  }
}

