const renderBoxPlot = (datasets: NamedStats[]) => {
  const width = 700
  const plotLeft = 80
  const plotRight = width - 40
  const plotWidth = plotRight - plotLeft
  const rowHeight = 60
  const topPad = 40
  const height = topPad + datasets.length * rowHeight + 40

  const allValues = datasets.flatMap((ds) => ds.data)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1
  const scaleMin = globalMin - padding
  const scaleMax = globalMax + padding
  const scaleRange = scaleMax - scaleMin

  const x = (val: number): number => plotLeft + ((val - scaleMin) / scaleRange) * plotWidth

  const tickCount = 8
  const tickStep = scaleRange / tickCount
  const ticks = Array.from({ length: tickCount + 1 }, (_, i) => scaleMin + i * tickStep)

  const tickElements = ticks.map((t) =>
    h('g', {},
      h('line', { x1: x(t), x2: x(t), y1: topPad - 5, y2: topPad + datasets.length * rowHeight, stroke: '#e0e0e0', 'stroke-width': '1' }),
      h('text', { x: x(t), y: topPad - 12, 'text-anchor': 'middle', 'font-size': '11', fill: '#777' }, fmt(t)),
    )
  )

  const boxPlots = datasets.map((ds, i) => {
    const color = COLORS[i % COLORS.length]
    const cy = topPad + i * rowHeight + rowHeight / 2
    const boxH = rowHeight * 0.5
    const { min, max, q1, q3, median } = ds.stats

    return h('g', {},
      h('line', { x1: x(min), x2: x(q1), y1: cy, y2: cy, stroke: color, 'stroke-width': '2' }),
      h('line', { x1: x(q3), x2: x(max), y1: cy, y2: cy, stroke: color, 'stroke-width': '2' }),
      h('line', { x1: x(min), x2: x(min), y1: cy - boxH / 4, y2: cy + boxH / 4, stroke: color, 'stroke-width': '2' }),
      h('line', { x1: x(max), x2: x(max), y1: cy - boxH / 4, y2: cy + boxH / 4, stroke: color, 'stroke-width': '2' }),
      h('rect', { x: x(q1), y: cy - boxH / 2, width: x(q3) - x(q1), height: boxH, fill: color, 'fill-opacity': '0.2', stroke: color, 'stroke-width': '2', rx: '3' }),
      h('line', { x1: x(median), x2: x(median), y1: cy - boxH / 2, y2: cy + boxH / 2, stroke: color, 'stroke-width': '3' }),
      h('text', { x: plotLeft - 8, y: cy + 4, 'text-anchor': 'end', 'font-size': '13', 'font-weight': '500', fill: color }, ds.name),
    )
  })

  return h('div', { style: styles.chartContainer },
    h('h2', { style: styles.heading }, 'Box Plot'),
    h('svg', { width, height, style: styles.svg, viewBox: `0 0 ${width} ${height}` },
      ...tickElements,
      ...boxPlots,
    ),
  )
}

const renderHistogram = (datasets: NamedStats[]) => {
  const width = 700
  const plotLeft = 60
  const plotBottom = 40
  const plotTop = 40
  const plotRight = width - 40
  const plotWidth = plotRight - plotLeft
  const height = 300
  const plotHeight = height - plotTop - plotBottom

  const allValues = datasets.flatMap((ds) => ds.data)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const binCount = Math.max(5, Math.min(20, Math.ceil(Math.sqrt(allValues.length))))
  const binWidth = (globalMax - globalMin) / binCount || 1

  type Bin = { lo: number; hi: number; count: number }

  const makeBins = (data: number[]): Bin[] => {
    const bins: Bin[] = Array.from({ length: binCount }, (_, i) => ({
      lo: globalMin + i * binWidth,
      hi: globalMin + (i + 1) * binWidth,
      count: 0,
    }))
    for (const v of data) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx].count++
    }
    return bins
  }

  const allBins = datasets.map((ds) => makeBins(ds.data))
  const maxCount = Math.max(1, ...allBins.flat().map((b) => b.count))

  const xScale = (val: number): number => plotLeft + ((val - globalMin) / (binCount * binWidth || 1)) * plotWidth
  const yScale = (count: number): number => plotTop + plotHeight - (count / maxCount) * plotHeight

  const barGroupWidth = binWidth / datasets.length

  const bars = datasets.flatMap((ds, di) => {
    const bins = allBins[di]
    const color = COLORS[di % COLORS.length]
    return bins.map((bin, bi) => {
      const bx = xScale(bin.lo + di * barGroupWidth)
      const bw = Math.max(1, xScale(bin.lo + barGroupWidth) - xScale(bin.lo) - 1)
      const by = yScale(bin.count)
      const bh = plotTop + plotHeight - by
      return h('rect', { x: bx, y: by, width: bw, height: bh, fill: color, 'fill-opacity': '0.6', stroke: color, 'stroke-width': '1' })
    })
  })

  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) => Math.round((maxCount / yTickCount) * i))
  const yTickEls = yTicks.map((t) =>
    h('g', {},
      h('line', { x1: plotLeft, x2: plotRight, y1: yScale(t), y2: yScale(t), stroke: '#e8e8e8', 'stroke-width': '1' }),
      h('text', { x: plotLeft - 8, y: yScale(t) + 4, 'text-anchor': 'end', 'font-size': '11', fill: '#777' }, t.toString()),
    )
  )

  const xTickCount = Math.min(binCount, 10)
  const xTickStep = Math.ceil(binCount / xTickCount)
  const xTicks = Array.from({ length: Math.ceil(binCount / xTickStep) + 1 }, (_, i) => i * xTickStep)
    .filter((i) => i <= binCount)
    .map((i) => globalMin + i * binWidth)
  const xTickEls = xTicks.map((t) =>
    h('text', { x: xScale(t), y: height - 12, 'text-anchor': 'middle', 'font-size': '11', fill: '#777' }, fmt(t))
  )

  const legend = datasets.map((ds, i) =>
    h('g', { transform: `translate(${plotLeft + i * 120}, ${plotTop - 20})` },
      h('rect', { x: 0, y: -8, width: 12, height: 12, fill: COLORS[i % COLORS.length], rx: '2' }),
      h('text', { x: 16, y: 2, 'font-size': '12', fill: '#555' }, ds.name),
    )
  )

  return h('div', { style: styles.chartContainer },
    h('h2', { style: styles.heading }, 'Histogram'),
    h('svg', { width, height, style: styles.svg, viewBox: `0 0 ${width} ${height}` },
      ...yTickEls,
      h('line', { x1: plotLeft, x2: plotRight, y1: plotTop + plotHeight, y2: plotTop + plotHeight, stroke: '#ccc', 'stroke-width': '1' }),
      ...bars,
      ...xTickEls,
      ...legend,
    ),
  )
}

export const renderDashboard = (datasets: NamedStats[]): string => {
  if (datasets.length === 0) {
    return '<div style="padding:24px;color:#888;">No datasets loaded. Add a dataset to get started.</div>'
  }

  const tree = h('div', { style: styles.container },
    h('h1', { style: { fontSize: '24px', fontWeight: '700', marginBottom: '24px' } }, 'Statistics Dashboard'),
    renderSummaryTable(datasets),
    renderBoxPlot(datasets),
    renderHistogram(datasets),
  )

  return tree as unknown as string
}

