const DATA_PATH = './data/datasets.json'

type StoredDatasets = {
  datasets: Record<string, number[]>
}

const loadStore = async (): Promise<StoredDatasets> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json() as Promise<StoredDatasets>
  }
  return { datasets: {} }
}

const saveStore = async (store: StoredDatasets): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const parseInput = (input: string): number[] => {
  const trimmed = input.trim()

  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }

  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !Number.isNaN(n))
}

export const addDataset = async (name: string, data: number[]): Promise<NamedStats> => {
  const store = await loadStore()
  store.datasets[name] = data
  await saveStore(store)
  const stats = computeStats(data)
  return { name, data, stats }
}

export const removeDataset = async (name: string): Promise<boolean> => {
  const store = await loadStore()
  if (!(name in store.datasets)) return false
  delete store.datasets[name]
  await saveStore(store)
  return true
}

export const getDataset = async (name: string): Promise<NamedStats | null> => {
  const store = await loadStore()
  const data = store.datasets[name]
  if (!data) return null
  return { name, data, stats: computeStats(data) }
}

export const getAllStats = async (): Promise<NamedStats[]> => {
  const store = await loadStore()
  return Object.entries(store.datasets).map(([name, data]) => ({
    name,
    data,
    stats: computeStats(data),
  }))
}

export const listDatasets = async (): Promise<string[]> => {
  const store = await loadStore()
  return Object.keys(store.datasets)
}

export const clearAllDatasets = async (): Promise<void> => {
  await saveStore({ datasets: {} })
}

export const render = async (): Promise<string> => {
  const allStats = await getAllStats()
  return renderDashboard(allStats)
}

const main = async () => {
  const args = process.argv.slice(2)
  const command = args[0]

  if (!command || command === 'help') {
    console.log(`Usage:
  bun run index.ts add <name> <data>     Add a named dataset (CSV or JSON array)
  bun run index.ts remove <name>         Remove a dataset
  bun run index.ts list                  List all datasets
  bun run index.ts stats [name]          Show stats for a dataset or all
  bun run index.ts render                Render HTML dashboard
  bun run index.ts clear                 Remove all datasets`)
    return
  }

  if (command === 'add') {
    const name = args[1]
    const raw = args.slice(2).join(' ')
    if (!name || !raw) {
      console.error('Usage: add <name> <data>')
      process.exit(1)
    }
    const data = parseInput(raw)
    if (data.length === 0) {
      console.error('No valid numbers found in input.')
      process.exit(1)
    }
    const result = await addDataset(name, data)
    console.log(`Added "${name}" with ${data.length} values.`)
    console.log(JSON.stringify(result.stats, null, 2))
    return
  }

  if (command === 'remove') {
    const name = args[1]
    if (!name) {
      console.error('Usage: remove <name>')
      process.exit(1)
    }
    const removed = await removeDataset(name)
    console.log(removed ? `Removed "${name}".` : `Dataset "${name}" not found.`)
    return
  }

  if (command === 'list') {
    const names = await listDatasets()
    if (names.length === 0) {
      console.log('No datasets.')
    } else {
      console.log('Datasets:')
      names.forEach((n) => console.log(`  - ${n}`))
    }
    return
  }

  if (command === 'stats') {
    const name = args[1]
    if (name) {
      const ds = await getDataset(name)
      if (!ds) {
        console.error(`Dataset "${name}" not found.`)
        process.exit(1)
      }
      console.log(`Stats for "${name}" (${ds.data.length} values):`)
      console.log(JSON.stringify(ds.stats, null, 2))
    } else {
      const all = await getAllStats()
      if (all.length === 0) {
        console.log('No datasets.')
        return
      }
      for (const ds of all) {
        console.log(`\n--- ${ds.name} (${ds.data.length} values) ---`)
        console.log(JSON.stringify(ds.stats, null, 2))
      }
    }
    return
  }

  if (command === 'render') {
    const html = await render()
    console.log(html)
    return
  }

  if (command === 'clear') {
    await clearAllDatasets()
    console.log('All datasets cleared.')
    return
  }

  console.error(`Unknown command: ${command}. Run with "help" for usage.`)
  process.exit(1)
}

main()

