export type NamedDataset = {
  name: string
  values: number[]
}

const parseValues = (raw: string): number[] => {
  const trimmed = raw.trim()
  if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !Number.isNaN(n))
}

export const parseInput = (input: string): NamedDataset[] => {
  const lines = input
    .split('\n')
    .map((l) => l.trim())
    .filter((l) => l.length > 0)

  const datasets: NamedDataset[] = []

  for (const line of lines) {
    const colonIdx = line.indexOf(':')
    if (colonIdx > 0) {
      const potentialName = line.slice(0, colonIdx).trim()
      const potentialValues = line.slice(colonIdx + 1).trim()
      if (potentialName.length > 0 && !/^\d+$/.test(potentialName)) {
        const values = parseValues(potentialValues)
        if (values.length > 0) {
          datasets.push({ name: potentialName, values })
          continue
        }
      }
    }
    const values = parseValues(line)
    if (values.length > 0) {
      datasets.push({ name: `Dataset ${datasets.length + 1}`, values })
    }
  }

  return datasets
}

export type Stats = {
  count: number
  mean: number
  median: number
  mode: number[]
  standardDeviation: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sorted = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const percentile = (sortedArr: number[], p: number): number => {
  const idx = (p / 100) * (sortedArr.length - 1)
  const lower = Math.floor(idx)
  const upper = Math.ceil(idx)
  if (lower === upper) return sortedArr[lower]
  const weight = idx - lower
  return sortedArr[lower] * (1 - weight) + sortedArr[upper] * weight
}

export const calculate = (values: number[]): Stats => {
  if (values.length === 0) {
    return {
      count: 0,
      mean: 0,
      median: 0,
      mode: [],
      standardDeviation: 0,
      variance: 0,
      min: 0,
      max: 0,
      range: 0,
      q1: 0,
      q3: 0,
      iqr: 0,
    }
  }

  const s = sorted(values)
  const n = s.length
  const sum = s.reduce((a, b) => a + b, 0)
  const mean = sum / n

  const median = percentile(s, 50)
  const q1 = percentile(s, 25)
  const q3 = percentile(s, 75)

  const variance = s.reduce((acc, v) => acc + (v - mean) ** 2, 0) / n
  const standardDeviation = Math.sqrt(variance)

  const min = s[0]
  const max = s[n - 1]

  const freqMap = new Map<number, number>()
  for (const v of s) {
    freqMap.set(v, (freqMap.get(v) ?? 0) + 1)
  }
  let maxFreq = 0
  for (const freq of freqMap.values()) {
    if (freq > maxFreq) maxFreq = freq
  }
  const mode = maxFreq > 1 ? [...freqMap.entries()].filter(([, f]) => f === maxFreq).map(([v]) => v) : []

  return {
    count: n,
    mean,
    median,
    mode,
    standardDeviation,
    variance,
    min,
    max,
    range: max - min,
    q1,
    q3,
    iqr: q3 - q1,
  }
}

export const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  return n.toFixed(4).replace(/0+$/, '').replace(/\.$/, '')
}

