const SVG_WIDTH = 600
const SVG_HEIGHT = 200
const PAD = { top: 30, right: 30, bottom: 40, left: 60 }

const scaleLinear = (domain: [number, number], range: [number, number]) => {
  const [d0, d1] = domain
  const [r0, r1] = range
  const span = d1 - d0 || 1
  return (value: number): number => r0 + ((value - d0) / span) * (r1 - r0)
}

const niceAxis = (min: number, max: number, ticks: number): number[] => {
  const range = max - min || 1
  const step = range / (ticks - 1)
  const result: number[] = []
  for (let i = 0; i < ticks; i++) {
    result.push(min + step * i)
  }
  return result
}

const renderBoxPlot = (datasets: DatasetWithStats[]) => {
  const allValues = datasets.flatMap((d) => d.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1
  const dataMin = globalMin - padding
  const dataMax = globalMax + padding

  const plotWidth = SVG_WIDTH - PAD.left - PAD.right
  const rowHeight = 40
  const totalHeight = PAD.top + datasets.length * rowHeight + PAD.bottom
  const x = scaleLinear([dataMin, dataMax], [PAD.left, PAD.left + plotWidth])

  const ticks = niceAxis(globalMin, globalMax, 6)
  const tickEls = ticks.map((t) =>
    h(Fragment, {},
      h('line', { x1: String(x(t)), x2: String(x(t)), y1: String(PAD.top - 5), y2: String(totalHeight - PAD.bottom), stroke: '#e0e0e0', 'stroke-dasharray': '3,3' }),
      h('text', { x: String(x(t)), y: String(totalHeight - PAD.bottom + 18), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, formatNumber(t))
    )
  )

  const boxes = datasets.map((ds, i) => {
    const { stats } = ds
    const cy = PAD.top + i * rowHeight + rowHeight / 2
    const boxH = rowHeight * 0.5

    const whiskerLow = Math.max(stats.min, stats.q1 - 1.5 * stats.iqr)
    const whiskerHigh = Math.min(stats.max, stats.q3 + 1.5 * stats.iqr)

    const outliers = ds.values.filter((v) => v < whiskerLow || v > whiskerHigh)

    const color = colorFor(i)

    return h(Fragment, {},
      h('line', { x1: String(x(whiskerLow)), x2: String(x(stats.q1)), y1: String(cy), y2: String(cy), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(x(stats.q3)), x2: String(x(whiskerHigh)), y1: String(cy), y2: String(cy), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(x(whiskerLow)), x2: String(x(whiskerLow)), y1: String(cy - boxH / 3), y2: String(cy + boxH / 3), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(x(whiskerHigh)), x2: String(x(whiskerHigh)), y1: String(cy - boxH / 3), y2: String(cy + boxH / 3), stroke: color, 'stroke-width': '2' }),
      h('rect', {
        x: String(x(stats.q1)),
        y: String(cy - boxH / 2),
        width: String(Math.max(0, x(stats.q3) - x(stats.q1))),
        height: String(boxH),
        fill: color,
        'fill-opacity': '0.2',
        stroke: color,
        'stroke-width': '2',
        rx: '2',
      }),
      h('line', { x1: String(x(stats.median)), x2: String(x(stats.median)), y1: String(cy - boxH / 2), y2: String(cy + boxH / 2), stroke: color, 'stroke-width': '3' }),
      ...outliers.map((o) =>
        h('circle', { cx: String(x(o)), cy: String(cy), r: '3', fill: 'none', stroke: color, 'stroke-width': '1.5' })
      ),
      h('text', { x: String(PAD.left - 8), y: String(cy + 4), 'text-anchor': 'end', 'font-size': '12', fill: '#333', 'font-weight': '500' }, ds.name)
    )
  })

  return h('div', { style: 'margin:16px 0' },
    h('h3', { style: 'font-family:system-ui,-apple-system,sans-serif;font-size:15px;font-weight:600;margin:0 0 8px;color:#333' }, 'Box Plot'),
    h('svg', { width: String(SVG_WIDTH), height: String(totalHeight), viewBox: `0 0 ${SVG_WIDTH} ${totalHeight}`, style: 'background:#fff;border:1px solid #eee;border-radius:6px' },
      ...tickEls,
      ...boxes
    )
  )
}

const renderHistogram = (datasets: DatasetWithStats[]) => {
  const allValues = datasets.flatMap((d) => d.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)

  const binCount = Math.max(5, Math.min(20, Math.ceil(Math.sqrt(allValues.length))))
  const binWidth = (globalMax - globalMin) / binCount || 1

  type BinData = { bins: number[]; maxCount: number }

  const dsHistData: BinData[] = datasets.map((ds) => {
    const bins = new Array(binCount).fill(0) as number[]
    for (const v of ds.values) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx]++
    }
    return { bins, maxCount: Math.max(...bins) }
  })

  const overallMax = Math.max(...dsHistData.map((d) => d.maxCount), 1)

  const plotWidth = SVG_WIDTH - PAD.left - PAD.right
  const plotHeight = SVG_HEIGHT - PAD.top - PAD.bottom
  const barGroupWidth = plotWidth / binCount
  const barWidth = barGroupWidth / datasets.length

  const y = scaleLinear([0, overallMax], [PAD.top + plotHeight, PAD.top])

  const yTicks = niceAxis(0, overallMax, 5)
  const yTickEls = yTicks.map((t) =>
    h(Fragment, {},
      h('line', { x1: String(PAD.left), x2: String(PAD.left + plotWidth), y1: String(y(t)), y2: String(y(t)), stroke: '#e0e0e0', 'stroke-dasharray': '2,2' }),
      h('text', { x: String(PAD.left - 8), y: String(y(t) + 4), 'text-anchor': 'end', 'font-size': '11', fill: '#666' }, String(Math.round(t)))
    )
  )

  const xTicks: { label: string; x: number }[] = []
  for (let i = 0; i <= binCount; i += Math.max(1, Math.floor(binCount / 6))) {
    const val = globalMin + i * binWidth
    xTicks.push({ label: formatNumber(val), x: PAD.left + i * barGroupWidth })
  }
  const xTickEls = xTicks.map((t) =>
    h('text', { x: String(t.x), y: String(PAD.top + plotHeight + 18), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, t.label)
  )

  const bars = dsHistData.flatMap((data, di) =>
    data.bins.map((count, bi) => {
      const bx = PAD.left + bi * barGroupWidth + di * barWidth
      const barH = PAD.top + plotHeight - y(count)
      return h('rect', {
        x: String(bx),
        y: String(y(count)),
        width: String(Math.max(0, barWidth - 1)),
        height: String(Math.max(0, barH)),
        fill: colorFor(di),
        'fill-opacity': '0.6',
        stroke: colorFor(di),
        'stroke-width': '1',
      })
    })
  )

  const legend = datasets.length > 1
    ? datasets.map((ds, i) =>
        h('span', { style: `display:inline-flex;align-items:center;margin-right:16px;font-size:12px;font-family:system-ui,-apple-system,sans-serif` },
          h('span', { style: `display:inline-block;width:12px;height:12px;background:${colorFor(i)};border-radius:2px;margin-right:6px;opacity:0.7` }),
          ds.name
        )
      )
    : []

  return h('div', { style: 'margin:16px 0' },
    h('h3', { style: 'font-family:system-ui,-apple-system,sans-serif;font-size:15px;font-weight:600;margin:0 0 8px;color:#333' }, 'Histogram'),
    ...(legend.length > 0 ? [h('div', { style: 'margin-bottom:8px' }, ...legend)] : []),
    h('svg', { width: String(SVG_WIDTH), height: String(SVG_HEIGHT), viewBox: `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`, style: 'background:#fff;border:1px solid #eee;border-radius:6px' },
      ...yTickEls,
      ...xTickEls,
      h('line', { x1: String(PAD.left), x2: String(PAD.left + plotWidth), y1: String(PAD.top + plotHeight), y2: String(PAD.top + plotHeight), stroke: '#ccc' }),
      h('line', { x1: String(PAD.left), x2: String(PAD.left), y1: String(PAD.top), y2: String(PAD.top + plotHeight), stroke: '#ccc' }),
      ...bars
    )
  )
}

export const renderAll = (datasets: DatasetWithStats[]) => {
  return h('div', { style: 'max-width:700px;margin:0 auto;padding:20px;font-family:system-ui,-apple-system,sans-serif' },
    h('h2', { style: 'font-size:20px;font-weight:700;margin:0 0 16px;color:#1a1a1a' }, 'Statistics Summary'),
    renderStatsTable(datasets),
    renderBoxPlot(datasets),
    renderHistogram(datasets)
  )
}

import { createSSR } from 'plaited'
import { parseInput, type NamedDataset } from './parser.ts'
import { calculate, type Stats } from './stats.ts'
import { renderAll } from './render.ts'

const DATA_PATH = './data/datasets.json'

type StoredDatasets = Record<string, number[]>

type DatasetWithStats = {
  name: string
  values: number[]
  stats: Stats
}

const loadStoredDatasets = async (): Promise<StoredDatasets> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return (await file.json()) as StoredDatasets
  }
  return {}
}

const saveDatasets = async (datasets: StoredDatasets): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(datasets, null, 2))
}

export const processInput = async (input: string): Promise<string> => {
  const parsed = parseInput(input)

  if (parsed.length === 0) {
    return '<p style="color:#c00;font-family:system-ui">No valid numeric data found. Provide comma-separated numbers or a JSON array.</p>'
  }

  const stored = await loadStoredDatasets()

  for (const ds of parsed) {
    stored[ds.name] = ds.values
  }
  await saveDatasets(stored)

  const datasetsWithStats: DatasetWithStats[] = parsed.map((ds) => ({
    name: ds.name,
    values: ds.values,
    stats: calculate(ds.values),
  }))

  const template = renderAll(datasetsWithStats)
  const { render } = createSSR()
  return render(template)
}

export const compareAll = async (): Promise<string> => {
  const stored = await loadStoredDatasets()
  const entries = Object.entries(stored)

  if (entries.length === 0) {
    return '<p style="color:#c00;font-family:system-ui">No stored datasets found.</p>'
  }

  const datasetsWithStats: DatasetWithStats[] = entries.map(([name, values]) => ({
    name,
    values,
    stats: calculate(values),
  }))

  const template = renderAll(datasetsWithStats)
  const { render } = createSSR()
  return render(template)
}

export const clearDatasets = async (): Promise<void> => {
  await saveDatasets({})
}

export const removeDataset = async (name: string): Promise<boolean> => {
  const stored = await loadStoredDatasets()
  if (name in stored) {
    delete stored[name]
    await saveDatasets(stored)
    return true
  }
  return false
}

export const listDatasets = async (): Promise<string[]> => {
  const stored = await loadStoredDatasets()
  return Object.keys(stored)
}

export { calculate, parseInput }
export type { Stats, NamedDataset }

