const calcMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const calcMode = (values: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of values) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return []
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const calcVariance = (values: number[], mean: number): number =>
  values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / values.length

const calcQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = (sorted.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

export const computeStats = (values: number[]): StatResult => {
  const sorted = sortAsc(values)
  const mean = calcMean(values)
  const variance = calcVariance(values, mean)
  const q1 = calcQuartile(sorted, 0.25)
  const q3 = calcQuartile(sorted, 0.75)

  return {
    count: values.length,
    mean,
    median: calcMedian(sorted),
    mode: calcMode(values),
    stdDev: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
  }
}

export const parseInput = (input: string): Dataset[] => {
  const datasets: Dataset[] = []

  // Check for multiple named datasets separated by |
  if (input.includes('|')) {
    const parts = input.split('|').map((p) => p.trim())
    for (const part of parts) {
      const colonIdx = part.indexOf(':')
      if (colonIdx !== -1) {
        const name = part.slice(0, colonIdx).trim()
        const valuesStr = part.slice(colonIdx + 1).trim()
        const values = parseValues(valuesStr)
        if (values.length > 0) {
          datasets.push({ name, values, stats: computeStats(values) })
        }
      }
    }
    return datasets
  }

  // Check for single named dataset with colon
  const colonIdx = input.indexOf(':')
  if (colonIdx !== -1 && !input.trimStart().startsWith('[')) {
    const maybeName = input.slice(0, colonIdx).trim()
    // Ensure the name part is not a number (avoid confusing "3: 4, 5" as name:values)
    if (maybeName.length > 0 && Number.isNaN(Number(maybeName))) {
      const valuesStr = input.slice(colonIdx + 1).trim()
      const values = parseValues(valuesStr)
      if (values.length > 0) {
        return [{ name: maybeName, values, stats: computeStats(values) }]
      }
    }
  }

  // Single unnamed dataset
  const values = parseValues(input)
  if (values.length > 0) {
    datasets.push({ name: 'dataset', values, stats: computeStats(values) })
  }

  return datasets
}

const parseValues = (input: string): number[] => {
  const trimmed = input.trim()

  // Try JSON array
  if (trimmed.startsWith('[')) {
    try {
      const parsed = JSON.parse(trimmed)
      if (Array.isArray(parsed)) {
        return parsed.filter((v): v is number => typeof v === 'number' && !Number.isNaN(v))
      }
    } catch {
      // Fall through to CSV parsing
    }
  }

  // CSV parsing
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !Number.isNaN(n))
}

import { h, Fragment } from 'plaited'
import type { Dataset, StatResult } from './stats.ts'

const COLORS = ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7']

const fmt = (n: number): string => {
  if (Number.isInteger(n)) return String(n)
  return n.toFixed(4).replace(/\.?0+$/, '')
}

const statLabel = (key: keyof StatResult): string => {
  const labels: Record<keyof StatResult, string> = {
    count: 'Count',
    mean: 'Mean',
    median: 'Median',
    mode: 'Mode',
    stdDev: 'Std Dev',
    variance: 'Variance',
    min: 'Min',
    max: 'Max',
    range: 'Range',
    q1: 'Q1 (25th)',
    q3: 'Q3 (75th)',
    iqr: 'IQR',
  }
  return labels[key]
}

const statKeys: (keyof StatResult)[] = [
  'count', 'mean', 'median', 'mode', 'stdDev', 'variance',
  'min', 'max', 'range', 'q1', 'q3', 'iqr',
]

const formatStatValue = (key: keyof StatResult, stats: StatResult): string => {
  if (key === 'mode') {
    return stats.mode.length === 0 ? 'None' : stats.mode.map(fmt).join(', ')
  }
  return fmt(stats[key] as number)
}

