const tableStyle = {
  borderCollapse: 'collapse',
  width: '100%',
  fontFamily: 'system-ui, -apple-system, sans-serif',
  fontSize: '14px',
  marginBottom: '24px',
}

const thStyle = {
  backgroundColor: '#f0f0f0',
  border: '1px solid #ddd',
  padding: '8px 12px',
  textAlign: 'left',
  fontWeight: '600',
}

const tdStyle = {
  border: '1px solid #ddd',
  padding: '8px 12px',
}

const tdLabelStyle = {
  ...tdStyle,
  fontWeight: '600',
  backgroundColor: '#fafafa',
}

const sectionStyle = {
  marginBottom: '32px',
}

const headingStyle = {
  fontFamily: 'system-ui, -apple-system, sans-serif',
  fontSize: '18px',
  fontWeight: '700',
  marginBottom: '12px',
  color: '#333',
}

const svgContainerStyle = {
  overflowX: 'auto',
  marginBottom: '24px',
}

// --- Summary Table ---

const renderSummaryTable = (datasets: Dataset[]) => {
  const isSingle = datasets.length === 1

  if (isSingle) {
    const ds = datasets[0]
    return h('div', { style: sectionStyle },
      h('h3', { style: headingStyle }, `Statistics: ${ds.name}`),
      h('table', { style: tableStyle },
        h('thead', {},
          h('tr', {},
            h('th', { style: thStyle }, 'Statistic'),
            h('th', { style: thStyle }, 'Value'),
          ),
        ),
        h('tbody', {},
          ...statKeys.map((key) =>
            h('tr', {},
              h('td', { style: tdLabelStyle }, statLabel(key)),
              h('td', { style: tdStyle }, formatStatValue(key, ds.stats)),
            )
          ),
        ),
      ),
    )
  }

  return h('div', { style: sectionStyle },
    h('h3', { style: headingStyle }, 'Comparison Table'),
    h('table', { style: tableStyle },
      h('thead', {},
        h('tr', {},
          h('th', { style: thStyle }, 'Statistic'),
          ...datasets.map((ds) =>
            h('th', { style: thStyle }, ds.name)
          ),
        ),
      ),
      h('tbody', {},
        ...statKeys.map((key) =>
          h('tr', {},
            h('td', { style: tdLabelStyle }, statLabel(key)),
            ...datasets.map((ds) =>
              h('td', { style: tdStyle }, formatStatValue(key, ds.stats))
            ),
          )
        ),
      ),
    ),
  )
}

// --- Box Plot (SVG) ---

const renderBoxPlot = (datasets: Dataset[]) => {
  const allValues = datasets.flatMap((ds) => ds.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1
  const plotMin = globalMin - padding
  const plotMax = globalMax + padding
  const plotRange = plotMax - plotMin

  const svgWidth = 600
  const plotLeft = 60
  const plotRight = svgWidth - 20
  const plotW = plotRight - plotLeft
  const rowHeight = 50
  const svgHeight = 40 + datasets.length * rowHeight + 30

  const scaleX = (v: number): number =>
    plotLeft + ((v - plotMin) / plotRange) * plotW

  // Generate tick values
  const tickCount = 8
  const tickStep = plotRange / tickCount
  const ticks: number[] = []
  for (let i = 0; i <= tickCount; i++) {
    ticks.push(plotMin + i * tickStep)
  }

  return h('div', { style: sectionStyle },
    h('h3', { style: headingStyle }, 'Box Plot'),
    h('div', { style: svgContainerStyle },
      h('svg', {
        width: String(svgWidth),
        height: String(svgHeight),
        viewBox: `0 0 ${svgWidth} ${svgHeight}`,
        xmlns: 'http://www.w3.org/2000/svg',
        style: { fontFamily: 'system-ui, -apple-system, sans-serif', fontSize: '11px' },
      },
        // Axis line
        h('line', {
          x1: String(plotLeft),
          y1: String(svgHeight - 25),
          x2: String(plotRight),
          y2: String(svgHeight - 25),
          stroke: '#999',
          'stroke-width': '1',
        }),
        // Tick marks and labels
        ...ticks.map((tick) =>
          h(Fragment, {},
            h('line', {
              x1: String(scaleX(tick)),
              y1: String(svgHeight - 25),
              x2: String(scaleX(tick)),
              y2: String(svgHeight - 20),
              stroke: '#999',
              'stroke-width': '1',
            }),
            h('text', {
              x: String(scaleX(tick)),
              y: String(svgHeight - 6),
              'text-anchor': 'middle',
              fill: '#666',
              style: { fontSize: '10px' },
            }, fmt(tick)),
          )
        ),
        // Box plots per dataset
        ...datasets.map((ds, i) => {
          const color = COLORS[i % COLORS.length]
          const y = 15 + i * rowHeight
          const midY = y + 18
          const boxH = 28
          const topY = midY - boxH / 2
          const sorted = [...ds.values].sort((a, b) => a - b)
          const { q1, q3, median, min, max, iqr } = ds.stats

          // Whisker bounds (1.5 * IQR rule)
          const lowerFence = q1 - 1.5 * iqr
          const upperFence = q3 + 1.5 * iqr
          const whiskerLow = Math.max(min, lowerFence)
          const whiskerHigh = Math.min(max, upperFence)
          // Actual whisker endpoints: nearest data points within fences
          const wLow = sorted.find((v) => v >= lowerFence) ?? min
          const wHigh = [...sorted].reverse().find((v) => v <= upperFence) ?? max
          // Outliers
          const outliers = sorted.filter((v) => v < lowerFence || v > upperFence)

          return h(Fragment, {},
            // Dataset label
            h('text', {
              x: '4',
              y: String(midY + 4),
              fill: '#333',
              style: { fontSize: '11px', fontWeight: '600' },
            }, ds.name.length > 8 ? ds.name.slice(0, 8) + '…' : ds.name),
            // Whisker line
            h('line', {
              x1: String(scaleX(wLow)),
              y1: String(midY),
              x2: String(scaleX(wHigh)),
              y2: String(midY),
              stroke: color,
              'stroke-width': '1.5',
            }),
            // Whisker caps
            h('line', {
              x1: String(scaleX(wLow)),
              y1: String(midY - 8),
              x2: String(scaleX(wLow)),
              y2: String(midY + 8),
              stroke: color,
              'stroke-width': '1.5',
            }),
            h('line', {
              x1: String(scaleX(wHigh)),
              y1: String(midY - 8),
              x2: String(scaleX(wHigh)),
              y2: String(midY + 8),
              stroke: color,
              'stroke-width': '1.5',
            }),
            // Box (Q1 to Q3)
            h('rect', {
              x: String(scaleX(q1)),
              y: String(topY),
              width: String(Math.max(scaleX(q3) - scaleX(q1), 1)),
              height: String(boxH),
              fill: color,
              'fill-opacity': '0.3',
              stroke: color,
              'stroke-width': '1.5',
              rx: '2',
            }),
            // Median line
            h('line', {
              x1: String(scaleX(median)),
              y1: String(topY),
              x2: String(scaleX(median)),
              y2: String(topY + boxH),
              stroke: color,
              'stroke-width': '2.5',
            }),
            // Outliers
            ...outliers.map((v) =>
              h('circle', {
                cx: String(scaleX(v)),
                cy: String(midY),
                r: '3',
                fill: 'none',
                stroke: color,
                'stroke-width': '1.5',
              })
            ),
          )
        }),
      ),
    ),
  )
}

// --- Histogram (SVG) ---

const renderHistogram = (datasets: Dataset[]) => {
  const allValues = datasets.flatMap((ds) => ds.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)

  // Sturges' rule for bin count, minimum 5
  const binCount = Math.max(5, Math.ceil(1 + Math.log2(Math.max(...datasets.map((d) => d.values.length)))))
  const binWidth = (globalMax - globalMin) / binCount || 1
  const adjustedMin = globalMin
  const adjustedMax = globalMin + binCount * binWidth

  // Build bins per dataset
  const datasetBins = datasets.map((ds) => {
    const bins = new Array<number>(binCount).fill(0)
    for (const v of ds.values) {
      let idx = Math.floor((v - adjustedMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx]++
    }
    return bins
  })

  const maxCount = Math.max(...datasetBins.flat())

  const svgWidth = 600
  const plotLeft = 50
  const plotBottom = 40
  const plotTop = 20
  const plotRight = svgWidth - 20
  const svgHeight = 260
  const plotH = svgHeight - plotTop - plotBottom
  const plotW = plotRight - plotLeft
  const barGroupWidth = plotW / binCount

  const isMultiple = datasets.length > 1
  const barPadding = 2
  const singleBarWidth = isMultiple
    ? (barGroupWidth - barPadding * 2) / datasets.length
    : barGroupWidth - barPadding * 2

  const scaleY = (count: number): number =>
    plotTop + plotH - (count / maxCount) * plotH

  return h('div', { style: sectionStyle },
    h('h3', { style: headingStyle }, 'Histogram'),
    h('div', { style: svgContainerStyle },
      h('svg', {
        width: String(svgWidth),
        height: String(svgHeight),
        viewBox: `0 0 ${svgWidth} ${svgHeight}`,
        xmlns: 'http://www.w3.org/2000/svg',
        style: { fontFamily: 'system-ui, -apple-system, sans-serif', fontSize: '11px' },
      },
        // Y-axis
        h('line', {
          x1: String(plotLeft),
          y1: String(plotTop),
          x2: String(plotLeft),
          y2: String(plotTop + plotH),
          stroke: '#999',
          'stroke-width': '1',
        }),
        // X-axis
        h('line', {
          x1: String(plotLeft),
          y1: String(plotTop + plotH),
          x2: String(plotRight),
          y2: String(plotTop + plotH),
          stroke: '#999',
          'stroke-width': '1',
        }),
        // Y-axis ticks
        ...Array.from({ length: 5 }, (_, i) => {
          const count = Math.round((maxCount / 4) * i)
          const y = scaleY(count)
          return h(Fragment, {},
            h('line', {
              x1: String(plotLeft - 4),
              y1: String(y),
              x2: String(plotLeft),
              y2: String(y),
              stroke: '#999',
              'stroke-width': '1',
            }),
            h('text', {
              x: String(plotLeft - 8),
              y: String(y + 3),
              'text-anchor': 'end',
              fill: '#666',
              style: { fontSize: '10px' },
            }, String(count)),
            // Grid line
            h('line', {
              x1: String(plotLeft),
              y1: String(y),
              x2: String(plotRight),
              y2: String(y),
              stroke: '#eee',
              'stroke-width': '1',
            }),
          )
        }),
        // X-axis bin labels
        ...Array.from({ length: binCount + 1 }, (_, i) => {
          const val = adjustedMin + i * binWidth
          const x = plotLeft + (i / binCount) * plotW
          return i % Math.ceil(binCount / 8) === 0 || i === binCount
            ? h('text', {
                x: String(x),
                y: String(plotTop + plotH + 16),
                'text-anchor': 'middle',
                fill: '#666',
                style: { fontSize: '10px' },
              }, fmt(val))
            : h(Fragment, {})
        }),
        // Bars
        ...datasetBins.flatMap((bins, dsIdx) =>
          bins.map((count, binIdx) => {
            if (count === 0) return h(Fragment, {})
            const color = COLORS[dsIdx % COLORS.length]
            const groupX = plotLeft + binIdx * barGroupWidth + barPadding
            const barX = isMultiple ? groupX + dsIdx * singleBarWidth : groupX
            const barH = (count / maxCount) * plotH
            return h('rect', {
              x: String(barX),
              y: String(plotTop + plotH - barH),
              width: String(Math.max(singleBarWidth - (isMultiple ? 1 : 0), 1)),
              height: String(barH),
              fill: color,
              'fill-opacity': '0.7',
              stroke: color,
              'stroke-width': '0.5',
            })
          })
        ),
        // Legend for multiple datasets
        ...(isMultiple
          ? datasets.map((ds, i) =>
              h(Fragment, {},
                h('rect', {
                  x: String(plotLeft + 10 + i * 100),
                  y: '4',
                  width: '12',
                  height: '12',
                  fill: COLORS[i % COLORS.length],
                  'fill-opacity': '0.7',
                  rx: '2',
                }),
                h('text', {
                  x: String(plotLeft + 26 + i * 100),
                  y: '14',
                  fill: '#333',
                  style: { fontSize: '11px' },
                }, ds.name),
              )
            )
          : []),
      ),
    ),
  )
}

