    renderBoxPlot(datasets),
    renderHistogram(datasets),
  )
}

import { createSSR } from 'plaited'
import { parseInput, computeStats } from './stats.ts'
import { renderStats } from './render.ts'
import type { Dataset, DatasetStore } from './stats.ts'

const DATA_PATH = new URL('./data/datasets.json', import.meta.url).pathname

// --- Persistence ---

const loadStore = async (): Promise<DatasetStore> => {
  try {
    const file = Bun.file(DATA_PATH)
    const exists = await file.exists()
    if (!exists) return {}
    const text = await file.text()
    return JSON.parse(text) as DatasetStore
  } catch {
    return {}
  }
}

const saveStore = async (store: DatasetStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

// --- Public API ---

export const addDataset = async (name: string, values: number[]): Promise<Dataset> => {
  const store = await loadStore()
  store[name] = values
  await saveStore(store)
  const stats = computeStats(values)
  return { name, values, stats }
}

export const getDataset = async (name: string): Promise<Dataset | null> => {
  const store = await loadStore()
  const values = store[name]
  if (!values) return null
  return { name, values, stats: computeStats(values) }
}

export const listDatasets = async (): Promise<string[]> => {
  const store = await loadStore()
  return Object.keys(store)
}

export const removeDataset = async (name: string): Promise<boolean> => {
  const store = await loadStore()
  if (!(name in store)) return false
  delete store[name]
  await saveStore(store)
  return true
}

export const processInput = async (input: string): Promise<{ datasets: Dataset[]; html: string }> => {
  const datasets = parseInput(input)

  // Persist each dataset
  const store = await loadStore()
  for (const ds of datasets) {
    store[ds.name] = ds.values
  }
  await saveStore(store)

  const tree = renderStats(datasets)
  const ssr = createSSR()
  const html = ssr(tree)

  return { datasets, html }
}

export const compareDatasets = async (names: string[]): Promise<{ datasets: Dataset[]; html: string } | null> => {
  const store = await loadStore()
  const datasets: Dataset[] = []

  for (const name of names) {
    const values = store[name]
    if (!values) return null
    datasets.push({ name, values, stats: computeStats(values) })
  }

  const tree = renderStats(datasets)
  const ssr = createSSR()
  const html = ssr(tree)

  return { datasets, html }
}

// --- CLI entry point ---

const main = async () => {
  const args = process.argv.slice(2)

  if (args.length === 0) {
    console.log('Usage:')
    console.log('  bun run index.ts "12, 15, 20, 22, 25, 30, 35"')
    console.log('  bun run index.ts "groupA: 10,20,30 | groupB: 15,25,35"')
    console.log('  bun run index.ts --list')
    console.log('  bun run index.ts --compare groupA groupB')
    console.log('  bun run index.ts --remove datasetName')
    return
  }

  if (args[0] === '--list') {
    const names = await listDatasets()
    if (names.length === 0) {
      console.log('No stored datasets.')
    } else {
      console.log('Stored datasets:')
      for (const name of names) {
        console.log(`  - ${name}`)
      }
    }
    return
  }

  if (args[0] === '--remove' && args[1]) {
    const removed = await removeDataset(args[1])
    console.log(removed ? `Removed "${args[1]}".` : `Dataset "${args[1]}" not found.`)
    return
  }

  if (args[0] === '--compare' && args.length > 2) {
    const names = args.slice(1)
    const result = await compareDatasets(names)
    if (!result) {
      console.log('One or more datasets not found. Use --list to see stored datasets.')
      return
    }
    for (const ds of result.datasets) {
      printDatasetStats(ds)
    }
    console.log(`\nHTML output written to stdout (${result.html.length} chars).`)
    return
  }

  const input = args.join(' ')
  const result = await processInput(input)

  for (const ds of result.datasets) {
    printDatasetStats(ds)
  }
}

const printDatasetStats = (ds: Dataset) => {
  console.log(`\n--- ${ds.name} (n=${ds.stats.count}) ---`)
  console.log(`  Mean:      ${ds.stats.mean}`)
  console.log(`  Median:    ${ds.stats.median}`)
  console.log(`  Mode:      ${ds.stats.mode.length === 0 ? 'None' : ds.stats.mode.join(', ')}`)
  console.log(`  Std Dev:   ${ds.stats.stdDev}`)
  console.log(`  Variance:  ${ds.stats.variance}`)
  console.log(`  Min:       ${ds.stats.min}`)
  console.log(`  Max:       ${ds.stats.max}`)
  console.log(`  Range:     ${ds.stats.range}`)
  console.log(`  Q1:        ${ds.stats.q1}`)
  console.log(`  Q3:        ${ds.stats.q3}`)
  console.log(`  IQR:       ${ds.stats.iqr}`)
}

main()

