import type { Playlist, PlaylistStore, Song, PlayerState, RepeatMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const generateId = (prefix: string): string =>
  `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`

export const loadStore = async (): Promise<PlaylistStore> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { playlists: [] }
}

export const saveStore = async (store: PlaylistStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

// In-memory player state (not persisted — resets on restart)
let playerState: PlayerState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  progress: 0,
  elapsed: 0,
  shuffle: false,
  repeat: 'none',
  shuffleOrder: [],
}

export const getPlayerState = (): PlayerState => ({ ...playerState })

export const setPlayerState = (updates: Partial<PlayerState>): PlayerState => {
  playerState = { ...playerState, ...updates }
  return { ...playerState }
}

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const createPlaylist = async (name: string, description = ''): Promise<Playlist> => {
  const store = await loadStore()
  const playlist: Playlist = {
    id: generateId('pl'),
    name,
    description,
    songs: [],
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }
  store.playlists.push(playlist)
  await saveStore(store)
  return playlist
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const store = await loadStore()
  return store.playlists.find((p) => p.id === id)
}

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  const store = await loadStore()
  return store.playlists
}

export const updatePlaylist = async (
  id: string,
  updates: Partial<Pick<Playlist, 'name' | 'description'>>,
): Promise<Playlist | undefined> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === id)
  if (!playlist) return undefined
  if (updates.name !== undefined) playlist.name = updates.name
  if (updates.description !== undefined) playlist.description = updates.description
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await loadStore()
  const idx = store.playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  store.playlists.splice(idx, 1)
  await saveStore(store)
  if (playerState.currentPlaylistId === id) {
    setPlayerState({ currentPlaylistId: null, isPlaying: false, progress: 0, elapsed: 0 })
  }
  return true
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>,
): Promise<Song | undefined> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return undefined
  const newSong: Song = { id: generateId('s'), ...song }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return true
}

export const reorderSongs = async (playlistId: string, songIds: string[]): Promise<boolean> => {
  const store = await loadStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const songMap = new Map(playlist.songs.map((s) => [s.id, s]))
  const reordered: Song[] = []
  for (const id of songIds) {
    const song = songMap.get(id)
    if (!song) return false
    reordered.push(song)
  }
  playlist.songs = reordered
  playlist.updatedAt = new Date().toISOString()
  await saveStore(store)
  return true
}

export const playTrack = async (
  playlistId: string,
  songIndex?: number,
): Promise<PlayerState> => {
  const playlist = await getPlaylist(playlistId)
  if (!playlist || playlist.songs.length === 0) return getPlayerState()
  const idx = songIndex ?? 0
  const shuffleOrder = playerState.shuffle
    ? generateShuffleOrder(playlist.songs.length, idx)
    : []
  return setPlayerState({
    currentPlaylistId: playlistId,
    currentSongIndex: idx,
    isPlaying: true,
    progress: 0,
    elapsed: 0,
    shuffleOrder: shuffleOrder,
  })
}

export const pauseTrack = (): PlayerState => setPlayerState({ isPlaying: false })

export const skipTrack = async (): Promise<PlayerState> => {
  const { currentPlaylistId, currentSongIndex, shuffle, shuffleOrder, repeat } = playerState
  if (!currentPlaylistId) return getPlayerState()
  const playlist = await getPlaylist(currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return getPlayerState()

  if (repeat === 'one') {
    return setPlayerState({ progress: 0, elapsed: 0, isPlaying: true })
  }

  let nextIndex: number
  if (shuffle && shuffleOrder.length > 0) {
    const currentShufflePos = shuffleOrder.indexOf(currentSongIndex)
    const nextShufflePos = currentShufflePos + 1
    if (nextShufflePos >= shuffleOrder.length) {
      if (repeat === 'all') {
        const newOrder = generateShuffleOrder(playlist.songs.length, shuffleOrder[0])
        nextIndex = newOrder[0]
        setPlayerState({ shuffleOrder: newOrder })
      } else {
        return setPlayerState({ isPlaying: false, progress: 0, elapsed: 0 })
      }
    } else {
      nextIndex = shuffleOrder[nextShufflePos]
    }
  } else {
    nextIndex = currentSongIndex + 1
    if (nextIndex >= playlist.songs.length) {
      if (repeat === 'all') {
        nextIndex = 0
      } else {
        return setPlayerState({ isPlaying: false, progress: 0, elapsed: 0 })
      }
    }
  }

  return setPlayerState({
    currentSongIndex: nextIndex,
    progress: 0,
    elapsed: 0,
    isPlaying: true,
  })
}

export const previousTrack = async (): Promise<PlayerState> => {
  const { currentPlaylistId, currentSongIndex, elapsed, repeat } = playerState
  if (!currentPlaylistId) return getPlayerState()

  // If more than 3 seconds in, restart current track
  if (elapsed > 3) {
    return setPlayerState({ progress: 0, elapsed: 0 })
  }

  const playlist = await getPlaylist(currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return getPlayerState()

  let prevIndex = currentSongIndex - 1
  if (prevIndex < 0) {
    prevIndex = repeat === 'all' ? playlist.songs.length - 1 : 0
  }

  return setPlayerState({
    currentSongIndex: prevIndex,
    progress: 0,
    elapsed: 0,
    isPlaying: true,
  })
}

export const toggleShuffle = async (): Promise<PlayerState> => {
  const newShuffle = !playerState.shuffle
  const shuffleOrder = newShuffle && playerState.currentPlaylistId
    ? await (async () => {
        const pl = await getPlaylist(playerState.currentPlaylistId!)
        return pl ? generateShuffleOrder(pl.songs.length, playerState.currentSongIndex) : []
      })()
    : []
  return setPlayerState({ shuffle: newShuffle, shuffleOrder: shuffleOrder })
}

export const cycleRepeat = (): PlayerState => {
  const modes: RepeatMode[] = ['none', 'all', 'one']
  const currentIdx = modes.indexOf(playerState.repeat)
  const nextMode = modes[(currentIdx + 1) % modes.length]
  return setPlayerState({ repeat: nextMode })
}

