      h('p', { style: { color: '#666', fontSize: '12px', margin: '0' } },
        `${playlist.songs.length} songs \u2022 ${formatDuration(totalDuration)}`,
      ),
    ),
    renderAddSongForm(playlist.id),
    h('div', {
      'p-target': 'song-list',
      'data-playlist-id': playlist.id,
    },
      ...playlist.songs.map((song, i) =>
        renderSongRow(
          song,
          i,
          playlist.id,
          isActivePlaylist && playerState.currentSongIndex === i,
        ),
      ),
      playlist.songs.length === 0
        ? h('div', { style: styles.emptyState },
            h('p', { style: { fontSize: '48px', margin: '0 0 12px 0' } }, '\u{1F3B6}'),
            h('p', { style: { fontSize: '16px' } }, 'No songs yet. Add one above!'),
          )
        : null,
    ),
  )
}

