const clientScript = (): string => `
(function() {
  // Drag and drop reorder
  let dragSrcId = null;
  let dragSrcIndex = null;

  document.addEventListener('dragstart', function(e) {
    const row = e.target.closest('[draggable="true"]');
    if (!row) return;
    dragSrcId = row.dataset.songId;
    dragSrcIndex = parseInt(row.dataset.index, 10);
    e.dataTransfer.effectAllowed = 'move';
    row.style.opacity = '0.5';
  });

  document.addEventListener('dragend', function(e) {
    const row = e.target.closest('[draggable="true"]');
    if (row) row.style.opacity = '1';
    document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
  });

  document.addEventListener('dragover', function(e) {
    e.preventDefault();
    const row = e.target.closest('[draggable="true"]');
    if (!row) return;
    e.dataTransfer.dropEffect = 'move';
    document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
    row.classList.add('drag-over');
  });

  document.addEventListener('drop', function(e) {
    e.preventDefault();
    const row = e.target.closest('[draggable="true"]');
    if (!row || !dragSrcId) return;
    row.classList.remove('drag-over');
    const targetIndex = parseInt(row.dataset.index, 10);
    if (dragSrcIndex === targetIndex) return;

    const songList = row.closest('[data-playlist-id]');
    if (!songList) return;
    const playlistId = songList.dataset.playlistId;

    const rows = Array.from(songList.querySelectorAll('[data-song-id]'));
    const songIds = rows.map(r => r.dataset.songId);

    // Move the dragged song
    const fromIdx = songIds.indexOf(dragSrcId);
    if (fromIdx === -1) return;
    songIds.splice(fromIdx, 1);
    const toIdx = Math.min(targetIndex, songIds.length);
    songIds.splice(toIdx, 0, dragSrcId);

    fetch('/playlists/' + playlistId + '/reorder', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ songIds: songIds })
    }).then(() => location.reload());
  });

  // Click handlers
  document.addEventListener('click', function(e) {
    const btn = e.target.closest('button, [data-playlist-id]');
    if (!btn) return;

    const trigger = btn.getAttribute('p-trigger');
    if (!trigger) return;
    const triggers = JSON.parse(trigger);
    const action = triggers.click;
    if (!action) return;

    if (action === 'select-playlist') {
      const id = btn.dataset.playlistId;
      window.location.href = '/?playlist=' + id;
    }
    else if (action === 'open-create-modal') {
      document.getElementById('create-modal').style.display = 'flex';
    }
    else if (action === 'close-modal') {
      document.getElementById('create-modal').style.display = 'none';
    }
    else if (action === 'play-song') {
      const playlistId = btn.dataset.playlistId;
      const songIndex = btn.dataset.songIndex;
      fetch('/player/play', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId, songIndex: parseInt(songIndex, 10) })
      }).then(() => location.reload());
    }
    else if (action === 'remove-song') {
      const playlistId = btn.dataset.playlistId;
      const songId = btn.dataset.songId;
      if (confirm('Remove this song?')) {
        fetch('/playlists/' + playlistId + '/songs/' + songId, { method: 'DELETE' })
          .then(() => location.reload());
      }
    }
    else if (action === 'player-play') {
      fetch('/player/play', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({})
      }).then(() => location.reload());
    }
    else if (action === 'player-pause') {
      fetch('/player/pause', { method: 'POST' }).then(() => location.reload());
    }
    else if (action === 'player-skip') {
      fetch('/player/skip', { method: 'POST' }).then(() => location.reload());
    }
    else if (action === 'player-previous') {
      fetch('/player/previous', { method: 'POST' }).then(() => location.reload());
    }
    else if (action === 'toggle-shuffle') {
      fetch('/player/shuffle', { method: 'POST' }).then(() => location.reload());
    }
    else if (action === 'cycle-repeat') {
      fetch('/player/repeat', { method: 'POST' }).then(() => location.reload());
    }
  });

  // Progress bar simulation
  let progressInterval = null;
  const isPlaying = document.querySelector('[p-target="player-bar"]');
  const playBtn = isPlaying ? isPlaying.querySelector('[title="Pause"]') : null;

  if (playBtn) {
    const elapsed = document.querySelector('[p-target="elapsed-time"]');
    const progressFill = document.querySelector('[p-target="progress-fill"]');
    const totalTime = document.querySelector('[p-target="total-time"]');

    if (elapsed && progressFill && totalTime) {
      const parseTime = (str) => {
        const parts = str.split(':');
        return parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10);
      };
      let currentElapsed = parseTime(elapsed.textContent);
      const total = parseTime(totalTime.textContent);

      progressInterval = setInterval(() => {
        currentElapsed++;
        if (currentElapsed >= total) {
          fetch('/player/skip', { method: 'POST' }).then(() => location.reload());
          clearInterval(progressInterval);
          return;
        }
        const mins = Math.floor(currentElapsed / 60);
        const secs = currentElapsed % 60;
        elapsed.textContent = mins + ':' + String(secs).padStart(2, '0');
        const pct = (currentElapsed / total) * 100;
        progressFill.style.width = pct + '%';
      }, 1000);
    }
  }

  // Seek on progress bar click
  document.addEventListener('click', function(e) {
    const bar = e.target.closest('[p-target="progress-bar"]');
    if (!bar) return;
    const rect = bar.getBoundingClientRect();
    const pct = ((e.clientX - rect.left) / rect.width) * 100;
    const fill = bar.querySelector('[p-target="progress-fill"]');
    if (fill) fill.style.width = pct + '%';
  });

  // Form submissions
  document.addEventListener('submit', function(e) {
    const form = e.target.closest('form');
    if (!form) return;
    const trigger = form.getAttribute('p-trigger');
    if (!trigger) return;
    const triggers = JSON.parse(trigger);
    const action = triggers.submit;

    e.preventDefault();
    const fd = new FormData(form);

    if (action === 'create-playlist-submit') {
      fetch('/playlists', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: fd.get('name'),
          description: fd.get('description') || ''
        })
      }).then(r => r.json()).then(pl => {
        window.location.href = '/?playlist=' + pl.id;
      });
    }
    else if (action === 'add-song-submit') {
      const playlistId = form.dataset.playlistId;
      fetch('/playlists/' + playlistId + '/songs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: fd.get('title'),
          artist: fd.get('artist'),
          album: fd.get('album') || '',
          duration: parseInt(fd.get('duration'), 10),
          albumArtUrl: fd.get('albumArtUrl') || ''
        })
      }).then(() => location.reload());
    }
  });
})();
`

import {
  getAllPlaylists,
  getPlaylist,
  createPlaylist,
  updatePlaylist,
  deletePlaylist,
  addSong,
  removeSong,
  reorderSongs,
  getPlayerState,
  playTrack,
  pauseTrack,
  skipTrack,
  previousTrack,
  toggleShuffle,
  cycleRepeat,
} from './store'
import { renderPage, renderCreatePlaylistModal } from './ui'
import type { Song } from './types'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> => {
  const text = await req.text()
  return text ? JSON.parse(text) : {}
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Main page
  if (path === '/' && method === 'GET') {
    const playlists = await getAllPlaylists()
    const selectedId = url.searchParams.get('playlist') ?? playlists[0]?.id ?? null
    const activePlaylist = selectedId ? (await getPlaylist(selectedId)) ?? null : null
    const playerState = getPlayerState()
    const currentSong =
      playerState.currentPlaylistId
        ? await (async () => {
            const pl = await getPlaylist(playerState.currentPlaylistId!)
            return pl?.songs[playerState.currentSongIndex] ?? null
          })()
        : null

    const pageHtml = renderPage(playlists, activePlaylist, playerState, currentSong)
    // Inject the create-playlist modal (hidden by default)
    const modalHtml = renderCreatePlaylistModal()
    const injected = pageHtml.replace(
      '</body>',
      `<div id="create-modal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,0.7);display:none;align-items:center;justify-content:center;z-index:2000">${modalHtml}</div></body>`,
    )
    return html(injected)
  }

  // Playlist CRUD
  if (path === '/playlists' && method === 'GET') {
    const playlists = await getAllPlaylists()
    return json(playlists)
  }

  if (path === '/playlists' && method === 'POST') {
    const body = await parseBody<{ name: string; description?: string }>(req)
    if (!body.name) return json({ error: 'Name is required' }, 400)
    const playlist = await createPlaylist(body.name, body.description)
    return json(playlist, 201)
  }

  const playlistMatch = path.match(/^\/playlists\/([^/]+)$/)
  if (playlistMatch) {
    const id = playlistMatch[1]

    if (method === 'GET') {
      const playlist = await getPlaylist(id)
      if (!playlist) return json({ error: 'Not found' }, 404)
      return json(playlist)
    }

    if (method === 'PUT') {
      const body = await parseBody<{ name?: string; description?: string }>(req)
      const playlist = await updatePlaylist(id, body)
      if (!playlist) return json({ error: 'Not found' }, 404)
      return json(playlist)
    }

    if (method === 'DELETE') {
      const deleted = await deletePlaylist(id)
      if (!deleted) return json({ error: 'Not found' }, 404)
      return json({ ok: true })
    }
  }

  // Song management
  const songsMatch = path.match(/^\/playlists\/([^/]+)\/songs$/)
  if (songsMatch && method === 'POST') {
    const playlistId = songsMatch[1]
    const body = await parseBody<Omit<Song, 'id'>>(req)
    if (!body.title || !body.artist || !body.duration) {
      return json({ error: 'title, artist, and duration are required' }, 400)
    }
    const song = await addSong(playlistId, {
      title: body.title,
      artist: body.artist,
      album: body.album ?? '',
      duration: body.duration,
      albumArtUrl: body.albumArtUrl ?? '',
    })
    if (!song) return json({ error: 'Playlist not found' }, 404)
    return json(song, 201)
  }

  const removeSongMatch = path.match(/^\/playlists\/([^/]+)\/songs\/([^/]+)$/)
  if (removeSongMatch && method === 'DELETE') {
    const [, playlistId, songId] = removeSongMatch
    const removed = await removeSong(playlistId, songId)
    if (!removed) return json({ error: 'Not found' }, 404)
    return json({ ok: true })
  }

  // Reorder
  const reorderMatch = path.match(/^\/playlists\/([^/]+)\/reorder$/)
  if (reorderMatch && method === 'PUT') {
    const playlistId = reorderMatch[1]
    const body = await parseBody<{ songIds: string[] }>(req)
    if (!body.songIds || !Array.isArray(body.songIds)) {
      return json({ error: 'songIds array is required' }, 400)
    }
    const reordered = await reorderSongs(playlistId, body.songIds)
    if (!reordered) return json({ error: 'Invalid song IDs or playlist not found' }, 400)
    return json({ ok: true })
  }

  // Player controls
  if (path === '/player/state' && method === 'GET') {
    return json(getPlayerState())
  }

  if (path === '/player/play' && method === 'POST') {
    const body = await parseBody<{ playlistId?: string; songIndex?: number }>(req)
    const state = getPlayerState()
    const playlistId = body.playlistId ?? state.currentPlaylistId
    if (!playlistId) return json({ error: 'No playlist specified' }, 400)
    const result = await playTrack(playlistId, body.songIndex)
    return json(result)
  }

  if (path === '/player/pause' && method === 'POST') {
    return json(pauseTrack())
  }

  if (path === '/player/skip' && method === 'POST') {
    const result = await skipTrack()
    return json(result)
  }

  if (path === '/player/previous' && method === 'POST') {
    const result = await previousTrack()
    return json(result)
  }

  if (path === '/player/shuffle' && method === 'POST') {
    const result = await toggleShuffle()
    return json(result)
  }

  if (path === '/player/repeat' && method === 'POST') {
    return json(cycleRepeat())
  }

  return json({ error: 'Not found' }, 404)
}

