import type { Store, Playlist, Song, PlaybackState, RepeatMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const generateId = (prefix: string): string =>
  `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`

const readStore = async (): Promise<Store> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    const initial: Store = {
      playlists: [],
      playback: {
        playlistId: null,
        songIndex: 0,
        isPlaying: false,
        shuffle: false,
        repeat: 'none',
        progress: 0,
        shuffleOrder: [],
      },
    }
    await Bun.write(DATA_PATH, JSON.stringify(initial, null, 2))
    return initial
  }
  return file.json()
}

const writeStore = async (store: Store): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const getPlaylists = async (): Promise<Playlist[]> => {
  const store = await readStore()
  return store.playlists
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const store = await readStore()
  return store.playlists.find((p) => p.id === id)
}

export const createPlaylist = async (name: string, description = ''): Promise<Playlist> => {
  const store = await readStore()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId('pl'),
    name,
    description,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  store.playlists.push(playlist)
  await writeStore(store)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await readStore()
  const idx = store.playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  store.playlists.splice(idx, 1)
  if (store.playback.playlistId === id) {
    store.playback = {
      playlistId: null,
      songIndex: 0,
      isPlaying: false,
      shuffle: false,
      repeat: store.playback.repeat,
      progress: 0,
      shuffleOrder: [],
    }
  }
  await writeStore(store)
  return true
}

export const addSong = async (playlistId: string, song: Omit<Song, 'id'>): Promise<Song | null> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { id: generateId('song'), ...song }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  await writeStore(store)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.playlistId === playlistId) {
    if (store.playback.songIndex >= playlist.songs.length) {
      store.playback.songIndex = Math.max(0, playlist.songs.length - 1)
    }
    if (playlist.songs.length === 0) {
      store.playback.isPlaying = false
    }
  }
  await writeStore(store)
  return true
}

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number,
): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return false
  if (toIndex < 0 || toIndex >= playlist.songs.length) return false
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.playlistId === playlistId) {
    const current = store.playback.songIndex
    if (current === fromIndex) {
      store.playback.songIndex = toIndex
    } else if (fromIndex < current && toIndex >= current) {
      store.playback.songIndex--
    } else if (fromIndex > current && toIndex <= current) {
      store.playback.songIndex++
    }
  }
  await writeStore(store)
  return true
}

export const getPlaybackState = async (): Promise<PlaybackState> => {
  const store = await readStore()
  return store.playback
}

export const playTrack = async (playlistId: string, songIndex: number): Promise<PlaybackState> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist || songIndex < 0 || songIndex >= playlist.songs.length) {
    return store.playback
  }
  store.playback.playlistId = playlistId
  store.playback.songIndex = songIndex
  store.playback.isPlaying = true
  store.playback.progress = 0
  if (store.playback.shuffle) {
    store.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length, songIndex)
  }
  await writeStore(store)
  return store.playback
}

export const togglePlay = async (): Promise<PlaybackState> => {
  const store = await readStore()
  if (store.playback.playlistId) {
    store.playback.isPlaying = !store.playback.isPlaying
    await writeStore(store)
  }
  return store.playback
}

export const nextTrack = async (): Promise<PlaybackState> => {
  const store = await readStore()
  const { playback } = store
  if (!playback.playlistId) return playback
  const playlist = store.playlists.find((p) => p.id === playback.playlistId)
  if (!playlist || playlist.songs.length === 0) return playback

  if (playback.repeat === 'one') {
    playback.progress = 0
    playback.isPlaying = true
    await writeStore(store)
    return playback
  }

  if (playback.shuffle && playback.shuffleOrder.length > 0) {
    const currentShuffleIdx = playback.shuffleOrder.indexOf(playback.songIndex)
    const nextShuffleIdx = currentShuffleIdx + 1
    if (nextShuffleIdx < playback.shuffleOrder.length) {
      playback.songIndex = playback.shuffleOrder[nextShuffleIdx]
    } else if (playback.repeat === 'all') {
      playback.shuffleOrder = generateShuffleOrder(playlist.songs.length, playback.songIndex)
      playback.songIndex = playback.shuffleOrder[0]
    } else {
      playback.isPlaying = false
      await writeStore(store)
      return playback
    }
  } else {
    const next = playback.songIndex + 1
    if (next < playlist.songs.length) {
      playback.songIndex = next
    } else if (playback.repeat === 'all') {
      playback.songIndex = 0
    } else {
      playback.isPlaying = false
      await writeStore(store)
      return playback
    }
  }

  playback.progress = 0
  playback.isPlaying = true
  await writeStore(store)
  return playback
}

export const prevTrack = async (): Promise<PlaybackState> => {
  const store = await readStore()
  const { playback } = store
  if (!playback.playlistId) return playback
  const playlist = store.playlists.find((p) => p.id === playback.playlistId)
  if (!playlist || playlist.songs.length === 0) return playback

  if (playback.progress > 3) {
    playback.progress = 0
    await writeStore(store)
    return playback
  }

  if (playback.shuffle && playback.shuffleOrder.length > 0) {
    const currentShuffleIdx = playback.shuffleOrder.indexOf(playback.songIndex)
    if (currentShuffleIdx > 0) {
      playback.songIndex = playback.shuffleOrder[currentShuffleIdx - 1]
    } else if (playback.repeat === 'all') {
      playback.songIndex = playback.shuffleOrder[playback.shuffleOrder.length - 1]
    }
  } else {
    const prev = playback.songIndex - 1
    if (prev >= 0) {
      playback.songIndex = prev
    } else if (playback.repeat === 'all') {
      playback.songIndex = playlist.songs.length - 1
    }
  }

  playback.progress = 0
  playback.isPlaying = true
  await writeStore(store)
  return playback
}

export const toggleShuffle = async (): Promise<PlaybackState> => {
  const store = await readStore()
  store.playback.shuffle = !store.playback.shuffle
  if (store.playback.shuffle && store.playback.playlistId) {
    const playlist = store.playlists.find((p) => p.id === store.playback.playlistId)
    if (playlist) {
      store.playback.shuffleOrder = generateShuffleOrder(
        playlist.songs.length,
        store.playback.songIndex,
      )
    }
  } else {
    store.playback.shuffleOrder = []
  }
  await writeStore(store)
  return store.playback
}

export const cycleRepeat = async (): Promise<PlaybackState> => {
  const store = await readStore()
  const modes: RepeatMode[] = ['none', 'all', 'one']
  const currentIdx = modes.indexOf(store.playback.repeat)
  store.playback.repeat = modes[(currentIdx + 1) % modes.length]
  await writeStore(store)
  return store.playback
}

export const seekTo = async (progress: number): Promise<PlaybackState> => {
  const store = await readStore()
  store.playback.progress = Math.max(0, progress)
  await writeStore(store)
  return store.playback
}

export const getNowPlaying = async (): Promise<{ song: Song; playlist: Playlist } | null> => {
  const store = await readStore()
  const { playback } = store
  if (!playback.playlistId) return null
  const playlist = store.playlists.find((p) => p.id === playback.playlistId)
  if (!playlist || playback.songIndex >= playlist.songs.length) return null
  return { song: playlist.songs[playback.songIndex], playlist }
}

