const clientScript = (): string => `
(function() {
  let dragSrcIndex = null;
  let dragPlaylistId = null;
  let progressTimer = null;

  // Drag and drop
  document.addEventListener('dragstart', function(e) {
    const row = e.target.closest('[draggable]');
    if (!row) return;
    dragSrcIndex = parseInt(row.dataset.index);
    dragPlaylistId = row.dataset.playlistId;
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', dragSrcIndex.toString());
    row.style.opacity = '0.5';
  });

  document.addEventListener('dragend', function(e) {
    const row = e.target.closest('[draggable]');
    if (row) row.style.opacity = '1';
    document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
  });

  document.addEventListener('dragover', function(e) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    const row = e.target.closest('[draggable]');
    if (row) {
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
      row.classList.add('drag-over');
    }
  });

  document.addEventListener('drop', function(e) {
    e.preventDefault();
    document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
    const row = e.target.closest('[draggable]');
    if (!row || dragSrcIndex === null) return;
    const toIndex = parseInt(row.dataset.index);
    if (dragSrcIndex === toIndex) return;
    fetch('/api/playlists/' + dragPlaylistId + '/reorder', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ fromIndex: dragSrcIndex, toIndex: toIndex })
    }).then(function() { location.reload(); });
  });

  // Song click to play
  document.addEventListener('click', function(e) {
    const row = e.target.closest('[data-song-index]');
    const removeBtn = e.target.closest('[data-song-id]');
    if (removeBtn) {
      e.stopPropagation();
      fetch('/api/playlists/' + removeBtn.dataset.playlistId + '/songs/' + removeBtn.dataset.songId, {
        method: 'DELETE'
      }).then(function() { location.reload(); });
      return;
    }
    if (row && !e.target.closest('button')) {
      const playlistId = row.dataset.playlistId;
      const songIndex = parseInt(row.dataset.songIndex);
      fetch('/api/playback/play', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId: playlistId, songIndex: songIndex })
      }).then(function() { location.reload(); });
    }
  });

  // Playback controls
  document.querySelectorAll('[p-trigger]').forEach(function(el) {
    const triggers = el.getAttribute('p-trigger');
    if (!triggers) return;
    triggers.split(' ').forEach(function(t) {
      const parts = t.split(':');
      const event = parts[0];
      const action = parts[1];
      if (event === 'click') {
        el.addEventListener('click', function(e) {
          handleAction(action, e, el);
        });
      }
      if (event === 'submit') {
        el.addEventListener('submit', function(e) {
          e.preventDefault();
          handleAction(action, e, el);
        });
      }
    });
  });

  function handleAction(action, e, el) {
    switch(action) {
      case 'toggle-play':
        fetch('/api/playback/toggle', { method: 'POST' }).then(function() { location.reload(); });
        break;
      case 'next-track':
        fetch('/api/playback/next', { method: 'POST' }).then(function() { location.reload(); });
        break;
      case 'prev-track':
        fetch('/api/playback/prev', { method: 'POST' }).then(function() { location.reload(); });
        break;
      case 'toggle-shuffle':
        fetch('/api/playback/shuffle', { method: 'POST' }).then(function() { location.reload(); });
        break;
      case 'cycle-repeat':
        fetch('/api/playback/repeat', { method: 'POST' }).then(function() { location.reload(); });
        break;
      case 'seek': {
        const bar = el;
        const rect = bar.getBoundingClientRect();
        const pct = (e.clientX - rect.left) / rect.width;
        // Get duration from the time display
        const timeDisplay = document.querySelector('[style*="text-align"]');
        if (timeDisplay) {
          const match = timeDisplay.textContent.match(/\\/ (\\d+):(\\d+)/);
          if (match) {
            const totalSec = parseInt(match[1]) * 60 + parseInt(match[2]);
            const seekTo = Math.floor(pct * totalSec);
            fetch('/api/playback/seek', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ progress: seekTo })
            }).then(function() { location.reload(); });
          }
        }
        break;
      }
      case 'create-playlist': {
        const form = el;
        const formData = new FormData(form);
        fetch('/api/playlists', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: formData.get('name'),
            description: formData.get('description') || ''
          })
        }).then(function() { location.reload(); });
        break;
      }
      case 'add-song-submit': {
        const form = el;
        const formData = new FormData(form);
        const playlistId = form.dataset.playlistId;
        const duration = parseInt(formData.get('duration'));
        fetch('/api/playlists/' + playlistId + '/songs', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            title: formData.get('title'),
            artist: formData.get('artist'),
            album: formData.get('album') || 'Unknown Album',
            duration: isNaN(duration) ? 200 : duration,
            albumArtUrl: formData.get('albumArtUrl') || 'https://placehold.co/300x300/3f3f46/a1a1aa?text=No+Art'
          })
        }).then(function() { location.reload(); });
        break;
      }
    }
  }

  // Simulate progress timer when playing
  function startProgressSim() {
    const timeEl = document.querySelector('[style*="text-align"]');
    if (!timeEl) return;
    const fill = document.querySelector('[p-target="progress-fill"]');
    if (!fill) return;

    progressTimer = setInterval(function() {
      const match = timeEl.textContent.match(/(\\d+):(\\d+) \\/ (\\d+):(\\d+)/);
      if (!match) return;
      let current = parseInt(match[1]) * 60 + parseInt(match[2]);
      const total = parseInt(match[3]) * 60 + parseInt(match[4]);
      current += 1;
      if (current >= total) {
        clearInterval(progressTimer);
        fetch('/api/playback/next', { method: 'POST' }).then(function() { location.reload(); });
        return;
      }
      const min = Math.floor(current / 60);
      const sec = (current % 60).toString().padStart(2, '0');
      timeEl.textContent = min + ':' + sec + ' / ' + match[3] + ':' + match[4];
      fill.style.width = ((current / total) * 100) + '%';
      // Persist progress
      fetch('/api/playback/seek', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ progress: current })
      });
    }, 1000);
  }

  // Check if currently playing and start sim
  const playBtn = document.querySelector('[title="Pause"]');
  if (playBtn) startProgressSim();
})();
`

import {
  getPlaylists,
  getPlaylist,
  createPlaylist,
  deletePlaylist,
  addSong,
  removeSong,
  reorderSong,
  getPlaybackState,
  playTrack,
  togglePlay,
  nextTrack,
  prevTrack,
  toggleShuffle,
  cycleRepeat,
  seekTo,
  getNowPlaying,
} from './store'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const parseBody = async (req: Request) => {
  try {
    return await req.json()
  } catch {
    return null
  }
}

export const handleApiRoute = async (req: Request, pathname: string): Promise<Response | null> => {
  const method = req.method

  // GET /api/playlists
  if (method === 'GET' && pathname === '/api/playlists') {
    return json(await getPlaylists())
  }

  // POST /api/playlists
  if (method === 'POST' && pathname === '/api/playlists') {
    const body = await parseBody(req)
    if (!body?.name) return json({ error: 'name is required' }, 400)
    const playlist = await createPlaylist(body.name, body.description)
    return json(playlist, 201)
  }

  // GET /api/playlists/:id
  const playlistMatch = pathname.match(/^\/api\/playlists\/([^/]+)$/)
  if (method === 'GET' && playlistMatch) {
    const playlist = await getPlaylist(playlistMatch[1])
    if (!playlist) return json({ error: 'not found' }, 404)
    return json(playlist)
  }

  // DELETE /api/playlists/:id
  if (method === 'DELETE' && playlistMatch) {
    const ok = await deletePlaylist(playlistMatch[1])
    if (!ok) return json({ error: 'not found' }, 404)
    return json({ ok: true })
  }

  // POST /api/playlists/:id/songs
  const songsMatch = pathname.match(/^\/api\/playlists\/([^/]+)\/songs$/)
  if (method === 'POST' && songsMatch) {
    const body = await parseBody(req)
    if (!body?.title || !body?.artist) {
      return json({ error: 'title and artist are required' }, 400)
    }
    const song = await addSong(songsMatch[1], {
      title: body.title,
      artist: body.artist,
      album: body.album || 'Unknown Album',
      duration: Number(body.duration) || 200,
      albumArtUrl: body.albumArtUrl || 'https://placehold.co/300x300/3f3f46/a1a1aa?text=No+Art',
    })
    if (!song) return json({ error: 'playlist not found' }, 404)
    return json(song, 201)
  }

  // DELETE /api/playlists/:id/songs/:songId
  const songDeleteMatch = pathname.match(/^\/api\/playlists\/([^/]+)\/songs\/([^/]+)$/)
  if (method === 'DELETE' && songDeleteMatch) {
    const ok = await removeSong(songDeleteMatch[1], songDeleteMatch[2])
    if (!ok) return json({ error: 'not found' }, 404)
    return json({ ok: true })
  }

  // PATCH /api/playlists/:id/reorder
  const reorderMatch = pathname.match(/^\/api\/playlists\/([^/]+)\/reorder$/)
  if (method === 'PATCH' && reorderMatch) {
    const body = await parseBody(req)
    if (body?.fromIndex === undefined || body?.toIndex === undefined) {
      return json({ error: 'fromIndex and toIndex are required' }, 400)
    }
    const ok = await reorderSong(reorderMatch[1], body.fromIndex, body.toIndex)
    if (!ok) return json({ error: 'invalid reorder' }, 400)
    return json({ ok: true })
  }

  // GET /api/playback
  if (method === 'GET' && pathname === '/api/playback') {
    return json(await getPlaybackState())
  }

  // POST /api/playback/play
  if (method === 'POST' && pathname === '/api/playback/play') {
    const body = await parseBody(req)
    if (!body?.playlistId || body?.songIndex === undefined) {
      return json({ error: 'playlistId and songIndex are required' }, 400)
    }
    return json(await playTrack(body.playlistId, body.songIndex))
  }

  // POST /api/playback/toggle
  if (method === 'POST' && pathname === '/api/playback/toggle') {
    return json(await togglePlay())
  }

  // POST /api/playback/next
  if (method === 'POST' && pathname === '/api/playback/next') {
    return json(await nextTrack())
  }

  // POST /api/playback/prev
  if (method === 'POST' && pathname === '/api/playback/prev') {
    return json(await prevTrack())
  }

  // POST /api/playback/shuffle
  if (method === 'POST' && pathname === '/api/playback/shuffle') {
    return json(await toggleShuffle())
  }

  // POST /api/playback/repeat
  if (method === 'POST' && pathname === '/api/playback/repeat') {
    return json(await cycleRepeat())
  }

  // POST /api/playback/seek
  if (method === 'POST' && pathname === '/api/playback/seek') {
    const body = await parseBody(req)
    if (body?.progress === undefined) return json({ error: 'progress is required' }, 400)
    return json(await seekTo(body.progress))
  }

  // GET /api/now-playing
  if (method === 'GET' && pathname === '/api/now-playing') {
    const np = await getNowPlaying()
    if (!np) return json(null)
    return json(np)
  }

  return null
}

import { createSSR } from 'plaited'
import { AppShell } from './components'
import { handleApiRoute } from './routes'
import { getPlaylists, getPlaybackState, getNowPlaying } from './store'

const ssr = createSSR()

const renderPage = async (): Promise<string> => {
  const [playlists, playback, nowPlaying] = await Promise.all([
    getPlaylists(),
    getPlaybackState(),
    getNowPlaying(),
  ])

  const tree = AppShell(
    playlists,
    playback,
    nowPlaying?.song ?? null,
    nowPlaying?.playlist ?? null,
  )

  return `<!DOCTYPE html>${ssr(tree)}`
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const pathname = url.pathname

    // API routes
    if (pathname.startsWith('/api/')) {
      const response = await handleApiRoute(req, pathname)
      if (response) return response
      return new Response(JSON.stringify({ error: 'not found' }), {
        status: 404,
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // Main page
    if (pathname === '/' || pathname === '/index.html') {
      const html = await renderPage()
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    // 404
    return new Response('Not Found', { status: 404 })
  },
})

