import type { Store, Playlist, Song, PlaybackState, RepeatMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const generateId = (): string => crypto.randomUUID()

const readStore = async (): Promise<Store> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    const initial: Store = {
      playlists: [],
      playback: {
        playlistId: null,
        songIndex: 0,
        isPlaying: false,
        shuffle: false,
        repeat: 'none',
        progress: 0,
        shuffleOrder: [],
      },
    }
    await Bun.write(DATA_PATH, JSON.stringify(initial, null, 2))
    return initial
  }
  return file.json()
}

const writeStore = async (store: Store): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

const generateShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i)
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[order[i], order[j]] = [order[j], order[i]]
  }
  return order
}

export const getPlaylists = async (): Promise<Playlist[]> => {
  const store = await readStore()
  return store.playlists
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const store = await readStore()
  return store.playlists.find((p) => p.id === id)
}

export const createPlaylist = async (name: string, description: string): Promise<Playlist> => {
  const store = await readStore()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId(),
    name,
    description,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  store.playlists.push(playlist)
  await writeStore(store)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await readStore()
  const idx = store.playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  store.playlists.splice(idx, 1)
  if (store.playback.playlistId === id) {
    store.playback = {
      playlistId: null,
      songIndex: 0,
      isPlaying: false,
      shuffle: false,
      repeat: store.playback.repeat,
      progress: 0,
      shuffleOrder: [],
    }
  }
  await writeStore(store)
  return true
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>,
): Promise<Song | null> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { id: generateId(), ...song }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.playlistId === playlistId && store.playback.shuffle) {
    store.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
  }
  await writeStore(store)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.playlistId === playlistId) {
    if (store.playback.songIndex >= playlist.songs.length) {
      store.playback.songIndex = Math.max(0, playlist.songs.length - 1)
    }
    if (playlist.songs.length === 0) {
      store.playback.isPlaying = false
    }
    if (store.playback.shuffle) {
      store.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
    }
  }
  await writeStore(store)
  return true
}

export const reorderSongs = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number,
): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return false
  if (toIndex < 0 || toIndex >= playlist.songs.length) return false
  const [moved] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, moved)
  playlist.updatedAt = new Date().toISOString()
  if (store.playback.playlistId === playlistId) {
    if (store.playback.songIndex === fromIndex) {
      store.playback.songIndex = toIndex
    } else if (fromIndex < store.playback.songIndex && toIndex >= store.playback.songIndex) {
      store.playback.songIndex--
    } else if (fromIndex > store.playback.songIndex && toIndex <= store.playback.songIndex) {
      store.playback.songIndex++
    }
  }
  await writeStore(store)
  return true
}

export const getPlaybackState = async (): Promise<PlaybackState> => {
  const store = await readStore()
  return store.playback
}

export const play = async (playlistId: string, songIndex: number): Promise<PlaybackState> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist || songIndex < 0 || songIndex >= playlist.songs.length) {
    return store.playback
  }
  const needsShuffle =
    store.playback.playlistId !== playlistId ||
    store.playback.shuffleOrder.length !== playlist.songs.length
  store.playback.playlistId = playlistId
  store.playback.songIndex = songIndex
  store.playback.isPlaying = true
  store.playback.progress = 0
  if (store.playback.shuffle && needsShuffle) {
    store.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
  }
  await writeStore(store)
  return store.playback
}

export const pause = async (): Promise<PlaybackState> => {
  const store = await readStore()
  store.playback.isPlaying = false
  await writeStore(store)
  return store.playback
}

export const resume = async (): Promise<PlaybackState> => {
  const store = await readStore()
  if (store.playback.playlistId) {
    store.playback.isPlaying = true
  }
  await writeStore(store)
  return store.playback
}

export const skip = async (): Promise<PlaybackState> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === store.playback.playlistId)
  if (!playlist || playlist.songs.length === 0) return store.playback

  if (store.playback.repeat === 'one') {
    store.playback.progress = 0
    await writeStore(store)
    return store.playback
  }

  if (store.playback.shuffle) {
    const currentShuffleIdx = store.playback.shuffleOrder.indexOf(store.playback.songIndex)
    const nextShuffleIdx = currentShuffleIdx + 1
    if (nextShuffleIdx >= store.playback.shuffleOrder.length) {
      if (store.playback.repeat === 'all') {
        store.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
        store.playback.songIndex = store.playback.shuffleOrder[0]
      } else {
        store.playback.isPlaying = false
      }
    } else {
      store.playback.songIndex = store.playback.shuffleOrder[nextShuffleIdx]
    }
  } else {
    const next = store.playback.songIndex + 1
    if (next >= playlist.songs.length) {
      if (store.playback.repeat === 'all') {
        store.playback.songIndex = 0
      } else {
        store.playback.isPlaying = false
      }
    } else {
      store.playback.songIndex = next
    }
  }
  store.playback.progress = 0
  await writeStore(store)
  return store.playback
}

export const previous = async (): Promise<PlaybackState> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === store.playback.playlistId)
  if (!playlist || playlist.songs.length === 0) return store.playback

  if (store.playback.progress > 10) {
    store.playback.progress = 0
    await writeStore(store)
    return store.playback
  }

  if (store.playback.shuffle) {
    const currentShuffleIdx = store.playback.shuffleOrder.indexOf(store.playback.songIndex)
    const prevShuffleIdx = currentShuffleIdx - 1
    if (prevShuffleIdx < 0) {
      if (store.playback.repeat === 'all') {
        store.playback.songIndex =
          store.playback.shuffleOrder[store.playback.shuffleOrder.length - 1]
      }
    } else {
      store.playback.songIndex = store.playback.shuffleOrder[prevShuffleIdx]
    }
  } else {
    const prev = store.playback.songIndex - 1
    if (prev < 0) {
      if (store.playback.repeat === 'all') {
        store.playback.songIndex = playlist.songs.length - 1
      }
    } else {
      store.playback.songIndex = prev
    }
  }
  store.playback.progress = 0
  await writeStore(store)
  return store.playback
}

export const toggleShuffle = async (): Promise<PlaybackState> => {
  const store = await readStore()
  store.playback.shuffle = !store.playback.shuffle
  if (store.playback.shuffle && store.playback.playlistId) {
    const playlist = store.playlists.find((p) => p.id === store.playback.playlistId)
    if (playlist) {
      store.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length)
    }
  }
  await writeStore(store)
  return store.playback
}

export const cycleRepeat = async (): Promise<PlaybackState> => {
  const store = await readStore()
  const modes: RepeatMode[] = ['none', 'all', 'one']
  const current = modes.indexOf(store.playback.repeat)
  store.playback.repeat = modes[(current + 1) % modes.length]
  await writeStore(store)
  return store.playback
}

export const seek = async (progress: number): Promise<PlaybackState> => {
  const store = await readStore()
  store.playback.progress = Math.max(0, Math.min(100, progress))
  await writeStore(store)
  return store.playback
}

