  const currentSong = isCurrentPlaylist ? playlist.songs[playback.songIndex] : null

  return h(Fragment, {},
    h('div', { style: styleToStr(styles.container) },
      h('a', { href: '/', style: styleToStr(styles.backLink) }, '\u2190 Back to playlists'),

      h('div', { style: styleToStr(styles.playlistHeader) },
        h('div', { style: styleToStr(styles.playlistCover) }, '\u{1F3B5}'),
        h('div', {},
          h('p', { style: 'font-size:13px;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px' }, 'Playlist'),
