      ? renderNowPlaying(currentSong, playback)
      : null,

    // Drag-and-drop script
    h('script', {}, `
      (function() {
        let dragSrcIndex = null;
        document.addEventListener('dragstart', function(e) {
          const row = e.target.closest('.song-row');
          if (!row) return;
          dragSrcIndex = parseInt(row.dataset.index);
          row.classList.add('dragging');
          e.dataTransfer.effectAllowed = 'move';
        });
        document.addEventListener('dragover', function(e) {
          const row = e.target.closest('.song-row');
          if (!row) return;
          e.preventDefault();
          e.dataTransfer.dropEffect = 'move';
          document.querySelectorAll('.song-row').forEach(r => r.classList.remove('drag-over'));
          row.classList.add('drag-over');
        });
        document.addEventListener('drop', function(e) {
          const row = e.target.closest('.song-row');
          if (!row || dragSrcIndex === null) return;
          e.preventDefault();
          const toIndex = parseInt(row.dataset.index);
          if (dragSrcIndex !== toIndex) {
            fetch('/playlist/${playlist.id}/reorder', {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ fromIndex: dragSrcIndex, toIndex: toIndex })
            }).then(() => window.location.reload());
          }
          document.querySelectorAll('.song-row').forEach(r => {
            r.classList.remove('drag-over');
            r.classList.remove('dragging');
          });
          dragSrcIndex = null;
        });
        document.addEventListener('dragend', function() {
          document.querySelectorAll('.song-row').forEach(r => {
            r.classList.remove('drag-over');
            r.classList.remove('dragging');
          });
          dragSrcIndex = null;
        });
      })();
    `),
  )
}

