    // Seek script
    h('script', {}, `
      (function() {
        document.querySelector('.progress-bar').addEventListener('click', function(e) {
          const rect = this.getBoundingClientRect();
          const pct = Math.round(((e.clientX - rect.left) / rect.width) * 100);
          fetch('/playback/seek', {
