type HandlerResult = {
  html?: unknown
  redirect?: string
  json?: unknown
  status?: number
}

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((v, k) => {
    result[k] = v
  })
  return result
}

const parseJson = async (req: Request): Promise<Record<string, unknown>> => {
  return req.json()
}

export const handleListPlaylists = async (): Promise<HandlerResult> => {
  const playlists = await getPlaylists()
  return { html: playlists }
}

export const handleGetPlaylist = async (id: string): Promise<HandlerResult> => {
  const playlist = await getPlaylist(id)
  if (!playlist) return { status: 404 }
  const playback = await getPlaybackState()
  return { html: { playlist, playback } }
}

export const handleCreatePlaylist = async (req: Request): Promise<HandlerResult> => {
  const form = await parseForm(req)
  const name = form.name?.trim()
  const description = form.description?.trim() || ''
  if (!name) return { redirect: '/' }
  await createPlaylist(name, description)
  return { redirect: '/' }
}

export const handleDeletePlaylist = async (id: string): Promise<HandlerResult> => {
  await deletePlaylist(id)
  return { redirect: '/' }
}

export const handleAddSong = async (playlistId: string, req: Request): Promise<HandlerResult> => {
  const form = await parseForm(req)
  const title = form.title?.trim()
  const artist = form.artist?.trim()
  const album = form.album?.trim()
  const duration = parseInt(form.duration, 10)
  const albumArtUrl = form.albumArtUrl?.trim() || `https://placehold.co/300x300/1a1a2e/e94560?text=${encodeURIComponent(title || 'Song')}`

  if (!title || !artist || !album || isNaN(duration)) {
    return { redirect: `/playlist/${playlistId}` }
  }

  await addSong(playlistId, { title, artist, album, duration, albumArtUrl })
  return { redirect: `/playlist/${playlistId}` }
}

export const handleRemoveSong = async (playlistId: string, songId: string): Promise<HandlerResult> => {
  await removeSong(playlistId, songId)
  return { redirect: `/playlist/${playlistId}` }
}

export const handleReorderSongs = async (playlistId: string, req: Request): Promise<HandlerResult> => {
  const body = await parseJson(req)
  const fromIndex = body.fromIndex as number
  const toIndex = body.toIndex as number
  const success = await reorderSongs(playlistId, fromIndex, toIndex)
  return { json: { success } }
}

export const handlePlay = async (req: Request): Promise<HandlerResult> => {
  const contentType = req.headers.get('content-type') || ''
  let playlistId: string
  let songIndex: number

  if (contentType.includes('application/json')) {
    const body = await parseJson(req)
    playlistId = body.playlistId as string
    songIndex = body.songIndex as number
  } else {
    const form = await parseForm(req)
    playlistId = form.playlistId
    songIndex = parseInt(form.songIndex, 10)
  }

  const state = await play(playlistId, songIndex)
  const playlist = await getPlaylist(playlistId)

  if (contentType.includes('application/json')) {
    return { json: state }
  }
  return { redirect: `/playlist/${playlistId}` }
}

