import { createSSR } from 'plaited/server'
import { renderLayout, renderPlaylistList, renderPlaylistDetail } from './components'
import {
  handleListPlaylists,
  handleGetPlaylist,
  handleCreatePlaylist,
  handleDeletePlaylist,
  handleAddSong,
  handleRemoveSong,
  handleReorderSongs,
  handlePlay,
  handlePause,
  handleResume,
  handleSkip,
  handlePrevious,
  handleToggleShuffle,
  handleCycleRepeat,
  handleSeek,
} from './handlers'

const ssr = createSSR()

const htmlResponse = (template: unknown): Response => {
  const html = ssr(template)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const redirect = (url: string): Response =>
  new Response(null, {
    status: 303,
    headers: { Location: url },
  })

const matchRoute = (
  pathname: string,
  method: string,
): { handler: string; params: Record<string, string> } | null => {
  const routes: Array<{
    method: string
    pattern: RegExp
    handler: string
    paramNames: string[]
  }> = [
    { method: 'GET', pattern: /^\/$/, handler: 'listPlaylists', paramNames: [] },
    { method: 'POST', pattern: /^\/playlist$/, handler: 'createPlaylist', paramNames: [] },
    { method: 'GET', pattern: /^\/playlist\/([^/]+)$/, handler: 'getPlaylist', paramNames: ['id'] },
    { method: 'POST', pattern: /^\/playlist\/([^/]+)\/delete$/, handler: 'deletePlaylist', paramNames: ['id'] },
    { method: 'POST', pattern: /^\/playlist\/([^/]+)\/song$/, handler: 'addSong', paramNames: ['playlistId'] },
    { method: 'POST', pattern: /^\/playlist\/([^/]+)\/song\/([^/]+)\/delete$/, handler: 'removeSong', paramNames: ['playlistId', 'songId'] },
    { method: 'PUT', pattern: /^\/playlist\/([^/]+)\/reorder$/, handler: 'reorderSongs', paramNames: ['playlistId'] },
    { method: 'POST', pattern: /^\/playback\/play$/, handler: 'play', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/pause$/, handler: 'pause', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/resume$/, handler: 'resume', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/skip$/, handler: 'skip', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/previous$/, handler: 'previous', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/shuffle$/, handler: 'shuffle', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/repeat$/, handler: 'repeat', paramNames: [] },
    { method: 'POST', pattern: /^\/playback\/seek$/, handler: 'seek', paramNames: [] },
  ]

  for (const route of routes) {
    if (route.method !== method) continue
    const match = pathname.match(route.pattern)
    if (match) {
      const params: Record<string, string> = {}
      route.paramNames.forEach((name, i) => {
        params[name] = match[i + 1]
      })
      return { handler: route.handler, params }
    }
  }
  return null
}

export default {
  port: 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    const route = matchRoute(pathname, method)
    if (!route) {
      return new Response('Not Found', { status: 404 })
    }

    switch (route.handler) {
      case 'listPlaylists': {
        const result = await handleListPlaylists()
        const playlists = result.html as Awaited<ReturnType<typeof import('./store').getPlaylists>>
        const content = renderPlaylistList(playlists)
        const page = renderLayout('Playlist Manager', content)
        return htmlResponse(page)
      }

      case 'getPlaylist': {
        const result = await handleGetPlaylist(route.params.id)
        if (result.status === 404) return new Response('Playlist not found', { status: 404 })
        const { playlist, playback } = result.html as { playlist: any; playback: any }
        const content = renderPlaylistDetail(playlist, playback)
        const page = renderLayout(`${playlist.name} - Playlist Manager`, content)
        return htmlResponse(page)
      }

      case 'createPlaylist': {
        const result = await handleCreatePlaylist(req)
        return redirect(result.redirect!)
      }

      case 'deletePlaylist': {
        const result = await handleDeletePlaylist(route.params.id)
        return redirect(result.redirect!)
      }

      case 'addSong': {
        const result = await handleAddSong(route.params.playlistId, req)
        return redirect(result.redirect!)
      }

      case 'removeSong': {
        const result = await handleRemoveSong(route.params.playlistId, route.params.songId)
        return redirect(result.redirect!)
      }

      case 'reorderSongs': {
        const result = await handleReorderSongs(route.params.playlistId, req)
        return jsonResponse(result.json)
      }

      case 'play': {
        const result = await handlePlay(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'pause': {
        const result = await handlePause(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'resume': {
        const result = await handleResume(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'skip': {
        const result = await handleSkip(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'previous': {
        const result = await handlePrevious(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'shuffle': {
        const result = await handleToggleShuffle(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'repeat': {
        const result = await handleCycleRepeat(req)
        if (result.json) return jsonResponse(result.json)
        return redirect(result.redirect!)
      }

      case 'seek': {
        const result = await handleSeek(req)
        return jsonResponse(result.json)
      }

      default:
        return new Response('Not Found', { status: 404 })
    }
  },
}

