  "version": "1.0.0",
  "description": "Newton's laws simulator with pendulum, projectile motion, and spring-mass systems",
  "modnet": {
    "contentType": "simulation",
    "structure": "steps",
    "mechanics": ["track", "chart"],
    "boundary": "all",
    "scale": 3
  },
