    "length": 1.5,
    "gravity": 9.81,
    "initialAngle": 0.5,
    "damping": 0.0
  },
  "projectile": {
    "angle": 45,
    "initialVelocity": 20,
    "gravity": 9.81
  },
  "spring": {
    "springConstant": 10,
    "mass": 1.0,
    "initialDisplacement": 1.0,
    "damping": 0.0
  },
  "speed": 1.0
}

export type Vec2 = {
  x: number
  y: number
}

export type SimulationMode = 'pendulum' | 'projectile' | 'spring'

export type PlaybackState = 'playing' | 'paused' | 'stopped'

export type PendulumParams = {
  length: number
  gravity: number
  initialAngle: number
  damping: number
}

export type PendulumState = {
  angle: number
  angularVelocity: number
  angularAcceleration: number
  time: number
}

export type ProjectileParams = {
  angle: number
  initialVelocity: number
  gravity: number
}

export type ProjectileState = {
  position: Vec2
  velocity: Vec2
  acceleration: Vec2
  time: number
  trajectory: Vec2[]
  landed: boolean
}

export type SpringParams = {
  springConstant: number
  mass: number
  initialDisplacement: number
  damping: number
}

export type SpringState = {
  displacement: number
  velocity: number
  acceleration: number
  time: number
}

export type SimulationState = {
  mode: SimulationMode
  playback: PlaybackState
  speed: number
  pendulum: {
    params: PendulumParams
    state: PendulumState
  }
  projectile: {
    params: ProjectileParams
    state: ProjectileState
  }
  spring: {
    params: SpringParams
    state: SpringState
  }
}

import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  Vec2,
} from './types'

const DT = 1 / 60

export const stepPendulum = (
  params: PendulumParams,
  state: PendulumState,
  speed: number
): PendulumState => {
  const dt = DT * speed
  const { length, gravity, damping } = params
  const angularAcceleration =
    (-gravity / length) * Math.sin(state.angle) - damping * state.angularVelocity
  const angularVelocity = state.angularVelocity + angularAcceleration * dt
  const angle = state.angle + angularVelocity * dt
  return {
    angle,
    angularVelocity,
    angularAcceleration,
    time: state.time + dt,
  }
}

export const initPendulumState = (params: PendulumParams): PendulumState => ({
  angle: params.initialAngle,
  angularVelocity: 0,
  angularAcceleration: (-params.gravity / params.length) * Math.sin(params.initialAngle),
  time: 0,
})

export const stepProjectile = (
  params: ProjectileParams,
  state: ProjectileState,
  speed: number
): ProjectileState => {
  if (state.landed) return state
  const dt = DT * speed
  const { gravity } = params
  const acceleration: Vec2 = { x: 0, y: -gravity }
  const velocity: Vec2 = {
    x: state.velocity.x + acceleration.x * dt,
    y: state.velocity.y + acceleration.y * dt,
  }
  const position: Vec2 = {
    x: state.position.x + velocity.x * dt,
    y: state.position.y + velocity.y * dt,
  }
  const landed = position.y <= 0 && state.time > 0
  if (landed) {
    position.y = 0
  }
  const trajectory = [...state.trajectory, { x: position.x, y: position.y }]
  return {
    position,
    velocity: landed ? { x: 0, y: 0 } : velocity,
    acceleration: landed ? { x: 0, y: 0 } : acceleration,
    time: state.time + dt,
    trajectory,
    landed,
  }
}

export const initProjectileState = (params: ProjectileParams): ProjectileState => {
  const rad = (params.angle * Math.PI) / 180
  return {
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(rad),
      y: params.initialVelocity * Math.sin(rad),
    },
    acceleration: { x: 0, y: -params.gravity },
    time: 0,
    trajectory: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepSpring = (
  params: SpringParams,
  state: SpringState,
  speed: number
): SpringState => {
  const dt = DT * speed
  const { springConstant, mass, damping } = params
  const omega2 = springConstant / mass
  const acceleration = -omega2 * state.displacement - damping * state.velocity
  const velocity = state.velocity + acceleration * dt
  const displacement = state.displacement + velocity * dt
  return {
    displacement,
    velocity,
    acceleration: -omega2 * displacement - damping * velocity,
    time: state.time + dt,
  }
}

export const initSpringState = (params: SpringParams): SpringState => ({
  displacement: params.initialDisplacement,
  velocity: 0,
  acceleration: (-params.springConstant / params.mass) * params.initialDisplacement,
  time: 0,
})

