const renderPendulumCanvas = (state: SimulationState) => {
  const { angle } = state.pendulum.state
  const { length } = state.pendulum.params
  const pivotX = 450
  const pivotY = 40
  const scale = 100
  const bobX = pivotX + Math.sin(angle) * length * scale
  const bobY = pivotY + Math.cos(angle) * length * scale
  return h('svg', {
    viewBox: '0 0 900 350',
    style: styleToStr({ width: '100%', height: '100%' }),
  },
    h('line', {
      x1: String(pivotX), y1: String(pivotY),
      x2: String(bobX), y2: String(bobY),
      stroke: '#8892b0', 'stroke-width': '2',
    }),
    h('circle', {
      cx: String(pivotX), cy: String(pivotY), r: '6',
      fill: '#233554', stroke: '#64ffda', 'stroke-width': '2',
    }),
    h('circle', {
      cx: String(bobX), cy: String(bobY), r: '18',
      fill: '#0f3460', stroke: '#64ffda', 'stroke-width': '2',
    }),
    h('line', {
      x1: String(pivotX), y1: String(pivotY),
      x2: String(pivotX), y2: String(pivotY + length * scale),
      stroke: '#233554', 'stroke-width': '1', 'stroke-dasharray': '4,4',
    }),
    h('text', {
      x: '20', y: '30',
      fill: '#8892b0', 'font-size': '13', 'font-family': 'monospace',
    }, `t = ${fmt(state.pendulum.state.time)}s`),
  )
}

const renderProjectileCanvas = (state: SimulationState) => {
  const { position, trajectory } = state.projectile.state
  const { angle: launchAngle, initialVelocity, gravity } = state.projectile.params
  const rad = (launchAngle * Math.PI) / 180
  const maxRange = (initialVelocity * initialVelocity * Math.sin(2 * rad)) / gravity
  const maxHeight = (initialVelocity * initialVelocity * Math.sin(rad) * Math.sin(rad)) / (2 * gravity)
  const scaleX = maxRange > 0 ? 800 / maxRange : 10
  const scaleY = maxHeight > 0 ? 280 / maxHeight : 10
  const scale = Math.min(scaleX, scaleY, 10)
  const groundY = 320
  const offsetX = 50
  const pathPoints = trajectory
    .map((p) => `${offsetX + p.x * scale},${groundY - p.y * scale}`)
    .join(' ')
  const cx = offsetX + position.x * scale
  const cy = groundY - position.y * scale
  return h('svg', {
    viewBox: '0 0 900 350',
    style: styleToStr({ width: '100%', height: '100%' }),
  },
    h('line', {
      x1: String(offsetX), y1: String(groundY),
      x2: '880', y2: String(groundY),
      stroke: '#233554', 'stroke-width': '1',
    }),
    h('line', {
      x1: String(offsetX), y1: '20',
      x2: String(offsetX), y2: String(groundY),
      stroke: '#233554', 'stroke-width': '1',
    }),
    trajectory.length > 1
      ? h('polyline', {
          points: pathPoints,
          fill: 'none',
          stroke: '#e6553a',
          'stroke-width': '2',
          'stroke-opacity': '0.6',
        })
      : h(Fragment, {}),
    h('circle', {
      cx: String(cx), cy: String(cy), r: '8',
      fill: '#e6553a', stroke: '#64ffda', 'stroke-width': '2',
    }),
    h('text', {
      x: '20', y: '30',
      fill: '#8892b0', 'font-size': '13', 'font-family': 'monospace',
    }, `t = ${fmt(state.projectile.state.time)}s`),
  )
}

const renderSpringCanvas = (state: SimulationState) => {
  const { displacement } = state.spring.state
  const anchorX = 100
  const centerY = 175
  const restX = 450
  const scale = 100
  const bobX = restX + displacement * scale
  const coils = 12
  const springPoints: string[] = [`${anchorX},${centerY}`]
  for (let i = 1; i <= coils; i++) {
    const frac = i / (coils + 1)
    const sx = anchorX + (bobX - 30 - anchorX) * frac
    const sy = centerY + (i % 2 === 0 ? -20 : 20)
    springPoints.push(`${sx},${sy}`)
  }
  springPoints.push(`${bobX - 30},${centerY}`)
  return h('svg', {
    viewBox: '0 0 900 350',
    style: styleToStr({ width: '100%', height: '100%' }),
  },
    h('rect', {
      x: String(anchorX - 10), y: String(centerY - 60),
      width: '10', height: '120',
      fill: '#233554',
    }),
    h('polyline', {
      points: springPoints.join(' '),
      fill: 'none',
      stroke: '#8892b0',
      'stroke-width': '2',
    }),
    h('rect', {
      x: String(bobX - 30), y: String(centerY - 25),
      width: '50', height: '50',
      rx: '6',
      fill: '#0f3460', stroke: '#64ffda', 'stroke-width': '2',
    }),
    h('line', {
      x1: String(restX), y1: String(centerY - 50),
      x2: String(restX), y2: String(centerY + 50),
      stroke: '#233554', 'stroke-width': '1', 'stroke-dasharray': '4,4',
    }),
    h('text', {
      x: String(restX - 5), y: String(centerY + 70),
      fill: '#8892b0', 'font-size': '11', 'font-family': 'monospace',
      'text-anchor': 'middle',
    }, 'equilibrium'),
    h('text', {
      x: '20', y: '30',
      fill: '#8892b0', 'font-size': '13', 'font-family': 'monospace',
    }, `t = ${fmt(state.spring.state.time)}s`),
  )
}

const renderPendulumSliders = (state: SimulationState) =>
