const renderPendulumReadouts = (state: SimulationState) => {
  const { angle, angularVelocity, angularAcceleration } = state.pendulum.state
  return h('div', { style: styleToStr(styles.readouts) },
    renderReadout('Angular Position', fmt(angle), 'rad'),
    renderReadout('Angular Velocity', fmt(angularVelocity), 'rad/s'),
