const renderProjectileReadouts = (state: SimulationState) => {
  const { position, velocity, acceleration } = state.projectile.state
  const speed = Math.sqrt(velocity.x ** 2 + velocity.y ** 2)
  return h('div', { style: styleToStr(styles.readouts) },
    renderReadout('Position', `(${fmt(position.x)}, ${fmt(position.y)})`, 'm'),
    renderReadout('Speed', fmt(speed), 'm/s'),
    renderReadout('Acceleration', fmt(Math.abs(acceleration.y)), 'm/s²'),
  )
}

const renderSpringReadouts = (state: SimulationState) => {
  const { displacement, velocity, acceleration } = state.spring.state
  return h('div', { style: styleToStr(styles.readouts) },
    renderReadout('Displacement', fmt(displacement), 'm'),
    renderReadout('Velocity', fmt(velocity), 'm/s'),
    renderReadout('Acceleration', fmt(acceleration), 'm/s²'),
  )
}

export const render = (state: SimulationState) => {
  const { mode, playback, speed } = state
  const isPlaying = playback === 'playing'

  const canvasContent =
    mode === 'pendulum'
      ? renderPendulumCanvas(state)
      : mode === 'projectile'
        ? renderProjectileCanvas(state)
        : renderSpringCanvas(state)

  const sliders =
    mode === 'pendulum'
      ? renderPendulumSliders(state)
      : mode === 'projectile'
        ? renderProjectileSliders(state)
        : renderSpringSliders(state)

  const readouts =
    mode === 'pendulum'
      ? renderPendulumReadouts(state)
      : mode === 'projectile'
        ? renderProjectileReadouts(state)
        : renderSpringReadouts(state)

  return h('div', { style: styleToStr(styles.container) },
    h('h1', { style: styleToStr(styles.header) }, "Newton's Laws Simulator"),
    h('div', { style: styleToStr(styles.tabBar) },
      renderTab('Pendulum', 'pendulum', mode === 'pendulum'),
      renderTab('Projectile', 'projectile', mode === 'projectile'),
      renderTab('Spring-Mass', 'spring', mode === 'spring'),
    ),
    h('div', { style: styleToStr(styles.canvas), 'p-target': 'canvas' }, canvasContent),
    h('div', { style: styleToStr(styles.controls) },
      renderButton(isPlaying ? '⏸ Pause' : '▶ Play', 'togglePlay', isPlaying),
      renderButton('↺ Reset', 'reset'),
    ),
    h('div', { style: styleToStr(styles.speedControl) },
      h('span', {}, 'Speed:'),
      renderButton('0.25×', 'setSpeed:0.25', speed === 0.25),
      renderButton('0.5×', 'setSpeed:0.5', speed === 0.5),
      renderButton('1×', 'setSpeed:1', speed === 1),
      renderButton('2×', 'setSpeed:2', speed === 2),
      renderButton('4×', 'setSpeed:4', speed === 4),
    ),
    sliders,
    readouts,
  )
}

import { createSSR } from 'plaited'
import type { SimulationMode, SimulationState } from './types'
import {
  initPendulumState,
  initProjectileState,
  initSpringState,
  stepPendulum,
  stepProjectile,
  stepSpring,
} from './physics'
import { render } from './renderer'

const defaultParams = await Bun.file(
  new URL('./data/defaults.json', import.meta.url).pathname
).json()

const createInitialState = (): SimulationState => ({
  mode: 'pendulum',
  playback: 'stopped',
  speed: defaultParams.speed,
  pendulum: {
    params: { ...defaultParams.pendulum },
    state: initPendulumState(defaultParams.pendulum),
  },
  projectile: {
    params: { ...defaultParams.projectile },
    state: initProjectileState(defaultParams.projectile),
  },
  spring: {
    params: { ...defaultParams.spring },
    state: initSpringState(defaultParams.spring),
  },
})

let state = createInitialState()
let animationTimer: ReturnType<typeof setInterval> | null = null

const tick = () => {
  if (state.playback !== 'playing') return
  switch (state.mode) {
    case 'pendulum':
      state.pendulum.state = stepPendulum(
        state.pendulum.params,
        state.pendulum.state,
        state.speed
      )
      break
    case 'projectile':
      state.projectile.state = stepProjectile(
        state.projectile.params,
        state.projectile.state,
        state.speed
      )
      break
    case 'spring':
      state.spring.state = stepSpring(
        state.spring.params,
        state.spring.state,
        state.speed
      )
      break
  }
}

const startLoop = () => {
  if (animationTimer) return
  animationTimer = setInterval(tick, 1000 / 60)
}

const stopLoop = () => {
  if (animationTimer) {
    clearInterval(animationTimer)
    animationTimer = null
  }
}

export const handleEvent = (trigger: string, value?: string) => {
  if (trigger.startsWith('selectMode:')) {
    const mode = trigger.split(':')[1] as SimulationMode
    state.mode = mode
    state.playback = 'stopped'
    stopLoop()
    resetCurrentSim()
  } else if (trigger === 'togglePlay') {
    if (state.playback === 'playing') {
      state.playback = 'paused'
      stopLoop()
    } else {
      state.playback = 'playing'
      startLoop()
    }
  } else if (trigger === 'reset') {
    state.playback = 'stopped'
    stopLoop()
    resetCurrentSim()
  } else if (trigger.startsWith('setSpeed:')) {
    state.speed = parseFloat(trigger.split(':')[1])
  } else if (trigger === 'setPendulumLength' && value) {
    state.pendulum.params.length = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setPendulumGravity' && value) {
    state.pendulum.params.gravity = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setPendulumAngle' && value) {
    state.pendulum.params.initialAngle = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setProjectileAngle' && value) {
    state.projectile.params.angle = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setProjectileVelocity' && value) {
    state.projectile.params.initialVelocity = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setSpringConstant' && value) {
    state.spring.params.springConstant = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setSpringMass' && value) {
    state.spring.params.mass = parseFloat(value)
    resetCurrentSim()
  } else if (trigger === 'setSpringDisplacement' && value) {
    state.spring.params.initialDisplacement = parseFloat(value)
    resetCurrentSim()
  }
}

const resetCurrentSim = () => {
  switch (state.mode) {
    case 'pendulum':
      state.pendulum.state = initPendulumState(state.pendulum.params)
      break
    case 'projectile':
      state.projectile.state = initProjectileState(state.projectile.params)
      break
    case 'spring':
      state.spring.state = initSpringState(state.spring.params)
      break
  }
}

export const getView = () => {
  const ssr = createSSR()
  return ssr(render(state))
}

export const getState = (): SimulationState => structuredClone(state)

export const reset = () => {
  stopLoop()
  state = createInitialState()
}

import { getView, handleEvent, getState, reset } from './index'

const PORT = 3000

const htmlPage = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Newton's Laws Simulator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #0a0a1a; min-height: 100vh; display: flex; justify-content: center; padding: 40px 16px; }
    input[type="range"] { height: 6px; border-radius: 3px; }
    button:hover { opacity: 0.85; }
  </style>
</head>
<body>
  <div id="app">${body}</div>
  <script>
    const refresh = async () => {
      const res = await fetch('/view');
      const html = await res.text();
      document.getElementById('app').innerHTML = html;
      bindEvents();
    };

    const bindEvents = () => {
      document.querySelectorAll('[p-trigger]').forEach(el => {
        const trigger = el.getAttribute('p-trigger');
        if (el.tagName === 'INPUT') {
          el.addEventListener('input', async (e) => {
            await fetch('/event', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ trigger, value: e.target.value }),
            });
            await refresh();
          });
        } else {
          el.addEventListener('click', async () => {
            await fetch('/event', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ trigger }),
            });
            await refresh();
          });
        }
      });
    };

    let animating = false;
    const animate = async () => {
      const res = await fetch('/state');
      const state = await res.json();
      if (state.playback === 'playing') {
        if (!animating) {
          animating = true;
          const loop = async () => {
            const s = await fetch('/state').then(r => r.json());
            if (s.playback !== 'playing') { animating = false; return; }
            await refresh();
            requestAnimationFrame(loop);
          };
          loop();
        }
      } else {
        animating = false;
      }
    };

    document.addEventListener('click', (e) => {
      if (e.target.closest('[p-trigger="togglePlay"]')) {
        setTimeout(animate, 50);
      }
    });

    bindEvents();
  </script>
</body>
</html>`

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '') {
      return new Response(htmlPage(getView()), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    if (url.pathname === '/view') {
      return new Response(getView(), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    if (url.pathname === '/state') {
      return Response.json(getState())
    }

    if (url.pathname === '/event' && req.method === 'POST') {
      const body = await req.json() as { trigger: string; value?: string }
      handleEvent(body.trigger, body.value)
      return Response.json({ ok: true })
    }

    if (url.pathname === '/reset' && req.method === 'POST') {
      reset()
      return Response.json({ ok: true })
    }

    return new Response('Not found', { status: 404 })
  },
})

