export type SimulationType = 'pendulum' | 'projectile' | 'spring';

export type PendulumParams = {
  length: number;
  gravity: number;
  initialAngle: number;
};

export type ProjectileParams = {
  angle: number;
  initialVelocity: number;
  gravity: number;
};

export type SpringParams = {
  springConstant: number;
  mass: number;
  initialDisplacement: number;
};

export type SimulationPresets = {
  pendulum: PendulumParams;
  projectile: ProjectileParams;
  spring: SpringParams;
};

export type Vec2 = {
  x: number;
  y: number;
};

// Physics computation functions using symplectic Euler integration
// for energy-conserving numerical stability in oscillatory systems

export const pendulumStep = (
  angle: number,
  angVel: number,
  length: number,
  gravity: number,
  dt: number,
): { angle: number; angVel: number; angAcc: number } => {
  const angAcc = -(gravity / length) * Math.sin(angle);
  const newAngVel = angVel + angAcc * dt;
  const newAngle = angle + newAngVel * dt;
  return { angle: newAngle, angVel: newAngVel, angAcc };
};

export const projectileStep = (
  x: number,
  y: number,
  vx: number,
  vy: number,
  gravity: number,
  dt: number,
): { x: number; y: number; vx: number; vy: number } => {
  const newVy = vy - gravity * dt;
  const newX = x + vx * dt;
  const newY = y + newVy * dt;
  return { x: newX, y: newY, vx, vy: newVy };
};

export const springStep = (
  displacement: number,
  velocity: number,
  springConstant: number,
  mass: number,
  dt: number,
): { displacement: number; velocity: number; acceleration: number } => {
  const acceleration = -(springConstant / mass) * displacement;
  const newVelocity = velocity + acceleration * dt;
  const newDisplacement = displacement + newVelocity * dt;
  return { displacement: newDisplacement, velocity: newVelocity, acceleration };
};

