(() => {
  // ===== Setup =====
  type SimType = 'pendulum' | 'projectile' | 'spring';

  const canvas = document.getElementById('sim-canvas') as HTMLCanvasElement;
  const ctx = canvas.getContext('2d')!;

  const dpr = window.devicePixelRatio || 1;
  const W = canvas.clientWidth;
  const H = canvas.clientHeight;
  canvas.width = W * dpr;
  canvas.height = H * dpr;
  ctx.scale(dpr, dpr);

  const $ = (id: string) => document.getElementById(id)!;

  // ===== State =====
  let sim: SimType = 'pendulum';
  let playing = false;
  let speed = 1;
  let lastTs = performance.now();
  let accumulator = 0;
  const DT = 1 / 120;

  // Pendulum
  let pAngle = Math.PI / 4;
  let pAngVel = 0;
  let pLen = 2;
  let pGrav = 9.8;
  let pInitAngle = Math.PI / 4;
  let pTrail: { x: number; y: number }[] = [];

  // Projectile
  let prX = 0;
  let prY = 0;
  let prVx = 0;
  let prVy = 0;
  let prAngle = 45;
  let prV0 = 20;
  let prGrav = 9.8;
  let prTime = 0;
  let prLanded = false;
  let prTrail: { x: number; y: number }[] = [];

  // Spring
  let sX = 1;
  let sV = 0;
  let sK = 10;
  let sM = 1;
  let sInitX = 1;

  // ===== Reset Functions =====
  const resetPendulum = () => {
    pAngle = pInitAngle;
    pAngVel = 0;
    pTrail = [];
  };

  const resetProjectile = () => {
    const rad = prAngle * Math.PI / 180;
    prX = 0;
    prY = 0;
    prVx = prV0 * Math.cos(rad);
    prVy = prV0 * Math.sin(rad);
    prTime = 0;
    prLanded = false;
    prTrail = [];
  };

  const resetSpring = () => {
    sX = sInitX;
    sV = 0;
  };

  const resetCurrent = () => {
    if (sim === 'pendulum') resetPendulum();
    else if (sim === 'projectile') resetProjectile();
    else resetSpring();
  };

  // ===== Physics Update (Symplectic Euler) =====
  const updatePhysics = (dt: number) => {
    if (sim === 'pendulum') {
      const angAcc = -(pGrav / pLen) * Math.sin(pAngle);
      pAngVel += angAcc * dt;
      pAngle += pAngVel * dt;

      const pivotX = W / 2;
      const pivotY = 80;
      const s = Math.min(260, (H - 130)) / (pLen * 1.15);
      pTrail.push({
        x: pivotX + pLen * s * Math.sin(pAngle),
        y: pivotY + pLen * s * Math.cos(pAngle),
      });
      if (pTrail.length > 350) pTrail.shift();
    } else if (sim === 'projectile') {
      if (prLanded) return;
      prVy -= prGrav * dt;
      prX += prVx * dt;
      prY += prVy * dt;
      prTime += dt;
      if (prY <= 0 && prTime > 0.02) {
        prY = 0;
        prVy = 0;
        prVx = 0;
        prLanded = true;
      }
      prTrail.push({ x: prX, y: Math.max(0, prY) });
    } else {
      const acc = -(sK / sM) * sX;
      sV += acc * dt;
      sX += sV * dt;
    }
  };

  // ===== Canvas Helpers =====
  const clear = () => {
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, 0, W, H);
  };

  const drawDashedLine = (
    x1: number, y1: number, x2: number, y2: number,
    color: string, width: number = 1,
  ) => {
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.setLineDash([4, 4]);
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();
    ctx.setLineDash([]);
  };

  const drawArrow = (
    x1: number, y1: number, x2: number, y2: number,
    color: string, width: number = 2,
  ) => {
    const dx = x2 - x1;
    const dy = y2 - y1;
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len < 2) return;
    const ux = dx / len;
    const uy = dy / len;

    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    const headLen = Math.min(10, len * 0.3);
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.moveTo(x2, y2);
    ctx.lineTo(x2 - ux * headLen - uy * headLen * 0.4, y2 - uy * headLen + ux * headLen * 0.4);
    ctx.lineTo(x2 - ux * headLen + uy * headLen * 0.4, y2 - uy * headLen - ux * headLen * 0.4);
    ctx.closePath();
    ctx.fill();
  };

  // ===== Pendulum Renderer =====
  const renderPendulum = () => {
    const pivotX = W / 2;
    const pivotY = 80;
    const s = Math.min(260, (H - 130)) / (pLen * 1.15);
    const bobX = pivotX + pLen * s * Math.sin(pAngle);
    const bobY = pivotY + pLen * s * Math.cos(pAngle);

    // Vertical reference
    drawDashedLine(pivotX, pivotY, pivotX, pivotY + pLen * s + 25, '#334155');

    // Trail
    if (pTrail.length > 1) {
      for (let i = 1; i < pTrail.length; i++) {
        const alpha = (i / pTrail.length) * 0.35;
        ctx.strokeStyle = `rgba(251, 191, 36, ${alpha})`;
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.moveTo(pTrail[i - 1].x, pTrail[i - 1].y);
        ctx.lineTo(pTrail[i].x, pTrail[i].y);
        ctx.stroke();
      }
    }

    // Angle arc
    if (Math.abs(pAngle) > 0.02) {
      ctx.strokeStyle = 'rgba(96, 165, 250, 0.5)';
      ctx.lineWidth = 2;
      ctx.beginPath();
      const arcR = 38;
      const vertAngle = Math.PI / 2;
      if (pAngle > 0) {
        ctx.arc(pivotX, pivotY, arcR, vertAngle - pAngle, vertAngle);
      } else {
        ctx.arc(pivotX, pivotY, arcR, vertAngle, vertAngle - pAngle);
      }
      ctx.stroke();

      ctx.fillStyle = '#60a5fa';
      ctx.font = '12px monospace';
      ctx.textAlign = 'center';
      const labelAngle = vertAngle - pAngle / 2;
      ctx.fillText(
        `${(pAngle * 180 / Math.PI).toFixed(1)}\u00B0`,
        pivotX + (arcR + 14) * Math.cos(labelAngle),
        pivotY + (arcR + 14) * Math.sin(labelAngle) + 4,
      );
    }

    // Rod
    ctx.strokeStyle = '#cbd5e1';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(pivotX, pivotY);
    ctx.lineTo(bobX, bobY);
    ctx.stroke();

    // Pivot mount
    ctx.fillStyle = '#64748b';
    ctx.fillRect(pivotX - 30, pivotY - 8, 60, 8);
    ctx.fillStyle = '#94a3b8';
    ctx.beginPath();
    ctx.arc(pivotX, pivotY, 5, 0, Math.PI * 2);
    ctx.fill();

    // Bob
    ctx.fillStyle = '#f59e0b';
    ctx.beginPath();
    ctx.arc(bobX, bobY, 15, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = '#d97706';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Gravity vector on bob
    drawArrow(bobX, bobY + 15, bobX, bobY + 50, '#ef4444', 2);
    ctx.fillStyle = '#ef4444';
    ctx.font = '11px monospace';
    ctx.textAlign = 'left';
    ctx.fillText('mg', bobX + 6, bobY + 45);

    // Info overlay
    ctx.fillStyle = '#94a3b8';
    ctx.font = '13px monospace';
    ctx.textAlign = 'left';
    ctx.fillText(`L = ${pLen.toFixed(1)} m`, 16, 24);
    ctx.fillText(`g = ${pGrav.toFixed(1)} m/s\u00B2`, 16, 42);
    const period = 2 * Math.PI * Math.sqrt(pLen / pGrav);
    ctx.fillText(`T \u2248 ${period.toFixed(2)} s`, 16, 60);

    // Energy bar
    const maxE = pGrav * pLen * (1 - Math.cos(pInitAngle));
    const pe = pGrav * pLen * (1 - Math.cos(pAngle));
    const ke = 0.5 * pLen * pLen * pAngVel * pAngVel;
    const barW = 140;
    const barH = 8;
    const barX = W - barW - 20;
    const barY = 20;
    ctx.fillStyle = '#334155';
    ctx.fillRect(barX, barY, barW, barH);
    const total = ke + pe;
    if (total > 0.001) {
      const keW = (ke / total) * barW;
      ctx.fillStyle = '#3b82f6';
      ctx.fillRect(barX, barY, keW, barH);
      ctx.fillStyle = '#ef4444';
      ctx.fillRect(barX + keW, barY, barW - keW, barH);
    }
    ctx.fillStyle = '#64748b';
    ctx.font = '10px monospace';
    ctx.textAlign = 'left';
    ctx.fillText('KE', barX, barY + 22);
    ctx.fillStyle = '#3b82f6';
    ctx.fillRect(barX + 18, barY + 15, 8, 8);
    ctx.fillStyle = '#64748b';
    ctx.fillText('PE', barX + 32, barY + 22);
    ctx.fillStyle = '#ef4444';
    ctx.fillRect(barX + 50, barY + 15, 8, 8);
    ctx.fillStyle = '#94a3b8';
    ctx.fillText(`E = ${total.toFixed(2)} J/kg`, barX + 66, barY + 22);
  };

  // ===== Projectile Renderer =====
  const renderProjectile = () => {
    const groundY = H - 50;
    const launchX = 70;
    const angleRad = prAngle * Math.PI / 180;
    const maxRange = (prV0 * prV0 * Math.sin(2 * angleRad)) / prGrav;
    const maxH = (prV0 * prV0 * Math.pow(Math.sin(angleRad), 2)) / (2 * prGrav);
    const scaleX = (W - 120) / Math.max(maxRange * 1.1, 1);
    const scaleY = (groundY - 60) / Math.max(maxH * 1.3, 1);
    const scale = Math.min(scaleX, scaleY, 20);

    // Ground
    ctx.fillStyle = '#162317';
    ctx.fillRect(0, groundY, W, H - groundY);
    ctx.strokeStyle = '#22c55e';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(0, groundY);
    ctx.lineTo(W, groundY);
    ctx.stroke();

    // Grid
    ctx.strokeStyle = '#1e3328';
    ctx.lineWidth = 0.5;
    const gridStep = Math.pow(10, Math.floor(Math.log10(Math.max(maxRange / 5, 1))));
    for (let gx = gridStep; launchX + gx * scale < W - 20; gx += gridStep) {
      const sx = launchX + gx * scale;
      ctx.beginPath();
      ctx.moveTo(sx, 20);
      ctx.lineTo(sx, groundY);
      ctx.stroke();
      ctx.fillStyle = '#475569';
      ctx.font = '10px monospace';
      ctx.textAlign = 'center';
      ctx.fillText(`${gx.toFixed(0)}m`, sx, groundY + 16);
    }
    const gridStepY = Math.pow(10, Math.floor(Math.log10(Math.max(maxH / 4, 1))));
    for (let gy = gridStepY; groundY - gy * scale > 30; gy += gridStepY) {
      const sy = groundY - gy * scale;
      ctx.beginPath();
      ctx.moveTo(launchX, sy);
      ctx.lineTo(W - 20, sy);
      ctx.stroke();
      ctx.fillStyle = '#475569';
      ctx.font = '10px monospace';
      ctx.textAlign = 'right';
      ctx.fillText(`${gy.toFixed(0)}m`, launchX - 6, sy + 4);
    }

    // Ideal trajectory (dashed)
    const totalFlight = (2 * prV0 * Math.sin(angleRad)) / prGrav;
    ctx.strokeStyle = '#475569';
    ctx.lineWidth = 1;
    ctx.setLineDash([4, 4]);
    ctx.beginPath();
    let first = true;
    for (let t = 0; t <= totalFlight; t += totalFlight / 80) {
      const ix = prV0 * Math.cos(angleRad) * t;
      const iy = prV0 * Math.sin(angleRad) * t - 0.5 * prGrav * t * t;
      const sx = launchX + ix * scale;
      const sy = groundY - Math.max(0, iy) * scale;
      if (first) { ctx.moveTo(sx, sy); first = false; }
      else ctx.lineTo(sx, sy);
    }
    ctx.stroke();
    ctx.setLineDash([]);

    // Actual trail
    if (prTrail.length > 1) {
      ctx.strokeStyle = '#f97316';
      ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.moveTo(launchX + prTrail[0].x * scale, groundY - prTrail[0].y * scale);
      for (let i = 1; i < prTrail.length; i++) {
        ctx.lineTo(launchX + prTrail[i].x * scale, groundY - prTrail[i].y * scale);
      }
      ctx.stroke();
    }

    // Launch angle indicator
    drawDashedLine(
      launchX, groundY,
      launchX + 55 * Math.cos(angleRad), groundY - 55 * Math.sin(angleRad),
      '#64748b', 1.5,
    );
    // Angle arc
    ctx.strokeStyle = '#60a5fa80';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.arc(launchX, groundY, 30, -angleRad, 0);
    ctx.stroke();
    ctx.fillStyle = '#60a5fa';
    ctx.font = '11px monospace';
    ctx.textAlign = 'left';
    ctx.fillText(`${prAngle}\u00B0`, launchX + 34, groundY - 8);

    // Projectile
    const sx = launchX + prX * scale;
    const sy = groundY - Math.max(0, prY) * scale;
    ctx.fillStyle = '#ef4444';
    ctx.beginPath();
    ctx.arc(sx, sy, 7, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = '#dc2626';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Velocity vector
    if (!prLanded && (Math.abs(prVx) > 0.1 || Math.abs(prVy) > 0.1)) {
      const vScale = 2.5;
      drawArrow(sx, sy, sx + prVx * vScale, sy - prVy * vScale, '#60a5fa', 1.5);
    }

    // Gravity arrow
    if (!prLanded) {
      drawArrow(sx, sy + 10, sx, sy + 40, '#ef4444', 1.5);
      ctx.fillStyle = '#ef4444';
      ctx.font = '10px monospace';
      ctx.textAlign = 'left';
      ctx.fillText('g', sx + 6, sy + 35);
    }

    // Info overlay
    ctx.fillStyle = '#94a3b8';
    ctx.font = '13px monospace';
    ctx.textAlign = 'left';
    ctx.fillText(`\u03B8 = ${prAngle}\u00B0`, 16, 24);
    ctx.fillText(`v\u2080 = ${prV0.toFixed(1)} m/s`, 16, 42);
    ctx.fillText(`t = ${prTime.toFixed(2)} s`, 16, 60);
    if (prLanded) {
      ctx.fillStyle = '#22c55e';
      ctx.font = '14px monospace';
      ctx.fillText(`Range: ${prX.toFixed(1)} m`, 16, 82);
      ctx.fillText(`Max H: ${((prV0 * Math.sin(angleRad)) ** 2 / (2 * prGrav)).toFixed(1)} m`, 16, 100);
    }
  };

  // ===== Spring Renderer =====
  const renderSpring = () => {
    const centerY = H / 2;
    const wallX = 55;
    const eqX = W * 0.38;
    const maxDisp = Math.max(sInitX, 3);
    const scale = Math.min(80, (W - eqX - 120) / maxDisp);
    const massX = eqX + sX * scale;
    const mW = 48;
    const mH = 48;

    // Floor
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(wallX, centerY + mH / 2 + 10);
    ctx.lineTo(W - 30, centerY + mH / 2 + 10);
    ctx.stroke();

    // Wall
    ctx.fillStyle = '#475569';
    ctx.fillRect(wallX - 16, centerY - 65, 16, 130);
    ctx.strokeStyle = '#64748b';
    ctx.lineWidth = 1;
    for (let i = -55; i < 70; i += 13) {
      ctx.beginPath();
      ctx.moveTo(wallX - 16, centerY + i);
      ctx.lineTo(wallX - 28, centerY + i + 13);
      ctx.stroke();
    }

    // Spring zigzag
    const springStart = wallX;
    const springEnd = massX - mW / 2;
    const numCoils = 18;
    const coilLen = springEnd - springStart;
    const straight = Math.max(coilLen * 0.06, 5);
    const coilRegion = coilLen - 2 * straight;

    ctx.strokeStyle = '#94a3b8';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(springStart, centerY);
    ctx.lineTo(springStart + straight, centerY);
    if (coilRegion > 10) {
      const segW = coilRegion / numCoils;
      const amp = Math.min(16, Math.max(6, 16 * (coilRegion / (W * 0.25))));
      for (let i = 0; i < numCoils; i++) {
        const cx = springStart + straight + segW * (i + 0.5);
        const cy = centerY + (i % 2 === 0 ? -amp : amp);
        ctx.lineTo(cx, cy);
      }
    }
    ctx.lineTo(springEnd, centerY);
    ctx.stroke();

    // Equilibrium reference
    drawDashedLine(eqX, centerY - 85, eqX, centerY + 85, '#334155');
    ctx.fillStyle = '#475569';
    ctx.font = '11px monospace';
    ctx.textAlign = 'center';
    ctx.fillText('x = 0', eqX, centerY + 100);

    // Displacement arrow
    if (Math.abs(sX) > 0.02) {
      const arrowY = centerY + mH / 2 + 30;
      drawArrow(eqX, arrowY, massX, arrowY, '#f59e0b', 2);
      ctx.fillStyle = '#f59e0b';
      ctx.font = '11px monospace';
      ctx.textAlign = 'center';
      ctx.fillText(`x = ${sX.toFixed(2)} m`, (eqX + massX) / 2, arrowY - 8);
    }

    // Force arrow on mass
    const force = -sK * sX;
    if (Math.abs(force) > 0.3) {
      const fScale = Math.min(2, 60 / Math.abs(force));
      const forceY = centerY - mH / 2 - 18;
      drawArrow(massX, forceY, massX + force * fScale, forceY, '#ef4444', 2.5);
      ctx.fillStyle = '#ef4444';
      ctx.font = '11px monospace';
      ctx.textAlign = 'center';
      ctx.fillText(`F = ${force.toFixed(1)} N`, massX + force * fScale * 0.5, forceY - 10);
    }

    // Mass block
    ctx.fillStyle = '#3b82f6';
    const radius = 6;
    const mx = massX - mW / 2;
    const my = centerY - mH / 2;
    ctx.beginPath();
    ctx.moveTo(mx + radius, my);
    ctx.lineTo(mx + mW - radius, my);
    ctx.quadraticCurveTo(mx + mW, my, mx + mW, my + radius);
    ctx.lineTo(mx + mW, my + mH - radius);
    ctx.quadraticCurveTo(mx + mW, my + mH, mx + mW - radius, my + mH);
    ctx.lineTo(mx + radius, my + mH);
    ctx.quadraticCurveTo(mx, my + mH, mx, my + mH - radius);
    ctx.lineTo(mx, my + radius);
    ctx.quadraticCurveTo(mx, my, mx + radius, my);
    ctx.closePath();
    ctx.fill();
    ctx.strokeStyle = '#2563eb';
    ctx.lineWidth = 2;
    ctx.stroke();

    ctx.fillStyle = '#e2e8f0';
    ctx.font = '12px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(`${sM.toFixed(1)}`, massX, centerY + 2);
    ctx.font = '9px monospace';
    ctx.fillText('kg', massX, centerY + 14);

    // Energy bar
    const pe = 0.5 * sK * sX * sX;
    const ke = 0.5 * sM * sV * sV;
    const total = pe + ke;
    const barW = 140;
    const barH = 8;
    const barX = W - barW - 20;
    const barY = 20;
    ctx.fillStyle = '#334155';
    ctx.fillRect(barX, barY, barW, barH);
    if (total > 0.001) {
      const keW = (ke / total) * barW;
      ctx.fillStyle = '#3b82f6';
      ctx.fillRect(barX, barY, keW, barH);
      ctx.fillStyle = '#ef4444';
      ctx.fillRect(barX + keW, barY, barW - keW, barH);
    }
    ctx.fillStyle = '#64748b';
    ctx.font = '10px monospace';
    ctx.textAlign = 'left';
    ctx.fillText('KE', barX, barY + 22);
    ctx.fillStyle = '#3b82f6';
    ctx.fillRect(barX + 18, barY + 15, 8, 8);
    ctx.fillStyle = '#64748b';
    ctx.fillText('PE', barX + 32, barY + 22);
    ctx.fillStyle = '#ef4444';
    ctx.fillRect(barX + 50, barY + 15, 8, 8);
    ctx.fillStyle = '#94a3b8';
    ctx.fillText(`E = ${total.toFixed(2)} J`, barX + 66, barY + 22);

    // Info
    ctx.fillStyle = '#94a3b8';
    ctx.font = '13px monospace';
    ctx.textAlign = 'left';
    ctx.fillText(`k = ${sK.toFixed(1)} N/m`, 16, 24);
    ctx.fillText(`m = ${sM.toFixed(1)} kg`, 16, 42);
    const omega = Math.sqrt(sK / sM);
    ctx.fillText(`\u03C9 = ${omega.toFixed(2)} rad/s`, 16, 60);
    ctx.fillText(`T = ${(2 * Math.PI / omega).toFixed(2)} s`, 16, 78);
  };

  // ===== Readout Updates =====
  const updateReadouts = () => {
    if (sim === 'pendulum') {
      const x = pLen * Math.sin(pAngle);
      const y = -pLen * Math.cos(pAngle);
      const vTan = pLen * pAngVel;
      const vx = vTan * Math.cos(pAngle);
      const vy = vTan * Math.sin(pAngle);
      const angAcc = -(pGrav / pLen) * Math.sin(pAngle);
      const aTan = pLen * angAcc;
      const aCen = pLen * pAngVel * pAngVel;
      $('pos-x').textContent = `x: ${x.toFixed(3)} m`;
      $('pos-y').textContent = `y: ${y.toFixed(3)} m`;
      $('vel-x').textContent = `vx: ${vx.toFixed(3)} m/s`;
      $('vel-y').textContent = `vy: ${vy.toFixed(3)} m/s`;
      $('acc-x').textContent = `a\u209C: ${aTan.toFixed(3)} m/s\u00B2`;
      $('acc-y').textContent = `a\u1D9C: ${aCen.toFixed(3)} m/s\u00B2`;
    } else if (sim === 'projectile') {
      $('pos-x').textContent = `x: ${prX.toFixed(3)} m`;
      $('pos-y').textContent = `y: ${Math.max(0, prY).toFixed(3)} m`;
      $('vel-x').textContent = `vx: ${prVx.toFixed(3)} m/s`;
      $('vel-y').textContent = `vy: ${prVy.toFixed(3)} m/s`;
      $('acc-x').textContent = `ax: 0.000 m/s\u00B2`;
      $('acc-y').textContent = `ay: ${(-prGrav).toFixed(3)} m/s\u00B2`;
    } else {
      const acc = -(sK / sM) * sX;
      const energy = 0.5 * sK * sX * sX + 0.5 * sM * sV * sV;
      $('pos-x').textContent = `x: ${sX.toFixed(3)} m`;
      $('pos-y').textContent = `F: ${(-sK * sX).toFixed(3)} N`;
      $('vel-x').textContent = `v: ${sV.toFixed(3)} m/s`;
      $('vel-y').textContent = `|v|: ${Math.abs(sV).toFixed(3)} m/s`;
      $('acc-x').textContent = `a: ${acc.toFixed(3)} m/s\u00B2`;
      $('acc-y').textContent = `E: ${energy.toFixed(3)} J`;
    }
  };

  // ===== Animation Loop =====
  const loop = (ts: number) => {
    const frameTime = Math.min((ts - lastTs) / 1000, 0.05);
    lastTs = ts;

    if (playing) {
      accumulator += frameTime * speed;
      while (accumulator >= DT) {
        updatePhysics(DT);
        accumulator -= DT;
      }
    }

    clear();
    if (sim === 'pendulum') renderPendulum();
    else if (sim === 'projectile') renderProjectile();
    else renderSpring();
    updateReadouts();

    requestAnimationFrame(loop);
  };

  // ===== Controls =====
  const bindSlider = (
    sliderId: string,
    labelId: string,
    onChange: (v: number) => void,
    decimals: number = 1,
  ) => {
    const el = $(sliderId) as HTMLInputElement;
    el.addEventListener('input', () => {
      const v = parseFloat(el.value);
      $(labelId).textContent = v.toFixed(decimals);
      onChange(v);
      resetCurrent();
    });
  };

  // Tab switching
  document.querySelectorAll('.tab').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tab').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      const newSim = (btn as HTMLElement).dataset.sim as SimType;
      sim = newSim;

      document.querySelectorAll('.param-group').forEach(g =>
        (g as HTMLElement).style.display = 'none',
      );
      $(`params-${newSim}`).style.display = 'flex';

      document.querySelectorAll('.sim-desc').forEach(d =>
        (d as HTMLElement).style.display = 'none',
      );
      $(`desc-${newSim}`).style.display = 'block';

      resetCurrent();
    });
  });

  // Playback
  $('btn-play').addEventListener('click', () => { playing = true; });
  $('btn-pause').addEventListener('click', () => { playing = false; });
  $('btn-reset').addEventListener('click', () => {
    playing = false;
    resetCurrent();
  });

  // Speed
  const speedEl = $('slider-speed') as HTMLInputElement;
  speedEl.addEventListener('input', () => {
    speed = parseFloat(speedEl.value);
    $('lbl-speed').textContent = speed.toFixed(1);
  });

  // Pendulum sliders
  bindSlider('slider-length', 'lbl-length', v => { pLen = v; });
  bindSlider('slider-gravity-p', 'lbl-gravity-p', v => { pGrav = v; });
  bindSlider('slider-angle-p', 'lbl-angle-p', v => { pInitAngle = v * Math.PI / 180; }, 0);

  // Projectile sliders
  bindSlider('slider-angle-pr', 'lbl-angle-pr', v => { prAngle = v; }, 0);
  bindSlider('slider-vel-pr', 'lbl-vel-pr', v => { prV0 = v; });
  bindSlider('slider-gravity-pr', 'lbl-gravity-pr', v => { prGrav = v; });

  // Spring sliders
  bindSlider('slider-k', 'lbl-k', v => { sK = v; });
  bindSlider('slider-mass', 'lbl-mass', v => { sM = v; });
  bindSlider('slider-disp', 'lbl-disp', v => { sInitX = v; });

  // ===== Init =====
  resetPendulum();
  resetProjectile();
  resetSpring();
  requestAnimationFrame(loop);
})();

