import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringMassParams,
  SpringMassState,
  Vec2,
} from './types'

export const initPendulum = (params: PendulumParams): PendulumState => {
  const { length, initialAngle } = params
  return {
    angle: initialAngle,
    angularVelocity: 0,
    angularAcceleration: 0,
    position: {
      x: length * Math.sin(initialAngle),
      y: -length * Math.cos(initialAngle),
    },
    velocity: { x: 0, y: 0 },
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number
): PendulumState => {
  const { length, gravity, damping } = params
  const angularAcceleration =
    -(gravity / length) * Math.sin(state.angle) - damping * state.angularVelocity
  const angularVelocity = state.angularVelocity + angularAcceleration * dt
  const angle = state.angle + angularVelocity * dt
  const position: Vec2 = {
    x: length * Math.sin(angle),
    y: -length * Math.cos(angle),
  }
  const tangentialSpeed = length * angularVelocity
  const velocity: Vec2 = {
    x: tangentialSpeed * Math.cos(angle),
    y: tangentialSpeed * Math.sin(angle),
  }
  return { angle, angularVelocity, angularAcceleration, position, velocity }
}

export const initProjectile = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  return {
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(angleRad),
      y: params.initialVelocity * Math.sin(angleRad),
    },
    acceleration: { x: 0, y: -params.gravity },
    trajectory: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number
): ProjectileState => {
  if (state.landed) return state

  const acceleration: Vec2 = { x: 0, y: -params.gravity }
  const velocity: Vec2 = {
    x: state.velocity.x + acceleration.x * dt,
    y: state.velocity.y + acceleration.y * dt,
  }
  const position: Vec2 = {
    x: state.position.x + velocity.x * dt,
    y: state.position.y + velocity.y * dt,
  }

  const landed = position.y < 0 && state.position.y >= 0 && state.trajectory.length > 1
  if (landed) {
    position.y = 0
    const tGround = state.position.y / (state.position.y - position.y + state.position.y)
    position.x = state.position.x + velocity.x * dt * tGround
  }

  const trajectory = [...state.trajectory, { x: position.x, y: position.y }]
  return { position, velocity, acceleration, trajectory, landed }
}

export const initSpringMass = (params: SpringMassParams): SpringMassState => ({
  displacement: params.initialDisplacement,
  velocity: 0,
  acceleration: -(params.springConstant / params.mass) * params.initialDisplacement,
})

export const stepSpringMass = (
  state: SpringMassState,
  params: SpringMassParams,
  dt: number
): SpringMassState => {
  const { springConstant, mass, damping } = params
  const acceleration =
    -(springConstant / mass) * state.displacement - damping * state.velocity
  const velocity = state.velocity + acceleration * dt
  const displacement = state.displacement + velocity * dt
  return { displacement, velocity, acceleration }
}

