  const acc = -(p.springConstant / p.mass) * s.disp - p.damping * s.vel;
  const vel = s.vel + acc * dt;
  const disp = s.disp + vel * dt;
  return { disp, vel, acc };
};

const resetSim = (name) => {
  const sim = SIMS[name];
  if (name === 'pendulum') sim.state = initPendulum(sim.params);
  else if (name === 'projectile') sim.state = initProjectile(sim.params);
  else sim.state = initSpring(sim.params);
};

const resetAll = () => { Object.keys(SIMS).forEach(resetSim); };
resetAll();

const drawPendulum = (ctx, w, h) => {
  const s = SIMS.pendulum.state;
  const p = SIMS.pendulum.params;
  const scale = 120;
  const ox = w / 2, oy = h * 0.25;

  // pivot
  ctx.fillStyle = '#3b5998';
  ctx.fillRect(ox - 30, oy - 3, 60, 6);

  // rod
  const bx = ox + s.pos.x * scale;
  const by = oy - s.pos.y * scale;
  ctx.strokeStyle = '#4a6a8a';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(ox, oy);
  ctx.lineTo(bx, by);
  ctx.stroke();

  // arc trail
  ctx.strokeStyle = 'rgba(96, 165, 250, 0.15)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.arc(ox, oy, p.length * scale, Math.PI / 2 - 0.8, Math.PI / 2 + 0.8);
  ctx.stroke();

  // bob
  const gradient = ctx.createRadialGradient(bx, by, 0, bx, by, 18);
  gradient.addColorStop(0, '#7db4fa');
  gradient.addColorStop(1, '#2563eb');
  ctx.fillStyle = gradient;
  ctx.beginPath();
  ctx.arc(bx, by, 16, 0, Math.PI * 2);
  ctx.fill();

  // velocity vector
  const vScale = 25;
  ctx.strokeStyle = '#f59e0b';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(bx, by);
  ctx.lineTo(bx + s.vel.x * vScale, by - s.vel.y * vScale);
  ctx.stroke();
  const vMag = Math.sqrt(s.vel.x ** 2 + s.vel.y ** 2);
  if (vMag > 0.01) {
    const aLen = 6;
    const vAngle = Math.atan2(-s.vel.y, s.vel.x);
    ctx.beginPath();
    ctx.moveTo(bx + s.vel.x * vScale, by - s.vel.y * vScale);
    ctx.lineTo(bx + s.vel.x * vScale - aLen * Math.cos(vAngle - 0.4), by - s.vel.y * vScale + aLen * Math.sin(vAngle - 0.4));
    ctx.moveTo(bx + s.vel.x * vScale, by - s.vel.y * vScale);
    ctx.lineTo(bx + s.vel.x * vScale - aLen * Math.cos(vAngle + 0.4), by - s.vel.y * vScale + aLen * Math.sin(vAngle + 0.4));
    ctx.stroke();
  }

  // angle indicator
  ctx.fillStyle = '#6b7a8d';
  ctx.font = '12px JetBrains Mono, monospace';
  ctx.fillText('\\u03b8 = ' + (s.angle * 180 / Math.PI).toFixed(1) + '\\u00b0', ox + 35, oy + 18);
};

const drawProjectile = (ctx, w, h) => {
  const s = SIMS.projectile.state;
  const p = SIMS.projectile.params;

  // calculate scale to fit trajectory
  const maxRange = (p.initialVelocity ** 2 * Math.sin(2 * p.angle * Math.PI / 180)) / p.gravity;
  const maxHeight = (p.initialVelocity ** 2 * Math.sin(p.angle * Math.PI / 180) ** 2) / (2 * p.gravity);
  const scaleX = (w - 100) / Math.max(maxRange, 1);
  const scaleY = (h - 120) / Math.max(maxHeight, 1);
  const scale = Math.min(scaleX, scaleY, 8);
  const ox = 50, gy = h - 50;

  // ground line
  ctx.strokeStyle = '#1e3a3a';
  ctx.lineWidth = 1;
  ctx.setLineDash([5, 5]);
  ctx.beginPath();
  ctx.moveTo(0, gy);
  ctx.lineTo(w, gy);
  ctx.stroke();
  ctx.setLineDash([]);

  // grid
  ctx.strokeStyle = 'rgba(30, 42, 58, 0.5)';
  ctx.lineWidth = 0.5;
  const gridStep = Math.max(Math.floor(maxRange / 8), 5);
  for (let gx = gridStep; gx * scale < w - 50; gx += gridStep) {
    ctx.beginPath();
    ctx.moveTo(ox + gx * scale, gy);
    ctx.lineTo(ox + gx * scale, gy - 5);
    ctx.stroke();
    ctx.fillStyle = '#4a5568';
    ctx.font = '10px sans-serif';
    ctx.fillText(gx + 'm', ox + gx * scale - 8, gy + 15);
  }

  // trajectory path
  if (s.trail.length > 1) {
    ctx.strokeStyle = 'rgba(96, 165, 250, 0.4)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(ox + s.trail[0].x * scale, gy - s.trail[0].y * scale);
    for (let i = 1; i < s.trail.length; i++) {
      ctx.lineTo(ox + s.trail[i].x * scale, gy - s.trail[i].y * scale);
    }
    ctx.stroke();

    // dotted trail
    for (let i = 0; i < s.trail.length; i += Math.max(1, Math.floor(s.trail.length / 30))) {
      ctx.fillStyle = 'rgba(96, 165, 250, 0.3)';
      ctx.beginPath();
      ctx.arc(ox + s.trail[i].x * scale, gy - s.trail[i].y * scale, 2, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  // projectile
  const px = ox + s.pos.x * scale;
  const py = gy - s.pos.y * scale;
  const gradient = ctx.createRadialGradient(px, py, 0, px, py, 10);
  gradient.addColorStop(0, '#fbbf24');
  gradient.addColorStop(1, '#d97706');
  ctx.fillStyle = gradient;
  ctx.beginPath();
  ctx.arc(px, py, 8, 0, Math.PI * 2);
  ctx.fill();

  // velocity vector
  const vScale = 3;
  ctx.strokeStyle = '#10b981';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(px, py);
  ctx.lineTo(px + s.vel.x * vScale, py - s.vel.y * vScale);
  ctx.stroke();

  // launch angle arc
  if (s.trail.length < 3) {
    ctx.strokeStyle = 'rgba(251, 191, 36, 0.5)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.arc(ox, gy, 40, -p.angle * Math.PI / 180, 0);
    ctx.stroke();
    ctx.fillStyle = '#fbbf24';
    ctx.font = '11px sans-serif';
    ctx.fillText(p.angle + '\\u00b0', ox + 45, gy - 10);
  }
};

const drawSpring = (ctx, w, h) => {
  const s = SIMS.springMass.state;
  const p = SIMS.springMass.params;
  const cx = w / 2, cy = h / 2;
  const scale = 80;
  const wallX = cx - 200;
  const massX = cx + s.disp * scale;

  // wall
  ctx.fillStyle = '#2a3a50';
  ctx.fillRect(wallX - 8, cy - 60, 8, 120);
  for (let i = 0; i < 6; i++) {
    ctx.strokeStyle = '#3b5068';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(wallX - 8, cy - 60 + i * 24);
    ctx.lineTo(wallX - 20, cy - 48 + i * 24);
    ctx.stroke();
  }

  // spring coils
  const springLen = massX - wallX - 25;
  const coils = 12;
  const coilW = springLen / coils;
  const coilH = 18;
  ctx.strokeStyle = '#60a5fa';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(wallX, cy);
  for (let i = 0; i < coils; i++) {
    const x1 = wallX + i * coilW + coilW * 0.25;
    const x2 = wallX + i * coilW + coilW * 0.75;
    ctx.lineTo(x1, cy - coilH);
    ctx.lineTo(x2, cy + coilH);
  }
  ctx.lineTo(massX - 25, cy);
  ctx.stroke();

  // equilibrium line
  ctx.strokeStyle = 'rgba(96, 165, 250, 0.2)';
  ctx.setLineDash([4, 4]);
  ctx.beginPath();
  ctx.moveTo(cx, cy - 50);
  ctx.lineTo(cx, cy + 50);
  ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle = '#4a5568';
  ctx.font = '10px sans-serif';
  ctx.fillText('x=0', cx + 4, cy + 60);

  // mass block
  const gradient = ctx.createLinearGradient(massX - 25, cy - 25, massX + 25, cy + 25);
  gradient.addColorStop(0, '#7c3aed');
  gradient.addColorStop(1, '#4c1d95');
  ctx.fillStyle = gradient;
  ctx.beginPath();
  ctx.roundRect(massX - 25, cy - 25, 50, 50, 6);
  ctx.fill();
  ctx.fillStyle = '#e0e6f0';
  ctx.font = 'bold 14px sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText(p.mass + 'kg', massX, cy + 5);
  ctx.textAlign = 'start';

  // displacement indicator
  if (Math.abs(s.disp) > 0.01) {
    ctx.strokeStyle = '#f59e0b';
    ctx.lineWidth = 1.5;
    const arrY = cy + 45;
    ctx.beginPath();
    ctx.moveTo(cx, arrY);
    ctx.lineTo(massX, arrY);
    ctx.stroke();
    ctx.beginPath();
    const dir = s.disp > 0 ? -1 : 1;
    ctx.moveTo(massX, arrY);
    ctx.lineTo(massX + dir * 6, arrY - 4);
    ctx.moveTo(massX, arrY);
    ctx.lineTo(massX + dir * 6, arrY + 4);
    ctx.stroke();
    ctx.fillStyle = '#f59e0b';
    ctx.font = '11px JetBrains Mono, monospace';
    ctx.textAlign = 'center';
    ctx.fillText('x=' + s.disp.toFixed(2) + 'm', (cx + massX) / 2, arrY - 8);
    ctx.textAlign = 'start';
  }

  // force arrow
  const force = -p.springConstant * s.disp;
  const fScale = 2;
  if (Math.abs(force) > 0.5) {
    ctx.strokeStyle = '#ef4444';
    ctx.lineWidth = 2.5;
    ctx.beginPath();
    ctx.moveTo(massX, cy);
    ctx.lineTo(massX + force * fScale, cy);
    ctx.stroke();
    const fDir = force > 0 ? -1 : 1;
    ctx.beginPath();
    ctx.moveTo(massX + force * fScale, cy);
    ctx.lineTo(massX + force * fScale + fDir * 8, cy - 5);
    ctx.moveTo(massX + force * fScale, cy);
    ctx.lineTo(massX + force * fScale + fDir * 8, cy + 5);
    ctx.stroke();
    ctx.fillStyle = '#ef4444';
    ctx.font = '10px sans-serif';
    ctx.fillText('F', massX + force * fScale + (force > 0 ? 5 : -15), cy - 10);
  }
};

const updateReadout = () => {
  const el = (id) => document.getElementById(id);
  if (activeSim === 'pendulum') {
    const s = SIMS.pendulum.state;
    el('r0l').textContent = 'Angle (\\u03b8)';
    el('r0v').textContent = (s.angle * 180 / Math.PI).toFixed(2) + '\\u00b0';
    el('r1l').textContent = 'Angular Vel (\\u03c9)';
    el('r1v').textContent = s.av.toFixed(4) + ' rad/s';
    el('r2l').textContent = 'Angular Acc (\\u03b1)';
    el('r2v').textContent = s.aa.toFixed(4) + ' rad/s\\u00b2';
    el('r3l').textContent = 'Position X';
    el('r3v').textContent = s.pos.x.toFixed(3) + ' m';
    el('r4l').textContent = 'Position Y';
    el('r4v').textContent = s.pos.y.toFixed(3) + ' m';
    el('r5l').textContent = 'Speed';
    el('r5v').textContent = Math.sqrt(s.vel.x ** 2 + s.vel.y ** 2).toFixed(3) + ' m/s';
  } else if (activeSim === 'projectile') {
    const s = SIMS.projectile.state;
    el('r0l').textContent = 'Position X';
    el('r0v').textContent = s.pos.x.toFixed(2) + ' m';
    el('r1l').textContent = 'Position Y';
    el('r1v').textContent = s.pos.y.toFixed(2) + ' m';
    el('r2l').textContent = 'Velocity X';
    el('r2v').textContent = s.vel.x.toFixed(2) + ' m/s';
    el('r3l').textContent = 'Velocity Y';
    el('r3v').textContent = s.vel.y.toFixed(2) + ' m/s';
    el('r4l').textContent = 'Speed';
    el('r4v').textContent = Math.sqrt(s.vel.x ** 2 + s.vel.y ** 2).toFixed(2) + ' m/s';
    el('r5l').textContent = 'Accel Y';
    el('r5v').textContent = s.acc.y.toFixed(2) + ' m/s\\u00b2';
  } else {
    const s = SIMS.springMass.state;
    const p = SIMS.springMass.params;
    el('r0l').textContent = 'Displacement';
    el('r0v').textContent = s.disp.toFixed(4) + ' m';
    el('r1l').textContent = 'Velocity';
    el('r1v').textContent = s.vel.toFixed(4) + ' m/s';
    el('r2l').textContent = 'Acceleration';
    el('r2v').textContent = s.acc.toFixed(4) + ' m/s\\u00b2';
    el('r3l').textContent = 'Spring Force';
    el('r3v').textContent = (-p.springConstant * s.disp).toFixed(3) + ' N';
    el('r4l').textContent = 'KE';
    el('r4v').textContent = (0.5 * p.mass * s.vel ** 2).toFixed(3) + ' J';
    el('r5l').textContent = 'PE';
    el('r5v').textContent = (0.5 * p.springConstant * s.disp ** 2).toFixed(3) + ' J';
  }
};

const draw = () => {
  const canvas = document.getElementById('simCanvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();
  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  ctx.scale(dpr, dpr);
  ctx.clearRect(0, 0, rect.width, rect.height);

  // background grid
  ctx.strokeStyle = 'rgba(30, 42, 58, 0.3)';
  ctx.lineWidth = 0.5;
  for (let x = 0; x < rect.width; x += 40) {
    ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, rect.height); ctx.stroke();
  }
  for (let y = 0; y < rect.height; y += 40) {
    ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(rect.width, y); ctx.stroke();
  }

  if (activeSim === 'pendulum') drawPendulum(ctx, rect.width, rect.height);
  else if (activeSim === 'projectile') drawProjectile(ctx, rect.width, rect.height);
  else drawSpring(ctx, rect.width, rect.height);

  // sim label
  ctx.fillStyle = 'rgba(96, 165, 250, 0.3)';
  ctx.font = '11px sans-serif';
  const labels = { pendulum: 'Simple Pendulum', projectile: 'Projectile Motion', springMass: 'Spring-Mass System' };
  ctx.fillText(labels[activeSim], 12, 20);

  updateReadout();
};

const loop = (time) => {
  if (lastTime === 0) lastTime = time;
  const rawDt = (time - lastTime) / 1000;
  lastTime = time;

  if (running) {
    const dt = Math.min(rawDt, 0.05) * speed;
    const steps = 4;
    const subDt = dt / steps;
    for (let i = 0; i < steps; i++) {
      if (activeSim === 'pendulum') SIMS.pendulum.state = stepPendulum(SIMS.pendulum.state, SIMS.pendulum.params, subDt);
      else if (activeSim === 'projectile') SIMS.projectile.state = stepProjectile(SIMS.projectile.state, SIMS.projectile.params, subDt);
      else SIMS.springMass.state = stepSpring(SIMS.springMass.state, SIMS.springMass.params, subDt);
    }
  }

  draw();
  animId = requestAnimationFrame(loop);
};

const switchTab = (name) => {
  activeSim = name;
  $$('.sim-tab').forEach((t) => {
    t.style.background = t.dataset.sim === name ? '#141c2b' : '#0f1520';
    t.style.color = t.dataset.sim === name ? '#60a5fa' : '#6b7a8d';
    t.style.borderColor = t.dataset.sim === name ? '#2a3a50' : '#1e2a3a';
  });
  setupControls();
  draw();
};

const setupControls = () => {
  const cDiv = document.getElementById('controls');
  if (!cDiv) return;
  let html = '';
  const mkSlider = (label, id, min, max, step, value, unit) =>
    '<div style="background:#0f1520;border-radius:8px;padding:14px;border:1px solid #1e2a3a;margin-bottom:8px">' +
    '<div style="display:flex;justify-content:space-between;font-size:12px;color:#8899aa;margin-bottom:6px;font-weight:500;text-transform:uppercase;letter-spacing:0.5px">' +
    '<span>' + label + '</span><span id="' + id + 'Val" style="color:#e0e6f0;font-family:JetBrains Mono,monospace">' + value + unit + '</span></div>' +
    '<input type="range" id="' + id + '" min="' + min + '" max="' + max + '" step="' + step + '" value="' + value + '" style="width:100%;accent-color:#60a5fa"></div>';

  if (activeSim === 'pendulum') {
    const p = SIMS.pendulum.params;
    html += mkSlider('Length', 'pLen', 0.5, 3, 0.1, p.length, ' m');
    html += mkSlider('Gravity', 'pGrav', 1, 20, 0.5, p.gravity, ' m/s\\u00b2');
    html += mkSlider('Initial Angle', 'pAngle', 5, 85, 1, Math.round(p.initialAngle * 180 / Math.PI), '\\u00b0');
  } else if (activeSim === 'projectile') {
    const p = SIMS.projectile.params;
    html += mkSlider('Launch Angle', 'prAngle', 5, 85, 1, p.angle, '\\u00b0');
    html += mkSlider('Initial Velocity', 'prVel', 5, 50, 1, p.initialVelocity, ' m/s');
  } else {
    const p = SIMS.springMass.params;
    html += mkSlider('Spring Constant (k)', 'smK', 1, 50, 1, p.springConstant, ' N/m');
    html += mkSlider('Mass', 'smM', 0.5, 10, 0.5, p.mass, ' kg');
    html += mkSlider('Init Displacement', 'smD', 0.2, 2.0, 0.1, p.initialDisplacement, ' m');
  }
  cDiv.innerHTML = html;

  // bind events
  if (activeSim === 'pendulum') {
    const bind = (id, key, unit, transform) => {
      const el = document.getElementById(id);
      if (el) el.oninput = () => {
        const v = parseFloat(el.value);
        SIMS.pendulum.params[key] = transform ? transform(v) : v;
        document.getElementById(id + 'Val').textContent = v + unit;
        resetSim('pendulum');
      };
    };
    bind('pLen', 'length', ' m');
    bind('pGrav', 'gravity', ' m/s\\u00b2');
    bind('pAngle', 'initialAngle', '\\u00b0', (v) => { SIMS.pendulum.params.initialAngle = v * Math.PI / 180; return v * Math.PI / 180; });
  } else if (activeSim === 'projectile') {
    const bind = (id, key, unit) => {
      const el = document.getElementById(id);
      if (el) el.oninput = () => {
        SIMS.projectile.params[key] = parseFloat(el.value);
        document.getElementById(id + 'Val').textContent = el.value + unit;
        resetSim('projectile');
      };
    };
    bind('prAngle', 'angle', '\\u00b0');
    bind('prVel', 'initialVelocity', ' m/s');
  } else {
    const bind = (id, key, unit) => {
      const el = document.getElementById(id);
      if (el) el.oninput = () => {
        SIMS.springMass.params[key] = parseFloat(el.value);
        document.getElementById(id + 'Val').textContent = el.value + unit;
        resetSim('springMass');
      };
    };
    bind('smK', 'springConstant', ' N/m');
    bind('smM', 'mass', ' kg');
    bind('smD', 'initialDisplacement', ' m');
  }
};

document.addEventListener('DOMContentLoaded', () => {
  // tabs
  $$('.sim-tab').forEach((t) => t.addEventListener('click', () => switchTab(t.dataset.sim)));

  // play/pause
  document.getElementById('btnPlay').addEventListener('click', () => {
    running = !running;
    document.getElementById('btnPlay').textContent = running ? '\\u23F8 Pause' : '\\u25B6 Play';
  });

  // reset
  document.getElementById('btnReset').addEventListener('click', () => {
    running = false;
    document.getElementById('btnPlay').textContent = '\\u25B6 Play';
    resetSim(activeSim);
  });

  // speed
  document.getElementById('speedSlider').addEventListener('input', (e) => {
    speed = parseFloat(e.target.value);
    document.getElementById('speedVal').textContent = speed.toFixed(2) + 'x';
  });

  setupControls();
  requestAnimationFrame(loop);
});
`

