                'div',
                { style: styleToString(styles.controlLabel as Record<string, string>) },
                h('span', {}, 'Speed'),
                h(
                  'span',
                  {
                    id: 'speedVal',
                    style: "color:#e0e6f0;font-family:'JetBrains Mono',monospace",
                  },
                  '1.00x'
                )
              ),
              h('input', {
                type: 'range',
                id: 'speedSlider',
                min: '0.25',
                max: '4',
                step: '0.25',
                value: '1',
                style: 'width:100%;accent-color:#60a5fa',
              })
            ),
            // Play/Pause + Reset
            h(
              'div',
              { style: styleToString(styles.buttons as Record<string, string>) },
              h(
                'button',
                {
                  id: 'btnPlay',
                  style: styleToString({
                    ...(styles.btn as Record<string, string>),
                    ...(styles.btnPlay as Record<string, string>),
                  }),
                },
                '\u25B6 Play'
              ),
              h(
                'button',
                {
                  id: 'btnReset',
                  style: styleToString({
                    ...(styles.btn as Record<string, string>),
                    ...(styles.btnReset as Record<string, string>),
                  }),
                },
                '\u21BB Reset'
              )
            ),
            // Readout panel
            h(
              'div',
              { style: styleToString(styles.readout as Record<string, string>) },
              h(
                'div',
                { style: styleToString(styles.readoutTitle as Record<string, string>) },
                'Real-Time Values'
              ),
              readoutRow(0),
              readoutRow(1),
              readoutRow(2),
              readoutRow(3),
              readoutRow(4),
              readoutRow(5)
            )
          )
        )
      ),
      h('script', {}, clientScript)
    )
  )

  return '<!DOCTYPE html>' + ssr(page)
}

import { renderPage } from './ui'

export type ServerConfig = {
  port: number
  hostname?: string
}

export const createServer = (config: ServerConfig = { port: 3000 }) => {
  const { port, hostname = 'localhost' } = config

  const cachedPage = renderPage()

  const server = Bun.serve({
    port,
    hostname,
    fetch: (req: Request): Response => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/index.html') {
        return new Response(cachedPage, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      if (url.pathname === '/api/defaults') {
        const file = Bun.file('./data/defaults.json')
        return new Response(file, {
          headers: { 'Content-Type': 'application/json' },
        })
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log(`Physics Simulator running at http://${hostname}:${port}`)
  return server
}
